import { PublicCard } from '../../../types';

export const biologyCards: PublicCard[] = [
  { id: 'dc-biology-0001', deck_id: 'deck-biology', sort_order: 1, front: "Cell Theory", back: "All living organisms are composed of one or more cells, the cell is the basic unit of life, and all cells arise from pre-existing cells. Formulated by Schleiden, Schwann, and Virchow." , front_translations: {"es":"Teoria Celular","de":"Zelltheorie","fr":"Théorie cellulaire","tr":"Hücre Teorisi","nl":"Celtheorie","ru":"Клеточная теория","zh":"细胞学说","pt_BR":"Teoria Celular","pt_PT":"Teoria Celular"}, back_translations: {"es":"Todos los organismos vivos son compuestos por una o más células, a célula es a unidad básica de la vida y todas las células surgem de células pré-existentes. Formulada por Schleiden, Schwann y Virchow.","de":"Alle lebenden Organismen bestehen aus einer oder mehreren Zellen, die Zelle ist die grundlegende Einheit des Lebens, und alle Zellen entstehen aus bereits existierenden Zellen. Formuliert von Schleiden, Schwann und Virchow.","fr":"Tous les organismes vivants sont composés d'une ou plusieurs cellules, la cellule est l'unité de base de la vie, et toutes les cellules proviennent de cellules préexistantes. Formulée par Schleiden, Schwann et Virchow.","tr":"Tüm canlı organizmalar bir veya daha fazla hücreden oluşur, hücre yaşamın temel birimidir ve tüm hücreler mevcut hücrelerden oluşur. Schleiden, Schwann ve Virchow tarafından formüle edilmiştir.","nl":"Alle levende organismen zijn opgebouwd uit één of meer cellen, de cel is de basiseenheid van het leven en alle cellen ontstaan uit reeds bestaande cellen. Geformuleerd door Schleiden, Schwann en Virchow.","ru":"Все живые организмы состоят из одной или нескольких клеток, клетка является основной единицей жизни, и все клетки возникают из уже существующих клеток. Сформулирована Шлейденом, Шванном и Вирховым.","zh":"所有生物体由一个或多个细胞组成，细胞是生命的基本单位，所有细胞均来自已有的细胞。由施莱登、施旺和魏尔啸提出。","pt_BR":"Todos os organismos vivos são compostos por uma ou mais células, a célula é a unidade básica da vida e todas as células surgem de células pré-existentes. Formulada por Schleiden, Schwann e Virchow.","pt_PT":"Todos os organismos vivos são compostos por uma ou mais células, a célula é a unidade básica da vida e todas as células surgem de células pré-existentes. Formulada por Schleiden, Schwann e Virchow."}},
  { id: 'dc-biology-0002', deck_id: 'deck-biology', sort_order: 2, front: "Prokaryotic Cell", back: "A cell lacking a membrane-bound nucleus and organelles. Genetic material is in a nucleoid region. Includes bacteria and archaea. Generally smaller (1–10 μm) than eukaryotic cells." , front_translations: {"es":"Célula Procariótica","de":"Prokaryotische Zelle","fr":"Cellule procaryote","tr":"Prokaryotik Hücre","nl":"Prokaryotische cel","ru":"Прокариотическая клетка","zh":"原核细胞","pt_BR":"Célula Procariótica","pt_PT":"Célula Procariota"}, back_translations: {"es":"Una célula sin núcleo y organelas delimitados por membrana. El material genético se encuentra en una región nucleoide. Inclui bacterias y arqueias. Geralmente menor (1–10 μm) del que células eucarióticas.","de":"Eine Zelle ohne membrangebundenen Zellkern und Organellen. Das genetische Material befindet sich in einer Nukleoidregion. Umfasst Bakterien und Archaeen. Generell kleiner (1–10 μm) als eukaryotische Zellen.","fr":"Une cellule dépourvue de noyau et d'organites entourés d'une membrane. Le matériel génétique se trouve dans une région nucléoïde. Comprend les bactéries et les archées. Généralement plus petite (1–10 μm) que les cellules eucaryotes.","tr":"Membranla çevrili çekirdek ve organel içermeyen bir hücre. Genetik materyal bir nükleoid bölgesinde bulunur. Bakteri ve arkeleri kapsar. Genellikle ökaryotik hücrelerden daha küçüktür (1–10 μm).","nl":"Een cel zonder membraangebonden kern en organellen. Genetisch materiaal bevindt zich in een nucleoïdregio. Omvat bacteriën en archaea. Over het algemeen kleiner (1–10 μm) dan eukaryotische cellen.","ru":"Клетка, лишённая окружённого мембраной ядра и органелл. Генетический материал находится в нуклеоидной области. Включает бактерии и архей. Как правило, меньше (1–10 мкм) эукариотических клеток.","zh":"没有膜包被细胞核和细胞器的细胞。遗传物质位于类核区。包括细菌和古菌。通常比真核细胞小（1–10 μm）。","pt_BR":"Uma célula sem núcleo e organelas delimitados por membrana. O material genético encontra-se numa região nucleoide. Inclui bactérias e arqueias. Geralmente menor (1–10 μm) do que células eucarióticas.","pt_PT":"Uma célula sem núcleo e organelos delimitados por membrana. O material genético encontra-se numa região nucleoide. Inclui bactérias e arqueas. Geralmente mais pequena (1–10 μm) do que as células eucariotas."}},
  { id: 'dc-biology-0003', deck_id: 'deck-biology', sort_order: 3, front: "Eukaryotic Cell", back: "A cell with a membrane-bound nucleus containing its DNA, and membrane-bound organelles. Includes all animals, plants, fungi, and protists. Generally larger (10–100 μm) than prokaryotes." , front_translations: {"es":"Célula Eucariótica","de":"Eukaryotische Zelle","fr":"Cellule eucaryote","tr":"Ökaryotik Hücre","nl":"Eukaryotische cel","ru":"Эукариотическая клетка","zh":"真核细胞","pt_BR":"Célula Eucariótica","pt_PT":"Célula Eucariota"}, back_translations: {"es":"Una célula con un núcleo delimitado por membrana conteniendo su DNA y organelas delimitadas por membrana. Inclui todos los animales, plantas, fungos y protistas. Geralmente mayor (10–100 μm) del que los procariotos.","de":"Eine Zelle mit einem membrangebundenen Zellkern, der ihre DNA enthält, sowie membrangebundenen Organellen. Umfasst alle Tiere, Pflanzen, Pilze und Protisten. Generell größer (10–100 μm) als Prokaryoten.","fr":"Une cellule possédant un noyau entouré d'une membrane contenant son ADN, ainsi que des organites membranaires. Comprend tous les animaux, plantes, champignons et protistes. Généralement plus grande (10–100 μm) que les procaryotes.","tr":"DNA'sını içeren membranla çevrili bir çekirdeğe ve membranla çevrili organellere sahip bir hücre. Tüm hayvanlar, bitkiler, mantarlar ve protestoları kapsar. Genellikle prokaryotlardan daha büyüktür (10–100 μm).","nl":"Een cel met een membraangebonden kern die zijn DNA bevat, en membraangebonden organellen. Omvat alle dieren, planten, schimmels en protisten. Over het algemeen groter (10–100 μm) dan prokaryoten.","ru":"Клетка с окружённым мембраной ядром, содержащим ДНК, и мембранными органеллами. Включает всех животных, растения, грибы и протистов. Как правило, крупнее (10–100 мкм) прокариот.","zh":"具有含有DNA的膜包被细胞核以及膜包被细胞器的细胞。包括所有动物、植物、真菌和原生生物。通常比原核生物大（10–100 μm）。","pt_BR":"Uma célula com um núcleo delimitado por membrana contendo seu DNA e organelas delimitadas por membrana. Inclui todos os animais, plantas, fungos e protistas. Geralmente maior (10–100 μm) do que os procariotos.","pt_PT":"Uma célula com um núcleo delimitado por membrana contendo o seu DNA e organelos delimitados por membrana. Inclui todos os animais, plantas, fungos e protistas. Geralmente maior (10–100 μm) do que os procariotas."}},
  { id: 'dc-biology-0004', deck_id: 'deck-biology', sort_order: 4, front: "Cell Membrane", back: "A phospholipid bilayer with embedded proteins that selectively controls what enters and exits the cell. The fluid mosaic model describes membrane proteins floating in the lipid bilayer." , front_translations: {"es":"Membrana Celular","de":"Zellmembran","fr":"Membrane cellulaire","tr":"Hücre Zarı","nl":"Celmembraan","ru":"Клеточная мембрана","zh":"细胞膜","pt_BR":"Membrana Celular","pt_PT":"Membrana Celular"}, back_translations: {"es":"Una bicamada fosfolipídica con proteínas incorporadas que controla seletivamente el que entra y sai de la célula. El modelo del mosaico fluido descreve proteínas de membrana flutuando en la bicamada lipídica.","de":"Eine Phospholipid-Doppelschicht mit eingebetteten Proteinen, die selektiv kontrolliert, was in die Zelle ein- und austritt. Das Fluid-Mosaik-Modell beschreibt Membranproteine, die in der Lipiddoppelschicht schwimmen.","fr":"Une bicouche phospholipidique avec des protéines intégrées qui contrôle sélectivement ce qui entre et sort de la cellule. Le modèle de la mosaïque fluide décrit les protéines membranaires flottant dans la bicouche lipidique.","tr":"Hücreye giren ve çıkan maddeleri seçici olarak kontrol eden, gömülü proteinlere sahip bir fosfolipid çift tabakası. Akışkan mozaik modeli, lipid çift tabakasında yüzen membran proteinlerini tanımlar.","nl":"Een fosfolipide dubbellaag met ingebedde eiwitten die selectief controleert wat de cel binnenkomt en verlaat. Het vloeistof-mozaïekmodel beschrijft membraaneiwitten die in de lipide dubbellaag drijven.","ru":"Фосфолипидный бислой со встроенными белками, избирательно контролирующий поступление веществ в клетку и их выход. Жидкостно-мозаичная модель описывает мембранные белки, плавающие в липидном бислое.","zh":"由磷脂双分子层及嵌入蛋白质构成，选择性地控制进出细胞的物质。流动镶嵌模型描述了膜蛋白在脂质双层中自由漂动的状态。","pt_BR":"Uma bicamada fosfolipídica com proteínas incorporadas que controla seletivamente o que entra e sai da célula. O modelo do mosaico fluido descreve proteínas de membrana flutuando na bicamada lipídica.","pt_PT":"Uma bicamada fosfolipídica com proteínas incorporadas que controla seletivamente o que entra e sai da célula. O modelo do mosaico fluido descreve proteínas de membrana a flutuar na bicamada lipídica."}},
  { id: 'dc-biology-0005', deck_id: 'deck-biology', sort_order: 5, front: "Mitochondria", back: "The organelle known as the 'powerhouse of the cell'; produces ATP through cellular respiration. Has its own DNA, supporting the endosymbiotic theory of its bacterial origins." , front_translations: {"es":"Mitocondria","de":"Mitochondrien","fr":"Mitochondrie","tr":"Mitokondri","nl":"Mitochondrium","ru":"Митохондрия","zh":"线粒体","pt_BR":"Mitocôndria","pt_PT":"Mitocôndria"}, back_translations: {"es":"La organela conocida como a 'usina de energía de la célula'; produce ATP por medio de la respiración celular. Possui su propio DNA, apoiando a teoría endossimbiótica de su origem bacteriana.","de":"Das Organell, bekannt als das 'Kraftwerk der Zelle'; produziert ATP durch Zellatmung. Besitzt eigene DNA, was die endosymbiotische Theorie seiner bakteriellen Herkunft unterstützt.","fr":"L'organite connu comme la «centrale énergétique de la cellule»; produit de l'ATP par la respiration cellulaire. Possède son propre ADN, ce qui soutient la théorie endosymbiotique de son origine bactérienne.","tr":"Hücrenin 'enerji santrali' olarak bilinen organel; hücresel solunum yoluyla ATP üretir. Kendi DNA'sına sahiptir; bu durum, bakteri kökenine ilişkin endosimbiyotik teoriyi destekler.","nl":"Het organel bekend als de 'krachtcentrale van de cel'; produceert ATP via cellulaire ademhaling. Heeft zijn eigen DNA, wat de endosymbiosetheorie van zijn bacteriële oorsprong ondersteunt.","ru":"Органелла, известная как «энергетическая станция клетки»; производит АТФ в процессе клеточного дыхания. Имеет собственную ДНК, что подтверждает эндосимбиотическую теорию её бактериального происхождения.","zh":"被称为细胞\"动力工厂\"的细胞器，通过细胞呼吸产生ATP。拥有自身DNA，支持其源自细菌的内共生理论。","pt_BR":"A organela conhecida como a 'usina de energia da célula'; produz ATP por meio da respiração celular. Possui seu próprio DNA, apoiando a teoria endossimbiótica de sua origem bacteriana.","pt_PT":"O organelo conhecido como a 'central energética da célula'; produz ATP através da respiração celular. Possui o seu próprio DNA, suportando a teoria endossimbiótica da sua origem bacteriana."}},
  { id: 'dc-biology-0006', deck_id: 'deck-biology', sort_order: 6, front: "Chloroplast", back: "The organelle in plant and algal cells where photosynthesis occurs. Contains thylakoids (for light reactions) and stroma (for the Calvin cycle). Has its own DNA; derived from cyanobacteria." , front_translations: {"es":"Cloroplasto","de":"Chloroplast","fr":"Chloroplaste","tr":"Kloroplast","nl":"Chloroplast","ru":"Хлоропласт","zh":"叶绿体","pt_BR":"Cloroplasto","pt_PT":"Cloroplasto"}, back_translations: {"es":"La organela en las células vegetais y de algas donde ocurre a fotossíntese. Contém tilacoides (para reacciones luminosas) y estroma (para el ciclo de Calvin). Possui propio DNA; derivado de cianobactérias.","de":"Das Organell in Pflanzen- und Algenzellen, in dem die Photosynthese stattfindet. Enthält Thylakoide (für Lichtreaktionen) und Stroma (für den Calvin-Zyklus). Besitzt eigene DNA; stammt von Cyanobakterien ab.","fr":"L'organite des cellules végétales et algales où se déroule la photosynthèse. Contient des thylakoïdes (pour les réactions lumineuses) et le stroma (pour le cycle de Calvin). Possède son propre ADN; dérivé des cyanobactéries.","tr":"Bitki ve alg hücrelerinde fotosentezin gerçekleştiği organel. Tilakoidler (ışık reaksiyonları için) ve stroma (Calvin döngüsü için) içerir. Kendi DNA'sına sahiptir; siyanobakterilerden türemiştir.","nl":"Het organel in plant- en algencellen waar fotosynthese plaatsvindt. Bevat thylakoïden (voor lichtreacties) en stroma (voor de calvincyclus). Heeft eigen DNA; afgeleid van cyanobacteriën.","ru":"Органелла в клетках растений и водорослей, где происходит фотосинтез. Содержит тилакоиды (для световых реакций) и строму (для цикла Калвина). Имеет собственную ДНК; произошла от цианобактерий.","zh":"植物和藻类细胞中进行光合作用的细胞器。含有类囊体（用于光反应）和基质（用于卡尔文循环）。拥有自身DNA，起源于蓝藻。","pt_BR":"A organela nas células vegetais e de algas onde ocorre a fotossíntese. Contém tilacoides (para reações luminosas) e estroma (para o ciclo de Calvin). Possui próprio DNA; derivado de cianobactérias.","pt_PT":"O organelo nas células vegetais e das algas onde ocorre a fotossíntese. Contém tilacoides (para reações luminosas) e estroma (para o ciclo de Calvin). Possui o seu próprio DNA; derivado de cianobactérias."}},
  { id: 'dc-biology-0007', deck_id: 'deck-biology', sort_order: 7, front: "Nucleus", back: "The membrane-bound organelle containing the cell's DNA. Bounded by the nuclear envelope with nuclear pores. Contains the nucleolus where ribosomes are assembled." , front_translations: {"es":"Núcleo","de":"Zellkern","fr":"Noyau","tr":"Çekirdek","nl":"Celkern","ru":"Ядро клетки","zh":"细胞核","pt_BR":"Núcleo","pt_PT":"Núcleo"}, back_translations: {"es":"La organela delimitada por membrana que contiene el DNA de la célula. Delimitada por el envelope nuclear con poros nucleares. Contém el nucléolo donde los ribossomos son montados.","de":"Das membrangebundene Organell, das die DNA der Zelle enthält. Umgeben von der Kernhülle mit Kernporen. Enthält den Nukleolus, in dem Ribosomen zusammengesetzt werden.","fr":"L'organite entouré d'une membrane contenant l'ADN de la cellule. Délimité par l'enveloppe nucléaire avec des pores nucléaires. Contient le nucléole où les ribosomes sont assemblés.","tr":"Hücrenin DNA'sını içeren membranla çevrili organel. Nükleer porlar içeren nükleer zar ile çevrilidir. Ribozomların bir araya getirildiği nükleolusu içerir.","nl":"Het membraangebonden organel dat het DNA van de cel bevat. Omgeven door de kernmembraan met kernporiën. Bevat de nucleolus waar ribosomen worden samengesteld.","ru":"Органелла, окружённая мембраной и содержащая ДНК клетки. Ограничена ядерной оболочкой с ядерными порами. Содержит ядрышко, где собираются рибосомы.","zh":"含有细胞DNA的膜包被细胞器。由具有核孔的核膜包围。含有核仁，核糖体在此组装。","pt_BR":"A organela delimitada por membrana que contém o DNA da célula. Delimitada pelo envelope nuclear com poros nucleares. Contém o nucléolo onde os ribossomos são montados.","pt_PT":"O organelo delimitado por membrana que contém o DNA da célula. Delimitado pelo envelope nuclear com poros nucleares. Contém o nucléolo onde os ribossomas são montados."}},
  { id: 'dc-biology-0008', deck_id: 'deck-biology', sort_order: 8, front: "Ribosome", back: "Cellular machinery that translates mRNA into protein. Consists of large and small subunits made of ribosomal RNA (rRNA) and proteins. Found free in cytoplasm and on rough ER." , front_translations: {"es":"Ribossomo","de":"Ribosom","fr":"Ribosome","tr":"Ribozom","nl":"Ribosoom","ru":"Рибосома","zh":"核糖体","pt_BR":"Ribossomo","pt_PT":"Ribossoma"}, back_translations: {"es":"Maquinaria celular que traduz mRNA en proteína. Consiste en subunidades grande y pequeña feitas de RNA ribossomal (rRNA) y proteínas. Encontrado livre en el citoplasma y en el RE rugoso.","de":"Zelluläre Maschinerie, die mRNA in Protein übersetzt. Besteht aus großen und kleinen Untereinheiten aus ribosomaler RNA (rRNA) und Proteinen. Findet sich frei im Zytoplasma und am rauen ER.","fr":"Machinerie cellulaire qui traduit l'ARNm en protéine. Composé de grandes et petites sous-unités constituées d'ARN ribosomique (ARNr) et de protéines. Se trouve libre dans le cytoplasme et sur le RE rugueux.","tr":"mRNA'yı proteine çeviren hücresel makine. Ribozomal RNA (rRNA) ve proteinlerden oluşan büyük ve küçük alt birimlerden oluşur. Sitoplazmada serbest halde ve kaba ER'de bulunur.","nl":"Cellulair apparaat dat mRNA vertaalt naar eiwit. Bestaat uit grote en kleine subeenheden gemaakt van ribosomaal RNA (rRNA) en eiwitten. Vrij aanwezig in het cytoplasma en op het ruw ER.","ru":"Клеточный механизм, транслирующий мРНК в белок. Состоит из большой и малой субъединиц, образованных рибосомальной РНК (рРНК) и белками. Обнаруживается свободно в цитоплазме и на шероховатом ЭПР.","zh":"将mRNA翻译成蛋白质的细胞机器。由核糖体RNA（rRNA）和蛋白质组成的大小亚基构成。游离于细胞质中或附着在粗面内质网上。","pt_BR":"Maquinaria celular que traduz mRNA em proteína. Consiste em subunidades grande e pequena feitas de RNA ribossomal (rRNA) e proteínas. Encontrado livre no citoplasma e no RE rugoso.","pt_PT":"Maquinaria celular que traduz o mRNA em proteína. Consiste em subunidades grande e pequena constituídas por RNA ribossómico (rRNA) e proteínas. Encontrado livre no citoplasma e no RE rugoso."}},
  { id: 'dc-biology-0009', deck_id: 'deck-biology', sort_order: 9, front: "Endoplasmic Reticulum (ER)", back: "A network of membranes continuous with the nuclear envelope. Rough ER (studded with ribosomes) synthesizes secretory proteins; smooth ER synthesizes lipids and detoxifies drugs." , front_translations: {"es":"Retículo Endoplasmático (RE)","de":"Endoplasmatisches Retikulum (ER)","fr":"Réticulum endoplasmique (RE)","tr":"Endoplazmik Retikulum (ER)","nl":"Endoplasmatisch reticulum (ER)","ru":"Эндоплазматическая сеть (ЭПС)","zh":"内质网（ER）","pt_BR":"Retículo Endoplasmático (RE)","pt_PT":"Retículo Endoplasmático (RE)"}, back_translations: {"es":"Una red de membranas contínua con el envelope nuclear. RE rugoso (repleto de ribossomos) sintetiza proteínas secretoras; RE liso sintetiza lipídeos y desintoxica medicamentos.","de":"Ein Membransystem, das mit der Kernhülle verbunden ist. Raues ER (mit Ribosomen besetzt) synthetisiert sekretorische Proteine; glattes ER synthetisiert Lipide und entgiftet Medikamente.","fr":"Un réseau de membranes en continuité avec l'enveloppe nucléaire. Le RE rugueux (parsemé de ribosomes) synthétise les protéines sécrétoires; le RE lisse synthétise les lipides et détoxifie les médicaments.","tr":"Nükleer zarla süreklilik gösteren membran ağı. Kaba ER (ribozomlarla kaplı) salgı proteinleri sentezler; düz ER lipid sentezler ve ilaçları detoksifiye eder.","nl":"Een netwerk van membranen dat in verbinding staat met de kernmembraan. Ruw ER (bezaaid met ribosomen) synthetiseert secretoire eiwitten; glad ER synthetiseert lipiden en ontgift geneesmiddelen.","ru":"Система мембран, непрерывных с ядерной оболочкой. Шероховатый ЭПС (покрытый рибосомами) синтезирует секреторные белки; гладкий ЭПС синтезирует липиды и детоксицирует лекарства.","zh":"与核膜相连续的膜状网络。粗面内质网（附着核糖体）合成分泌蛋白；光面内质网合成脂质并解毒药物。","pt_BR":"Uma rede de membranas contínua com o envelope nuclear. RE rugoso (repleto de ribossomos) sintetiza proteínas secretoras; RE liso sintetiza lipídeos e desintoxica medicamentos.","pt_PT":"Uma rede de membranas contínua com o envelope nuclear. RE rugoso (coberto de ribossomas) sintetiza proteínas secretoras; RE liso sintetiza lípidos e desintoxica medicamentos."}},
  { id: 'dc-biology-0010', deck_id: 'deck-biology', sort_order: 10, front: "Golgi Apparatus", back: "The cell's 'post office'; modifies, packages, and directs proteins from the rough ER to their final destinations (secretion, lysosomes, plasma membrane). Has cis (receiving) and trans (shipping) faces." , front_translations: {"es":"Complexo de Golgi","de":"Golgi-Apparat","fr":"Appareil de Golgi","tr":"Golgi Aygıtı","nl":"Golgiapparaat","ru":"Аппарат Гольджи","zh":"高尔基体","pt_BR":"Complexo de Golgi","pt_PT":"Complexo de Golgi"}, back_translations: {"es":"El 'correio' de la célula; modifica, empacota y direciona proteínas del RE rugoso para sus destinos finais (secreción, lisossomos, membrana plasmática). Possui faces cis (receptora) y trans (expedidora).","de":"Die 'Post' der Zelle; modifiziert, verpackt und leitet Proteine vom rauen ER an ihre endgültigen Ziele (Sekretion, Lysosomen, Plasmamembran). Hat eine cis- (Empfangs-) und eine trans- (Versand-)Seite.","fr":"La «poste» de la cellule; modifie, emballe et dirige les protéines du RE rugueux vers leurs destinations finales (sécrétion, lysosomes, membrane plasmique). Possède des faces cis (réception) et trans (expédition).","tr":"Hücrenin 'postanesi'; kaba ER'den gelen proteinleri modifiye eder, paketler ve nihai hedeflerine (salgılama, lizozomlar, plazma zarı) yönlendirir. Cis (alıcı) ve trans (gönderici) yüzleri vardır.","nl":"Het 'postkantoor' van de cel; modificeert, verpakt en stuurt eiwitten van het ruw ER naar hun eindbestemming (secretie, lysosomen, plasmamembraan). Heeft cis- (ontvangst) en trans- (verzending) zijden.","ru":"«Почта» клетки; модифицирует, упаковывает и направляет белки из шероховатого ЭПС к конечным адресатам (секреция, лизосомы, плазматическая мембрана). Имеет цис- (принимающую) и транс- (отправляющую) стороны.","zh":"细胞的\"邮局\"；对来自粗面内质网的蛋白质进行加工、包装，并将其导向最终目的地（分泌、溶酶体、质膜）。具有顺面（接收）和反面（输出）。","pt_BR":"O 'correio' da célula; modifica, empacota e direciona proteínas do RE rugoso para seus destinos finais (secreção, lisossomos, membrana plasmática). Possui faces cis (receptora) e trans (expedidora).","pt_PT":"O 'correio' da célula; modifica, empacota e direciona proteínas do RE rugoso para os seus destinos finais (secreção, lisossomas, membrana plasmática). Possui faces cis (recetora) e trans (expedidora)."}},
  { id: 'dc-biology-0011', deck_id: 'deck-biology', sort_order: 11, front: "Lysosome", back: "A membrane-bound organelle containing digestive enzymes (hydrolases) that break down waste materials, cellular debris, and foreign material. Maintains its acidic interior (pH ~4.5–5)." , front_translations: {"es":"Lisossomo","de":"Lysosom","fr":"Lysosome","tr":"Lizozom","nl":"Lysosoom","ru":"Лизосома","zh":"溶酶体","pt_BR":"Lisossomo","pt_PT":"Lisossoma"}, back_translations: {"es":"Una organela delimitada por membrana conteniendo enzimas digestivas (hidrolases) que degradam materiais de descarte, detritos celulares y material estranho. Mantém su interior ácido (pH ~4,5–5).","de":"Ein membrangebundenes Organell, das Verdauungsenzyme (Hydrolasen) enthält, die Abfallmaterialien, Zelltrümmer und Fremdmaterial abbauen. Behält sein saures Inneres aufrecht (pH ~4,5–5).","fr":"Un organite entouré d'une membrane contenant des enzymes digestives (hydrolases) qui dégradent les déchets, les débris cellulaires et les corps étrangers. Maintient son intérieur acide (pH ~4,5–5).","tr":"Atık maddeleri, hücresel artıkları ve yabancı materyali parçalayan sindirim enzimleri (hidrolazlar) içeren membranla çevrili organel. Asidik iç yapısını korur (pH ~4,5–5).","nl":"Een membraangebonden organel dat spijsverteringsenzymen (hydrolases) bevat die afvalstoffen, celresten en vreemd materiaal afbreken. Handhaaft zijn zure interieur (pH ~4,5–5).","ru":"Органелла, окружённая мембраной и содержащая пищеварительные ферменты (гидролазы), расщепляющие отходы, клеточный дебрис и чужеродный материал. Поддерживает кислую внутреннюю среду (pH ~4,5–5).","zh":"含有水解酶的膜包被细胞器，降解废物、细胞碎片和外来物质。维持其酸性内部环境（pH约4.5–5）。","pt_BR":"Uma organela delimitada por membrana contendo enzimas digestivas (hidrolases) que degradam materiais de descarte, detritos celulares e material estranho. Mantém seu interior ácido (pH ~4,5–5).","pt_PT":"Um organelo delimitado por membrana contendo enzimas digestivas (hidrolases) que degradam materiais de resíduo, detritos celulares e material estranho. Mantém o seu interior ácido (pH ~4,5–5)."}},
  { id: 'dc-biology-0012', deck_id: 'deck-biology', sort_order: 12, front: "Vacuole", back: "A membrane-bound storage organelle. In plant cells, the large central vacuole stores water, waste products, and nutrients, and provides turgor pressure. Contractile vacuoles in protists expel excess water." , front_translations: {"es":"Vacúolo","de":"Vakuole","fr":"Vacuole","tr":"Vakuol","nl":"Vacuole","ru":"Вакуоль","zh":"液泡","pt_BR":"Vacúolo","pt_PT":"Vacúolo"}, back_translations: {"es":"Una organela de almacenamiento delimitada por membrana. Nas células vegetais, el grande vacúolo central almacena agua, productos de resíduo y nutrientes, y proporciona presión de turgor. Vacúolos contráteis en protistas expelem el exceso de agua.","de":"Ein membrangebundenes Speicherorganell. In Pflanzenzellen speichert die große zentrale Vakuole Wasser, Abfallprodukte und Nährstoffe und sorgt für Turgordruck. Kontraktile Vakuolen in Protisten stoßen überschüssiges Wasser aus.","fr":"Un organite de stockage entouré d'une membrane. Dans les cellules végétales, la grande vacuole centrale stocke l'eau, les déchets et les nutriments, et fournit la pression de turgescence. Les vacuoles contractiles des protistes expulsent l'excès d'eau.","tr":"Membranla çevrili bir depolama organeli. Bitki hücrelerinde büyük merkezi vakuol su, atık ürünler ve besinleri depolar, turgor basıncı sağlar. Protestolardaki kontraktil vakuoller fazla suyu dışarı atar.","nl":"Een membraangebonden opslagorganel. In plantencellen slaat de grote centrale vacuole water, afvalstoffen en voedingsstoffen op en zorgt voor turgordruk. Contractiele vacuolen in protisten stoten overtollig water uit.","ru":"Ограниченная мембраной запасающая органелла. В растительных клетках большая центральная вакуоль хранит воду, продукты отходов и питательные вещества, обеспечивая тургорное давление. Сократительные вакуоли протистов выводят избыток воды.","zh":"由膜包被的储存细胞器。在植物细胞中，大型中央液泡储存水分、废物和养分，提供膨压。原生生物中的伸缩泡排出多余的水分。","pt_BR":"Uma organela de armazenamento delimitada por membrana. Nas células vegetais, o grande vacúolo central armazena água, produtos de resíduo e nutrientes, e fornece pressão de turgor. Vacúolos contráteis em protistas expelem o excesso de água.","pt_PT":"Um organelo de armazenamento delimitado por membrana. Nas células vegetais, o grande vacúolo central armazena água, produtos de resíduo e nutrientes, e fornece pressão de turgescência. Os vacúolos contrácteis dos protistas expelem o excesso de água."}},
  { id: 'dc-biology-0013', deck_id: 'deck-biology', sort_order: 13, front: "Cytoskeleton", back: "A network of protein fibers (microfilaments, intermediate filaments, microtubules) that provides structural support, facilitates cell movement, and helps organize organelles within eukaryotic cells." , front_translations: {"es":"Citoesqueleto","de":"Zytoskelett","fr":"Cytosquelette","tr":"Sitoiskelett","nl":"Cytoskelet","ru":"Цитоскелет","zh":"细胞骨架","pt_BR":"Citoesqueleto","pt_PT":"Citoesqueleto"}, back_translations: {"es":"Una red de fibras proteicas (microfilamentos, filamentos intermediários, microtúbulos) que proporciona suporte estrutural, facilita el movimiento celular y ayuda a organizar las organelas en células eucarióticas.","de":"Ein Netzwerk aus Proteinfasern (Mikrofilamente, Intermediärfilamente, Mikrotubuli), das strukturelle Unterstützung bietet, Zellbewegung erleichtert und bei der Organisation von Organellen in eukaryotischen Zellen hilft.","fr":"Un réseau de fibres protéiques (microfilaments, filaments intermédiaires, microtubules) qui assure un soutien structurel, facilite le mouvement cellulaire et aide à organiser les organites dans les cellules eucaryotes.","tr":"Yapısal destek sağlayan, hücre hareketini kolaylaştıran ve ökaryotik hücrelerde organellerin düzenlenmesine yardımcı olan protein lifleri ağı (mikrofilamentler, ara filamentler, mikrotübüller).","nl":"Een netwerk van eiwitvezels (microfilamenten, intermediaire filamenten, microtubuli) dat structurele ondersteuning biedt, celbeweging vergemakkelijkt en helpt bij het organiseren van organellen in eukaryotische cellen.","ru":"Сеть белковых волокон (микрофиламенты, промежуточные филаменты, микротрубочки), обеспечивающая структурную поддержку, облегчающая движение клеток и помогающая организовывать органеллы в эукариотических клетках.","zh":"由蛋白质纤维（微丝、中间纤维、微管）组成的网络，提供结构支撑，促进细胞运动，并帮助组织真核细胞内的细胞器。","pt_BR":"Uma rede de fibras proteicas (microfilamentos, filamentos intermediários, microtúbulos) que fornece suporte estrutural, facilita o movimento celular e ajuda a organizar as organelas em células eucarióticas.","pt_PT":"Uma rede de fibras proteicas (microfilamentos, filamentos intermédios, microtúbulos) que fornece suporte estrutural, facilita o movimento celular e ajuda a organizar os organelos nas células eucariotas."}},
  { id: 'dc-biology-0014', deck_id: 'deck-biology', sort_order: 14, front: "Microtubules", back: "Hollow cylinders of tubulin protein; the largest cytoskeletal elements. Form the mitotic spindle during cell division, and are the structural component of cilia and flagella." , front_translations: {"es":"Microtúbulos","de":"Mikrotubuli","fr":"Microtubules","tr":"Mikrotübüller","nl":"Microtubuli","ru":"Микротрубочки","zh":"微管","pt_BR":"Microtúbulos","pt_PT":"Microtúbulos"}, back_translations: {"es":"Cilindros ocos de proteína tubulina; los mayores elementos del citoesqueleto. Formam el fuso mitótico durante a divisão celular y son el componente estrutural de cílios y flagelos.","de":"Hohle Zylinder aus Tubulinprotein; die größten zytoskelettalen Elemente. Bilden die mitotische Spindel bei der Zellteilung und sind der strukturelle Bestandteil von Zilien und Flagellen.","fr":"Cylindres creux de protéine tubuline; les plus grands éléments du cytosquelette. Forment le fuseau mitotique lors de la division cellulaire et constituent le composant structurel des cils et des flagelles.","tr":"Tübülin proteininden oluşan içi boş silindirler; en büyük sitoiskeletal elementler. Hücre bölünmesi sırasında mitotik iği oluşturur ve siliyaların ile kamçıların yapısal bileşenidir.","nl":"Holle cylinders van tubuline-eiwit; de grootste cytoskeletale elementen. Vormen de mitotische spil tijdens celdeling en zijn het structurele onderdeel van cilia en flagellen.","ru":"Полые цилиндры из белка тубулина; наиболее крупные элементы цитоскелета. Образуют митотическое веретено при делении клеток и являются структурным компонентом ресничек и жгутиков.","zh":"由微管蛋白构成的空心圆柱体；是最大的细胞骨架元件。在细胞分裂时形成有丝分裂纺锤体，也是纤毛和鞭毛的结构组分。","pt_BR":"Cilindros ocos de proteína tubulina; os maiores elementos do citoesqueleto. Formam o fuso mitótico durante a divisão celular e são o componente estrutural de cílios e flagelos.","pt_PT":"Cilindros ocos de proteína tubulina; os maiores elementos do citoesqueleto. Formam o fuso mitótico durante a divisão celular e são o componente estrutural dos cílios e flagelos."}},
  { id: 'dc-biology-0015', deck_id: 'deck-biology', sort_order: 15, front: "Cell Wall", back: "A rigid outer layer found in plants (cellulose), fungi (chitin), and bacteria (peptidoglycan). Provides structural support and protection but is permeable. Absent in animal cells." , front_translations: {"es":"Parede Celular","de":"Zellwand","fr":"Paroi cellulaire","tr":"Hücre Duvarı","nl":"Celwand","ru":"Клеточная стенка","zh":"细胞壁","pt_BR":"Parede Celular","pt_PT":"Parede Celular"}, back_translations: {"es":"Una capa externa rígida encontrada en plantas (celulose), fungos (quitina) y bacterias (peptidoglicano). Fornece suporte estrutural y protección, pero es permeable. Ausente en células animales.","de":"Eine starre äußere Schicht bei Pflanzen (Zellulose), Pilzen (Chitin) und Bakterien (Peptidoglykan). Bietet strukturelle Unterstützung und Schutz, ist aber durchlässig. In tierischen Zellen nicht vorhanden.","fr":"Une couche externe rigide présente chez les plantes (cellulose), les champignons (chitine) et les bactéries (peptidoglycane). Fournit un soutien structurel et une protection, mais est perméable. Absente dans les cellules animales.","tr":"Bitkilerde (selüloz), mantarlarda (kitin) ve bakterilerde (peptidoglikan) bulunan sert dış tabaka. Yapısal destek ve koruma sağlar ancak geçirgendir. Hayvan hücrelerinde bulunmaz.","nl":"Een rigide buitenlaag aanwezig in planten (cellulose), schimmels (chitine) en bacteriën (peptidoglycaan). Biedt structurele ondersteuning en bescherming maar is doorlaatbaar. Afwezig in dierlijke cellen.","ru":"Жёсткий наружный слой, присутствующий у растений (целлюлоза), грибов (хитин) и бактерий (пептидогликан). Обеспечивает структурную поддержку и защиту, но проницаем. Отсутствует в животных клетках.","zh":"存在于植物（纤维素）、真菌（几丁质）和细菌（肽聚糖）中的坚硬外层。提供结构支撑和保护，但具有通透性。动物细胞中没有细胞壁。","pt_BR":"Uma camada externa rígida encontrada em plantas (celulose), fungos (quitina) e bactérias (peptidoglicano). Fornece suporte estrutural e proteção, mas é permeável. Ausente em células animais.","pt_PT":"Uma camada externa rígida encontrada em plantas (celulose), fungos (quitina) e bactérias (peptidoglicano). Fornece suporte estrutural e proteção, mas é permeável. Ausente nas células animais."}},
  { id: 'dc-biology-0016', deck_id: 'deck-biology', sort_order: 16, front: "Osmosis", back: "The passive movement of water across a semipermeable membrane from a region of lower solute concentration (higher water potential) to a region of higher solute concentration." , front_translations: {"es":"Osmose","de":"Osmose","fr":"Osmose","tr":"Ozmoz","nl":"Osmose","ru":"Осмос","zh":"渗透作用","pt_BR":"Osmose","pt_PT":"Osmose"}, back_translations: {"es":"El movimiento passivo de la agua a través de una membrana semipermeable de una región de menor concentración de soluto (mayor potencial hídrico) para una región de mayor concentración de soluto.","de":"Die passive Bewegung von Wasser durch eine semipermeable Membran von einem Bereich mit niedrigerer Gelöststoffkonzentration (höheres Wasserpotenzial) zu einem Bereich mit höherer Gelöststoffkonzentration.","fr":"Le mouvement passif de l'eau à travers une membrane semi-perméable d'une région de plus faible concentration en soluté (potentiel hydrique plus élevé) vers une région de plus forte concentration en soluté.","tr":"Suyun yarı geçirgen bir membran boyunca düşük çözünen konsantrasyonlu bölgeden (yüksek su potansiyeli) yüksek çözünen konsantrasyonlu bölgeye pasif hareketi.","nl":"De passieve beweging van water over een semipermeabel membraan van een gebied met lagere opgeloste stofconcentratie (hoger waterpotentiaal) naar een gebied met hogere opgeloste stofconcentratie.","ru":"Пассивное перемещение воды через полупроницаемую мембрану из области с меньшей концентрацией растворённого вещества (более высокий водный потенциал) в область с более высокой концентрацией растворённого вещества.","zh":"水分子通过半透膜从溶质浓度较低（水势较高）的区域向溶质浓度较高的区域被动移动的过程。","pt_BR":"O movimento passivo da água através de uma membrana semipermeável de uma região de menor concentração de soluto (maior potencial hídrico) para uma região de maior concentração de soluto.","pt_PT":"O movimento passivo da água através de uma membrana semipermeável de uma região de menor concentração de soluto (maior potencial hídrico) para uma região de maior concentração de soluto."}},
  { id: 'dc-biology-0017', deck_id: 'deck-biology', sort_order: 17, front: "Diffusion", back: "The passive movement of molecules from a region of high concentration to a region of low concentration down a concentration gradient. Requires no energy. Rate increases with temperature and concentration difference." , front_translations: {"es":"Difusão","de":"Diffusion","fr":"Diffusion","tr":"Difüzyon","nl":"Diffusie","ru":"Диффузия","zh":"扩散","pt_BR":"Difusão","pt_PT":"Difusão"}, back_translations: {"es":"El movimiento passivo de moléculas de una región de alta concentración para una región de baja concentración, seguindo un gradiente de concentración. No requiere energía. La taxa aumenta con a temperatura y a diferencia de concentración.","de":"Die passive Bewegung von Molekülen von einem Bereich hoher Konzentration zu einem Bereich niedriger Konzentration entlang eines Konzentrationsgradienten. Erfordert keine Energie. Die Rate steigt mit Temperatur und Konzentrationsunterschied.","fr":"Le mouvement passif de molécules d'une région de haute concentration vers une région de faible concentration, suivant un gradient de concentration. Ne nécessite pas d'énergie. Le taux augmente avec la température et la différence de concentration.","tr":"Moleküllerin konsantrasyon gradyanı boyunca yüksek konsantrasyonlu bölgeden düşük konsantrasyonlu bölgeye pasif hareketi. Enerji gerektirmez. Hız, sıcaklık ve konsantrasyon farkıyla artar.","nl":"De passieve beweging van moleculen van een gebied met hoge concentratie naar een gebied met lage concentratie, langs een concentratiegradiënt. Vereist geen energie. Snelheid neemt toe met temperatuur en concentratieverschil.","ru":"Пассивное перемещение молекул из области высокой концентрации в область низкой концентрации по градиенту концентрации. Не требует энергии. Скорость возрастает с увеличением температуры и разности концентраций.","zh":"分子沿浓度梯度从高浓度区向低浓度区的被动移动。不需要能量。速率随温度升高和浓度差增大而加快。","pt_BR":"O movimento passivo de moléculas de uma região de alta concentração para uma região de baixa concentração, seguindo um gradiente de concentração. Não requer energia. A taxa aumenta com a temperatura e a diferença de concentração.","pt_PT":"O movimento passivo de moléculas de uma região de alta concentração para uma região de baixa concentração, ao longo de um gradiente de concentração. Não requer energia. A taxa aumenta com a temperatura e a diferença de concentração."}},
  { id: 'dc-biology-0018', deck_id: 'deck-biology', sort_order: 18, front: "Active Transport", back: "Movement of molecules against their concentration gradient, requiring energy (ATP) and carrier proteins. The Na⁺/K⁺-ATPase pump is a classic example, maintaining electrochemical gradients in neurons." , front_translations: {"es":"Transporte Ativo","de":"Aktiver Transport","fr":"Transport actif","tr":"Aktif Taşıma","nl":"Actief transport","ru":"Активный транспорт","zh":"主动运输","pt_BR":"Transporte Ativo","pt_PT":"Transporte Ativo"}, back_translations: {"es":"Movimento de moléculas contra su gradiente de concentración, exigindo energía (ATP) y proteínas carreadoras. La bomba Na+/K+-ATPase es un ejemplo clássico, manteniendo gradientes eletroquímicos en neuronas.","de":"Bewegung von Molekülen gegen ihren Konzentrationsgradienten, die Energie (ATP) und Trägerproteine erfordert. Die Na+/K+-ATPase-Pumpe ist ein klassisches Beispiel, das elektrochemische Gradienten in Neuronen aufrechterhält.","fr":"Mouvement de molécules contre leur gradient de concentration, nécessitant de l'énergie (ATP) et des protéines porteuses. La pompe Na+/K+-ATPase en est un exemple classique, maintenant les gradients électrochimiques dans les neurones.","tr":"Moleküllerin konsantrasyon gradyanlarına karşı hareket etmesi; enerji (ATP) ve taşıyıcı proteinler gerektirir. Na+/K+-ATPaz pompası, nöronlardaki elektrokimyasal gradyanları koruyan klasik bir örnektir.","nl":"Beweging van moleculen tegen hun concentratiegradiënt in, waarbij energie (ATP) en dragereiwitten nodig zijn. De Na+/K+-ATPase-pomp is een klassiek voorbeeld dat elektrochemische gradiënten in neuronen handhaaft.","ru":"Перемещение молекул против градиента концентрации, требующее энергии (АТФ) и белков-переносчиков. Na+/K+-АТФаза — классический пример, поддерживающий электрохимические градиенты в нейронах.","zh":"分子逆浓度梯度的运动，需要消耗能量（ATP）和载体蛋白。Na+/K+-ATP酶泵是经典例子，维持神经元中的电化学梯度。","pt_BR":"Movimento de moléculas contra seu gradiente de concentração, exigindo energia (ATP) e proteínas carreadoras. A bomba Na+/K+-ATPase é um exemplo clássico, mantendo gradientes eletroquímicos em neurônios.","pt_PT":"Movimento de moléculas contra o seu gradiente de concentração, requerendo energia (ATP) e proteínas transportadoras. A bomba Na+/K+-ATPase é um exemplo clássico, mantendo gradientes eletroquímicos nos neurónios."}},
  { id: 'dc-biology-0019', deck_id: 'deck-biology', sort_order: 19, front: "Endocytosis", back: "The process by which a cell engulfs external material by infolding the plasma membrane. Phagocytosis engulfs large particles; pinocytosis takes in fluids; receptor-mediated endocytosis is selective." , front_translations: {"es":"Endocitose","de":"Endozytose","fr":"Endocytose","tr":"Endositoz","nl":"Endocytose","ru":"Эндоцитоз","zh":"内吞作用","pt_BR":"Endocitose","pt_PT":"Endocitose"}, back_translations: {"es":"El proceso por el qual una célula engloba material externo por invaginación de la membrana plasmática. La fagocitose engloba grandes partículas; a pinocitose capta fluidos; a endocitose mediada por receptor es seletiva.","de":"Der Prozess, bei dem eine Zelle äußeres Material aufnimmt, indem sie die Plasmamembran einstülpt. Phagozytose nimmt große Partikel auf; Pinozytose nimmt Flüssigkeiten auf; rezeptorvermittelte Endozytose ist selektiv.","fr":"Le processus par lequel une cellule engloutit du matériel externe en invaginant la membrane plasmique. La phagocytose engloutit de grandes particules; la pinocytose absorbe des fluides; l'endocytose médiée par récepteur est sélective.","tr":"Bir hücrenin plazma zarını içe katlayarak dış materyali engelleme süreci. Fagositoz büyük parçacıkları alır; pinositoz sıvıları alır; reseptör aracılı endositoz seçicidir.","nl":"Het proces waarbij een cel extern materiaal omsluit door de plasmamembraan naar binnen te vouwen. Fagocytose omsluit grote deeltjes; pinocytose neemt vloeistoffen op; receptorgemedieerde endocytose is selectief.","ru":"Процесс, при котором клетка поглощает внешний материал путём впячивания плазматической мембраны. Фагоцитоз захватывает крупные частицы; пиноцитоз — жидкости; рецептор-опосредованный эндоцитоз — избирателен.","zh":"细胞通过质膜内陷吞入外部物质的过程。吞噬作用吞入大颗粒；胞饮作用摄取液体；受体介导的内吞作用具有选择性。","pt_BR":"O processo pelo qual uma célula engloba material externo por invaginação da membrana plasmática. A fagocitose engloba grandes partículas; a pinocitose capta fluidos; a endocitose mediada por receptor é seletiva.","pt_PT":"O processo pelo qual uma célula engloba material externo por invaginação da membrana plasmática. A fagocitose engloba grandes partículas; a pinocitose capta fluidos; a endocitose mediada por receptor é seletiva."}},
  { id: 'dc-biology-0020', deck_id: 'deck-biology', sort_order: 20, front: "Exocytosis", back: "The process by which a cell secretes materials by fusing vesicles with the plasma membrane and releasing contents outside. Used to secrete hormones, neurotransmitters, and proteins." , front_translations: {"es":"Exocitose","de":"Exozytose","fr":"Exocytose","tr":"Ekzositoz","nl":"Exocytose","ru":"Экзоцитоз","zh":"胞吐作用","pt_BR":"Exocitose","pt_PT":"Exocitose"}, back_translations: {"es":"El proceso por el qual una célula secreta materiais por fusión de vesículas con a membrana plasmática y liberación del conteúdo para el exterior. Usado para secretar hormonas, neurotransmissores y proteínas.","de":"Der Prozess, durch den eine Zelle Materialien absondert, indem Vesikel mit der Plasmamembran fusionieren und Inhalte nach außen freisetzen. Wird zur Sekretion von Hormonen, Neurotransmittern und Proteinen verwendet.","fr":"Le processus par lequel une cellule sécrète des matériaux en fusionnant des vésicules avec la membrane plasmique et en libérant le contenu à l'extérieur. Utilisé pour sécréter des hormones, des neurotransmetteurs et des protéines.","tr":"Bir hücrenin vezikülleri plazma zarıyla kaynaştırarak içerikleri dışarı salmasıyla madde salgılama süreci. Hormonlar, nörotransmiterler ve proteinlerin salgılanmasında kullanılır.","nl":"Het proces waarbij een cel materialen uitscheidt door vesikels met de plasmamembraan te laten fuseren en inhoud naar buiten vrij te geven. Gebruikt om hormonen, neurotransmitters en eiwitten uit te scheiden.","ru":"Процесс, при котором клетка секретирует вещества путём слияния везикул с плазматической мембраной и высвобождения содержимого наружу. Используется для секреции гормонов, нейромедиаторов и белков.","zh":"细胞通过囊泡与质膜融合将内容物释放到细胞外的分泌过程。用于分泌激素、神经递质和蛋白质。","pt_BR":"O processo pelo qual uma célula secreta materiais por fusão de vesículas com a membrana plasmática e liberação do conteúdo para o exterior. Usado para secretar hormônios, neurotransmissores e proteínas.","pt_PT":"O processo pelo qual uma célula secreta materiais por fusão de vesículas com a membrana plasmática e libertação do conteúdo para o exterior. Usado para secretar hormonas, neurotransmissores e proteínas."}},
  { id: 'dc-biology-0021', deck_id: 'deck-biology', sort_order: 21, front: "Mitosis", back: "Division of the nucleus producing two genetically identical daughter nuclei, each with the same chromosome number as the parent. Stages: prophase, metaphase, anaphase, telophase. Followed by cytokinesis." , front_translations: {"es":"Mitose","de":"Mitose","fr":"Mitose","tr":"Mitoz","nl":"Mitose","ru":"Митоз","zh":"有丝分裂","pt_BR":"Mitose","pt_PT":"Mitose"}, back_translations: {"es":"Divisão del núcleo produciendo de los núcleos hijos geneticamente identicos, cada un con el mismo número de cromossomos que el núcleo pai. Estágios: prófase, metáfase, anáfase, telófase. Seguida de citocinese.","de":"Kernteilung, die zwei genetisch identische Tochterkerne erzeugt, die jeweils die gleiche Chromosomenzahl wie die Mutterzelle haben. Stadien: Prophase, Metaphase, Anaphase, Telophase. Gefolgt von Zytokinese.","fr":"Division du noyau produisant deux noyaux filles génétiquement identiques, ayant chacun le même nombre de chromosomes que le noyau parent. Étapes: prophase, métaphase, anaphase, télophase. Suivie de la cytocinèse.","tr":"Her biri ana hücreyle aynı sayıda kromozoma sahip, genetik olarak özdeş iki yavru çekirdek üreten çekirdek bölünmesi. Aşamalar: profaz, metafaz, anafaz, telofaz. Sitokinez ile tamamlanır.","nl":"Deling van de kern die twee genetisch identieke dochterkernen produceert, elk met hetzelfde chromosoomaantal als de moederkern. Stadia: profase, metafase, anafase, telofase. Gevolgd door cytokinese.","ru":"Деление ядра, при котором образуются два генетически идентичных дочерних ядра, каждое с таким же числом хромосом, что и родительское. Стадии: профаза, метафаза, анафаза, телофаза. За ним следует цитокинез.","zh":"细胞核的分裂，产生两个与亲代具有相同染色体数目的遗传上相同的子核。阶段：前期、中期、后期、末期。之后进行胞质分裂。","pt_BR":"Divisão do núcleo produzindo dois núcleos filhos geneticamente idênticos, cada um com o mesmo número de cromossomos que o núcleo pai. Estágios: prófase, metáfase, anáfase, telófase. Seguida de citocinese.","pt_PT":"Divisão do núcleo produzindo dois núcleos filhos geneticamente idênticos, cada um com o mesmo número de cromossomas que o núcleo progenitor. Fases: profase, metafase, anafase, telofase. Seguida de citocinese."}},
  { id: 'dc-biology-0022', deck_id: 'deck-biology', sort_order: 22, front: "Meiosis", back: "Two-stage cell division producing four genetically unique haploid gametes (n) from one diploid (2n) cell. Includes meiosis I (homologs separate) and meiosis II (sister chromatids separate)." , front_translations: {"es":"Meiose","de":"Meiose","fr":"Méiose","tr":"Mayoz","nl":"Meiose","ru":"Мейоз","zh":"减数分裂","pt_BR":"Meiose","pt_PT":"Meiose"}, back_translations: {"es":"Divisão celular en de los etapas que produce cuatro gametas haploides (n) geneticamente únicos a partir de una célula diploide (2n). Inclui meiose I (homólogos se separan) y meiose II (cromátides irmãs se separan).","de":"Zweistufige Zellteilung, die aus einer diploiden (2n) Zelle vier genetisch einzigartige haploide Gameten (n) erzeugt. Umfasst Meiose I (Trennung der Homologen) und Meiose II (Trennung der Schwesterchromatiden).","fr":"Division cellulaire en deux étapes produisant quatre gamètes haploïdes (n) génétiquement uniques à partir d'une cellule diploïde (2n). Comprend la méiose I (séparation des homologues) et la méiose II (séparation des chromatides sœurs).","tr":"Bir diploid (2n) hücreden genetik olarak benzersiz dört haploid gamet (n) üreten iki aşamalı hücre bölünmesi. Mayoz I (homologların ayrılması) ve Mayoz II (kardeş kromatidlerin ayrılması) içerir.","nl":"Tweeledige celdeling die vier genetisch unieke haploïde gameten (n) produceert uit één diploïde (2n) cel. Omvat meiose I (homologen scheiden) en meiose II (zusterchromatiden scheiden).","ru":"Двухэтапное деление клетки, при котором из одной диплоидной (2n) клетки образуются четыре генетически уникальных гаплоидных гамет (n). Включает мейоз I (расхождение гомологов) и мейоз II (расхождение сестринских хроматид).","zh":"由一个二倍体（2n）细胞经两次分裂产生四个遗传上独特的单倍体配子（n）。包括减数第一次分裂（同源染色体分离）和减数第二次分裂（姐妹染色单体分离）。","pt_BR":"Divisão celular em dois estágios que produz quatro gametas haploides (n) geneticamente únicos a partir de uma célula diploide (2n). Inclui meiose I (homólogos se separam) e meiose II (cromátides irmãs se separam).","pt_PT":"Divisão celular em dois estágios que produz quatro gâmetas haploides (n) geneticamente únicos a partir de uma célula diploide (2n). Inclui meiose I (homólogos separam-se) e meiose II (cromatídeos irmãos separam-se)."}},
  { id: 'dc-biology-0023', deck_id: 'deck-biology', sort_order: 23, front: "Cell Cycle", back: "The ordered series of events in a cell's life: G1 (growth), S (DNA synthesis), G2 (preparation for division), and M (mitosis + cytokinesis). Checkpoints ensure DNA integrity before proceeding." , front_translations: {"es":"Ciclo Celular","de":"Zellzyklus","fr":"Cycle cellulaire","tr":"Hücre Döngüsü","nl":"Celcyclus","ru":"Клеточный цикл","zh":"细胞周期","pt_BR":"Ciclo Celular","pt_PT":"Ciclo Celular"}, back_translations: {"es":"La série ordenada de eventos en la vida de una célula: G1 (crecimiento), S (síntese de DNA), G2 (preparación para divisão) y M (mitose + citocinese). Pontos de verificación garantizan a integridad del DNA antes de prosseguir.","de":"Die geordnete Abfolge von Ereignissen im Leben einer Zelle: G1 (Wachstum), S (DNA-Synthese), G2 (Vorbereitung auf die Teilung) und M (Mitose + Zytokinese). Kontrollpunkte stellen die DNA-Integrität vor dem Fortschreiten sicher.","fr":"La série ordonnée d'événements dans la vie d'une cellule: G1 (croissance), S (synthèse de l'ADN), G2 (préparation à la division) et M (mitose + cytocinèse). Des points de contrôle vérifient l'intégrité de l'ADN avant de continuer.","tr":"Bir hücrenin yaşamındaki sıralı olaylar dizisi: G1 (büyüme), S (DNA sentezi), G2 (bölünmeye hazırlık) ve M (mitoz + sitokinez). Kontrol noktaları ilerlemeden önce DNA bütünlüğünü sağlar.","nl":"De geordende reeks gebeurtenissen in het leven van een cel: G1 (groei), S (DNA-synthese), G2 (voorbereiding op deling) en M (mitose + cytokinese). Controlepunten zorgen voor DNA-integriteit voordat verder gegaan wordt.","ru":"Упорядоченная последовательность событий в жизни клетки: G1 (рост), S (синтез ДНК), G2 (подготовка к делению) и M (митоз + цитокинез). Контрольные точки обеспечивают целостность ДНК перед продолжением цикла.","zh":"细胞生命中有序的事件序列：G1期（生长）、S期（DNA合成）、G2期（分裂准备）和M期（有丝分裂+胞质分裂）。检查点确保在继续之前DNA的完整性。","pt_BR":"A série ordenada de eventos na vida de uma célula: G1 (crescimento), S (síntese de DNA), G2 (preparação para divisão) e M (mitose + citocinese). Pontos de verificação garantem a integridade do DNA antes de prosseguir.","pt_PT":"A série ordenada de eventos na vida de uma célula: G1 (crescimento), S (síntese de DNA), G2 (preparação para divisão) e M (mitose + citocinese). Os pontos de controlo garantem a integridade do DNA antes de prosseguir."}},
  { id: 'dc-biology-0024', deck_id: 'deck-biology', sort_order: 24, front: "Apoptosis", back: "Programmed cell death; a controlled, energy-dependent process in which a cell dismantles itself. Essential for development (e.g., digit formation) and eliminating damaged or cancerous cells." , front_translations: {"es":"Apoptose","de":"Apoptose","fr":"Apoptose","tr":"Apoptoz","nl":"Apoptose","ru":"Апоптоз","zh":"细胞凋亡","pt_BR":"Apoptose","pt_PT":"Apoptose"}, back_translations: {"es":"Morte celular programada; un proceso controlado y dependente de energía en el qual una célula se desmonta. Essencial para el desarrollo (ex.: formación de los dígitos) y para eliminar células danificadas o cancerosas.","de":"Programmierter Zelltod; ein kontrollierter, energieabhängiger Prozess, bei dem sich eine Zelle selbst abbaut. Wesentlich für die Entwicklung (z. B. Fingerbildung) und die Eliminierung geschädigter oder krebsartiger Zellen.","fr":"Mort cellulaire programmée; un processus contrôlé et énergie-dépendant dans lequel une cellule se démantèle elle-même. Essentiel au développement (par ex., formation des doigts) et à l'élimination des cellules endommagées ou cancéreuses.","tr":"Programlanmış hücre ölümü; bir hücrenin kendini parçaladığı kontrollü, enerji bağımlı bir süreç. Gelişim için (örn. parmak oluşumu) ve hasarlı veya kanserli hücrelerin ortadan kaldırılması için esastır.","nl":"Geprogrammeerde celdood; een gecontroleerd, energieafhankelijk proces waarbij een cel zichzelf ontmantelt. Essentieel voor ontwikkeling (bijv. vingervorming) en het elimineren van beschadigde of kankercellen.","ru":"Программируемая гибель клетки; контролируемый, энергозависимый процесс, при котором клетка разрушает себя. Необходим для развития (например, формирование пальцев) и устранения повреждённых или раковых клеток.","zh":"程序性细胞死亡；细胞有序自我解体的受控、能量依赖过程。对发育（如手指形成）以及清除受损或癌变细胞至关重要。","pt_BR":"Morte celular programada; um processo controlado e dependente de energia no qual uma célula se desmonta. Essencial para o desenvolvimento (ex.: formação dos dígitos) e para eliminar células danificadas ou cancerosas.","pt_PT":"Morte celular programada; um processo controlado e dependente de energia no qual uma célula se desmantela. Essencial para o desenvolvimento (ex.: formação dos dedos) e para eliminar células danificadas ou cancerosas."}},
  { id: 'dc-biology-0025', deck_id: 'deck-biology', sort_order: 25, front: "DNA Structure", back: "A double helix of two antiparallel strands of nucleotides connected by hydrogen bonds between bases: A–T (2 bonds) and G–C (3 bonds). Backbone: alternating deoxyribose and phosphate groups." , front_translations: {"es":"Estrutura del DNA","de":"DNA-Struktur","fr":"Structure de l'ADN","tr":"DNA Yapısı","nl":"DNA-structuur","ru":"Структура ДНК","zh":"DNA结构","pt_BR":"Estrutura do DNA","pt_PT":"Estrutura do DNA"}, back_translations: {"es":"Una dupla hélice de de los fitas antiparalelas de nucleotídeos conectadas por enlaces de hidrógeno entre las bases: La-T (2 enlaces) y G-C (3 enlaces). Esqueleto: grupos alternados de desoxirribose y fosfato.","de":"Eine Doppelhelix aus zwei antiparallelen Strängen von Nukleotiden, die durch Wasserstoffbrücken zwischen den Basen verbunden sind: A-T (2 Bindungen) und G-C (3 Bindungen). Rückgrat: abwechselnde Desoxyribose- und Phosphatgruppen.","fr":"Une double hélice de deux brins antiparallèles de nucléotides reliés par des liaisons hydrogène entre les bases: A-T (2 liaisons) et G-C (3 liaisons). Squelette: groupes désoxyribose et phosphate alternés.","tr":"Bazlar arasındaki hidrojen bağlarıyla birbirine bağlanan iki antiparalel nükleotid zincirinden oluşan çift sarmal: A-T (2 bağ) ve G-C (3 bağ). Omurga: dönüşümlü deoksiriboz ve fosfat grupları.","nl":"Een dubbele helix van twee antiparallelle strengen van nucleotiden verbonden door waterstofbruggen tussen de basen: A-T (2 bindingen) en G-C (3 bindingen). Ruggengraat: afwisselende desoxyribose- en fosfaatgroepen.","ru":"Двойная спираль из двух антипараллельных цепей нуклеотидов, соединённых водородными связями между основаниями: А-Т (2 связи) и Г-Ц (3 связи). Остов: чередующиеся группы дезоксирибозы и фосфата.","zh":"由两条反向平行的核苷酸链通过碱基间氢键相连形成的双螺旋：A-T（2个氢键）和G-C（3个氢键）。骨架：交替排列的脱氧核糖和磷酸基团。","pt_BR":"Uma dupla hélice de duas fitas antiparalelas de nucleotídeos conectadas por ligações de hidrogênio entre as bases: A-T (2 ligações) e G-C (3 ligações). Esqueleto: grupos alternados de desoxirribose e fosfato.","pt_PT":"Uma dupla hélice de duas cadeias antiparalelas de nucleótidos ligadas por pontes de hidrogénio entre as bases: A-T (2 ligações) e G-C (3 ligações). Esqueleto: grupos alternados de desoxirribose e fosfato."}},
  { id: 'dc-biology-0026', deck_id: 'deck-biology', sort_order: 26, front: "DNA Replication", back: "The process of copying the DNA double helix before cell division. DNA helicase unwinds the helix, and DNA polymerase synthesizes a complementary strand on each template. Semi-conservative." , front_translations: {"es":"Replicación del DNA","de":"DNA-Replikation","fr":"Réplication de l'ADN","tr":"DNA Replikasyonu","nl":"DNA-replicatie","ru":"Репликация ДНК","zh":"DNA复制","pt_BR":"Replicação do DNA","pt_PT":"Replicação do ADN"}, back_translations: {"es":"El proceso de cópia de la dupla hélice de DNA antes de la divisão celular. La helicase de DNA desenrola a hélice, y a DNA polimerase sintetiza una fita complementar en cada molde. Semiconservativo.","de":"Der Prozess, bei dem die DNA-Doppelhelix vor der Zellteilung kopiert wird. Die DNA-Helikase entwirrt die Helix, und die DNA-Polymerase synthetisiert einen komplementären Strang auf jeder Matrize. Semikonservativ.","fr":"Le processus de copie de la double hélice d'ADN avant la division cellulaire. L'hélicase dénature la double hélice, et l'ADN polymérase synthétise un brin complémentaire sur chaque matrice. Semi-conservatif.","tr":"Hücre bölünmesinden önce DNA çift sarmalının kopyalanması süreci. DNA helikaz sarmalı açar, DNA polimeraz her kalıp üzerinde tamamlayıcı bir iplik sentezler. Yarı-koruyucu.","nl":"Het proces waarbij de DNA-dubbelhelix wordt gekopieerd vóór celdeling. DNA-helicase ontrolt de helix, en DNA-polymerase synthetiseert een complementaire streng op elke matrijs. Semi-conservatief.","ru":"Процесс копирования двойной спирали ДНК перед делением клетки. Геликаза ДНК раскручивает спираль, а ДНК-полимераза синтезирует комплементарную цепь на каждой матрице. Полуконсервативный процесс.","zh":"细胞分裂前复制DNA双螺旋的过程。DNA解旋酶解开双螺旋，DNA聚合酶在每条模板上合成互补链。半保留复制。","pt_BR":"O processo de cópia da dupla hélice de DNA antes da divisão celular. A helicase de DNA desenrola a hélice, e a DNA polimerase sintetiza uma fita complementar em cada molde. Semiconservativo.","pt_PT":"O processo de cópia da dupla hélice de ADN antes da divisão celular. A helicase de ADN desenrola a hélice, e a ADN polimerase sintetiza uma fita complementar em cada molde. Semiconservativo."}},
  { id: 'dc-biology-0027', deck_id: 'deck-biology', sort_order: 27, front: "Transcription", back: "The synthesis of RNA from a DNA template by RNA polymerase. Occurs in the nucleus. The resulting pre-mRNA is processed (5' cap, poly-A tail, splicing) before export to the cytoplasm." , front_translations: {"es":"Transcrición","de":"Transkription","fr":"Transcription","tr":"Transkripsiyon","nl":"Transcriptie","ru":"Транскрипция","zh":"转录","pt_BR":"Transcrição","pt_PT":"Transcrição"}, back_translations: {"es":"La síntese de RNA a partir de un molde de DNA por la RNA polimerase. Ocorre en el núcleo. El pré-mRNA resultante es processado (5' cap, cauda poli-A, splicing) antes de ser exportado para el citoplasma.","de":"Die Synthese von RNA aus einer DNA-Matrize durch die RNA-Polymerase. Findet im Zellkern statt. Die entstehende prä-mRNA wird prozessiert (5'-Kappe, Poly-A-Schwanz, Spleißen), bevor sie in das Zytoplasma exportiert wird.","fr":"La synthèse d'ARN à partir d'une matrice d'ADN par l'ARN polymérase. A lieu dans le noyau. Le pré-ARNm résultant est traité (coiffe 5', queue poly-A, épissage) avant d'être exporté vers le cytoplasme.","tr":"RNA polimeraz tarafından bir DNA şablonundan RNA sentezi. Çekirdekte gerçekleşir. Ortaya çıkan ön-mRNA, sitoplazmaya ihraç edilmeden önce işlenir (5' başlık, poli-A kuyruğu, kesme-birleştirme).","nl":"De synthese van RNA uit een DNA-matrijs door RNA-polymerase. Vindt plaats in de kern. Het resulterende pre-mRNA wordt verwerkt (5'-kap, poly-A-staart, splicing) vóór export naar het cytoplasma.","ru":"Синтез РНК на матрице ДНК с помощью РНК-полимеразы. Происходит в ядре. Образующаяся пре-мРНК обрабатывается (5'-кэп, поли-A хвост, сплайсинг) перед экспортом в цитоплазму.","zh":"由RNA聚合酶以DNA为模板合成RNA的过程。在细胞核中进行。生成的前体mRNA经加工（5'帽子、多聚腺苷酸尾、剪接）后出口至细胞质。","pt_BR":"A síntese de RNA a partir de um molde de DNA pela RNA polimerase. Ocorre no núcleo. O pré-mRNA resultante é processado (5' cap, cauda poli-A, splicing) antes de ser exportado para o citoplasma.","pt_PT":"A síntese de ARN a partir de um molde de ADN pela ARN polimerase. Ocorre no núcleo. O pré-ARNm resultante é processado (5' cap, cauda poli-A, splicing) antes de ser exportado para o citoplasma."}},
  { id: 'dc-biology-0028', deck_id: 'deck-biology', sort_order: 28, front: "Translation", back: "The synthesis of protein from an mRNA template at the ribosome. tRNA molecules bring amino acids corresponding to each codon. Begins at the AUG start codon; ends at a stop codon." , front_translations: {"es":"Tradución","de":"Translation","fr":"Traduction","tr":"Translasyon","nl":"Translatie","ru":"Трансляция","zh":"翻译","pt_BR":"Tradução","pt_PT":"Tradução"}, back_translations: {"es":"La síntese de proteína a partir de un molde de mRNA en el ribossomo. Moléculas de tRNA trazem aminoácidos correspondentes a cada códon. Começa en el códon de início AUG; termina en un códon de parada.","de":"Die Synthese von Proteinen aus einer mRNA-Matrize am Ribosom. tRNA-Moleküle bringen Aminosäuren, die jedem Codon entsprechen. Beginnt am AUG-Startcodon; endet an einem Stoppcodon.","fr":"La synthèse de protéine à partir d'un ARNm au niveau du ribosome. Les molécules d'ARNt apportent les acides aminés correspondant à chaque codon. Commence au codon d'initiation AUG ; se termine à un codon stop.","tr":"Ribozomdaki bir mRNA şablonundan protein sentezi. tRNA molekülleri her kodona karşılık gelen amino asitleri taşır. AUG başlangıç kodonunda başlar; bir dur kodonunda sona erer.","nl":"De synthese van eiwit uit een mRNA-matrijs aan het ribosoom. tRNA-moleculen brengen aminozuren die overeenkomen met elk codon. Begint bij het AUG-startcodon; eindigt bij een stopcodon.","ru":"Синтез белка на матрице мРНК на рибосоме. Молекулы тРНК доставляют аминокислоты, соответствующие каждому кодону. Начинается с кодона AUG (Met); заканчивается на стоп-кодоне.","zh":"在核糖体上以mRNA为模板合成蛋白质的过程。tRNA分子携带与每个密码子对应的氨基酸。从AUG起始密码子开始，在终止密码子处结束。","pt_BR":"A síntese de proteína a partir de um molde de mRNA no ribossomo. Moléculas de tRNA trazem aminoácidos correspondentes a cada códon. Começa no códon de início AUG; termina em um códon de parada.","pt_PT":"A síntese de proteína a partir de um molde de ARNm no ribossoma. Moléculas de ARNt trazem aminoácidos correspondentes a cada codão. Começa no codão de início AUG; termina num codão de paragem."}},
  { id: 'dc-biology-0029', deck_id: 'deck-biology', sort_order: 29, front: "Genetic Code", back: "The set of rules by which nucleotide triplets (codons) are translated into amino acids. 64 codons encode 20 amino acids (redundant/degenerate code). AUG = start (Met); UAA, UAG, UGA = stop." , front_translations: {"es":"Código Genético","de":"Genetischer Code","fr":"Code génétique","tr":"Genetik Kod","nl":"Genetische code","ru":"Генетический код","zh":"遗传密码","pt_BR":"Código Genético","pt_PT":"Código Genético"}, back_translations: {"es":"El conjunto de regras por el qual tripletos de nucleotídeos (códons) son traduzidos en aminoácidos. 64 códons codifican 20 aminoácidos (código redundante/degenerado). AUG = início (Met); UAA, UAG, UGA = parada.","de":"Der Satz von Regeln, nach denen Nukleotidtripletts (Codons) in Aminosäuren übersetzt werden. 64 Codons kodieren 20 Aminosäuren (redundanter/degenerierter Code). AUG = Start (Met); UAA, UAG, UGA = Stopp.","fr":"L'ensemble des règles par lesquelles les triplets de nucléotides (codons) sont traduits en acides aminés. 64 codons codent pour 20 acides aminés (code redondant/dégénéré). AUG = start (Met) ; UAA, UAG, UGA = stop.","tr":"Nükleotid üçlülerinin (kodonların) amino asitlere çevrildiği kural seti. 64 kodon 20 amino asidi kodlar (gereksiz/dejenere kod). AUG = başlangıç (Met); UAA, UAG, UGA = dur.","nl":"Het stelsel van regels waarmee nucleotidetripletten (codons) worden vertaald in aminozuren. 64 codons coderen voor 20 aminozuren (redundante/degenererende code). AUG = start (Met); UAA, UAG, UGA = stop.","ru":"Набор правил, по которым нуклеотидные триплеты (кодоны) переводятся в аминокислоты. 64 кодона кодируют 20 аминокислот (вырожденный код). AUG = старт (Met); UAA, UAG, UGA = стоп-кодоны.","zh":"将核苷酸三联体（密码子）翻译为氨基酸的规则集合。64个密码子编码20种氨基酸（简并/冗余密码）。AUG=起始（Met）；UAA、UAG、UGA=终止密码子。","pt_BR":"O conjunto de regras pelo qual tripletos de nucleotídeos (códons) são traduzidos em aminoácidos. 64 códons codificam 20 aminoácidos (código redundante/degenerado). AUG = início (Met); UAA, UAG, UGA = parada.","pt_PT":"O conjunto de regras pelo qual tripletos de nucleotídeos (codões) são traduzidos em aminoácidos. 64 codões codificam 20 aminoácidos (código redundante/degenerado). AUG = início (Met); UAA, UAG, UGA = paragem."}},
  { id: 'dc-biology-0030', deck_id: 'deck-biology', sort_order: 30, front: "Codon vs. Anticodon", back: "A codon is a three-nucleotide sequence on mRNA specifying an amino acid. An anticodon is the complementary triplet on tRNA that recognizes the codon and delivers the correct amino acid to the ribosome." , front_translations: {"es":"Códon vs. Anticódon","de":"Codon vs. Anticodon","fr":"Codon vs. Anticodon","tr":"Kodon ve Antikodon","nl":"Codon vs. anticodon","ru":"Кодон и антикодон","zh":"密码子与反密码子","pt_BR":"Códon vs. Anticódon","pt_PT":"Codão vs. Anticodão"}, back_translations: {"es":"Un códon es una secuencia de tres nucleotídeos en el mRNA que especifica un aminoácido. Un anticódon es el triplete complementar en el tRNA que reconhece el códon y entrega el aminoácido correto al ribossomo.","de":"Ein Codon ist eine Drei-Nukleotid-Sequenz auf der mRNA, die eine Aminosäure spezifiziert. Ein Anticodon ist das komplementäre Triplett auf der tRNA, das das Codon erkennt und die richtige Aminosäure zum Ribosom liefert.","fr":"Un codon est une séquence de trois nucléotides sur l'ARNm spécifiant un acide aminé. Un anticodon est le triplet complémentaire sur l'ARNt qui reconnaît le codon et délivre le bon acide aminé au ribosome.","tr":"Kodon, mRNA üzerinde bir amino asidi belirten üç nükleotitlik bir dizidir. Antikodon, kodonu tanıyan ve doğru amino asidi ribozoma ileten tRNA üzerindeki tamamlayıcı üçlüdür.","nl":"Een codon is een drie-nucleotidesequentie op mRNA die een aminozuur specificeert. Een anticodon is het complementaire triplet op tRNA dat het codon herkent en het juiste aminozuur aan het ribosoom levert.","ru":"Кодон — трёхнуклеотидная последовательность мРНК, кодирующая аминокислоту. Антикодон — комплементарный триплет тРНК, распознающий кодон и доставляющий нужную аминокислоту к рибосоме.","zh":"密码子是mRNA上编码一个氨基酸的三核苷酸序列。反密码子是tRNA上与密码子互补的三联体，能识别密码子并将正确的氨基酸运送到核糖体。","pt_BR":"Um códon é uma sequência de três nucleotídeos no mRNA que especifica um aminoácido. Um anticódon é o triplete complementar no tRNA que reconhece o códon e entrega o aminoácido correto ao ribossomo.","pt_PT":"Um codão é uma sequência de três nucleotídeos no ARNm que especifica um aminoácido. Um anticodão é o triplete complementar no ARNt que reconhece o codão e entrega o aminoácido correto ao ribossoma."}},
  { id: 'dc-biology-0031', deck_id: 'deck-biology', sort_order: 31, front: "Gene Expression", back: "The process by which information encoded in a gene is used to produce a functional product (protein or RNA). Regulated at transcription, RNA processing, translation, and post-translational levels." , front_translations: {"es":"Expresión Genica","de":"Genexpression","fr":"Expression génique","tr":"Gen İfadesi","nl":"Genexpressie","ru":"Экспрессия генов","zh":"基因表达","pt_BR":"Expressão Gênica","pt_PT":"Expressão Génica"}, back_translations: {"es":"El proceso por el qual a información codificada en un gen es usada para produzir un producto funcional (proteína o RNA). Regulado en los niveles de transcrición, procesamiento de RNA, tradución y pós-traducional.","de":"Der Prozess, durch den die in einem Gen kodierte Information zur Herstellung eines funktionellen Produkts (Protein oder RNA) verwendet wird. Reguliert auf Transkriptions-, RNA-Prozessierungs-, Translations- und posttranslationaler Ebene.","fr":"Le processus par lequel l'information encodée dans un gène est utilisée pour produire un produit fonctionnel (protéine ou ARN). Régulée aux niveaux de la transcription, du traitement de l'ARN, de la traduction et post-traductionnel.","tr":"Bir gende kodlanan bilginin işlevsel bir ürün (protein veya RNA) üretmek için kullanıldığı süreç. Transkripsiyon, RNA işleme, translasyon ve translasyon sonrası düzeylerde düzenlenir.","nl":"Het proces waarbij informatie die in een gen is gecodeerd wordt gebruikt om een functioneel product (eiwit of RNA) te produceren. Gereguleerd op transcriptie-, RNA-verwerkings-, translatie- en post-translationaal niveau.","ru":"Процесс, посредством которого информация, закодированная в гене, используется для производства функционального продукта (белка или РНК). Регулируется на уровнях транскрипции, процессинга РНК, трансляции и посттрансляционных модификаций.","zh":"将基因中编码的信息用于产生功能性产物（蛋白质或RNA）的过程。在转录、RNA加工、翻译和翻译后修饰等多个层次上受到调控。","pt_BR":"O processo pelo qual a informação codificada em um gene é usada para produzir um produto funcional (proteína ou RNA). Regulado nos níveis de transcrição, processamento de RNA, tradução e pós-traducional.","pt_PT":"O processo pelo qual a informação codificada num gene é usada para produzir um produto funcional (proteína ou ARN). Regulado a níveis de transcrição, processamento de ARN, tradução e pós-traducional."}},
  { id: 'dc-biology-0032', deck_id: 'deck-biology', sort_order: 32, front: "Operon (Lac Operon)", back: "A unit of gene regulation in prokaryotes: a promoter, operator, and related genes. In the lac operon, the repressor protein blocks transcription unless lactose (allolactose) is present to remove it." , front_translations: {"es":"Operon (Operon Lac)","de":"Operon (Lac-Operon)","fr":"Opéron (opéron lac)","tr":"Operon (Lac Operonu)","nl":"Operon (lac-operon)","ru":"Оперон (лак-оперон)","zh":"操纵子（乳糖操纵子）","pt_BR":"Operon (Operon Lac)","pt_PT":"Operão (Operão Lac)"}, back_translations: {"es":"Una unidad de regulación genica en procariotos: un promotor, operador y genes relacionados. No operon lac, a proteína repressora bloqueia a transcrición a menos que a lactose (alolactose) esteja presente para remove-la.","de":"Eine Einheit der Genregulation in Prokaryoten: ein Promotor, ein Operator und zugehörige Gene. Im lac-Operon blockiert das Repressor-Protein die Transkription, es sei denn, Laktose (Allolaktose) ist vorhanden, um es zu entfernen.","fr":"Une unité de régulation génique chez les procaryotes : un promoteur, un opérateur et des gènes apparentés. Dans l'opéron lac, la protéine répresseur bloque la transcription sauf si le lactose (allolactose) est présent pour le déplacer.","tr":"Prokaryotlarda gen düzenleme birimi: bir promotör, bir operatör ve ilgili genler. Lac operonunda, laktoz (allolaktoz) onu uzaklaştırmak için mevcut olmadıkça repressör protein transkripsiyonu engeller.","nl":"Een eenheid van genregulatie bij prokaryoten: een promotor, operator en verwante genen. In het lac-operon blokkeert het repressorproteïne de transcriptie tenzij lactose (allolactose) aanwezig is om het te verwijderen.","ru":"Единица генетической регуляции у прокариот: промотор, оператор и связанные гены. В лак-опероне белок-репрессор блокирует транскрипцию, если только лактоза (аллолактоза) не присутствует, чтобы его устранить.","zh":"原核生物基因调控单元：由启动子、操纵序列和相关基因组成。在乳糖操纵子中，除非乳糖（别位乳糖）存在而解除阻遏，否则阻遏蛋白会阻止转录。","pt_BR":"Uma unidade de regulação gênica em procariotos: um promotor, operador e genes relacionados. No operon lac, a proteína repressora bloqueia a transcrição a menos que a lactose (alolactose) esteja presente para removê-la.","pt_PT":"Uma unidade de regulação génica em procariotas: um promotor, operador e genes relacionados. No operão lac, a proteína repressora bloqueia a transcrição a menos que a lactose (alolactose) esteja presente para a remover."}},
  { id: 'dc-biology-0033', deck_id: 'deck-biology', sort_order: 33, front: "Mutation: Point Mutation", back: "A change in a single nucleotide base. Types: silent (no amino acid change), missense (different amino acid), nonsense (creates stop codon). Can arise from errors in replication or mutagens." , front_translations: {"es":"Mutación: Mutación Puntiforme","de":"Mutation: Punktmutation","fr":"Mutation : mutation ponctuelle","tr":"Mutasyon: Nokta Mutasyonu","nl":"Mutatie: puntmutatie","ru":"Мутация: точечная мутация","zh":"突变：点突变","pt_BR":"Mutação: Mutação Puntiforme","pt_PT":"Mutação: Mutação Pontual"}, back_translations: {"es":"Una cambio en un único nucleotídeo de base. Tipos: silenciosa (sin cambio de aminoácido), missense (aminoácido diferente), nonsense (crea códon de parada). Pode surgir de erros de replicación o mutágenos.","de":"Eine Veränderung in einer einzigen Nukleotidbase. Typen: still (keine Aminosäurenänderung), Missense (andere Aminosäure), Nonsense (erzeugt Stoppcodon). Kann durch Replikationsfehler oder Mutagene entstehen.","fr":"Un changement dans une seule base nucléotidique. Types : silencieuse (pas de changement d'acide aminé), faux-sens (acide aminé différent), non-sens (crée un codon stop). Peut résulter d'erreurs de réplication ou de mutagènes.","tr":"Tek bir nükleotid bazındaki değişiklik. Türleri: sessiz (amino asit değişikliği yok), yanlış anlam (farklı amino asit), anlamsız (dur kodonu oluşturur). Replikasyon hataları veya mutagenlerden kaynaklanabilir.","nl":"Een verandering in één enkele nucleotidebasis. Types: stil (geen aminozuurverandering), missense (ander aminozuur), nonsense (creëert stopcodon). Kan ontstaan door fouten bij replicatie of mutagenen.","ru":"Изменение одного нуклеотидного основания. Типы: молчащая (нет изменения аминокислоты), миссенс (другая аминокислота), нонсенс (создаёт стоп-кодон). Может возникать из-за ошибок репликации или мутагенов.","zh":"单个核苷酸碱基的改变。类型：沉默突变（氨基酸不变）、错义突变（氨基酸改变）、无义突变（产生终止密码子）。可由复制错误或诱变剂引起。","pt_BR":"Uma mudança em um único nucleotídeo de base. Tipos: silenciosa (sem mudança de aminoácido), missense (aminoácido diferente), nonsense (cria códon de parada). Pode surgir de erros de replicação ou mutágenos.","pt_PT":"Uma mudança num único nucleotídeo de base. Tipos: silenciosa (sem mudança de aminoácido), missense (aminoácido diferente), nonsense (cria codão de paragem). Pode surgir de erros de replicação ou mutagénios."}},
  { id: 'dc-biology-0034', deck_id: 'deck-biology', sort_order: 34, front: "Mutation: Frameshift Mutation", back: "An insertion or deletion of nucleotides (not in multiples of 3) that shifts the reading frame of the mRNA. Typically causes catastrophic changes to the protein sequence from the mutation point onward." , front_translations: {"es":"Mutación: Mutación de Deslocamento de Quadro","de":"Mutation: Rasterschubmutation","fr":"Mutation : mutation par décalage du cadre de lecture","tr":"Mutasyon: Çerçeve Kayması Mutasyonu","nl":"Mutatie: rasterverschuivingsmutatie","ru":"Мутация: мутация сдвига рамки считывания","zh":"突变：移码突变","pt_BR":"Mutação: Mutação de Deslocamento de Quadro","pt_PT":"Mutação: Mutação de Desvio de Grelha"}, back_translations: {"es":"Una inserción o deleción de nucleotídeos (no en múltiplos de 3) que desloca el quadro de leitura del mRNA. Tipicamente causa cambios catastróficas en la secuencia proteica a partir del punto de mutación.","de":"Eine Insertion oder Deletion von Nukleotiden (nicht in Vielfachen von 3), die den Leserahmen der mRNA verschiebt. Verursacht typischerweise katastrophale Veränderungen in der Proteinsequenz ab dem Mutationspunkt.","fr":"Une insertion ou délétion de nucléotides (pas en multiples de 3) qui décale le cadre de lecture de l'ARNm. Provoque généralement des changements catastrophiques dans la séquence protéique à partir du point de mutation.","tr":"Nükleotitlerin (3'ün katları olmayan) eklenmesi veya silinmesi, mRNA'nın okuma çerçevesini kaydırır. Genellikle mutasyon noktasından itibaren protein dizisinde yıkıcı değişikliklere neden olur.","nl":"Een insertie of deletie van nucleotiden (niet in veelvouden van 3) die het leesraam van het mRNA verschuift. Veroorzaakt doorgaans catastrofale veranderingen in de eiwitsequentie vanaf het mutatiepunt.","ru":"Вставка или делеция нуклеотидов (не кратная 3), сдвигающая рамку считывания мРНК. Как правило, вызывает катастрофические изменения в аминокислотной последовательности белка, начиная с точки мутации.","zh":"插入或缺失核苷酸（非3的倍数），导致mRNA阅读框移位。通常从突变位点起，蛋白质序列发生灾难性变化。","pt_BR":"Uma inserção ou deleção de nucleotídeos (não em múltiplos de 3) que desloca o quadro de leitura do mRNA. Tipicamente causa mudanças catastróficas na sequência proteica a partir do ponto de mutação.","pt_PT":"Uma inserção ou deleção de nucleotídeos (não em múltiplos de 3) que desloca a grelha de leitura do ARNm. Tipicamente causa mudanças catastróficas na sequência proteica a partir do ponto de mutação."}},
  { id: 'dc-biology-0035', deck_id: 'deck-biology', sort_order: 35, front: "Mendel's Law of Segregation", back: "Each individual carries two alleles for each trait that separate during gamete formation; each gamete receives one allele. The underlying mechanism is the separation of homologs during meiosis I." , front_translations: {"es":"Ley de la Segregación de Mendel","de":"Mendels Trennungsgesetz","fr":"Loi de ségrégation de Mendel","tr":"Mendel'in Ayrılma Yasası","nl":"Wet van segregatie van Mendel","ru":"Закон расщепления Менделя","zh":"孟德尔分离定律","pt_BR":"Lei da Segregação de Mendel","pt_PT":"Lei da Segregação de Mendel"}, back_translations: {"es":"Cada indivíduo carrega de los alelos para cada característica que se separan durante a formación de gametas; cada gameta recibe un alelo. El mecanismo subjacente es a separación de los homólogos durante a meiose I.","de":"Jedes Individuum trägt für jedes Merkmal zwei Allele, die sich bei der Gametenbildung trennen; jede Gamete erhält ein Allel. Der zugrunde liegende Mechanismus ist die Trennung von Homologen während der Meiose I.","fr":"Chaque individu possède deux allèles pour chaque caractère, qui se séparent lors de la formation des gamètes ; chaque gamète reçoit un allèle. Le mécanisme sous-jacent est la séparation des homologues lors de la méiose I.","tr":"Her birey, her özellik için iki alel taşır; bunlar gamet oluşumu sırasında ayrılır; her gamet bir alel alır. Altta yatan mekanizma, mayoz I sırasında homologların ayrılmasıdır.","nl":"Elk individu draagt twee allelen voor elk kenmerk die scheiden tijdens gametvorming; elke gamet ontvangt één allel. Het onderliggende mechanisme is de scheiding van homologen tijdens meiose I.","ru":"Каждый организм несёт два аллеля для каждого признака, которые расходятся при образовании гамет; каждая гамета получает по одному аллелю. В основе лежит расхождение гомологов в мейозе I.","zh":"每个个体携带每个性状的两个等位基因，在配子形成时分离，每个配子获得一个等位基因。其基础机制是减数第一次分裂时同源染色体的分离。","pt_BR":"Cada indivíduo carrega dois alelos para cada característica que se separam durante a formação de gametas; cada gameta recebe um alelo. O mecanismo subjacente é a separação dos homólogos durante a meiose I.","pt_PT":"Cada indivíduo carrega dois alelos para cada característica que se separam durante a formação dos gâmetas; cada gâmeta recebe um alelo. O mecanismo subjacente é a separação dos homólogos durante a meiose I."}},
  { id: 'dc-biology-0036', deck_id: 'deck-biology', sort_order: 36, front: "Mendel's Law of Independent Assortment", back: "Alleles of different genes assort independently during gamete formation when genes are on different chromosomes. Gives the 9:3:3:1 phenotypic ratio in F2 dihybrid crosses." , front_translations: {"es":"Ley de la Segregación Independente de Mendel","de":"Mendels Gesetz der unabhängigen Spaltung","fr":"Loi d'assortiment indépendant de Mendel","tr":"Mendel'in Bağımsız Dağılım Yasası","nl":"Wet van onafhankelijke assortiment van Mendel","ru":"Закон независимого комбинирования Менделя","zh":"孟德尔自由组合定律","pt_BR":"Lei da Segregação Independente de Mendel","pt_PT":"Lei da Segregação Independente de Mendel"}, back_translations: {"es":"Alelos de genes diferentes se separan independentemente durante a formación de gametas cuando los genes están en cromossomos diferentes. Produz a proporción fenotípica 9:3:3:1 en cruzamentos dihíbridos F2.","de":"Allele verschiedener Gene sortieren sich bei der Gametenbildung unabhängig, wenn sich die Gene auf verschiedenen Chromosomen befinden. Ergibt das Phänotypverhältnis 9:3:3:1 in F2-Dihybridkreuzungen.","fr":"Les allèles de différents gènes s'assortissent indépendamment lors de la formation des gamètes lorsque les gènes sont sur des chromosomes différents. Donne le rapport phénotypique 9:3:3:1 dans les croisements dihybrides F2.","tr":"Farklı genlerin allelleri, genler farklı kromozomlarda bulunduğunda gamet oluşumu sırasında bağımsız olarak dağılır. F2 dihybrid çaprazlamalarında 9:3:3:1 fenotipik oranı verir.","nl":"Allelen van verschillende genen assortieren onafhankelijk tijdens gametvorming wanneer genen op verschillende chromosomen liggen. Geeft de 9:3:3:1 fenotypische verhouding in F2-dihybride kruisingen.","ru":"Аллели разных генов при образовании гамет распределяются независимо, если гены находятся на разных хромосомах. Даёт фенотипическое соотношение 9:3:3:1 в F2 при дигибридном скрещивании.","zh":"不同基因的等位基因在配子形成时独立分配（基因位于不同染色体时）。在F2代双杂交中产生9:3:3:1的表型比例。","pt_BR":"Alelos de genes diferentes se separam independentemente durante a formação de gametas quando os genes estão em cromossomos diferentes. Produz a proporção fenotípica 9:3:3:1 em cruzamentos dihíbridos F2.","pt_PT":"Alelos de genes diferentes separam-se independentemente durante a formação dos gâmetas quando os genes estão em cromossomas diferentes. Produz a proporção fenotípica 9:3:3:1 em cruzamentos dihíbridos F2."}},
  { id: 'dc-biology-0037', deck_id: 'deck-biology', sort_order: 37, front: "Dominant vs. Recessive Allele", back: "A dominant allele is expressed in the phenotype even when only one copy is present; a recessive allele is expressed only in homozygous form. Dominant does not mean more common or better." , front_translations: {"es":"Alelo Dominante vs. Recessivo","de":"Dominantes vs. rezessives Allel","fr":"Allèle dominant vs. allèle récessif","tr":"Baskın ve Çekinik Alel","nl":"Dominant vs. recessief allel","ru":"Доминантный и рецессивный аллель","zh":"显性等位基因与隐性等位基因","pt_BR":"Alelo Dominante vs. Recessivo","pt_PT":"Alelo Dominante vs. Recessivo"}, back_translations: {"es":"Un alelo dominante es expresso en el fenótipo mismo cuando solo una cópia está presente; un alelo recessivo es expresso solo en la forma homozigótica. Dominante no significa más comum o mejor.","de":"Ein dominantes Allel wird im Phänotyp exprimiert, auch wenn nur eine Kopie vorhanden ist; ein rezessives Allel wird nur in homozygoter Form exprimiert. Dominant bedeutet nicht häufiger oder besser.","fr":"Un allèle dominant s'exprime dans le phénotype même lorsqu'une seule copie est présente ; un allèle récessif ne s'exprime qu'à l'état homozygote. Dominant ne signifie pas plus commun ou meilleur.","tr":"Baskın alel, yalnızca bir kopya mevcut olsa bile fenotipte ifade edilir; çekinik alel yalnızca homozigot formda ifade edilir. Baskın daha yaygın veya daha iyi anlamına gelmez.","nl":"Een dominant allel wordt uitgedrukt in het fenotype zelfs wanneer slechts één kopie aanwezig is; een recessief allel wordt alleen uitgedrukt in homozygote vorm. Dominant betekent niet vaker of beter.","ru":"Доминантный аллель проявляется в фенотипе даже при наличии одной копии; рецессивный аллель проявляется только в гомозиготном состоянии. Доминантный не означает более распространённый или лучший.","zh":"显性等位基因即使只有一个拷贝也能在表型中表达；隐性等位基因只在纯合状态下才表达。显性并不意味着更常见或更优越。","pt_BR":"Um alelo dominante é expresso no fenótipo mesmo quando apenas uma cópia está presente; um alelo recessivo é expresso apenas na forma homozigótica. Dominante não significa mais comum ou melhor.","pt_PT":"Um alelo dominante é expresso no fenótipo mesmo quando apenas uma cópia está presente; um alelo recessivo é expresso apenas na forma homozigótica. Dominante não significa mais comum ou melhor."}},
  { id: 'dc-biology-0038', deck_id: 'deck-biology', sort_order: 38, front: "Codominance", back: "Both alleles are fully expressed in the heterozygote. Example: AB blood type — both A and B antigens are present on red blood cells. Neither allele masks the other." , front_translations: {"es":"Codominancia","de":"Kodominanz","fr":"Codominance","tr":"Kodominans","nl":"Codominantie","ru":"Кодоминирование","zh":"共显性","pt_BR":"Codominância","pt_PT":"Codominância"}, back_translations: {"es":"Ambos los alelos son totalmente expressos en el heterozigoto. Exemplo: tipo sanguíneo AB — los antígenos A y B están presentes en las hemácias. Nenhum alelo mascara el outro.","de":"Beide Allele werden beim Heterozygoten vollständig exprimiert. Beispiel: Blutgruppe AB — sowohl A- als auch B-Antigene sind auf roten Blutkörperchen vorhanden. Keines der Allele maskiert das andere.","fr":"Les deux allèles sont pleinement exprimés chez l'hétérozygote. Exemple : groupe sanguin AB — les antigènes A et B sont tous deux présents sur les globules rouges. Aucun allèle ne masque l'autre.","tr":"Her iki alel de heterozigotta tam olarak ifade edilir. Örnek: AB kan grubu — hem A hem de B antijenleri kırmızı kan hücrelerinde bulunur. Hiçbir alel diğerini maskelemez.","nl":"Beide allelen worden volledig tot expressie gebracht in de heterozygoot. Voorbeeld: bloedgroep AB — zowel A- als B-antigenen zijn aanwezig op rode bloedcellen. Geen enkel allel maskeert het andere.","ru":"Оба аллеля полностью экспрессируются у гетерозиготы. Пример: группа крови AB — на эритроцитах присутствуют и антиген A, и антиген B. Ни один аллель не подавляет другой.","zh":"杂合子中两种等位基因均完全表达。例：AB血型——红细胞上同时存在A和B抗原。两个等位基因互不掩盖。","pt_BR":"Ambos os alelos são totalmente expressos no heterozigoto. Exemplo: tipo sanguíneo AB — os antígenos A e B estão presentes nas hemácias. Nenhum alelo mascara o outro.","pt_PT":"Ambos os alelos são totalmente expressos no heterozigótico. Exemplo: grupo sanguíneo AB — os antigénios A e B estão presentes nos glóbulos vermelhos. Nenhum alelo mascara o outro."}},
  { id: 'dc-biology-0039', deck_id: 'deck-biology', sort_order: 39, front: "Incomplete Dominance", back: "The heterozygote shows an intermediate phenotype between the two homozygous phenotypes. Example: red × white → pink in snapdragons. The dominant allele does not completely mask the recessive." , front_translations: {"es":"Dominancia Incompleta","de":"Unvollständige Dominanz","fr":"Dominance incomplète","tr":"Eksik Dominans","nl":"Onvolledige dominantie","ru":"Неполное доминирование","zh":"不完全显性","pt_BR":"Dominância Incompleta","pt_PT":"Dominância Incompleta"}, back_translations: {"es":"El heterozigoto mostra un fenótipo intermediário entre los de los fenótipos homozigóticos. Exemplo: rojo × branco → rosa en bocas-de-leão. El alelo dominante no mascara completamente el recessivo.","de":"Der Heterozygote zeigt einen Phänotyp, der zwischen den beiden homozygoten Phänotypen liegt. Beispiel: rot × weiß → rosa bei Löwenmäulchen. Das dominante Allel verdeckt das rezessive nicht vollständig.","fr":"L'hétérozygote présente un phénotype intermédiaire entre les deux phénotypes homozygotes. Exemple : rouge × blanc → rose chez les mufliers. L'allèle dominant ne masque pas complètement le récessif.","tr":"Heterozigot, iki homozigot fenotip arasında ara bir fenotip gösterir. Örnek: aslanağzında kırmızı × beyaz → pembe. Baskın alel, çekinik aleli tamamen maskelemez.","nl":"De heterozygoot vertoont een fenotype dat tussenlicht tussen de twee homozygote fenotypen. Voorbeeld: rood × wit → roze bij leeuwebekjes. Het dominante allel maskeert het recessieve niet volledig.","ru":"Гетерозигота демонстрирует промежуточный фенотип между двумя гомозиготными. Пример: красный × белый → розовый у львиного зева. Доминантный аллель не полностью маскирует рецессивный.","zh":"杂合子表现出介于两种纯合表型之间的中间表型。例：金鱼草中红色×白色→粉红色。显性等位基因不能完全掩盖隐性等位基因。","pt_BR":"O heterozigoto mostra um fenótipo intermediário entre os dois fenótipos homozigóticos. Exemplo: vermelho × branco → rosa em bocas-de-leão. O alelo dominante não mascara completamente o recessivo.","pt_PT":"O heterozigótico mostra um fenótipo intermédio entre os dois fenótipos homozigóticos. Exemplo: vermelho × branco → rosa em bocas-de-lobo. O alelo dominante não mascara completamente o recessivo."}},
  { id: 'dc-biology-0040', deck_id: 'deck-biology', sort_order: 40, front: "Sex-Linked Inheritance", back: "Genes located on the sex chromosomes (X or Y). X-linked recessive traits (e.g., hemophilia, color blindness) are more common in males (XY) because they have only one X chromosome." , front_translations: {"es":"Herança Ligada al Sexo","de":"Geschlechtsgebundene Vererbung","fr":"Hérédité liée au sexe","tr":"Cinsiyete Bağlı Kalıtım","nl":"Geslachtsgebonden overerving","ru":"Сцепленное с полом наследование","zh":"伴性遗传","pt_BR":"Herança Ligada ao Sexo","pt_PT":"Herança Ligada ao Sexo"}, back_translations: {"es":"Genes localizados en los cromossomos sexuais (X o Y). Características recessivas ligadas al X (ex.: hemofilia, daltonismo) son más comuns en machos (XY) porque tienen solo un cromossomo X.","de":"Gene, die auf den Geschlechtschromosomen (X oder Y) liegen. X-gebundene rezessive Merkmale (z. B. Hämophilie, Farbenblindheit) sind bei Männern (XY) häufiger, da sie nur ein X-Chromosom haben.","fr":"Gènes situés sur les chromosomes sexuels (X ou Y). Les caractères récessifs liés à l'X (ex. hémophilie, daltonisme) sont plus fréquents chez les mâles (XY) car ils n'ont qu'un seul chromosome X.","tr":"Cinsiyet kromozomlarında (X veya Y) bulunan genler. X'e bağlı çekinik özellikler (ör. hemofili, renk körlüğü) erkeklerde (XY) daha yaygındır çünkü yalnızca bir X kromozomları vardır.","nl":"Genen gelegen op de geslachtschromosomen (X of Y). X-gebonden recessieve eigenschappen (bijv. hemofilie, kleurenblindheid) zijn vaker bij mannen (XY) omdat zij slechts één X-chromosoom hebben.","ru":"Гены, расположенные на половых хромосомах (X или Y). Х-сцепленные рецессивные признаки (например, гемофилия, дальтонизм) чаще встречаются у самцов (XY), так как у них только одна X-хромосома.","zh":"位于性染色体（X或Y）上的基因。X染色体连锁隐性性状（如血友病、色盲）在男性（XY）中更常见，因为男性只有一条X染色体。","pt_BR":"Genes localizados nos cromossomos sexuais (X ou Y). Características recessivas ligadas ao X (ex.: hemofilia, daltonismo) são mais comuns em machos (XY) porque têm apenas um cromossomo X.","pt_PT":"Genes localizados nos cromossomas sexuais (X ou Y). Características recessivas ligadas ao X (ex.: hemofilia, daltonismo) são mais comuns nos machos (XY) porque têm apenas um cromossoma X."}},
  { id: 'dc-biology-0041', deck_id: 'deck-biology', sort_order: 41, front: "Hardy-Weinberg Equilibrium", back: "p² + 2pq + q² = 1; p + q = 1. Describes allele and genotype frequencies in a non-evolving population. Requires: no mutation, no migration, large population, random mating, no selection." , front_translations: {"es":"Equilíbrio de Hardy-Weinberg","de":"Hardy-Weinberg-Gleichgewicht","fr":"Équilibre de Hardy-Weinberg","tr":"Hardy-Weinberg Dengesi","nl":"Hardy-Weinberg-evenwicht","ru":"Закон Харди–Вайнберга","zh":"哈迪-温伯格平衡","pt_BR":"Equilíbrio de Hardy-Weinberg","pt_PT":"Equilíbrio de Hardy-Weinberg"}, back_translations: {"es":"p² + 2pq + q² = 1; p + q = 1. Descreve frequencias alélicas y genotípicas en una población no evoluindo. Requer: sin mutación, sin migración, población grande, acasalamento aleatório, sin seleción.","de":"p² + 2pq + q² = 1; p + q = 1. Beschreibt Allel- und Genotypfrequenzen in einer nicht evolvierenden Population. Voraussetzungen: keine Mutation, keine Migration, große Population, zufällige Paarung, keine Selektion.","fr":"p² + 2pq + q² = 1 ; p + q = 1. Décrit les fréquences alléliques et génotypiques dans une population non évolutive. Conditions : pas de mutation, pas de migration, grande population, accouplement aléatoire, pas de sélection.","tr":"p² + 2pq + q² = 1; p + q = 1. Evrimleşmeyen bir popülasyondaki alel ve genotip frekanslarını tanımlar. Gerektirir: mutasyon yok, göç yok, büyük popülasyon, rastgele çiftleşme, seçilim yok.","nl":"p² + 2pq + q² = 1; p + q = 1. Beschrijft allel- en genotypefrequenties in een niet-evoluerende populatie. Vereist: geen mutatie, geen migratie, grote populatie, willekeurige paring, geen selectie.","ru":"p² + 2pq + q² = 1; p + q = 1. Описывает частоты аллелей и генотипов в неэволюционирующей популяции. Условия: отсутствие мутаций, миграций, большая популяция, случайное скрещивание, отсутствие отбора.","zh":"p² + 2pq + q² = 1；p + q = 1。描述非进化种群中等位基因和基因型频率。条件：无突变、无迁移、大种群、随机交配、无自然选择。","pt_BR":"p² + 2pq + q² = 1; p + q = 1. Descreve frequências alélicas e genotípicas em uma população não evoluindo. Requer: sem mutação, sem migração, população grande, acasalamento aleatório, sem seleção.","pt_PT":"p² + 2pq + q² = 1; p + q = 1. Descreve frequências alélicas e genotípicas numa população em não evolução. Requer: sem mutação, sem migração, população grande, acasalamento aleatório, sem seleção."}},
  { id: 'dc-biology-0042', deck_id: 'deck-biology', sort_order: 42, front: "Natural Selection", back: "The mechanism of evolution proposed by Darwin: individuals with traits better suited to their environment survive and reproduce more successfully, passing those traits to offspring." , front_translations: {"es":"Seleción Natural","de":"Natürliche Selektion","fr":"Sélection naturelle","tr":"Doğal Seçilim","nl":"Natuurlijke selectie","ru":"Естественный отбор","zh":"自然选择","pt_BR":"Seleção Natural","pt_PT":"Seleção Natural"}, back_translations: {"es":"El mecanismo de evolución proposto por Darwin: indivíduos con características más adequadas al su ambiente sobrevivem y se reproduzem con más éxito, passando essas características para a prole.","de":"Der von Darwin vorgeschlagene Evolutionsmechanismus: Individuen mit Merkmalen, die besser an ihre Umgebung angepasst sind, überleben und pflanzen sich erfolgreicher fort und vererben diese Merkmale an den Nachwuchs.","fr":"Le mécanisme d'évolution proposé par Darwin : les individus possédant des traits mieux adaptés à leur environnement survivent et se reproduisent plus avec succès, transmettant ces traits à leur descendance.","tr":"Darwin tarafından önerilen evrim mekanizması: çevrelerine daha uygun özelliklere sahip bireyler hayatta kalır ve daha başarılı ürer, bu özellikleri yavrularına aktarır.","nl":"Het evoltiemechanisme voorgesteld door Darwin: individuen met eigenschappen die beter geschikt zijn aan hun omgeving overleven en reproduceren succesvoller, waarbij die eigenschappen worden doorgegeven aan nakomelingen.","ru":"Механизм эволюции, предложенный Дарвином: особи с признаками, лучше приспособленными к среде обитания, выживают и размножаются успешнее, передавая эти признаки потомству.","zh":"达尔文提出的进化机制：具有更适应环境特征的个体存活并繁殖更成功，将这些特征传递给后代。","pt_BR":"O mecanismo de evolução proposto por Darwin: indivíduos com características mais adequadas ao seu ambiente sobrevivem e se reproduzem com mais sucesso, passando essas características para a prole.","pt_PT":"O mecanismo de evolução proposto por Darwin: indivíduos com características mais adequadas ao seu ambiente sobrevivem e reproduzem-se com mais sucesso, passando essas características para a descendência."}},
  { id: 'dc-biology-0043', deck_id: 'deck-biology', sort_order: 43, front: "Types of Natural Selection", back: "Directional (one extreme phenotype favored), stabilizing (intermediate phenotype favored; reduces variation), disruptive (both extreme phenotypes favored over intermediate; can lead to speciation)." , front_translations: {"es":"Tipos de Seleción Natural","de":"Arten der natürlichen Selektion","fr":"Types de sélection naturelle","tr":"Doğal Seçilim Türleri","nl":"Soorten natuurlijke selectie","ru":"Типы естественного отбора","zh":"自然选择的类型","pt_BR":"Tipos de Seleção Natural","pt_PT":"Tipos de Seleção Natural"}, back_translations: {"es":"Direcional (un fenótipo extremo favorecido), estabilizadora (fenótipo intermediário favorecido; reduce variación), disruptiva (ambos los fenótipos extremos favorecidos sobre el intermediário; puede levar a la especiación).","de":"Direktionale Selektion (ein extremer Phänotyp bevorzugt), stabilisierende Selektion (mittlerer Phänotyp bevorzugt; reduziert Variation), disruptive Selektion (beide extremen Phänotypen gegenüber dem mittleren bevorzugt; kann zur Artbildung führen).","fr":"Directionnelle (un phénotype extrême favorisé), stabilisatrice (phénotype intermédiaire favorisé ; réduit la variation), disruptive (les deux phénotypes extrêmes favorisés par rapport à l'intermédiaire ; peut mener à la spéciation).","tr":"Yönlü (bir uç fenotip tercih edilir), dengeleyici (orta fenotip tercih edilir; varyasyonu azaltır), bozucu (her iki uç fenotip de orta fenotipin üzerinde tercih edilir; türleşmeye yol açabilir).","nl":"Directioneel (één extreem fenotype begunstigd), stabiliserend (gemiddeld fenotype begunstigd; vermindert variatie), disruptief (beide extreme fenotypen begunstigd boven gemiddeld; kan leiden tot speciatie).","ru":"Движущий отбор (предпочтение одному крайнему фенотипу), стабилизирующий (предпочтение среднему фенотипу; снижает изменчивость), разрывающий (предпочтение обоим крайним фенотипам; может приводить к видообразованию).","zh":"定向选择（有利于一种极端表型）、稳定选择（有利于中间表型，减少变异）、分裂选择（有利于两种极端表型，可能导致物种形成）。","pt_BR":"Direcional (um fenótipo extremo favorecido), estabilizadora (fenótipo intermediário favorecido; reduz variação), disruptiva (ambos os fenótipos extremos favorecidos sobre o intermediário; pode levar à especiação).","pt_PT":"Direcional (um fenótipo extremo favorecido), estabilizadora (fenótipo intermédio favorecido; reduz variação), disruptiva (ambos os fenótipos extremos favorecidos sobre o intermédio; pode levar à especiação)."}},
  { id: 'dc-biology-0044', deck_id: 'deck-biology', sort_order: 44, front: "Genetic Drift", back: "Random changes in allele frequencies in a population, especially significant in small populations. The bottleneck effect (population crash) and founder effect (small founding group) are examples." , front_translations: {"es":"Deriva Genética","de":"Genetische Drift","fr":"Dérive génétique","tr":"Genetik Sürüklenme","nl":"Genetische drift","ru":"Генетический дрейф","zh":"遗传漂变","pt_BR":"Deriva Genética","pt_PT":"Deriva Genética"}, back_translations: {"es":"Mudanças aleatórias en las frequencias alélicas en una población, especialmente significativas en poblaciones pequeñas. El efecto gargalo (colapso populacional) y el efecto fundador (pequeño grupo fundador) son ejemplos.","de":"Zufällige Veränderungen der Allelfrequenzen in einer Population, besonders bedeutsam in kleinen Populationen. Der Flaschenhalseffekt (Populationsabsturz) und der Gründereffekt (kleine Gründungsgruppe) sind Beispiele.","fr":"Changements aléatoires des fréquences alléliques dans une population, particulièrement significatifs dans les petites populations. L'effet fondateur (petit groupe fondateur) et l'effet goulot d'étranglement (effondrement de population) en sont des exemples.","tr":"Bir popülasyondaki alel frekanslarındaki rastgele değişimler, özellikle küçük popülasyonlarda önemlidir. Darboğaz etkisi (popülasyon çöküşü) ve kurucu etkisi (küçük kurucu grup) örneklerdir.","nl":"Willekeurige veranderingen in allelfrequenties in een populatie, vooral significant in kleine populaties. Het flessenhalsefffect (populatiecrash) en het grondleggereffect (kleine stichtingsgroep) zijn voorbeelden.","ru":"Случайные изменения частот аллелей в популяции, особенно значимые в малых популяциях. Примеры: эффект бутылочного горлышка (резкое сокращение популяции) и эффект основателя (малая группа-основатель).","zh":"种群中等位基因频率的随机变化，在小种群中尤为显著。瓶颈效应（种群数量骤减）和奠基者效应（小型创始群体）是其典型例子。","pt_BR":"Mudanças aleatórias nas frequências alélicas em uma população, especialmente significativas em populações pequenas. O efeito gargalo (colapso populacional) e o efeito fundador (pequeno grupo fundador) são exemplos.","pt_PT":"Mudanças aleatórias nas frequências alélicas numa população, especialmente significativas em populações pequenas. O efeito garrafa (colapso populacional) e o efeito fundador (pequeno grupo fundador) são exemplos."}},
  { id: 'dc-biology-0045', deck_id: 'deck-biology', sort_order: 45, front: "Speciation", back: "The evolutionary process by which populations diverge into new species. Allopatric speciation occurs via geographic isolation; sympatric speciation occurs without physical separation, often via polyploidy or resource partitioning." , front_translations: {"es":"Especiación","de":"Artbildung (Speziation)","fr":"Spéciation","tr":"Türleşme","nl":"Speciatie","ru":"Видообразование","zh":"物种形成","pt_BR":"Especiação","pt_PT":"Especiação"}, back_translations: {"es":"El proceso evolutivo por el qual poblaciones divergem en nuevas especies. La especiación alopátrica ocurre por isolamento geográfico; a especiación simpátrica ocurre sin separación física, frecuentemente via poliploidia o particionamento de recursos.","de":"Der evolutionäre Prozess, durch den sich Populationen zu neuen Arten entwickeln. Allopatrische Speziation erfolgt durch geografische Isolation; sympatrische Speziation erfolgt ohne physische Trennung, oft durch Polyploidie oder Ressourcenteilung.","fr":"Le processus évolutif par lequel les populations divergent en nouvelles espèces. La spéciation allopatrique se produit par isolation géographique ; la spéciation sympatrique se produit sans séparation physique, souvent par polyploïdie ou partitionnement des ressources.","tr":"Popülasyonların yeni türlere ayrıştığı evrimsel süreç. Allopatrik türleşme coğrafi izolasyon yoluyla gerçekleşir; sempatrik türleşme fiziksel ayrılma olmaksızın, genellikle poliploidi veya kaynak bölümlenmesi yoluyla gerçekleşir.","nl":"Het evolutionaire proces waarbij populaties divergeren in nieuwe soorten. Allopatrische speciatie treedt op via geografische isolatie; sympatrische speciatie treedt op zonder fysieke scheiding, vaak via polyploïdie of bronnenverdeling.","ru":"Эволюционный процесс, в ходе которого популяции расходятся и образуют новые виды. Аллопатрическое видообразование происходит в результате географической изоляции; симпатрическое — без физического разделения, часто через полиплоидию или разделение ресурсов.","zh":"种群分化形成新物种的进化过程。异域物种形成通过地理隔离发生；同域物种形成在没有物理分隔的情况下发生，通常通过多倍体化或资源分割。","pt_BR":"O processo evolutivo pelo qual populações divergem em novas espécies. A especiação alopátrica ocorre por isolamento geográfico; a especiação simpátrica ocorre sem separação física, frequentemente via poliploidia ou particionamento de recursos.","pt_PT":"O processo evolutivo pelo qual as populações divergem em novas espécies. A especiação alopátrica ocorre por isolamento geográfico; a especiação simpátrica ocorre sem separação física, frequentemente via poliploidia ou partilha de recursos."}},
  { id: 'dc-biology-0046', deck_id: 'deck-biology', sort_order: 46, front: "Phylogenetics", back: "The study of evolutionary relationships among organisms. Represented by phylogenetic trees (cladograms). Based on morphological, molecular, and fossil evidence. Monophyletic groups include an ancestor and all descendants." , front_translations: {"es":"Filogenética","de":"Phylogenetik","fr":"Phylogénétique","tr":"Filogenetik","nl":"Fylogenetica","ru":"Филогенетика","zh":"系统发育学","pt_BR":"Filogenética","pt_PT":"Filogenética"}, back_translations: {"es":"El estudio de las relaciones evolutivas entre organismos. Representado por árvores filogenéticas (cladogramas). Baseado en evidencias morfológicas, moleculares y fósseis. Grupos monofiléticos incluyen un ancestral y todos los descendentes.","de":"Das Studium der evolutionären Beziehungen zwischen Organismen. Dargestellt durch phylogenetische Bäume (Kladogramme). Basiert auf morphologischen, molekularen und fossilen Belegen. Monophyletische Gruppen umfassen einen Vorfahren und alle Nachkommen.","fr":"L'étude des relations évolutives entre les organismes. Représentée par des arbres phylogénétiques (cladogrammes). Basée sur des données morphologiques, moléculaires et fossiles. Les groupes monophylétiques incluent un ancêtre et tous ses descendants.","tr":"Organizmalar arasındaki evrimsel ilişkilerin incelenmesi. Filogenetik ağaçlarla (kladogramlar) temsil edilir. Morfolojik, moleküler ve fosil kanıtlara dayanır. Monofiletik gruplar bir atayı ve tüm torunlarını içerir.","nl":"De studie van evolutionaire relaties tussen organismen. Weergegeven door fylogenetische bomen (cladogrammen). Gebaseerd op morfologisch, moleculair en fossiel bewijs. Monofyletische groepen omvatten een voorouder en alle nakomelingen.","ru":"Изучение эволюционных взаимосвязей между организмами. Представляется филогенетическими деревьями (кладограммами). Основано на морфологических, молекулярных и ископаемых данных. Монофилетические группы включают предка и всех его потомков.","zh":"研究生物体间进化关系的学科。用系统发育树（分支图）来表示。基于形态学、分子和化石证据。单系群包含一个祖先及其所有后代。","pt_BR":"O estudo das relações evolutivas entre organismos. Representado por árvores filogenéticas (cladogramas). Baseado em evidências morfológicas, moleculares e fósseis. Grupos monofiléticos incluem um ancestral e todos os descendentes.","pt_PT":"O estudo das relações evolutivas entre organismos. Representado por árvores filogenéticas (cladogramas). Baseado em evidências morfológicas, moleculares e fósseis. Grupos monofiléticos incluem um ancestral e todos os descendentes."}},
  { id: 'dc-biology-0047', deck_id: 'deck-biology', sort_order: 47, front: "Photosynthesis Overview", back: "6CO₂ + 6H₂O + light energy → C₆H₁₂O₆ + 6O₂. Occurs in two stages: light-dependent reactions (thylakoids; produce ATP, NADPH, O₂) and the Calvin cycle (stroma; fixes CO₂ into glucose)." , front_translations: {"es":"Visão Geral de la Fotossíntese","de":"Photosynthese: Überblick","fr":"Vue d'ensemble de la photosynthèse","tr":"Fotosentez Genel Bakış","nl":"Overzicht fotosynthese","ru":"Фотосинтез: общий обзор","zh":"光合作用概述","pt_BR":"Visão Geral da Fotossíntese","pt_PT":"Visão Geral da Fotossíntese"}, back_translations: {"es":"6CO₂ + 6H₂El + energía luminosa → C₆H₁₂El₆ + 6El₂. Ocorre en de los etapas: reacciones dependentes de luz (tilacoides; producen ATP, NADPH, El₂) y el ciclo de Calvin (estroma; fixa CO₂ en glicose).","de":"6CO₂ + 6H₂O + Lichtenergie → C₆H₁₂O₆ + 6O₂. Verläuft in zwei Phasen: lichtabhängige Reaktionen (Thylakoide; produzieren ATP, NADPH, O₂) und der Calvin-Zyklus (Stroma; fixiert CO₂ zu Glukose).","fr":"6CO₂ + 6H₂O + énergie lumineuse → C₆H₁₂O₆ + 6O₂. Se déroule en deux étapes : réactions lumino-dépendantes (thylakoïdes ; produisent ATP, NADPH, O₂) et cycle de Calvin (stroma ; fixe le CO₂ en glucose).","tr":"6CO₂ + 6H₂O + ışık enerjisi → C₆H₁₂O₆ + 6O₂. İki aşamada gerçekleşir: ışığa bağımlı reaksiyonlar (tilakoidler; ATP, NADPH, O₂ üretir) ve Calvin döngüsü (stroma; CO₂'yi glikoza dönüştürür).","nl":"6CO₂ + 6H₂O + lichtenergie → C₆H₁₂O₆ + 6O₂. Verloopt in twee fasen: lichtafhankelijke reacties (thylakoïden; produceren ATP, NADPH, O₂) en de Calvin-cyclus (stroma; zet CO₂ om in glucose).","ru":"6CO₂ + 6H₂O + световая энергия → C₆H₁₂O₆ + 6O₂. Протекает в два этапа: световые реакции (тилакоиды; вырабатываются ATP, NADPH, O₂) и цикл Кальвина (строма; фиксирует CO₂ в глюкозу).","zh":"6CO₂ + 6H₂O + 光能 → C₆H₁₂O₆ + 6O₂。分两个阶段进行：光反应（类囊体膜；产生ATP、NADPH、O₂）和卡尔文循环（叶绿体基质；将CO₂固定为葡萄糖）。","pt_BR":"6CO₂ + 6H₂O + energia luminosa → C₆H₁₂O₆ + 6O₂. Ocorre em duas etapas: reações dependentes de luz (tilacoides; produzem ATP, NADPH, O₂) e o ciclo de Calvin (estroma; fixa CO₂ em glicose).","pt_PT":"6CO₂ + 6H₂O + energia luminosa → C₆H₁₂O₆ + 6O₂. Ocorre em duas etapas: reações dependentes de luz (tilacoides; produzem ATP, NADPH, O₂) e o ciclo de Calvin (estroma; fixa CO₂ em glicose)."}},
  { id: 'dc-biology-0048', deck_id: 'deck-biology', sort_order: 48, front: "Calvin Cycle (Light-Independent Reactions)", back: "Uses ATP and NADPH from light reactions to fix CO₂ into G3P, which is used to make glucose. Three turns incorporate three CO₂ molecules and regenerate RuBP. Also called the dark reactions." , front_translations: {"es":"Ciclo de Calvin (Reaciones Independentes de Luz)","de":"Calvin-Zyklus (lichtunabhängige Reaktionen)","fr":"Cycle de Calvin (réactions indépendantes de la lumière)","tr":"Calvin Döngüsü (Işığa Bağımsız Reaksiyonlar)","nl":"Calvin-cyclus (lichtOnafhankelijke reacties)","ru":"Цикл Кальвина (световые реакции)","zh":"卡尔文循环（光无关反应）","pt_BR":"Ciclo de Calvin (Reações Independentes de Luz)","pt_PT":"Ciclo de Calvin (Reações Independentes da Luz)"}, back_translations: {"es":"Usa ATP y NADPH de las reacciones de luz para fixar CO₂ en G3P, que es usado para fazer glicose. Tres voltas incorporam tres moléculas de CO₂ y regeneram RuBP. También llamadas de reacciones escuras.","de":"Verwendet ATP und NADPH aus den Lichtreaktionen, um CO₂ in G3P zu fixieren, das zur Herstellung von Glukose verwendet wird. Drei Durchläufe inkorporieren drei CO₂-Moleküle und regenerieren RuBP. Auch Dunkelreaktionen genannt.","fr":"Utilise l'ATP et le NADPH des réactions lumineuses pour fixer le CO₂ en G3P, utilisé pour fabriquer du glucose. Trois tours incorporent trois molécules de CO₂ et régénèrent le RuBP. Aussi appelées réactions obscures.","tr":"CO₂'yi G3P'ye sabitlemek için ışık reaksiyonlarından ATP ve NADPH kullanır; G3P glukoz yapmak için kullanılır. Üç tur üç CO₂ molekülünü birleştirir ve RuBP'yi yeniler. Karanlık reaksiyonlar olarak da adlandırılır.","nl":"Gebruikt ATP en NADPH uit de lichtreacties om CO₂ te fixeren in G3P, dat wordt gebruikt om glucose te maken. Drie ronden incorporeren drie CO₂-moleculen en regenereren RuBP. Ook donkerreacties genoemd.","ru":"Использует ATP и NADPH из световых реакций для фиксации CO₂ в G3P, из которого синтезируется глюкоза. За три оборота фиксируются три молекулы CO₂ и регенерируется RuBP. Также называют тёмными реакциями.","zh":"利用光反应产生的ATP和NADPH将CO₂固定为G3P，G3P用于合成葡萄糖。三轮循环固定三个CO₂分子并再生RuBP。也称为暗反应。","pt_BR":"Usa ATP e NADPH das reações de luz para fixar CO₂ em G3P, que é usado para fazer glicose. Três voltas incorporam três moléculas de CO₂ e regeneram RuBP. Também chamadas de reações escuras.","pt_PT":"Usa ATP e NADPH das reações de luz para fixar CO₂ em G3P, que é usado para fazer glicose. Três voltas incorporam três moléculas de CO₂ e regeneram RuBP. Também chamadas de reações escuras."}},
  { id: 'dc-biology-0049', deck_id: 'deck-biology', sort_order: 49, front: "Cellular Respiration Overview", back: "C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + ~36–38 ATP. Three stages: glycolysis (cytoplasm), pyruvate oxidation + Krebs cycle (mitochondrial matrix), oxidative phosphorylation (inner mitochondrial membrane)." , front_translations: {"es":"Visão Geral de la Respiración Celular","de":"Zelluläre Atmung: Überblick","fr":"Vue d'ensemble de la respiration cellulaire","tr":"Hücresel Solunum Genel Bakış","nl":"Overzicht cellulaire ademhaling","ru":"Клеточное дыхание: общий обзор","zh":"细胞呼吸概述","pt_BR":"Visão Geral da Respiração Celular","pt_PT":"Visão Geral da Respiração Celular"}, back_translations: {"es":"C₆H₁₂El₆ + 6El₂ → 6CO₂ + 6H₂El + ~36–38 ATP. Tres etapas: glicólise (citoplasma), oxidación del piruvato + ciclo de Krebs (matriz mitocondrial), fosforilación oxidativa (membrana mitocondrial interna).","de":"C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + ~36–38 ATP. Drei Stufen: Glykolyse (Zytoplasma), Pyruvat-Oxidation + Krebs-Zyklus (mitochondriale Matrix), oxidative Phosphorylierung (innere Mitochondrienmembran).","fr":"C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + ~36–38 ATP. Trois étapes : glycolyse (cytoplasme), oxydation du pyruvate + cycle de Krebs (matrice mitochondriale), phosphorylation oxydative (membrane mitochondriale interne).","tr":"C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + ~36–38 ATP. Üç aşama: glikoliz (sitoplazma), pirüvat oksidasyonu + Krebs döngüsü (mitokondri matrisi), oksidatif fosforilasyon (iç mitokondri zarı).","nl":"C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + ~36–38 ATP. Drie fasen: glycolyse (cytoplasma), pyruvaatoxidatie + citroenzuurcyclus (mitochondriale matrix), oxidatieve fosforylering (binnenste mitochondriale membraan).","ru":"C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + ~36–38 ATP. Три этапа: гликолиз (цитоплазма), окисление пирувата + цикл Кребса (матрикс митохондрий), окислительное фосфорилирование (внутренняя мембрана митохондрий).","zh":"C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + ~36–38 ATP。三个阶段：糖酵解（细胞质）、丙酮酸氧化+克雷布斯循环（线粒体基质）、氧化磷酸化（线粒体内膜）。","pt_BR":"C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + ~36–38 ATP. Três etapas: glicólise (citoplasma), oxidação do piruvato + ciclo de Krebs (matriz mitocondrial), fosforilação oxidativa (membrana mitocondrial interna).","pt_PT":"C₆H₁₂O₆ + 6O₂ → 6CO₂ + 6H₂O + ~36–38 ATP. Três etapas: glicólise (citoplasma), oxidação do piruvato + ciclo de Krebs (matriz mitocondrial), fosforilação oxidativa (membrana mitocondrial interna)."}},
  { id: 'dc-biology-0050', deck_id: 'deck-biology', sort_order: 50, front: "Glycolysis", back: "Anaerobic breakdown of one glucose (6C) into two pyruvate (3C) molecules in the cytoplasm. Net yield: 2 ATP and 2 NADH. Does not require oxygen; the first stage of cellular respiration." , front_translations: {"es":"Glicólise","de":"Glykolyse","fr":"Glycolyse","tr":"Glikoliz","nl":"Glycolyse","ru":"Гликолиз","zh":"糖酵解","pt_BR":"Glicólise","pt_PT":"Glicólise"}, back_translations: {"es":"Degradación anaeróbica de una glicose (6C) en de los moléculas de piruvato (3C) en el citoplasma. Rendimento líquido: 2 ATP y 2 NADH. No requiere oxígeno; a primera etapa de la respiración celular.","de":"Anaerober Abbau einer Glukose (6C) zu zwei Pyruvat-Molekülen (3C) im Zytoplasma. Nettoertrag: 2 ATP und 2 NADH. Benötigt keinen Sauerstoff; die erste Stufe der zellulären Atmung.","fr":"Dégradation anaérobie d'un glucose (6C) en deux molécules de pyruvate (3C) dans le cytoplasme. Rendement net : 2 ATP et 2 NADH. Ne nécessite pas d'oxygène ; première étape de la respiration cellulaire.","tr":"Sitoplazmada bir glikozun (6C) iki pirüvat (3C) molekülüne anaerobik yıkımı. Net verim: 2 ATP ve 2 NADH. Oksijen gerektirmez; hücresel solunumun ilk aşamasıdır.","nl":"Anaerobe afbraak van één glucose (6C) tot twee pyruvaatmoleculen (3C) in het cytoplasma. Netto opbrengst: 2 ATP en 2 NADH. Vereist geen zuurstof; de eerste fase van cellulaire ademhaling.","ru":"Анаэробное расщепление одной молекулы глюкозы (6C) до двух молекул пирувата (3C) в цитоплазме. Чистый выход: 2 ATP и 2 NADH. Не требует кислорода; первый этап клеточного дыхания.","zh":"在细胞质中将一分子葡萄糖（6C）无氧分解为两分子丙酮酸（3C）的过程。净产量：2个ATP和2个NADH。不需要氧气；是细胞呼吸的第一个阶段。","pt_BR":"Degradação anaeróbica de uma glicose (6C) em duas moléculas de piruvato (3C) no citoplasma. Rendimento líquido: 2 ATP e 2 NADH. Não requer oxigênio; a primeira etapa da respiração celular.","pt_PT":"Degradação anaeróbica de uma glicose (6C) em duas moléculas de piruvato (3C) no citoplasma. Rendimento líquido: 2 ATP e 2 NADH. Não requer oxigénio; a primeira etapa da respiração celular."}},
  { id: 'dc-biology-0051', deck_id: 'deck-biology', sort_order: 51, front: "Krebs Cycle (Citric Acid Cycle)", back: "Occurs in the mitochondrial matrix. Each pyruvate (converted to acetyl-CoA) enters the cycle, releasing CO₂ and producing NADH, FADH₂, and ATP. Generates most of the electron carriers for oxidative phosphorylation." , front_translations: {"es":"Ciclo de Krebs (Ciclo del Ácido Cítrico)","de":"Krebs-Zyklus (Zitronensäurezyklus)","fr":"Cycle de Krebs (cycle de l'acide citrique)","tr":"Krebs Döngüsü (Sitrik Asit Döngüsü)","nl":"Krebs-cyclus (citroenzuurcyclus)","ru":"Цикл Кребса (цикл лимонной кислоты)","zh":"克雷布斯循环（柠檬酸循环）","pt_BR":"Ciclo de Krebs (Ciclo do Ácido Cítrico)","pt_PT":"Ciclo de Krebs (Ciclo do Ácido Cítrico)"}, back_translations: {"es":"Ocorre en la matriz mitocondrial. Cada piruvato (convertido en acetil-CoA) entra en el ciclo, liberando CO₂ y produciendo NADH, FADH₂ y ATP. Gera a mayor parte de los transportadores de electrones para a fosforilación oxidativa.","de":"Findet in der Mitochondrienmatrix statt. Jedes Pyruvat (zu Acetyl-CoA umgewandelt) tritt in den Zyklus ein, gibt CO₂ ab und produziert NADH, FADH₂ und ATP. Liefert den Großteil der Elektronenträger für die oxidative Phosphorylierung.","fr":"Se déroule dans la matrice mitochondriale. Chaque pyruvate (converti en acétyl-CoA) entre dans le cycle, libérant du CO₂ et produisant du NADH, du FADH₂ et de l'ATP. Génère la majorité des transporteurs d'électrons pour la phosphorylation oxydative.","tr":"Mitokondri matriksinde gerçekleşir. Her pirüvat (asetil-CoA'ya dönüştürülür) döngüye girerek CO₂ salar ve NADH, FADH₂ ve ATP üretir. Oksidatif fosforilasyon için elektron taşıyıcılarının büyük bölümünü sağlar.","nl":"Vindt plaats in de mitochondriale matrix. Elk pyruvaat (omgezet naar acetyl-CoA) treedt de cyclus in, waarbij CO₂ vrijkomt en NADH, FADH₂ en ATP worden geproduceerd. Genereert de meeste elektronendragers voor oxidatieve fosforylering.","ru":"Происходит в матриксе митохондрий. Каждый пируват (превращённый в ацетил-КоА) вступает в цикл, выделяя CO₂ и производя НАДН, ФАДН₂ и АТФ. Генерирует большинство переносчиков электронов для окислительного фосфорилирования.","zh":"发生在线粒体基质中。每个丙酮酸（转化为乙酰辅酶A）进入循环，释放CO₂并产生NADH、FADH₂和ATP。为氧化磷酸化提供大部分电子载体。","pt_BR":"Ocorre na matriz mitocondrial. Cada piruvato (convertido em acetil-CoA) entra no ciclo, liberando CO₂ e produzindo NADH, FADH₂ e ATP. Gera a maior parte dos transportadores de elétrons para a fosforilação oxidativa.","pt_PT":"Ocorre na matriz mitocondrial. Cada piruvato (convertido em acetil-CoA) entra no ciclo, libertando CO₂ e produzindo NADH, FADH₂ e ATP. Gera a maior parte dos transportadores de eletrões para a fosforilação oxidativa."}},
  { id: 'dc-biology-0052', deck_id: 'deck-biology', sort_order: 52, front: "Oxidative Phosphorylation", back: "NADH and FADH₂ donate electrons to the electron transport chain (inner mitochondrial membrane), driving ATP synthase via a proton gradient. Produces ~34 ATP per glucose molecule; requires O₂." , front_translations: {"es":"Fosforilación Oxidativa","de":"Oxidative Phosphorylierung","fr":"Phosphorylation oxydative","tr":"Oksidatif Fosforilasyon","nl":"Oxidatieve fosforylering","ru":"Окислительное фосфорилирование","zh":"氧化磷酸化","pt_BR":"Fosforilação Oxidativa","pt_PT":"Fosforilação Oxidativa"}, back_translations: {"es":"El NADH y el FADH₂ doam electrones para a cadeia de transporte de electrones (membrana mitocondrial interna), acionando a ATP sintase por medio de un gradiente de protones. Produz ~34 ATP por molécula de glicose; requiere El₂.","de":"NADH und FADH₂ geben Elektronen an die Elektronentransportkette (innere Mitochondrienmembran) ab und treiben die ATP-Synthase über einen Protonengradienten an. Produziert ~34 ATP pro Glukosemolekül; benötigt O₂.","fr":"Le NADH et le FADH₂ donnent des électrons à la chaîne de transport d'électrons (membrane mitochondriale interne), entraînant l'ATP synthase via un gradient de protons. Produit ~34 ATP par molécule de glucose; nécessite O₂.","tr":"NADH ve FADH₂, elektronları elektron taşıma zincirine (iç mitokondri zarı) vererek proton gradyanı aracılığıyla ATP sentazı çalıştırır. Glikoz başına ~34 ATP üretir; O₂ gerektirir.","nl":"NADH en FADH₂ doneren elektronen aan de elektronentransportketen (binnenste mitochondriale membraan), waarbij ATP-synthase via een protongradiënt wordt aangedreven. Produceert ~34 ATP per glucosemolecuul; vereist O₂.","ru":"НАДН и ФАДН₂ передают электроны цепи переноса электронов (внутренняя мембрана митохондрий), приводя в действие АТФ-синтазу через протонный градиент. Производит ~34 АТФ на молекулу глюкозы; требует O₂.","zh":"NADH和FADH₂将电子供给电子传递链（线粒体内膜），通过质子梯度驱动ATP合酶。每分子葡萄糖产生约34个ATP；需要O₂。","pt_BR":"O NADH e o FADH₂ doam elétrons para a cadeia de transporte de elétrons (membrana mitocondrial interna), acionando a ATP sintase por meio de um gradiente de prótons. Produz ~34 ATP por molécula de glicose; requer O₂.","pt_PT":"O NADH e o FADH₂ doam eletrões para a cadeia de transporte de eletrões (membrana mitocondrial interna), acionando a ATP sintase através de um gradiente de protões. Produz ~34 ATP por molécula de glicose; requer O₂."}},
  { id: 'dc-biology-0053', deck_id: 'deck-biology', sort_order: 53, front: "Fermentation", back: "Anaerobic regeneration of NAD⁺ from NADH to sustain glycolysis when O₂ is absent. Lactic acid fermentation (muscles, bacteria): pyruvate → lactate. Alcoholic fermentation (yeast): pyruvate → ethanol + CO₂." , front_translations: {"es":"Fermentación","de":"Gärung (Fermentation)","fr":"Fermentation","tr":"Fermantasyon","nl":"Fermentatie","ru":"Брожение (ферментация)","zh":"发酵","pt_BR":"Fermentação","pt_PT":"Fermentação"}, back_translations: {"es":"Regeneración anaeróbica de NAD⁺ a partir de NADH para sustentar a glicólise en la ausencia de El₂. Fermentación lática (músculos, bacterias): piruvato → lactato. Fermentación alcoólica (leveduras): piruvato → etanol + CO₂.","de":"Anaerobe Regeneration von NAD⁺ aus NADH, um die Glykolyse aufrechtzuerhalten, wenn kein O₂ vorhanden ist. Milchsäuregärung (Muskeln, Bakterien): Pyruvat → Laktat. Alkoholische Gärung (Hefe): Pyruvat → Ethanol + CO₂.","fr":"Régénération anaérobie du NAD⁺ à partir du NADH pour maintenir la glycolyse en l'absence d'O₂. Fermentation lactique (muscles, bactéries) : pyruvate → lactate. Fermentation alcoolique (levures) : pyruvate → éthanol + CO₂.","tr":"O₂ yokken glikolizi sürdürmek için NADH'dan anaerobik olarak NAD⁺ yenilenmesi. Laktik asit fermantasyonu (kaslar, bakteriler): pirüvat → laktat. Alkollü fermantasyon (maya): pirüvat → etanol + CO₂.","nl":"Anaerobe regeneratie van NAD⁺ uit NADH om glycolyse in stand te houden wanneer er geen O₂ aanwezig is. Melkzuurfermentatie (spieren, bacteriën): pyruvaat → lactaat. Alcoholische fermentatie (gist): pyruvaat → ethanol + CO₂.","ru":"Анаэробная регенерация НАД⁺ из НАДН для поддержания гликолиза при отсутствии O₂. Молочнокислое брожение (мышцы, бактерии): пируват → лактат. Спиртовое брожение (дрожжи): пируват → этанол + CO₂.","zh":"在缺乏O₂时，从NADH无氧再生NAD⁺以维持糖酵解。乳酸发酵（肌肉、细菌）：丙酮酸→乳酸。酒精发酵（酵母）：丙酮酸→乙醇 + CO₂。","pt_BR":"Regeneração anaeróbica de NAD⁺ a partir de NADH para sustentar a glicólise na ausência de O₂. Fermentação lática (músculos, bactérias): piruvato → lactato. Fermentação alcoólica (leveduras): piruvato → etanol + CO₂.","pt_PT":"Regeneração anaeróbica de NAD⁺ a partir de NADH para sustentar a glicólise na ausência de O₂. Fermentação láctica (músculos, bactérias): piruvato → lactato. Fermentação alcoólica (leveduras): piruvato → etanol + CO₂."}},
  { id: 'dc-biology-0054', deck_id: 'deck-biology', sort_order: 54, front: "Enzyme", back: "A biological catalyst (usually a protein) that accelerates a chemical reaction by lowering its activation energy. Enzymes are highly specific (lock-and-key or induced fit model) and not consumed." , front_translations: {"es":"Enzima","de":"Enzym","fr":"Enzyme","tr":"Enzim","nl":"Enzym","ru":"Фермент","zh":"酶","pt_BR":"Enzima","pt_PT":"Enzima"}, back_translations: {"es":"Un catalizador biológico (generalmente una proteína) que acelera una reacción química al reduzir su energía de ativación. As enzimas son altamente específicas (modelo chave-fechadura o ajuste induzido) y no son consumidas.","de":"Ein biologischer Katalysator (meist ein Protein), der eine chemische Reaktion beschleunigt, indem er deren Aktivierungsenergie senkt. Enzyme sind hochspezifisch (Schlüssel-Schloss- oder Induced-Fit-Modell) und werden nicht verbraucht.","fr":"Un catalyseur biologique (généralement une protéine) qui accélère une réaction chimique en abaissant son énergie d'activation. Les enzymes sont très spécifiques (modèle clé-serrure ou ajustement induit) et ne sont pas consommés.","tr":"Aktivasyon enerjisini düşürerek kimyasal bir reaksiyonu hızlandıran biyolojik bir katalizör (genellikle bir protein). Enzimler yüksek özgüllüğe sahiptir (anahtar-kilit veya uyum sağlama modeli) ve tüketilmezler.","nl":"Een biologische katalysator (meestal een eiwit) die een chemische reactie versnelt door de activeringsenergie te verlagen. Enzymen zijn zeer specifiek (sleutel-slot- of induced-fit-model) en worden niet verbruikt.","ru":"Биологический катализатор (обычно белок), ускоряющий химическую реакцию за счёт снижения энергии активации. Ферменты высокоспецифичны (модель «ключ-замок» или индуцированного соответствия) и не расходуются.","zh":"生物催化剂（通常是蛋白质），通过降低活化能来加速化学反应。酶具有高度特异性（锁钥模型或诱导契合模型），且不被消耗。","pt_BR":"Um catalisador biológico (geralmente uma proteína) que acelera uma reação química ao reduzir sua energia de ativação. As enzimas são altamente específicas (modelo chave-fechadura ou ajuste induzido) e não são consumidas.","pt_PT":"Um catalisador biológico (geralmente uma proteína) que acelera uma reação química ao reduzir a sua energia de ativação. As enzimas são altamente específicas (modelo chave-fechadura ou ajuste induzido) e não são consumidas."}},
  { id: 'dc-biology-0055', deck_id: 'deck-biology', sort_order: 55, front: "Enzyme Active Site", back: "The specific region on an enzyme where the substrate binds. Shaped to match the substrate (specificity). After the reaction, the enzyme releases the product and is ready to catalyze again." , front_translations: {"es":"Sítio Ativo de la Enzima","de":"Aktives Zentrum des Enzyms","fr":"Site actif de l'enzyme","tr":"Enzimin Aktif Bölgesi","nl":"Actief centrum van het enzym","ru":"Активный центр фермента","zh":"酶的活性位点","pt_BR":"Sítio Ativo da Enzima","pt_PT":"Centro Ativo da Enzima"}, back_translations: {"es":"La región específica de una enzima donde el substrato se liga. Tem formato compatible con el substrato (especificidad). Após a reacción, a enzima libera el producto y está pronta para catalisar novamente.","de":"Der spezifische Bereich eines Enzyms, an dem das Substrat bindet. Geformt, um zum Substrat zu passen (Spezifität). Nach der Reaktion setzt das Enzym das Produkt frei und ist bereit, erneut zu katalysieren.","fr":"La région spécifique d'une enzyme où le substrat se lie. Façonné pour correspondre au substrat (spécificité). Après la réaction, l'enzyme libère le produit et est prête à catalyser à nouveau.","tr":"Bir enzimde substratın bağlandığı özgül bölge. Substrata uyacak şekilde şekillenmiştir (özgüllük). Reaksiyon sonrasında enzim ürünü serbest bırakır ve tekrar katalizlemeye hazır hâle gelir.","nl":"Het specifieke gebied op een enzym waar het substraat bindt. Gevormd om bij het substraat te passen (specificiteit). Na de reactie laat het enzym het product los en is het klaar om opnieuw te katalyseren.","ru":"Специфическая область фермента, где связывается субстрат. Форма соответствует субстрату (специфичность). После реакции фермент высвобождает продукт и готов снова катализировать реакцию.","zh":"酶上与底物结合的特定区域，其形状与底物相匹配（特异性）。反应后，酶释放产物并准备再次催化。","pt_BR":"A região específica de uma enzima onde o substrato se liga. Tem formato compatível com o substrato (especificidade). Após a reação, a enzima libera o produto e está pronta para catalisar novamente.","pt_PT":"A região específica de uma enzima onde o substrato se liga. Tem forma compatível com o substrato (especificidade). Após a reação, a enzima liberta o produto e está pronta para catalisar novamente."}},
  { id: 'dc-biology-0056', deck_id: 'deck-biology', sort_order: 56, front: "Competitive Inhibition", back: "An inhibitor molecule resembles the substrate and competes for the active site, reducing enzyme activity. Can be overcome by increasing substrate concentration. Does not change Vmax, but increases apparent Km." , front_translations: {"es":"Inibición Competitiva","de":"Kompetitive Hemmung","fr":"Inhibition compétitive","tr":"Rekabetçi İnhibisyon","nl":"Competitieve remming","ru":"Конкурентное ингибирование","zh":"竞争性抑制","pt_BR":"Inibição Competitiva","pt_PT":"Inibição Competitiva"}, back_translations: {"es":"Una molécula inibidora se assemelha al substrato y compete por el sítio ativo, reduciendo a atividad enzimática. Pode ser superada aumentando a concentración del substrato. No altera el Vmax, pero aumenta el Km aparente.","de":"Ein Hemmstoffmolekül ähnelt dem Substrat und konkurriert um das aktive Zentrum, wodurch die Enzymaktivität verringert wird. Kann durch Erhöhung der Substratkonzentration überwunden werden. Ändert nicht Vmax, erhöht aber den scheinbaren Km.","fr":"Une molécule inhibitrice ressemble au substrat et entre en compétition pour le site actif, réduisant l'activité enzymatique. Peut être surmontée en augmentant la concentration du substrat. Ne modifie pas Vmax mais augmente le Km apparent.","tr":"Bir inhibitör molekülü substrata benzer ve aktif bölge için rekabet ederek enzim aktivitesini azaltır. Substrat konsantrasyonu artırılarak aşılabilir. Vmax'ı değiştirmez, ancak görünür Km'yi artırır.","nl":"Een remmermolecuul lijkt op het substraat en concurreert om het actieve centrum, waardoor de enzymactiviteit afneemt. Kan worden overwonnen door de substraatconcentratie te verhogen. Verandert Vmax niet, maar verhoogt de schijnbare Km.","ru":"Молекула ингибитора напоминает субстрат и конкурирует за активный центр, снижая активность фермента. Может быть преодолено увеличением концентрации субстрата. Не изменяет Vmax, но увеличивает видимый Km.","zh":"抑制剂分子类似底物，竞争活性位点，降低酶活性。可通过增加底物浓度来克服。不改变Vmax，但增加表观Km。","pt_BR":"Uma molécula inibidora se assemelha ao substrato e compete pelo sítio ativo, reduzindo a atividade enzimática. Pode ser superada aumentando a concentração do substrato. Não altera o Vmax, mas aumenta o Km aparente.","pt_PT":"Uma molécula inibidora assemelha-se ao substrato e compete pelo centro ativo, reduzindo a atividade enzimática. Pode ser superada aumentando a concentração do substrato. Não altera o Vmax, mas aumenta o Km aparente."}},
  { id: 'dc-biology-0057', deck_id: 'deck-biology', sort_order: 57, front: "Allosteric Regulation", back: "Regulation of enzyme activity by molecules (activators or inhibitors) binding to a site other than the active site (allosteric site), causing conformational changes that alter enzyme activity." , front_translations: {"es":"Regulación Alostérica","de":"Allosterische Regulation","fr":"Régulation allostérique","tr":"Alosterik Düzenleme","nl":"Allosterische regulatie","ru":"Аллостерическая регуляция","zh":"别构调节","pt_BR":"Regulação Alostérica","pt_PT":"Regulação Alostérica"}, back_translations: {"es":"Regulación de la atividad enzimática por moléculas (ativadores o inibidores) que se ligam a un sítio diferente del sítio ativo (sítio alostérico), causando cambios conformacionais que alteran a atividad de la enzima.","de":"Regulation der Enzymaktivität durch Moleküle (Aktivatoren oder Inhibitoren), die an eine andere Stelle als das aktive Zentrum (allosterische Stelle) binden und Konformationsänderungen verursachen, die die Enzymaktivität verändern.","fr":"Régulation de l'activité enzymatique par des molécules (activateurs ou inhibiteurs) se liant à un site autre que le site actif (site allostérique), provoquant des changements conformationnels qui modifient l'activité enzymatique.","tr":"Aktif bölge dışındaki bir bölgeye (alosterik bölge) bağlanan moleküllerin (aktivatörler veya inhibitörler) enzim aktivitesini konformasyonel değişiklikler aracılığıyla değiştirmesi yoluyla gerçekleştirilen enzim aktivitesi düzenlemesi.","nl":"Regulatie van enzymactiviteit door moleculen (activatoren of remmers) die binden aan een andere locatie dan het actieve centrum (allosterische locatie), wat conformatieveranderingen veroorzaakt die de enzymactiviteit veranderen.","ru":"Регуляция активности фермента молекулами (активаторами или ингибиторами), связывающимися с участком, отличным от активного центра (аллостерическим участком), вызывая конформационные изменения, которые меняют активность фермента.","zh":"通过与活性位点以外的位点（别构位点）结合的分子（激活剂或抑制剂）调节酶活性，引起构象变化从而改变酶活性。","pt_BR":"Regulação da atividade enzimática por moléculas (ativadores ou inibidores) que se ligam a um sítio diferente do sítio ativo (sítio alostérico), causando mudanças conformacionais que alteram a atividade da enzima.","pt_PT":"Regulação da atividade enzimática por moléculas (ativadores ou inibidores) que se ligam a um local diferente do centro ativo (local alostérico), causando alterações conformacionais que modificam a atividade da enzima."}},
  { id: 'dc-biology-0058', deck_id: 'deck-biology', sort_order: 58, front: "ATP (Adenosine Triphosphate)", back: "The primary energy currency of the cell. Energy is released by hydrolysis of the terminal phosphate bond (ATP → ADP + Pᵢ, ~30.5 kJ/mol). Produced by cellular respiration and photosynthesis." , front_translations: {"es":"ATP (Adenosina Trifosfato)","de":"ATP (Adenosintriphosphat)","fr":"ATP (Adénosine triphosphate)","tr":"ATP (Adenozin Trifosfat)","nl":"ATP (Adenosinetrifosfaat)","ru":"АТФ (аденозинтрифосфат)","zh":"ATP（腺苷三磷酸）","pt_BR":"ATP (Adenosina Trifosfato)","pt_PT":"ATP (Adenosina Trifosfato)"}, back_translations: {"es":"La principal moeda energética de la célula. La energía es liberada por la hidrólise de la enlace fosfato terminal (ATP → ADP + Pᵢ, ~30,5 kJ/mol). Produzida por la respiración celular y por la fotossíntese.","de":"Die primäre Energiewährung der Zelle. Energie wird durch Hydrolyse der terminalen Phosphatbindung freigesetzt (ATP → ADP + Pᵢ, ~30,5 kJ/mol). Wird durch Zellatmung und Photosynthese produziert.","fr":"La principale monnaie énergétique de la cellule. L'énergie est libérée par hydrolyse de la liaison phosphate terminale (ATP → ADP + Pᵢ, ~30,5 kJ/mol). Produit par la respiration cellulaire et la photosynthèse.","tr":"Hücrenin birincil enerji para birimi. Enerji, terminal fosfat bağının hidrolizi ile açığa çıkar (ATP → ADP + Pᵢ, ~30,5 kJ/mol). Hücresel solunum ve fotosentez ile üretilir.","nl":"De primaire energievaluta van de cel. Energie wordt vrijgegeven door hydrolyse van de terminale fosfaatbinding (ATP → ADP + Pᵢ, ~30,5 kJ/mol). Geproduceerd door cellulaire ademhaling en fotosynthese.","ru":"Основная энергетическая валюта клетки. Энергия выделяется при гидролизе концевой фосфатной связи (АТФ → АДФ + Фн, ~30,5 кДж/моль). Производится клеточным дыханием и фотосинтезом.","zh":"细胞的主要能量货币。能量通过末端磷酸键水解释放（ATP → ADP + Pi，约30.5 kJ/mol）。由细胞呼吸和光合作用产生。","pt_BR":"A principal moeda energética da célula. A energia é liberada pela hidrólise da ligação fosfato terminal (ATP → ADP + Pᵢ, ~30,5 kJ/mol). Produzida pela respiração celular e pela fotossíntese.","pt_PT":"A principal moeda energética da célula. A energia é libertada pela hidrólise da ligação fosfato terminal (ATP → ADP + Pᵢ, ~30,5 kJ/mol). Produzida pela respiração celular e pela fotossíntese."}},
  { id: 'dc-biology-0059', deck_id: 'deck-biology', sort_order: 59, front: "Homeostasis", back: "The maintenance of a stable internal environment despite external changes. Achieved through negative feedback loops (most common) that counteract deviations, and positive feedback loops that amplify signals." , front_translations: {"es":"Homeostase","de":"Homöostase","fr":"Homéostasie","tr":"Homeostasis","nl":"Homeostase","ru":"Гомеостаз","zh":"稳态","pt_BR":"Homeostase","pt_PT":"Homeostasia"}, back_translations: {"es":"La manutención de un ambiente interno estable apesar de las cambios externas. Alcançada por alças de retroalimentación negativa (más comuns) que combatem los desvios, y alças de retroalimentación positiva que amplificam los señales.","de":"Die Aufrechterhaltung eines stabilen inneren Milieus trotz äußerer Veränderungen. Erreicht durch negative Rückkopplungsschleifen (am häufigsten), die Abweichungen entgegenwirken, und positive Rückkopplungsschleifen, die Signale verstärken.","fr":"Le maintien d'un environnement interne stable malgré les changements externes. Réalisé par des boucles de rétroaction négative (les plus courantes) qui contrecarrent les écarts, et des boucles de rétroaction positive qui amplifient les signaux.","tr":"Dış değişikliklere rağmen kararlı bir iç ortamın sürdürülmesi. Sapmaları dengeleyen negatif geri bildirim döngüleri (en yaygın) ve sinyalleri güçlendiren pozitif geri bildirim döngüleri aracılığıyla sağlanır.","nl":"Het handhaven van een stabiele interne omgeving ondanks externe veranderingen. Bereikt via negatieve terugkoppelingslussen (meest voorkomend) die afwijkingen tegengaan, en positieve terugkoppelingslussen die signalen versterken.","ru":"Поддержание стабильной внутренней среды несмотря на внешние изменения. Достигается посредством петель отрицательной обратной связи (наиболее распространённых), противодействующих отклонениям, и петель положительной обратной связи, усиливающих сигналы.","zh":"尽管外部环境发生变化，仍维持稳定的内部环境。通过负反馈回路（最常见，抵消偏差）和正反馈回路（放大信号）实现。","pt_BR":"A manutenção de um ambiente interno estável apesar das mudanças externas. Alcançada por alças de retroalimentação negativa (mais comuns) que combatem os desvios, e alças de retroalimentação positiva que amplificam os sinais.","pt_PT":"A manutenção de um ambiente interno estável apesar das alterações externas. Conseguida através de ciclos de retroação negativa (mais comuns) que contrariam os desvios, e ciclos de retroação positiva que amplificam os sinais."}},
  { id: 'dc-biology-0060', deck_id: 'deck-biology', sort_order: 60, front: "Negative Feedback", back: "A control mechanism where the response to a stimulus reduces or reverses the original stimulus, maintaining a set point. Examples: body temperature regulation, blood glucose control." , front_translations: {"es":"Retroalimentación Negativa","de":"Negative Rückkopplung","fr":"Rétroaction négative","tr":"Negatif Geri Bildirim","nl":"Negatieve terugkoppeling","ru":"Отрицательная обратная связь","zh":"负反馈","pt_BR":"Retroalimentação Negativa","pt_PT":"Retroação Negativa"}, back_translations: {"es":"Un mecanismo de controle en que a respuesta a un estímulo reduce o reverte el estímulo original, manteniendo un punto de ajuste. Exemplos: regulación de la temperatura corporal, controle de la glicose en el sangre.","de":"Ein Kontrollmechanismus, bei dem die Reaktion auf einen Stimulus den ursprünglichen Stimulus reduziert oder umkehrt und so einen Sollwert aufrechterhält. Beispiele: Körpertemperaturregulation, Blutzuckerkontrolle.","fr":"Un mécanisme de contrôle où la réponse à un stimulus réduit ou inverse le stimulus original, maintenant un point de consigne. Exemples : régulation de la température corporelle, contrôle de la glycémie.","tr":"Bir uyarana verilen yanıtın özgün uyaranı azaltarak veya tersine çevirerek bir ayar noktasını koruduğu kontrol mekanizması. Örnekler: vücut sıcaklığının düzenlenmesi, kan şekeri kontrolü.","nl":"Een controlemechanisme waarbij de reactie op een prikkel de oorspronkelijke prikkel vermindert of omkeert, waardoor een setpoint wordt gehandhaafd. Voorbeelden: lichaamstemperatuurregulatie, bloedglucoseregulatie.","ru":"Механизм управления, при котором реакция на стимул уменьшает или отменяет исходный стимул, поддерживая заданное значение. Примеры: регуляция температуры тела, контроль уровня глюкозы в крови.","zh":"一种控制机制，对刺激的反应会减弱或逆转原始刺激，从而维持设定点。例如：体温调节、血糖控制。","pt_BR":"Um mecanismo de controle em que a resposta a um estímulo reduz ou reverte o estímulo original, mantendo um ponto de ajuste. Exemplos: regulação da temperatura corporal, controle da glicose no sangue.","pt_PT":"Um mecanismo de controlo em que a resposta a um estímulo reduz ou reverte o estímulo original, mantendo um valor de referência. Exemplos: regulação da temperatura corporal, controlo da glicose no sangue."}},
  { id: 'dc-biology-0061', deck_id: 'deck-biology', sort_order: 61, front: "Positive Feedback", back: "A control mechanism where the response amplifies the original stimulus. Less common; used in events requiring completion (e.g., childbirth contractions, blood clotting, ovulation surge)." , front_translations: {"es":"Retroalimentación Positiva","de":"Positive Rückkopplung","fr":"Rétroaction positive","tr":"Pozitif Geri Bildirim","nl":"Positieve terugkoppeling","ru":"Положительная обратная связь","zh":"正反馈","pt_BR":"Retroalimentação Positiva","pt_PT":"Retroação Positiva"}, back_translations: {"es":"Un mecanismo de controle en que a respuesta amplifica el estímulo original. Menos comum; utilizado en eventos que requieren conclusão (ex.: contraciones del parto, coagulación sanguínea, pico de ovulación).","de":"Ein Kontrollmechanismus, bei dem die Reaktion den ursprünglichen Stimulus verstärkt. Seltener; wird bei Ereignissen eingesetzt, die abgeschlossen werden müssen (z. B. Geburtswehen, Blutgerinnung, Ovulationsanstieg).","fr":"Un mécanisme de contrôle où la réponse amplifie le stimulus original. Moins courant ; utilisé dans les événements nécessitant une completion (ex. : contractions lors de l'accouchement, coagulation sanguine, pic d'ovulation).","tr":"Yanıtın özgün uyaranı güçlendirdiği kontrol mekanizması. Daha az yaygındır; tamamlanması gereken olaylarda kullanılır (ör. doğum kasılmaları, kan pıhtılaşması, ovülasyon artışı).","nl":"Een controlemechanisme waarbij de reactie het oorspronkelijke signaal versterkt. Minder gebruikelijk; gebruikt bij gebeurtenissen die voltooid moeten worden (bijv. weeën bij bevalling, bloedstolling, ovulatiegolf).","ru":"Механизм управления, при котором реакция усиливает исходный стимул. Менее распространён; используется в процессах, требующих завершения (например, схватки при родах, свёртывание крови, овуляционный пик).","zh":"一种控制机制，反应会放大原始刺激。较少见；用于需要完成的事件（如分娩宫缩、血液凝固、排卵峰值）。","pt_BR":"Um mecanismo de controle em que a resposta amplifica o estímulo original. Menos comum; utilizado em eventos que requerem conclusão (ex.: contrações do parto, coagulação sanguínea, pico de ovulação).","pt_PT":"Um mecanismo de controlo em que a resposta amplifica o estímulo original. Menos comum; utilizado em eventos que requerem conclusão (ex.: contrações do parto, coagulação sanguínea, pico de ovulação)."}},
  { id: 'dc-biology-0062', deck_id: 'deck-biology', sort_order: 62, front: "Nervous System: Neuron Structure", back: "A nerve cell with dendrites (receive signals), cell body (soma), axon (transmits signals), and axon terminals. Signals travel as action potentials along the axon to synapses." , front_translations: {"es":"Sistema Nervoso: Estrutura del Neuronio","de":"Nervensystem: Neuronenstruktur","fr":"Système nerveux : structure du neurone","tr":"Sinir Sistemi: Nöron Yapısı","nl":"Zenuwstelsel: neuronenstructuur","ru":"Нервная система: строение нейрона","zh":"神经系统：神经元结构","pt_BR":"Sistema Nervoso: Estrutura do Neurônio","pt_PT":"Sistema Nervoso: Estrutura do Neurónio"}, back_translations: {"es":"Una célula nervosa con dendritos (reciben señales), cuerpo celular (suma), axonio (transmite señales) y terminais axonicos. Los señales viajam como potenciais de acción a lo ancho del axonio hasta las sinapses.","de":"Eine Nervenzelle mit Dendriten (empfangen Signale), Zellkörper (Soma), Axon (überträgt Signale) und Axonterminalen. Signale wandern als Aktionspotenziale entlang des Axons zu Synapsen.","fr":"Une cellule nerveuse avec des dendrites (reçoivent les signaux), un corps cellulaire (soma), un axone (transmet les signaux) et des terminaisons axonales. Les signaux se déplacent comme des potentiels d'action le long de l'axone vers les synapses.","tr":"Dendritler (sinyal alır), hücre gövdesi (soma), akson (sinyal iletir) ve akson terminallerinden oluşan sinir hücresi. Sinyaller, akson boyunca sinaps bölgelerine doğru aksiyon potansiyelleri şeklinde ilerler.","nl":"Een zenuwcel met dendrieten (ontvangen signalen), cellichaam (soma), axon (stuurt signalen door) en axonterminalen. Signalen reizen als actiepotentialen langs het axon naar synapsen.","ru":"Нервная клетка с дендритами (принимают сигналы), телом клетки (сомой), аксоном (передаёт сигналы) и аксонными терминалями. Сигналы распространяются в виде потенциалов действия вдоль аксона к синапсам.","zh":"神经细胞，由树突（接收信号）、细胞体（胞体）、轴突（传递信号）和轴突末梢组成。信号以动作电位的形式沿轴突传向突触。","pt_BR":"Uma célula nervosa com dendritos (recebem sinais), corpo celular (soma), axônio (transmite sinais) e terminais axônicos. Os sinais viajam como potenciais de ação ao longo do axônio até as sinapses.","pt_PT":"Uma célula nervosa com dendrites (recebem sinais), corpo celular (soma), axónio (transmite sinais) e terminais axónicos. Os sinais viajam como potenciais de ação ao longo do axónio até às sinapses."}},
  { id: 'dc-biology-0063', deck_id: 'deck-biology', sort_order: 63, front: "Action Potential", back: "A rapid electrical signal along a neuron's axon due to sequential opening of Na⁺ and K⁺ voltage-gated channels. Threshold: ~-55 mV. All-or-nothing response; propagates without weakening." , front_translations: {"es":"Potencial de Ación","de":"Aktionspotenzial","fr":"Potentiel d'action","tr":"Aksiyon Potansiyeli","nl":"Actiepotentiaal","ru":"Потенциал действия","zh":"动作电位","pt_BR":"Potencial de Ação","pt_PT":"Potencial de Ação"}, back_translations: {"es":"Un señal eléctrico rápido a lo ancho del axonio de un neurona debido a la abertura sequencial de canais de Na⁺ y K⁺ voltaje-dependentes. Limiar: ~-55 mV. Resposta tudo-o-nada; propaga-se sin enfraquecer.","de":"Ein schnelles elektrisches Signal entlang des Axons eines Neurons durch sequenzielle Öffnung spannungsgesteuerter Na⁺- und K⁺-Kanäle. Schwellenwert: ~-55 mV. Alles-oder-Nichts-Reaktion; breitet sich ohne Abschwächung aus.","fr":"Un signal électrique rapide le long de l'axone d'un neurone dû à l'ouverture séquentielle de canaux Na⁺ et K⁺ voltage-dépendants. Seuil : ~-55 mV. Réponse tout-ou-rien ; se propage sans s'affaiblir.","tr":"Voltaj kapılı Na⁺ ve K⁺ kanallarının sıralı açılmasıyla oluşan, nöronun aksonu boyunca ilerleyen hızlı bir elektriksel sinyal. Eşik: ~-55 mV. Hep ya da hiç tepkisi; zayıflamadan yayılır.","nl":"Een snel elektrisch signaal langs het axon van een neuron door sequentieel openen van spanningsgestuurde Na⁺- en K⁺-kanalen. Drempelwaarde: ~-55 mV. Alles-of-niets-reactie; verspreidt zich zonder verzwakking.","ru":"Быстрый электрический сигнал вдоль аксона нейрона, обусловленный последовательным открытием потенциалзависимых каналов Na⁺ и K⁺. Порог: ~-55 мВ. Реакция «всё или ничего»; распространяется без затухания.","zh":"由电压门控Na⁺和K⁺通道依次开放引起的、沿神经元轴突传播的快速电信号。阈值约为-55 mV。全或无反应；不衰减地传播。","pt_BR":"Um sinal elétrico rápido ao longo do axônio de um neurônio devido à abertura sequencial de canais de Na⁺ e K⁺ voltagem-dependentes. Limiar: ~-55 mV. Resposta tudo-ou-nada; propaga-se sem enfraquecer.","pt_PT":"Um sinal elétrico rápido ao longo do axónio de um neurónio devido à abertura sequencial de canais de Na⁺ e K⁺ dependentes de voltagem. Limiar: ~-55 mV. Resposta tudo-ou-nada; propaga-se sem se enfraquecer."}},
  { id: 'dc-biology-0064', deck_id: 'deck-biology', sort_order: 64, front: "Synapse", back: "The junction between two neurons or a neuron and an effector. Chemical synapse: neurotransmitter released from presynaptic terminal crosses the synaptic cleft and binds receptors on the postsynaptic cell." , front_translations: {"es":"Sinapse","de":"Synapse","fr":"Synapse","tr":"Sinaps","nl":"Synaps","ru":"Синапс","zh":"突触","pt_BR":"Sinapse","pt_PT":"Sinapse"}, back_translations: {"es":"La junción entre de los neuronas o entre un neurona y un efetor. Sinapse química: el neurotransmissor liberado por el terminal pré-sináptico atravessa a fenda sináptica y se liga a receptores en la célula pós-sináptica.","de":"Die Verbindung zwischen zwei Neuronen oder einem Neuron und einem Effektor. Chemische Synapse: Neurotransmitter werden aus dem präsynaptischen Terminal freigesetzt, überqueren den synaptischen Spalt und binden Rezeptoren auf der postsynaptischen Zelle.","fr":"La jonction entre deux neurones ou un neurone et un effecteur. Synapse chimique : le neurotransmetteur libéré de la terminaison présynaptique traverse la fente synaptique et se lie aux récepteurs de la cellule postsynaptique.","tr":"İki nöron veya bir nöron ile efektör arasındaki bağlantı noktası. Kimyasal sinaps: presinaptik terminalden salınan nörotransmitter, sinaptik aralığı geçerek postsinaptik hücredeki reseptörlere bağlanır.","nl":"De verbinding tussen twee neuronen of een neuron en een effector. Chemische synaps: neurotransmitter vrijgegeven uit de presynaptische terminal steekt de synaptische spleet over en bindt receptoren op de postsynaptische cel.","ru":"Соединение между двумя нейронами или нейроном и эффектором. Химический синапс: нейромедиатор высвобождается из пресинаптического терминала, пересекает синаптическую щель и связывается с рецепторами постсинаптической клетки.","zh":"两个神经元之间或神经元与效应器之间的连接处。化学突触：神经递质从突触前末梢释放，穿过突触间隙，与突触后细胞上的受体结合。","pt_BR":"A junção entre dois neurônios ou entre um neurônio e um efetor. Sinapse química: o neurotransmissor liberado pelo terminal pré-sináptico atravessa a fenda sináptica e se liga a receptores na célula pós-sináptica.","pt_PT":"A junção entre dois neurónios ou entre um neurónio e um efetor. Sinapse química: o neurotransmissor libertado pelo terminal pré-sináptico atravessa a fenda sináptica e liga-se a receptores na célula pós-sináptica."}},
  { id: 'dc-biology-0065', deck_id: 'deck-biology', sort_order: 65, front: "Neurotransmitters", back: "Chemical messengers released at synapses. Examples: acetylcholine (muscle, memory), dopamine (reward), serotonin (mood), GABA (inhibitory), glutamate (excitatory), norepinephrine (stress response)." , front_translations: {"es":"Neurotransmissores","de":"Neurotransmitter","fr":"Neurotransmetteurs","tr":"Nörotransmiterler","nl":"Neurotransmitters","ru":"Нейромедиаторы","zh":"神经递质","pt_BR":"Neurotransmissores","pt_PT":"Neurotransmissores"}, back_translations: {"es":"Mensageros químicos liberados en las sinapses. Exemplos: acetilcolina (músculos, memoria), dopamina (recompensa), serotonina (humor), GABA (inibitório), glutamato (excitatório), norepinefrina (respuesta al estresse).","de":"Chemische Botenstoffe, die an Synapsen freigesetzt werden. Beispiele: Acetylcholin (Muskeln, Gedächtnis), Dopamin (Belohnung), Serotonin (Stimmung), GABA (hemmend), Glutamat (erregend), Noradrenalin (Stressreaktion).","fr":"Messagers chimiques libérés aux synapses. Exemples : acétylcholine (muscles, mémoire), dopamine (récompense), sérotonine (humeur), GABA (inhibiteur), glutamate (excitateur), norépinéphrine (réponse au stress).","tr":"Sinapslarda salınan kimyasal haberciler. Örnekler: asetilkolin (kas, bellek), dopamin (ödül), serotonin (ruh hali), GABA (inhibe edici), glutamat (uyarıcı), norepinefrin (stres yanıtı).","nl":"Chemische boodschappers die vrijkomen bij synapsen. Voorbeelden: acetylcholine (spieren, geheugen), dopamine (beloning), serotonine (stemming), GABA (remmend), glutamaat (opwekkend), norepinefrine (stressrespons).","ru":"Химические мессенджеры, высвобождаемые в синапсах. Примеры: ацетилхолин (мышцы, память), дофамин (вознаграждение), серотонин (настроение), ГАМК (тормозной), глутамат (возбуждающий), норэпинефрин (реакция на стресс).","zh":"在突触处释放的化学信使。例如：乙酰胆碱（肌肉、记忆）、多巴胺（奖励）、血清素（情绪）、GABA（抑制性）、谷氨酸（兴奋性）、去甲肾上腺素（应激反应）。","pt_BR":"Mensageiros químicos liberados nas sinapses. Exemplos: acetilcolina (músculos, memória), dopamina (recompensa), serotonina (humor), GABA (inibitório), glutamato (excitatório), norepinefrina (resposta ao estresse).","pt_PT":"Mensageiros químicos libertados nas sinapses. Exemplos: acetilcolina (músculos, memória), dopamina (recompensa), serotonina (humor), GABA (inibitório), glutamato (excitatório), noradrenalina (resposta ao stress)."}},
  { id: 'dc-biology-0066', deck_id: 'deck-biology', sort_order: 66, front: "Endocrine System", back: "Regulates body functions through hormones secreted by glands into the bloodstream. Acts more slowly than the nervous system but has longer-lasting effects. Major glands: pituitary, thyroid, adrenal, pancreas, gonads." , front_translations: {"es":"Sistema Endócrino","de":"Endokrines System","fr":"Système endocrinien","tr":"Endokrin Sistem","nl":"Endocrien systeem","ru":"Эндокринная система","zh":"内分泌系统","pt_BR":"Sistema Endócrino","pt_PT":"Sistema Endócrino"}, back_translations: {"es":"Regula las funciones corporais por medio de hormonas secretados por las glándulas en la corrente sanguínea. Age más lentamente que el sistema nervioso, pero tiene efectos más duradouros. Principais glándulas: hipófise, tireoide, adrenal, pancreas, gonadas.","de":"Reguliert Körperfunktionen durch Hormone, die von Drüsen in den Blutkreislauf abgegeben werden. Wirkt langsamer als das Nervensystem, hat aber länger anhaltende Wirkungen. Wichtige Drüsen: Hypophyse, Schilddrüse, Nebenniere, Pankreas, Gonaden.","fr":"Régule les fonctions corporelles par des hormones sécrétées par des glandes dans la circulation sanguine. Agit plus lentement que le système nerveux mais a des effets plus durables. Glandes principales : hypophyse, thyroïde, surrénale, pancréas, gonades.","tr":"Bezlerden kana salgılanan hormonlar aracılığıyla vücut fonksiyonlarını düzenler. Sinir sisteminden daha yavaş çalışır ancak daha uzun süreli etkilere sahiptir. Başlıca bezler: hipofiz, tiroit, adrenal, pankreas, gonadlar.","nl":"Reguleert lichaamsfuncties via hormonen die door klieren in de bloedbaan worden uitgescheiden. Werkt langzamer dan het zenuwstelsel maar heeft langduriger effecten. Belangrijke klieren: hypofyse, schildklier, bijnier, alvleesklier, gonaden.","ru":"Регулирует функции организма с помощью гормонов, выделяемых железами в кровоток. Действует медленнее нервной системы, но оказывает более длительные эффекты. Основные железы: гипофиз, щитовидная железа, надпочечники, поджелудочная железа, гонады.","zh":"通过腺体分泌到血液中的激素调节身体功能。比神经系统作用慢，但效果持续时间更长。主要腺体：垂体、甲状腺、肾上腺、胰腺、性腺。","pt_BR":"Regula as funções corporais por meio de hormônios secretados pelas glândulas na corrente sanguínea. Age mais lentamente que o sistema nervoso, mas tem efeitos mais duradouros. Principais glândulas: hipófise, tireoide, adrenal, pâncreas, gônadas.","pt_PT":"Regula as funções corporais através de hormonas secretadas pelas glândulas para a corrente sanguínea. Age mais lentamente que o sistema nervoso, mas tem efeitos mais duradouros. Principais glândulas: hipófise, tiróide, suprarrenal, pâncreas, gónadas."}},
  { id: 'dc-biology-0067', deck_id: 'deck-biology', sort_order: 67, front: "Hormone Types", back: "Steroid hormones (lipid-soluble, derived from cholesterol; bind intracellular receptors, affect gene expression). Peptide/protein hormones (water-soluble; bind membrane receptors and use second messengers)." , front_translations: {"es":"Tipos de Hormonios","de":"Hormontypen","fr":"Types d'hormones","tr":"Hormon Türleri","nl":"Hormoontypen","ru":"Типы гормонов","zh":"激素类型","pt_BR":"Tipos de Hormônios","pt_PT":"Tipos de Hormonas"}, back_translations: {"es":"Hormonios esteroides (lipossolúveis, derivados del colesterol; ligam-se a receptores intracelulares, afectan a expresión genica). Hormonios peptídicos/proteicos (hidrossolúveis; ligam-se a receptores de membrana y usam segundos mensageros).","de":"Steroidhormone (lipidlöslich, aus Cholesterin; binden intrazelluläre Rezeptoren, beeinflussen Genexpression). Peptid-/Proteinhormone (wasserlöslich; binden Membranrezeptoren und nutzen second messenger).","fr":"Hormones stéroïdiennes (liposolubles, dérivées du cholestérol ; se lient aux récepteurs intracellulaires, affectent l'expression génique). Hormones peptidiques/protéiques (hydrosolubles ; se lient aux récepteurs membranaires et utilisent des seconds messagers).","tr":"Steroid hormonlar (lipid çözünür, kolesterolden türetilir; hücre içi reseptörlere bağlanır, gen ekspresyonunu etkiler). Peptit/protein hormonlar (suda çözünür; membran reseptörlerine bağlanır ve ikincil habercileri kullanır).","nl":"Steroïdhormonen (lipofiel, afgeleid van cholesterol; binden aan intracellulaire receptoren, beïnvloeden genexpressie). Peptide/eiwithormonen (wateroplosbaar; binden aan membraanreceptoren en gebruiken tweede boodschappers).","ru":"Стероидные гормоны (жирорастворимые, производные холестерина; связываются с внутриклеточными рецепторами, влияют на экспрессию генов). Пептидные/белковые гормоны (водорастворимые; связываются с мембранными рецепторами и используют вторичные мессенджеры).","zh":"类固醇激素（脂溶性，源自胆固醇；与胞内受体结合，影响基因表达）。肽/蛋白质激素（水溶性；与膜受体结合，使用第二信使）。","pt_BR":"Hormônios esteroides (lipossolúveis, derivados do colesterol; ligam-se a receptores intracelulares, afetam a expressão gênica). Hormônios peptídicos/proteicos (hidrossolúveis; ligam-se a receptores de membrana e usam segundos mensageiros).","pt_PT":"Hormonas esteroides (lipossolúveis, derivadas do colesterol; ligam-se a recetores intracelulares, afetam a expressão génica). Hormonas peptídicas/proteicas (hidrossolúveis; ligam-se a recetores de membrana e utilizam segundos mensageiros)."}},
  { id: 'dc-biology-0068', deck_id: 'deck-biology', sort_order: 68, front: "Blood Glucose Regulation", back: "Insulin (from beta cells) lowers blood glucose by promoting cellular glucose uptake and glycogen synthesis. Glucagon (from alpha cells) raises blood glucose by stimulating glycogen breakdown and gluconeogenesis." , front_translations: {"es":"Regulación de la Glicose Sanguínea","de":"Blutzuckerregulation","fr":"Régulation de la glycémie","tr":"Kan Şekeri Düzenlenmesi","nl":"Bloedglucoseregulatie","ru":"Регуляция уровня глюкозы в крови","zh":"血糖调节","pt_BR":"Regulação da Glicose Sanguínea","pt_PT":"Regulação da Glicose no Sangue"}, back_translations: {"es":"La insulina (de las células beta) reduce a glicose en el sangre promovendo a captación celular de glicose y a síntese de glicogenio. El glucagon (de las células alfa) eleva a glicose en el sangre estimulando a degradación del glicogenio y a gliconeogenese.","de":"Insulin (aus Betazellen) senkt den Blutzucker, indem es die zelluläre Glukoseaufnahme und Glykogensynthese fördert. Glukagon (aus Alphazellen) erhöht den Blutzucker, indem es den Glykogenabbau und die Glukoneogenese stimuliert.","fr":"L'insuline (des cellules bêta) abaisse la glycémie en favorisant l'absorption cellulaire du glucose et la synthèse du glycogène. Le glucagon (des cellules alpha) élève la glycémie en stimulant la dégradation du glycogène et la gluconéogenèse.","tr":"İnsülin (beta hücrelerinden), hücresel glukoz alımını ve glikojen sentezini teşvik ederek kan şekerini düşürür. Glukagon (alfa hücrelerinden), glikojen yıkımını ve glukoneogenezi uyararak kan şekerini yükseltir.","nl":"Insuline (van bètacellen) verlaagt de bloedglucose door cellulaire glucoseopname en glycogeensynthese te bevorderen. Glucagon (van alfacellen) verhoogt de bloedglucose door glycogeenafbraak en gluconeogenese te stimuleren.","ru":"Инсулин (из бета-клеток) снижает уровень глюкозы в крови, способствуя клеточному поглощению глюкозы и синтезу гликогена. Глюкагон (из альфа-клеток) повышает уровень глюкозы, стимулируя распад гликогена и глюконеогенез.","zh":"胰岛素（来自β细胞）通过促进细胞摄取葡萄糖和糖原合成来降低血糖。胰高血糖素（来自α细胞）通过刺激糖原分解和糖异生来升高血糖。","pt_BR":"A insulina (das células beta) reduz a glicose no sangue promovendo a captação celular de glicose e a síntese de glicogênio. O glucagon (das células alfa) eleva a glicose no sangue estimulando a degradação do glicogênio e a gliconeogênese.","pt_PT":"A insulina (das células beta) reduz a glicose no sangue promovendo a captação celular de glicose e a síntese de glicogénio. O glucagon (das células alfa) eleva a glicose no sangue estimulando a degradação do glicogénio e a gliconeogénese."}},
  { id: 'dc-biology-0069', deck_id: 'deck-biology', sort_order: 69, front: "Immune System: Innate Immunity", back: "The non-specific first line of defense. Includes physical barriers (skin, mucus), phagocytes (neutrophils, macrophages), NK cells, complement proteins, and inflammation. Responds immediately without prior exposure." , front_translations: {"es":"Sistema Imunológico: Imunidad Inata","de":"Immunsystem: Angeborene Immunität","fr":"Système immunitaire : immunité innée","tr":"Bağışıklık Sistemi: Doğal Bağışıklık","nl":"Immuunsysteem: aangeboren immuniteit","ru":"Иммунная система: врождённый иммунитет","zh":"免疫系统：固有免疫","pt_BR":"Sistema Imunológico: Imunidade Inata","pt_PT":"Sistema Imunitário: Imunidade Inata"}, back_translations: {"es":"La primera línea de defesa no específica. Inclui barreras físicas (piel, muco), fagócitos (neutrófilos, macrófagos), células NK, proteínas del complemento y inflamación. Responde imediatamente sin exposición prévia.","de":"Die erste unspezifische Verteidigungslinie. Umfasst physische Barrieren (Haut, Schleim), Phagozyten (Neutrophile, Makrophagen), NK-Zellen, Komplementproteine und Entzündung. Reagiert sofort ohne vorherige Exposition.","fr":"La première ligne de défense non spécifique. Comprend les barrières physiques (peau, mucus), les phagocytes (neutrophiles, macrophages), les cellules NK, les protéines du complément et l'inflammation. Répond immédiatement sans exposition préalable.","tr":"Spesifik olmayan ilk savunma hattı. Fiziksel bariyerleri (deri, mukus), fagositleri (nötrofiller, makrofajlar), NK hücrelerini, kompleman proteinlerini ve inflamasyonu kapsar. Önceden maruz kalma olmaksızın hemen yanıt verir.","nl":"De niet-specifieke eerste verdedigingslinie. Omvat fysieke barrières (huid, slijm), fagocyten (neutrofielen, macrofagen), NK-cellen, complementeiwitten en ontsteking. Reageert onmiddellijk zonder voorafgaande blootstelling.","ru":"Первая неспецифическая линия защиты. Включает физические барьеры (кожа, слизь), фагоциты (нейтрофилы, макрофаги), NK-клетки, белки комплемента и воспаление. Реагирует немедленно без предшествующего воздействия.","zh":"非特异性第一道防线。包括物理屏障（皮肤、黏液）、吞噬细胞（中性粒细胞、巨噬细胞）、NK细胞、补体蛋白和炎症。无需先前接触即可立即响应。","pt_BR":"A primeira linha de defesa não específica. Inclui barreiras físicas (pele, muco), fagócitos (neutrófilos, macrófagos), células NK, proteínas do complemento e inflamação. Responde imediatamente sem exposição prévia.","pt_PT":"A primeira linha de defesa não específica. Inclui barreiras físicas (pele, muco), fagócitos (neutrófilos, macrófagos), células NK, proteínas do complemento e inflamação. Responde imediatamente sem exposição prévia."}},
  { id: 'dc-biology-0070', deck_id: 'deck-biology', sort_order: 70, front: "Immune System: Adaptive Immunity", back: "A specific defense that develops after exposure to a specific antigen. Mediated by B cells (antibody production) and T cells (cell-mediated immunity). Generates immunological memory for faster future responses." , front_translations: {"es":"Sistema Imunológico: Imunidad Adaptativa","de":"Immunsystem: Adaptive Immunität","fr":"Système immunitaire : immunité adaptative","tr":"Bağışıklık Sistemi: Adaptif Bağışıklık","nl":"Immuunsysteem: adaptieve immuniteit","ru":"Иммунная система: адаптивный иммунитет","zh":"免疫系统：适应性免疫","pt_BR":"Sistema Imunológico: Imunidade Adaptativa","pt_PT":"Sistema Imunitário: Imunidade Adaptativa"}, back_translations: {"es":"Una defesa específica que se desenvolve após a exposición a un antígeno específico. Mediada por células B (producción de anticorpos) y células T (imunidad celular). Gera memoria imunológica para respuestas futuras más rápidas.","de":"Eine spezifische Abwehr, die sich nach der Exposition gegenüber einem bestimmten Antigen entwickelt. Vermittelt durch B-Zellen (Antikörperproduktion) und T-Zellen (zelluläre Immunität). Erzeugt immunologisches Gedächtnis für schnellere zukünftige Reaktionen.","fr":"Une défense spécifique qui se développe après exposition à un antigène spécifique. Médiée par les lymphocytes B (production d'anticorps) et les lymphocytes T (immunité à médiation cellulaire). Génère une mémoire immunologique pour des réponses futures plus rapides.","tr":"Belirli bir antijene maruz kalınmasının ardından gelişen özgül savunma. B hücreleri (antikor üretimi) ve T hücreleri (hücresel bağışıklık) aracılığıyla gerçekleşir. Daha hızlı gelecek yanıtlar için immünolojik bellek oluşturur.","nl":"Een specifieke verdediging die zich ontwikkelt na blootstelling aan een specifiek antigeen. Gemedieerd door B-cellen (antilichaamproductie) en T-cellen (cel-gemedieerde immuniteit). Genereert immunologisch geheugen voor snellere toekomstige reacties.","ru":"Специфическая защита, развивающаяся после воздействия конкретного антигена. Опосредована В-клетками (выработка антител) и Т-клетками (клеточный иммунитет). Формирует иммунологическую память для более быстрых будущих ответов.","zh":"接触特定抗原后发展起来的特异性防御。由B细胞（抗体产生）和T细胞（细胞介导免疫）介导。产生免疫记忆，使未来的免疫应答更快。","pt_BR":"Uma defesa específica que se desenvolve após a exposição a um antígeno específico. Mediada por células B (produção de anticorpos) e células T (imunidade celular). Gera memória imunológica para respostas futuras mais rápidas.","pt_PT":"Uma defesa específica que se desenvolve após a exposição a um antigénio específico. Mediada por células B (produção de anticorpos) e células T (imunidade celular). Gera memória imunológica para respostas futuras mais rápidas."}},
  { id: 'dc-biology-0071', deck_id: 'deck-biology', sort_order: 71, front: "Antibody (Immunoglobulin)", back: "A Y-shaped protein produced by plasma cells (differentiated B cells) that binds specifically to an antigen via its variable region. Neutralizes pathogens, marks them for destruction, and activates complement." , front_translations: {"es":"Anticorpo (Imunoglobulina)","de":"Antikörper (Immunglobulin)","fr":"Anticorps (immunoglobuline)","tr":"Antikor (İmmünoglobulin)","nl":"Antilichaam (immunoglobuline)","ru":"Антитело (иммуноглобулин)","zh":"抗体（免疫球蛋白）","pt_BR":"Anticorpo (Imunoglobulina)","pt_PT":"Anticorpo (Imunoglobulina)"}, back_translations: {"es":"Una proteína en forma de Y producida por plasmócitos (células B diferenciadas) que se liga especificamente a un antígeno por medio de su región variable. Neutraliza patógenos, marca-los para destrucción y ativa el complemento.","de":"Ein Y-förmiges Protein, das von Plasmazellen (differenzierten B-Zellen) produziert wird und spezifisch über seine variable Region an ein Antigen bindet. Neutralisiert Krankheitserreger, markiert sie zur Zerstörung und aktiviert das Komplementsystem.","fr":"Une protéine en forme de Y produite par les plasmocytes (lymphocytes B différenciés) qui se lie spécifiquement à un antigène via sa région variable. Neutralise les agents pathogènes, les marque pour la destruction et active le complément.","tr":"Plazma hücreleri (farklılaşmış B hücreleri) tarafından üretilen, değişken bölgesi aracılığıyla bir antijene özgül şekilde bağlanan Y şekilli protein. Patojenleri nötralize eder, yıkım için işaretler ve komplementi aktive eder.","nl":"Een Y-vormig eiwit geproduceerd door plasmacellen (gedifferentieerde B-cellen) dat via zijn variabele regio specifiek aan een antigeen bindt. Neutraliseert pathogenen, markeert ze voor vernietiging en activeert complement.","ru":"Y-образный белок, вырабатываемый плазматическими клетками (дифференцированными В-клетками), специфически связывающийся с антигеном через вариабельный участок. Нейтрализует патогены, маркирует их для уничтожения и активирует комплемент.","zh":"由浆细胞（分化的B细胞）产生的Y形蛋白，通过其可变区与抗原特异性结合。中和病原体，标记其待消灭，并激活补体。","pt_BR":"Uma proteína em forma de Y produzida por plasmócitos (células B diferenciadas) que se liga especificamente a um antígeno por meio de sua região variável. Neutraliza patógenos, marca-os para destruição e ativa o complemento.","pt_PT":"Uma proteína em forma de Y produzida por plasmócitos (células B diferenciadas) que se liga especificamente a um antigénio através da sua região variável. Neutraliza agentes patogénicos, marca-os para destruição e ativa o complemento."}},
  { id: 'dc-biology-0072', deck_id: 'deck-biology', sort_order: 72, front: "MHC (Major Histocompatibility Complex)", back: "Cell surface proteins that display peptide fragments for T cell recognition. MHC class I (on all nucleated cells) presents intracellular antigens to cytotoxic T cells. MHC class II (on APCs) presents to helper T cells." , front_translations: {"es":"MHC (Complexo Principal de Histocompatibilidad)","de":"MHC (Haupthistokompatibilitätskomplex)","fr":"CMH (complexe majeur d'histocompatibilité)","tr":"MHC (Majör Histouyumluluk Kompleksi)","nl":"MHC (Major Histocompatibiliteitscomplex)","ru":"МГК (главный комплекс гистосовместимости)","zh":"MHC（主要组织相容性复合体）","pt_BR":"MHC (Complexo Principal de Histocompatibilidade)","pt_PT":"MHC (Complexo Major de Histocompatibilidade)"}, back_translations: {"es":"Proteínas de superficie celular que exibem fragmentos peptídicos para el reconhecimento por las células T. MHC de clase I (en todas las células nucleadas) apresenta antígenos intracelulares a las células T citotóxicas. MHC de clase II (en las APCs) apresenta a las células T auxiliares.","de":"Zelloberflächenproteine, die Peptidfragmente für die T-Zell-Erkennung präsentieren. MHC-Klasse I (auf allen kernhaltigen Zellen) präsentiert intrazelluläre Antigene zytotoxischen T-Zellen. MHC-Klasse II (auf APCs) präsentiert Helfer-T-Zellen.","fr":"Protéines de surface cellulaire qui présentent des fragments peptidiques pour la reconnaissance par les lymphocytes T. CMH de classe I (sur toutes les cellules nucléées) présente les antigènes intracellulaires aux lymphocytes T cytotoxiques. CMH de classe II (sur les CPAs) présente aux lymphocytes T auxiliaires.","tr":"T hücre tanıması için peptit fragmanları sunan hücre yüzeyi proteinleri. MHC sınıf I (tüm çekirdekli hücrelerde) hücre içi antijenleri sitotoksik T hücrelerine sunar. MHC sınıf II (APC'lerde) yardımcı T hücrelerine sunar.","nl":"Celoppervlakeiwitten die peptidefragmenten presenteren voor T-celherkenning. MHC klasse I (op alle gekernde cellen) presenteert intracellulaire antigenen aan cytotoxische T-cellen. MHC klasse II (op APC's) presenteert aan helper-T-cellen.","ru":"Белки клеточной поверхности, представляющие пептидные фрагменты для распознавания Т-клетками. МГК класса I (на всех ядросодержащих клетках) представляет внутриклеточные антигены цитотоксическим Т-клеткам. МГК класса II (на АПК) представляет хелперным Т-клеткам.","zh":"展示肽片段供T细胞识别的细胞表面蛋白。MHC I类（存在于所有有核细胞上）向细胞毒性T细胞呈递胞内抗原。MHC II类（存在于APC上）向辅助性T细胞呈递。","pt_BR":"Proteínas de superfície celular que exibem fragmentos peptídicos para o reconhecimento pelas células T. MHC de classe I (em todas as células nucleadas) apresenta antígenos intracelulares às células T citotóxicas. MHC de classe II (nas APCs) apresenta às células T auxiliares.","pt_PT":"Proteínas de superfície celular que apresentam fragmentos peptídicos para o reconhecimento pelas células T. MHC de classe I (em todas as células nucleadas) apresenta antigénios intracelulares às células T citotóxicas. MHC de classe II (nas APCs) apresenta às células T auxiliares."}},
  { id: 'dc-biology-0073', deck_id: 'deck-biology', sort_order: 73, front: "Vaccination", back: "Exposure to a weakened/killed pathogen or its antigens to stimulate adaptive immunity and immunological memory without causing disease. Based on the principle that the second response to an antigen is faster and stronger." , front_translations: {"es":"Vacinación","de":"Impfung","fr":"Vaccination","tr":"Aşılama","nl":"Vaccinatie","ru":"Вакцинация","zh":"疫苗接种","pt_BR":"Vacinação","pt_PT":"Vacinação"}, back_translations: {"es":"Exposición a un patógeno enfraquecido/morto o a los sus antígenos para estimular a imunidad adaptativa y a memoria imunológica sin causar enfermedad. Baseada en el principio de que a segunda respuesta a un antígeno es más rápida y más fuerte.","de":"Exposition gegenüber einem abgeschwächten/abgetöteten Erreger oder seinen Antigenen, um die adaptive Immunität und das immunologische Gedächtnis anzuregen, ohne eine Krankheit auszulösen. Basiert auf dem Prinzip, dass die zweite Reaktion auf ein Antigen schneller und stärker ist.","fr":"Exposition à un agent pathogène affaibli/tué ou à ses antigènes pour stimuler l'immunité adaptative et la mémoire immunologique sans provoquer de maladie. Basée sur le principe que la deuxième réponse à un antigène est plus rapide et plus forte.","tr":"Hastalığa yol açmadan adaptif bağışıklığı ve immünolojik belleği uyarmak amacıyla zayıflatılmış/öldürülmüş bir patojene veya antijenlerine maruz bırakma. Bir antijene verilen ikinci yanıtın daha hızlı ve güçlü olduğu ilkesine dayanır.","nl":"Blootstelling aan een verzwakte/gedode ziekteverwekker of zijn antigenen om adaptieve immuniteit en immunologisch geheugen te stimuleren zonder ziekte te veroorzaken. Gebaseerd op het principe dat de tweede respons op een antigeen sneller en sterker is.","ru":"Воздействие ослабленного/убитого патогена или его антигенов для стимуляции адаптивного иммунитета и иммунологической памяти без развития заболевания. Основана на принципе, что второй ответ на антиген быстрее и сильнее.","zh":"接触减毒/灭活病原体或其抗原，以刺激适应性免疫和免疫记忆，而不引发疾病。基于对抗原的第二次免疫应答更快更强的原理。","pt_BR":"Exposição a um patógeno enfraquecido/morto ou aos seus antígenos para estimular a imunidade adaptativa e a memória imunológica sem causar doença. Baseada no princípio de que a segunda resposta a um antígeno é mais rápida e mais forte.","pt_PT":"Exposição a um agente patogénico enfraquecido/morto ou aos seus antigénios para estimular a imunidade adaptativa e a memória imunológica sem causar doença. Baseada no princípio de que a segunda resposta a um antigénio é mais rápida e mais forte."}},
  { id: 'dc-biology-0074', deck_id: 'deck-biology', sort_order: 74, front: "Heart Anatomy", back: "Four chambers: right atrium and ventricle (pulmonary circuit) and left atrium and ventricle (systemic circuit). Right side receives deoxygenated blood; left side pumps oxygenated blood to the body." , front_translations: {"es":"Anatomia del Coración","de":"Herzanatomie","fr":"Anatomie du cœur","tr":"Kalp Anatomisi","nl":"Hartanatomie","ru":"Анатомия сердца","zh":"心脏解剖","pt_BR":"Anatomia do Coração","pt_PT":"Anatomia do Coração"}, back_translations: {"es":"Quatro camaras: átrio y ventrículo derechos (circuito pulmonar) y átrio y ventrículo esquerdos (circuito sistemico). El lado derecho recibe sangre desoxigenado; el lado esquerdo bombeia sangre oxigenado para el cuerpo.","de":"Vier Kammern: rechter Vorhof und rechte Kammer (Lungenkreislauf) sowie linker Vorhof und linke Kammer (Körperkreislauf). Die rechte Seite empfängt sauerstoffarmes Blut; die linke Seite pumpt sauerstoffreiches Blut in den Körper.","fr":"Quatre cavités : oreillette droite et ventricule droit (circuit pulmonaire) et oreillette gauche et ventricule gauche (circuit systémique). Le côté droit reçoit le sang désoxygéné ; le côté gauche pompe le sang oxygéné vers le corps.","tr":"Dört boşluk: sağ atriyum ve ventriküler (pulmoner devre) ile sol atriyum ve ventrikül (sistemik devre). Sağ taraf oksijensiz kanı alır; sol taraf oksijenlenen kanı vücuda pompalar.","nl":"Vier kamers: rechterboezem en rechterkamer (longcirculatie) en linkerboezem en linkerkamer (systemische circulatie). De rechterkant ontvangt zuurstofarm bloed; de linkerkant pompt zuurstofrijk bloed naar het lichaam.","ru":"Четыре камеры: правое предсердие и правый желудочек (малый круг кровообращения) и левое предсердие и левый желудочек (большой круг кровообращения). Правая сторона получает венозную кровь; левая сторона нагнетает артериальную кровь в организм.","zh":"四个腔室：右心房和右心室（肺循环）以及左心房和左心室（体循环）。右侧接收脱氧血液；左侧将含氧血液泵向全身。","pt_BR":"Quatro câmaras: átrio e ventrículo direitos (circuito pulmonar) e átrio e ventrículo esquerdos (circuito sistêmico). O lado direito recebe sangue desoxigenado; o lado esquerdo bombeia sangue oxigenado para o corpo.","pt_PT":"Quatro câmaras: átrio e ventrículo direitos (circuito pulmonar) e átrio e ventrículo esquerdos (circuito sistémico). O lado direito recebe sangue desoxigenado; o lado esquerdo bombeia sangue oxigenado para o corpo."}},
  { id: 'dc-biology-0075', deck_id: 'deck-biology', sort_order: 75, front: "Cardiac Cycle", back: "The sequence of events in one heartbeat: atrial contraction (atrial systole), ventricular contraction (ventricular systole), and relaxation (diastole). Controlled by the SA node (pacemaker)." , front_translations: {"es":"Ciclo Cardíaco","de":"Herzkreislauf","fr":"Cycle cardiaque","tr":"Kardiyak Döngü","nl":"Hartcyclus","ru":"Сердечный цикл","zh":"心动周期","pt_BR":"Ciclo Cardíaco","pt_PT":"Ciclo Cardíaco"}, back_translations: {"es":"La secuencia de eventos en un batimento cardíaco: contración atrial (sístole atrial), contración ventricular (sístole ventricular) y relaxamento (diástole). Controlado por el nó SA (marcapasso).","de":"Die Abfolge der Ereignisse in einem Herzschlag: Vorhofkontraktion (Vorhofsystole), Kammerkontraktion (Kammersystole) und Entspannung (Diastole). Kontrolliert vom SA-Knoten (Schrittmacher).","fr":"La séquence d'événements en un battement cardiaque : contraction auriculaire (systole auriculaire), contraction ventriculaire (systole ventriculaire) et relaxation (diastole). Contrôlé par le nœud sinusal (pacemaker).","tr":"Bir kalp atışındaki olayların sırası: atriyal kasılma (atriyal sistol), ventriküler kasılma (ventriküler sistol) ve gevşeme (diyastol). SA düğümü (pacemaker) tarafından kontrol edilir.","nl":"De reeks gebeurtenissen in één hartslag: atriumcontractie (atriumsystole), ventrikelcontractie (ventrikelssystole) en ontspanning (diastole). Gecontroleerd door de SA-knoop (pacemaker).","ru":"Последовательность событий одного сердечного сокращения: сокращение предсердий (систола предсердий), сокращение желудочков (систола желудочков) и расслабление (диастола). Управляется синоатриальным узлом (водителем ритма).","zh":"一次心跳中事件的顺序：心房收缩（心房收缩期）、心室收缩（心室收缩期）和舒张（舒张期）。由窦房结（起搏点）控制。","pt_BR":"A sequência de eventos em um batimento cardíaco: contração atrial (sístole atrial), contração ventricular (sístole ventricular) e relaxamento (diástole). Controlado pelo nó SA (marcapasso).","pt_PT":"A sequência de eventos num batimento cardíaco: contração atrial (sístole atrial), contração ventricular (sístole ventricular) e relaxamento (diástole). Controlado pelo nó SA (pacemaker)."}},
  { id: 'dc-biology-0076', deck_id: 'deck-biology', sort_order: 76, front: "Respiratory System: Gas Exchange", back: "O₂ diffuses from alveoli into pulmonary capillaries; CO₂ diffuses in the opposite direction. Driven by partial pressure gradients. Alveoli provide enormous surface area (~70 m²) and thin walls for efficient diffusion." , front_translations: {"es":"Sistema Respiratório: Troca Gasosa","de":"Atmungssystem: Gasaustausch","fr":"Système respiratoire : échanges gazeux","tr":"Solunum Sistemi: Gaz Değişimi","nl":"Ademhalingsstelsel: Gasuitwisseling","ru":"Дыхательная система: газообмен","zh":"呼吸系统：气体交换","pt_BR":"Sistema Respiratório: Troca Gasosa","pt_PT":"Sistema Respiratório: Troca Gasosa"}, back_translations: {"es":"El El₂ difunde de los alvéolos para los capilares pulmonares; el CO₂ difunde en la dirección oposta. Impulsionado por gradientes de presión parcial. Los alvéolos proporcionan enorme área de superficie (~70 m²) y paredes delgadas para difusão eficiente.","de":"O₂ diffundiert aus den Alveolen in die Lungenkapillaren; CO₂ diffundiert in entgegengesetzter Richtung. Angetrieben durch Partialdruckgradienten. Die Alveolen bieten eine enorme Oberfläche (~70 m²) und dünne Wände für eine effiziente Diffusion.","fr":"L'O₂ diffuse des alvéoles vers les capillaires pulmonaires ; le CO₂ diffuse dans la direction opposée. Conduit par des gradients de pression partielle. Les alvéoles offrent une énorme surface (~70 m²) et des parois minces pour une diffusion efficace.","tr":"O₂, alveollerden pulmoner kılcal damarlara diffüzlenirken; CO₂ ters yönde diffüzlenir. Kısmi basınç gradyanları tarafından yönlendirilir. Alveollar verimli difüzyon için büyük bir yüzey alanı (~70 m²) ve ince duvarlar sağlar.","nl":"O₂ diffundeert van de alveolen naar de longcapillairen; CO₂ diffundeert in de tegenovergestelde richting. Aangedreven door partiaaldrukgradiënten. Alveolen bieden een enorm oppervlak (~70 m²) en dunne wanden voor efficiënte diffusie.","ru":"O₂ диффундирует из альвеол в лёгочные капилляры; CO₂ диффундирует в обратном направлении. Движущей силой служат градиенты парциального давления. Альвеолы обеспечивают огромную площадь поверхности (~70 м²) и тонкие стенки для эффективной диффузии.","zh":"O₂从肺泡扩散到肺毛细血管；CO₂向相反方向扩散。由分压梯度驱动。肺泡提供巨大的表面积（约70 m²）和薄壁，以实现高效扩散。","pt_BR":"O O₂ difunde dos alvéolos para os capilares pulmonares; o CO₂ difunde na direção oposta. Impulsionado por gradientes de pressão parcial. Os alvéolos fornecem enorme área de superfície (~70 m²) e paredes finas para difusão eficiente.","pt_PT":"O O₂ difunde dos alvéolos para os capilares pulmonares; o CO₂ difunde na direção oposta. Impulsionado por gradientes de pressão parcial. Os alvéolos fornecem enorme área de superfície (~70 m²) e paredes finas para difusão eficiente."}},
  { id: 'dc-biology-0077', deck_id: 'deck-biology', sort_order: 77, front: "Kidney Function (Nephron)", back: "The functional unit of the kidney. Filters blood via glomerular filtration, then selectively reabsorbs nutrients and water (proximal tubule, loop of Henle, distal tubule), and secretes waste into the urine." , front_translations: {"es":"Función Renal (Néfron)","de":"Nierenfunktion (Nephron)","fr":"Fonction rénale (néphron)","tr":"Böbrek Fonksiyonu (Nefron)","nl":"Nierfunctie (Nefron)","ru":"Функция почек (нефрон)","zh":"肾脏功能（肾单位）","pt_BR":"Função Renal (Néfron)","pt_PT":"Função Renal (Néfron)"}, back_translations: {"es":"La unidad funcional del riñón. Filtra el sangre por filtración glomerular, después reabsorve seletivamente nutrientes y agua (túbulo proximal, alça de Henle, túbulo distal) y secreta resíduos en la urina.","de":"Die funktionelle Einheit der Niere. Filtert Blut durch glomeruläre Filtration, resorbiert dann selektiv Nährstoffe und Wasser (proximaler Tubulus, Henle-Schleife, distaler Tubulus) und scheidet Abfallstoffe in den Urin aus.","fr":"L'unité fonctionnelle du rein. Filtre le sang par filtration glomérulaire, puis réabsorbe sélectivement les nutriments et l'eau (tubule proximal, anse de Henlé, tubule distal), et sécrète les déchets dans l'urine.","tr":"Böbreğin fonksiyonel birimidir. Glomerüler filtrasyon yoluyla kanı filtreler, ardından besin maddelerini ve suyu seçici olarak geri emer (proksimal tübül, Henle kulpu, distal tübül) ve atıkları idrar içine salgılar.","nl":"De functionele eenheid van de nier. Filtert bloed via glomerulaire filtratie, reabsorbeert vervolgens selectief nutriënten en water (proximale tubulus, lis van Henle, distale tubulus) en secreteert afvalstoffen in de urine.","ru":"Функциональная единица почки. Фильтрует кровь посредством клубочковой фильтрации, затем избирательно реабсорбирует питательные вещества и воду (проксимальный каналец, петля Генле, дистальный каналец) и секретирует отходы в мочу.","zh":"肾脏的功能单位。通过肾小球过滤血液，然后选择性地重吸收营养物质和水分（近曲小管、亨利环、远曲小管），并将废物分泌到尿液中。","pt_BR":"A unidade funcional do rim. Filtra o sangue por filtração glomerular, depois reabsorve seletivamente nutrientes e água (túbulo proximal, alça de Henle, túbulo distal) e secreta resíduos na urina.","pt_PT":"A unidade funcional do rim. Filtra o sangue por filtração glomerular, depois reabsorve seletivamente nutrientes e água (túbulo proximal, alça de Henle, túbulo distal) e secreta resíduos na urina."}},
  { id: 'dc-biology-0078', deck_id: 'deck-biology', sort_order: 78, front: "Digestive System Overview", back: "Mouth → esophagus → stomach → small intestine (duodenum, jejunum, ileum) → large intestine → rectum → anus. Digestion is chemical (enzymes, acids) and mechanical (chewing, peristalsis)." , front_translations: {"es":"Visão Geral del Sistema Digestivo","de":"Überblick über das Verdauungssystem","fr":"Vue d'ensemble du système digestif","tr":"Sindirim Sistemine Genel Bakış","nl":"Overzicht van het spijsverteringsstelsel","ru":"Обзор пищеварительной системы","zh":"消化系统概述","pt_BR":"Visão Geral do Sistema Digestivo","pt_PT":"Visão Geral do Sistema Digestivo"}, back_translations: {"es":"Boca → esofago → estomago → intestino delgado (duodeno, jejuno, íleo) → intestino grueso → reto → anus. La digestión es química (enzimas, ácidos) y mecánica (mastigación, peristaltismo).","de":"Mund → Speiseröhre → Magen → Dünndarm (Duodenum, Jejunum, Ileum) → Dickdarm → Rektum → After. Die Verdauung ist chemisch (Enzyme, Säuren) und mechanisch (Kauen, Peristaltik).","fr":"Bouche → œsophage → estomac → intestin grêle (duodénum, jéjunum, iléon) → gros intestin → rectum → anus. La digestion est chimique (enzymes, acides) et mécanique (mastication, péristaltisme).","tr":"Ağız → yemek borusu → mide → ince bağırsak (duodenum, jejunum, ileum) → kalın bağırsak → rektum → anüs. Sindirim kimyasal (enzimler, asitler) ve mekaniktir (çiğneme, peristaltizm).","nl":"Mond → slokdarm → maag → dunne darm (duodenum, jejunum, ileum) → dikke darm → rectum → anus. Vertering is chemisch (enzymen, zuren) en mechanisch (kauwen, peristaltiek).","ru":"Рот → пищевод → желудок → тонкая кишка (двенадцатиперстная, тощая, подвздошная) → толстая кишка → прямая кишка → анус. Пищеварение бывает химическим (ферменты, кислоты) и механическим (жевание, перистальтика).","zh":"口腔 → 食道 → 胃 → 小肠（十二指肠、空肠、回肠）→ 大肠 → 直肠 → 肛门。消化包括化学消化（酶、酸）和机械消化（咀嚼、蠕动）。","pt_BR":"Boca → esôfago → estômago → intestino delgado (duodeno, jejuno, íleo) → intestino grosso → reto → ânus. A digestão é química (enzimas, ácidos) e mecânica (mastigação, peristaltismo).","pt_PT":"Boca → esófago → estômago → intestino delgado (duodeno, jejuno, íleo) → intestino grosso → reto → ânus. A digestão é química (enzimas, ácidos) e mecânica (mastigação, peristaltismo)."}},
  { id: 'dc-biology-0079', deck_id: 'deck-biology', sort_order: 79, front: "Enzyme: Amylase", back: "A digestive enzyme that hydrolyzes starch (polysaccharide) into maltose (disaccharide). Salivary amylase begins starch digestion in the mouth; pancreatic amylase continues it in the small intestine." , front_translations: {"es":"Enzima: Amilase","de":"Enzym: Amylase","fr":"Enzyme : amylase","tr":"Enzim: Amilaz","nl":"Enzym: Amylase","ru":"Фермент: амилаза","zh":"酶：淀粉酶","pt_BR":"Enzima: Amilase","pt_PT":"Enzima: Amilase"}, back_translations: {"es":"Una enzima digestiva que hidrolisa el amido (polissacarídeo) en maltose (dissacarídeo). La amilase salivar inicia a digestión del amido en la boca; a amilase pancreática a continua en el intestino delgado.","de":"Ein Verdauungsenzym, das Stärke (Polysaccharid) in Maltose (Disaccharid) hydrolysiert. Die Speichelamylase beginnt die Stärkeverdauung im Mund; die Pankreasamylase setzt sie im Dünndarm fort.","fr":"Une enzyme digestive qui hydrolyse l'amidon (polysaccharide) en maltose (disaccharide). L'amylase salivaire commence la digestion de l'amidon dans la bouche ; l'amylase pancréatique la poursuit dans l'intestin grêle.","tr":"Nişastayı (polisakkarit) maltoza (disakkarit) hidrolize eden bir sindirim enzimidir. Tükürük amilazı, nişasta sindirimini ağızda başlatır; pankreas amilazı ise ince bağırsakta devam ettirir.","nl":"Een spijsverteringsenzym dat zetmeel (polysaccharide) hydrolyseert tot maltose (disaccharide). Speekselamylase begint zetmeelvertering in de mond; pancreasamilase zet dit voort in de dunne darm.","ru":"Пищеварительный фермент, гидролизующий крахмал (полисахарид) до мальтозы (дисахарида). Слюнная амилаза начинает расщепление крахмала во рту; панкреатическая амилаза продолжает этот процесс в тонкой кишке.","zh":"一种消化酶，将淀粉（多糖）水解为麦芽糖（二糖）。唾液淀粉酶在口腔中开始淀粉消化；胰腺淀粉酶在小肠中继续消化。","pt_BR":"Uma enzima digestiva que hidrolisa o amido (polissacarídeo) em maltose (dissacarídeo). A amilase salivar inicia a digestão do amido na boca; a amilase pancreática a continua no intestino delgado.","pt_PT":"Uma enzima digestiva que hidrolisa o amido (polissacarídeo) em maltose (dissacarídeo). A amilase salivar inicia a digestão do amido na boca; a amilase pancreática a continua no intestino delgado."}},
  { id: 'dc-biology-0080', deck_id: 'deck-biology', sort_order: 80, front: "Taxonomy: Domain System", back: "The three-domain system: Bacteria (prokaryotes), Archaea (prokaryotes with distinct biochemistry), and Eukarya (all eukaryotes). Proposed by Carl Woese based on rRNA sequence analysis." , front_translations: {"es":"Taxonomia: Sistema de Domínios","de":"Taxonomie: Domänen-System","fr":"Taxonomie : système des domaines","tr":"Taksonomi: Alan Sistemi","nl":"Taxonomie: Domeinsysteem","ru":"Таксономия: система доменов","zh":"分类学：域系统","pt_BR":"Taxonomia: Sistema de Domínios","pt_PT":"Taxonomia: Sistema de Domínios"}, back_translations: {"es":"El sistema de tres domínios: Bacteria (procariotos), Archaea (procariotos con bioquímica distinta) y Eukarya (todos los eucariotos). Proposto por Carl Woese con base en la análise de secuencias de rRNA.","de":"Das Drei-Domänen-System: Bakterien (Prokaryoten), Archaea (Prokaryoten mit eigener Biochemie) und Eukarya (alle Eukaryoten). Vorgeschlagen von Carl Woese auf der Grundlage der rRNA-Sequenzanalyse.","fr":"Le système à trois domaines : Bacteria (procaryotes), Archaea (procaryotes à biochimie distincte) et Eukarya (tous les eucaryotes). Proposé par Carl Woese sur la base de l'analyse des séquences d'ARNr.","tr":"Üç alanlı sistem: Bakteri (prokaryotlar), Arkea (farklı biyokimyaya sahip prokaryotlar) ve Ökaryot (tüm ökaryotlar). Carl Woese tarafından rRNA dizi analizine dayanarak önerilmiştir.","nl":"Het drie-domeinsysteem: Bacteria (prokaryoten), Archaea (prokaryoten met onderscheiden biochemie) en Eukarya (alle eukaryoten). Voorgesteld door Carl Woese op basis van rRNA-sequentieanalyse.","ru":"Трёхдоменная система: бактерии (прокариоты), археи (прокариоты с особой биохимией) и эукариоты (все эукариотические организмы). Предложена Карлом Вёзе на основе анализа последовательностей рРНК.","zh":"三域系统：细菌（原核生物）、古菌（具有独特生化特性的原核生物）和真核生物（所有真核生物）。由卡尔·沃斯基于rRNA序列分析提出。","pt_BR":"O sistema de três domínios: Bacteria (procariotos), Archaea (procariotos com bioquímica distinta) e Eukarya (todos os eucariotos). Proposto por Carl Woese com base na análise de sequências de rRNA.","pt_PT":"O sistema de três domínios: Bacteria (procariotas), Archaea (procariotas com bioquímica distinta) e Eukarya (todos os eucariotas). Proposto por Carl Woese com base na análise de sequências de rRNA."}},
  { id: 'dc-biology-0081', deck_id: 'deck-biology', sort_order: 81, front: "Taxonomy: Hierarchy", back: "Domain > Kingdom > Phylum > Class > Order > Family > Genus > Species. Remember: Dear King Philip Came Over For Good Soup. Species is the most specific level; each organism has a two-part binomial name." , front_translations: {"es":"Taxonomia: Hierarquia","de":"Taxonomie: Hierarchie","fr":"Taxonomie : hiérarchie","tr":"Taksonomi: Hiyerarşi","nl":"Taxonomie: Hiërarchie","ru":"Таксономия: иерархия","zh":"分类学：层级","pt_BR":"Taxonomia: Hierarquia","pt_PT":"Taxonomia: Hierarquia"}, back_translations: {"es":"Domínio > Reino > Filo > Classe > Ordem > Família > Genero > Espécie. Mnemonico: Dear King Philip Came Over For Good Soup. La especie es el nivel más específico; cada organismo tiene un nombre binomial de de los partes.","de":"Domäne > Reich > Stamm > Klasse > Ordnung > Familie > Gattung > Art. Merksatz: Doch Könnte Peter Claudia Oft Früh Guten Schlaf bringen. Die Art ist die spezifischste Ebene; jeder Organismus hat einen zweiteiligen binomialen Namen.","fr":"Domaine > Règne > Embranchement > Classe > Ordre > Famille > Genre > Espèce. Mnémotechnique : De Grands Rois Pour Commander Fort Bien Savent. L'espèce est le niveau le plus spécifique ; chaque organisme porte un nom binomial en deux parties.","tr":"Alan > Alem > Şube > Sınıf > Takım > Familya > Cins > Tür. Anımsatıcı: Derin Krallarda Parlayan Çiçekler Oldukça Fazla Güzel Süsler. Tür en özel düzeydir; her organizmanın iki parçalı bir binom adı vardır.","nl":"Domein > Rijk > Stam > Klasse > Orde > Familie > Geslacht > Soort. Ezelsbruggetje: Dat Kunnen Princessen Claimen Op Fraaie Gouden Schoenen. Soort is het meest specifieke niveau; elk organisme heeft een tweedelige binominale naam.","ru":"Домен > Царство > Тип > Класс > Отряд > Семейство > Род > Вид. Мнемоника: Dear King Philip Came Over For Good Soup. Вид — наиболее специфический уровень; каждый организм имеет двойное биноминальное название.","zh":"域 > 界 > 门 > 纲 > 目 > 科 > 属 > 种。记忆口诀：Dear King Philip Came Over For Good Soup。种是最具体的层级；每个生物有一个双名命名法的名称。","pt_BR":"Domínio > Reino > Filo > Classe > Ordem > Família > Gênero > Espécie. Mnemônico: Dear King Philip Came Over For Good Soup. A espécie é o nível mais específico; cada organismo tem um nome binomial de duas partes.","pt_PT":"Domínio > Reino > Filo > Classe > Ordem > Família > Género > Espécie. Mnemónico: Dear King Philip Came Over For Good Soup. A espécie é o nível mais específico; cada organismo tem um nome binomial de duas partes."}},
  { id: 'dc-biology-0082', deck_id: 'deck-biology', sort_order: 82, front: "Binomial Nomenclature", back: "The scientific naming system using a two-part Latin name: genus (capitalized) + species (lowercase), both italicized. E.g., Homo sapiens. Ensures universal, unambiguous identification." , front_translations: {"es":"Nomenclatura Binomial","de":"Binomiale Nomenklatur","fr":"Nomenclature binominale","tr":"Binom Terminolojisi","nl":"Binominale nomenclatuur","ru":"Бинарная номенклатура","zh":"双名命名法","pt_BR":"Nomenclatura Binomial","pt_PT":"Nomenclatura Binomial"}, back_translations: {"es":"El sistema de nomenclatura científica usando un nombre latino de de los partes: genero (capitalizado) + especie (minúsculo), ambos en itálico. Ex.: Homo sapiens. Garante identificación universal y inequívoca.","de":"Das wissenschaftliche Benennungssystem mit einem zweiteiligen lateinischen Namen: Gattung (großgeschrieben) + Art (kleingeschrieben), beide kursiv. Z. B. Homo sapiens. Gewährleistet eine universelle, eindeutige Identifikation.","fr":"Le système de dénomination scientifique utilisant un nom latin en deux parties : genre (avec majuscule) + espèce (en minuscules), tous deux en italique. Ex. : Homo sapiens. Assure une identification universelle et sans ambiguïté.","tr":"İki parçalı Latince isim kullanan bilimsel adlandırma sistemi: cins (büyük harfle) + tür (küçük harfle), her ikisi de italik. Örn. Homo sapiens. Evrensel, net bir tanımlama sağlar.","nl":"Het wetenschappelijke naamgevingssysteem met een tweedelige Latijnse naam: geslacht (met hoofdletter) + soort (in kleine letters), beide cursief. Bijv. Homo sapiens. Zorgt voor universele, ondubbelzinnige identificatie.","ru":"Система научного именования, использующая двойное латинское название: род (с заглавной буквы) + вид (строчными), оба курсивом. Например, Homo sapiens. Обеспечивает универсальную и однозначную идентификацию.","zh":"使用两部分拉丁文名称的科学命名系统：属名（大写）+ 种名（小写），均用斜体。例如：Homo sapiens。确保全球通用、无歧义的识别。","pt_BR":"O sistema de nomenclatura científica usando um nome latino de duas partes: gênero (capitalizado) + espécie (minúsculo), ambos em itálico. Ex.: Homo sapiens. Garante identificação universal e inequívoca.","pt_PT":"O sistema de nomenclatura científica usando um nome latino de duas partes: género (capitalizado) + espécie (minúsculo), ambos em itálico. Ex.: Homo sapiens. Garante identificação universal e inequívoca."}},
  { id: 'dc-biology-0083', deck_id: 'deck-biology', sort_order: 83, front: "Virus", back: "An acellular obligate intracellular parasite consisting of genetic material (DNA or RNA) enclosed in a protein coat (capsid), sometimes with a lipid envelope. Not considered alive by most definitions." , front_translations: {"es":"Vírus","de":"Virus","fr":"Virus","tr":"Virüs","nl":"Virus","ru":"Вирус","zh":"病毒","pt_BR":"Vírus","pt_PT":"Vírus"}, back_translations: {"es":"Un parasita intracelular obrigatório acelular compuesto de material genético (DNA o RNA) envolto en un invólucro proteico (capsídeo), a las veces con un envelope lipídico. No considerado vivo por la maioria de las definiciones.","de":"Ein azellulärer, obligat intrazellulärer Parasit, der aus genetischem Material (DNA oder RNA) besteht, das in einer Proteinhülle (Kapsid) eingeschlossen ist, manchmal mit einer Lipidhülle. Von den meisten Definitionen nicht als lebendig betrachtet.","fr":"Un parasite intracellulaire obligatoire acellulaire constitué de matériel génétique (ADN ou ARN) enfermé dans une enveloppe protéique (capside), parfois entourée d'une enveloppe lipidique. Non considéré comme vivant selon la plupart des définitions.","tr":"Bazen lipid zarfıyla çevrilmiş bir protein kılıfı (kapsit) içine hapsedilmiş genetik materyalden (DNA veya RNA) oluşan asellüler, zorunlu hücre içi parazit. Çoğu tanıma göre canlı sayılmaz.","nl":"Een acellulaire verplicht intracellulaire parasiet bestaande uit genetisch materiaal (DNA of RNA) ingesloten in een eiwitmantel (capside), soms met een lipidenomhulsel. Wordt door de meeste definities niet als levend beschouwd.","ru":"Внеклеточный облигатный внутриклеточный паразит, состоящий из генетического материала (ДНК или РНК), заключённого в белковую оболочку (капсид), иногда с липидной оболочкой. По большинству определений не считается живым организмом.","zh":"一种非细胞的专性胞内寄生体，由遗传物质（DNA或RNA）组成，包裹在蛋白质外壳（衣壳）中，有时具有脂质包膜。按大多数定义不被认为是有生命的。","pt_BR":"Um parasita intracelular obrigatório acelular composto de material genético (DNA ou RNA) envolto em um invólucro proteico (capsídeo), às vezes com um envelope lipídico. Não considerado vivo pela maioria das definições.","pt_PT":"Um parasita intracelular obrigatório acelular composto de material genético (DNA ou RNA) envolto num invólucro proteico (capsídeo), por vezes com um envelope lipídico. Não é considerado vivo pela maioria das definições."}},
  { id: 'dc-biology-0084', deck_id: 'deck-biology', sort_order: 84, front: "Lytic vs. Lysogenic Cycle", back: "Lytic cycle: virus replicates rapidly, lyses (destroys) the host cell, releases new virions. Lysogenic cycle: viral DNA integrates into host genome (prophage), replicates with the host until triggered to enter the lytic cycle." , front_translations: {"es":"Ciclo Lítico vs. Lisogenico","de":"Lytischer vs. lysogener Zyklus","fr":"Cycle lytique vs cycle lysogénique","tr":"Litik ve Lizojenik Döngü","nl":"Lytische vs. lysogene cyclus","ru":"Литический и лизогенный циклы","zh":"裂解循环与溶原循环","pt_BR":"Ciclo Lítico vs. Lisogênico","pt_PT":"Ciclo Lítico vs. Lisogénico"}, back_translations: {"es":"Ciclo lítico: el virus replica rápidamente, lisa (destruye) a célula hospedera y libera nuevos vírions. Ciclo lisogenico: el DNA viral integra-se al genoma hospedero (profago), replica-se con el hospedero hasta ser acionado a entrar en el ciclo lítico.","de":"Lytischer Zyklus: Das Virus repliziert sich schnell, lysiert (zerstört) die Wirtszelle und setzt neue Virionen frei. Lysogener Zyklus: Die virale DNA integriert sich ins Wirtsgenom (Prophage), repliziert sich mit dem Wirt, bis sie durch einen Auslöser in den lytischen Zyklus übergeht.","fr":"Cycle lytique : le virus se réplique rapidement, lyse (détruit) la cellule hôte et libère de nouveaux virions. Cycle lysogénique : l'ADN viral s'intègre dans le génome hôte (prophage), se réplique avec l'hôte jusqu'à ce qu'un déclencheur provoque l'entrée dans le cycle lytique.","tr":"Litik döngü: virüs hızla çoğalır, konak hücreyi parçalar (yok eder) ve yeni virionlar serbest bırakır. Lizojenik döngü: viral DNA, konak genoma (profaj) entegre olur, tetiklenene kadar konakla birlikte çoğalır ve litik döngüye girer.","nl":"Lytische cyclus: het virus repliceert snel, lyseert (vernietigt) de gastheercel en geeft nieuwe virionen vrij. Lysogene cyclus: viraal DNA integreert in het gastheergenom (profaag), repliceert mee met de gastheer totdat een trigger de lytische cyclus induceert.","ru":"Литический цикл: вирус быстро размножается, лизирует (разрушает) клетку-хозяина, высвобождая новые вирионы. Лизогенный цикл: вирусная ДНК встраивается в геном хозяина (профаг), реплицируется вместе с ним до тех пор, пока триггер не запустит литический цикл.","zh":"裂解循环：病毒迅速复制，裂解（摧毁）宿主细胞，释放新的病毒颗粒。溶原循环：病毒DNA整合到宿主基因组（前噬菌体）中，随宿主一起复制，直到被触发进入裂解循环。","pt_BR":"Ciclo lítico: o vírus replica rapidamente, lisa (destrói) a célula hospedeira e libera novos vírions. Ciclo lisogênico: o DNA viral integra-se ao genoma hospedeiro (profago), replica-se com o hospedeiro até ser acionado a entrar no ciclo lítico.","pt_PT":"Ciclo lítico: o vírus replica rapidamente, lisa (destrói) a célula hospedeira e libera novos viriões. Ciclo lisogénico: o DNA viral integra-se no genoma hospedeiro (profago), replica-se com o hospedeiro até ser ativado a entrar no ciclo lítico."}},
  { id: 'dc-biology-0085', deck_id: 'deck-biology', sort_order: 85, front: "Ecology: Trophic Levels", back: "Producers (autotrophs, level 1) → primary consumers (herbivores, level 2) → secondary consumers (level 3) → tertiary consumers (level 4). Each level transfers ~10% of energy to the next (10% rule)." , front_translations: {"es":"Ecologia: Nibles Tróficos","de":"Ökologie: Trophische Ebenen","fr":"Écologie : niveaux trophiques","tr":"Ekoloji: Trofik Seviyeler","nl":"Ecologie: Trofische niveaus","ru":"Экология: трофические уровни","zh":"生态学：营养级","pt_BR":"Ecologia: Níveis Tróficos","pt_PT":"Ecologia: Níveis Tróficos"}, back_translations: {"es":"Produtores (autotróficos, nivel 1) → consumidores primários (herbívoros, nivel 2) → consumidores secundários (nivel 3) → consumidores terciários (nivel 4). Cada nivel transfere ~10% de energía para el próximo (regra de los 10%).","de":"Produzenten (Autotrophe, Ebene 1) → Primärkonsumenten (Pflanzenfresser, Ebene 2) → Sekundärkonsumenten (Ebene 3) → Tertiärkonsumenten (Ebene 4). Jede Ebene überträgt ca. 10 % der Energie auf die nächste (10 %-Regel).","fr":"Producteurs (autotrophes, niveau 1) → consommateurs primaires (herbivores, niveau 2) → consommateurs secondaires (niveau 3) → consommateurs tertiaires (niveau 4). Chaque niveau transfère environ 10 % de l'énergie au suivant (règle des 10 %).","tr":"Üreticiler (ototrof, 1. seviye) → birincil tüketiciler (otçullar, 2. seviye) → ikincil tüketiciler (3. seviye) → üçüncül tüketiciler (4. seviye). Her seviye enerjinin yaklaşık %10'unu bir sonrakine aktarır (%10 kuralı).","nl":"Producenten (autotrofen, niveau 1) → primaire consumenten (herbivoren, niveau 2) → secundaire consumenten (niveau 3) → tertiaire consumenten (niveau 4). Elk niveau draagt ~10% van de energie over naar het volgende (10%-regel).","ru":"Производители (автотрофы, 1-й уровень) → первичные потребители (травоядные, 2-й уровень) → вторичные потребители (3-й уровень) → третичные потребители (4-й уровень). Каждый уровень передаёт следующему ~10% энергии (правило 10%).","zh":"生产者（自养生物，第1级）→ 初级消费者（草食动物，第2级）→ 次级消费者（第3级）→ 三级消费者（第4级）。每一级将约10%的能量传递给下一级（10%法则）。","pt_BR":"Produtores (autotróficos, nível 1) → consumidores primários (herbívoros, nível 2) → consumidores secundários (nível 3) → consumidores terciários (nível 4). Cada nível transfere ~10% de energia para o próximo (regra dos 10%).","pt_PT":"Produtores (autotróficos, nível 1) → consumidores primários (herbívoros, nível 2) → consumidores secundários (nível 3) → consumidores terciários (nível 4). Cada nível transfere ~10% de energia para o próximo (regra dos 10%)."}},
  { id: 'dc-biology-0086', deck_id: 'deck-biology', sort_order: 86, front: "Food Web", back: "A network of interconnected food chains showing feeding relationships in an ecosystem. More realistic than a simple food chain. Loss of a keystone species can collapse the entire structure." , front_translations: {"es":"Teia Alimentar","de":"Nahrungsnetz","fr":"Réseau trophique","tr":"Besin Ağı","nl":"Voedselweb","ru":"Пищевая сеть","zh":"食物网","pt_BR":"Teia Alimentar","pt_PT":"Teia Alimentar"}, back_translations: {"es":"Una red de cadeias alimentares interconectadas mostrando las relaciones alimentares en un ecossistema. Más realista del que una simples cadena alimentaria. La perda de una especie-chave puede colapsar toda a estructura.","de":"Ein Netzwerk miteinander verbundener Nahrungsketten, das die Ernährungsbeziehungen in einem Ökosystem zeigt. Realistischer als eine einfache Nahrungskette. Der Verlust einer Schlüsselart kann die gesamte Struktur zum Zusammenbruch bringen.","fr":"Un réseau de chaînes alimentaires interconnectées montrant les relations trophiques dans un écosystème. Plus réaliste qu'une simple chaîne alimentaire. La perte d'une espèce clé peut entraîner l'effondrement de toute la structure.","tr":"Bir ekosistemde beslenme ilişkilerini gösteren birbirine bağlı besin zincirlerinden oluşan ağ. Basit bir besin zincirinden daha gerçekçidir. Bir kilit taşı türünün kaybı tüm yapıyı çökertebilir.","nl":"Een netwerk van onderling verbonden voedselketens dat voedingsrelaties in een ecosysteem toont. Realistischer dan een eenvoudige voedselketen. Het verlies van een sleutelsoort kan de volledige structuur laten instorten.","ru":"Сеть взаимосвязанных пищевых цепей, отражающая пищевые отношения в экосистеме. Более реалистична, чем простая пищевая цепь. Потеря ключевого вида может привести к коллапсу всей структуры.","zh":"展示生态系统中捕食关系的相互关联食物链网络。比简单食物链更为真实。关键种的消失可能导致整个结构崩溃。","pt_BR":"Uma rede de cadeias alimentares interconectadas mostrando as relações alimentares em um ecossistema. Mais realista do que uma simples cadeia alimentar. A perda de uma espécie-chave pode colapsar toda a estrutura.","pt_PT":"Uma rede de cadeias alimentares interligadas que mostra as relações alimentares num ecossistema. Mais realista do que uma simples cadeia alimentar. A perda de uma espécie-chave pode colapsar toda a estrutura."}},
  { id: 'dc-biology-0087', deck_id: 'deck-biology', sort_order: 87, front: "Biomes", back: "Major terrestrial ecological communities characterized by climate, vegetation, and fauna: tundra, boreal forest (taiga), temperate forest, tropical rainforest, grassland, desert, chaparral, wetlands." , front_translations: {"es":"Biomas","de":"Biome","fr":"Biomes","tr":"Biyomlar","nl":"Biomen","ru":"Биомы","zh":"生物群系","pt_BR":"Biomas","pt_PT":"Biomas"}, back_translations: {"es":"Grandes comunidades ecológicas terrestres caracterizadas por clima, vegetación y fauna: tundra, floresta boreal (taiga), floresta temperada, floresta tropical, campo, deserto, chaparral, áreas úmidas.","de":"Wichtige terrestrische Ökosysteme, die durch Klima, Vegetation und Fauna charakterisiert sind: Tundra, borealer Wald (Taiga), gemäßigter Wald, tropischer Regenwald, Grasland, Wüste, Chaparral, Feuchtgebiete.","fr":"Grandes communautés écologiques terrestres caractérisées par le climat, la végétation et la faune : toundra, forêt boréale (taïga), forêt tempérée, forêt tropicale humide, prairie, désert, chaparral, zones humides.","tr":"İklim, bitki örtüsü ve fauna ile karakterize edilen büyük karasal ekolojik topluluklar: tundra, boreal orman (taiga), ılıman orman, tropikal yağmur ormanı, çayırlık, çöl, şaparel, sulak alanlar.","nl":"Grote terrestrische ecologische gemeenschappen gekenmerkt door klimaat, vegetatie en fauna: toendra, boreaal bos (taiga), gematigd bos, tropisch regenwoud, graslanden, woestijn, chaparral, wetlands.","ru":"Крупные наземные экологические сообщества, характеризуемые климатом, растительностью и фауной: тундра, бореальный лес (тайга), умеренный лес, тропический дождевой лес, луга, пустыня, чапараль, водно-болотные угодья.","zh":"由气候、植被和动物群特征决定的主要陆地生态群落：冻原、北方森林（针叶林）、温带森林、热带雨林、草地、荒漠、查帕拉尔灌木林、湿地。","pt_BR":"Grandes comunidades ecológicas terrestres caracterizadas por clima, vegetação e fauna: tundra, floresta boreal (taiga), floresta temperada, floresta tropical, campo, deserto, chaparral, áreas úmidas.","pt_PT":"Grandes comunidades ecológicas terrestres caracterizadas por clima, vegetação e fauna: tundra, floresta boreal (taiga), floresta temperada, floresta tropical, campo, deserto, chaparral, zonas húmidas."}},
  { id: 'dc-biology-0088', deck_id: 'deck-biology', sort_order: 88, front: "Population Dynamics", back: "Factors regulating population size: biotic potential (max growth rate), carrying capacity (K), density-dependent factors (predation, disease), and density-independent factors (weather, natural disasters)." , front_translations: {"es":"Dinamica Populacional","de":"Populationsdynamik","fr":"Dynamique des populations","tr":"Popülasyon Dinamiği","nl":"Populatiedynamiek","ru":"Динамика популяции","zh":"种群动态","pt_BR":"Dinâmica Populacional","pt_PT":"Dinâmica Populacional"}, back_translations: {"es":"Fatores que regulan el tamaño de la población: potencial biótico (taxa de crecimiento máximo), capacidad de suporte (K), fatores densidad-dependentes (predación, enfermedad) y fatores densidad-independentes (clima, desastres naturais).","de":"Faktoren, die die Populationsgröße regulieren: biotisches Potenzial (maximale Wachstumsrate), Tragfähigkeit (K), dichteabhängige Faktoren (Prädation, Krankheit) und dichteunabhängige Faktoren (Wetter, Naturkatastrophen).","fr":"Facteurs régulant la taille des populations : potentiel biotique (taux de croissance maximal), capacité de charge (K), facteurs densité-dépendants (prédation, maladie) et facteurs densité-indépendants (météo, catastrophes naturelles).","tr":"Popülasyon büyüklüğünü düzenleyen faktörler: biyotik potansiyel (maksimum büyüme hızı), taşıma kapasitesi (K), yoğunluğa bağımlı faktörler (yırtıcılık, hastalık) ve yoğunluktan bağımsız faktörler (hava, doğal afetler).","nl":"Factoren die de populatieomvang reguleren: biotisch potentieel (maximale groeisnelheid), draagcapaciteit (K), dichtheidsafhankelijke factoren (predatie, ziekte) en dichtheidsonafhankelijke factoren (weer, natuurrampen).","ru":"Факторы, регулирующие численность популяции: биотический потенциал (максимальная скорость роста), ёмкость среды (K), зависящие от плотности факторы (хищничество, болезни) и независящие от плотности факторы (погода, стихийные бедствия).","zh":"调节种群大小的因素：生物潜力（最大增长率）、环境容纳量（K）、密度制约因素（捕食、疾病）和非密度制约因素（气候、自然灾害）。","pt_BR":"Fatores que regulam o tamanho da população: potencial biótico (taxa de crescimento máximo), capacidade de suporte (K), fatores densidade-dependentes (predação, doença) e fatores densidade-independentes (clima, desastres naturais).","pt_PT":"Fatores que regulam o tamanho da população: potencial biótico (taxa de crescimento máximo), capacidade de carga (K), fatores densidade-dependentes (predação, doença) e fatores densidade-independentes (clima, desastres naturais)."}},
  { id: 'dc-biology-0089', deck_id: 'deck-biology', sort_order: 89, front: "Logistic Growth", back: "Population growth that slows as it approaches carrying capacity (K). Described by an S-shaped (sigmoidal) curve. Growth rate is highest at N = K/2. Most natural populations exhibit logistic growth." , front_translations: {"es":"Crescimento Logístico","de":"Logistisches Wachstum","fr":"Croissance logistique","tr":"Lojistik Büyüme","nl":"Logistische groei","ru":"Логистический рост","zh":"逻辑斯谛增长","pt_BR":"Crescimento Logístico","pt_PT":"Crescimento Logístico"}, back_translations: {"es":"Crescimento populacional que desacelera a la medida que se aproxima de la capacidad de suporte (K). Descrito por una curva en S (sigmoidal). La taxa de crecimiento es más alta en N = K/2. La maioria de las poblaciones naturais exibe crecimiento logístico.","de":"Populationswachstum, das sich verlangsamt, wenn es sich der Tragfähigkeit (K) nähert. Beschrieben durch eine S-förmige (sigmoide) Kurve. Die Wachstumsrate ist am höchsten bei N = K/2. Die meisten natürlichen Populationen zeigen logistisches Wachstum.","fr":"Croissance d'une population qui ralentit à l'approche de la capacité de charge (K). Décrite par une courbe en S (sigmoïde). Le taux de croissance est maximal à N = K/2. La plupart des populations naturelles suivent une croissance logistique.","tr":"Taşıma kapasitesine (K) yaklaştıkça yavaşlayan popülasyon büyümesi. S şeklinde (sigmoidal) eğri ile tanımlanır. Büyüme hızı N = K/2'de en yüksektir. Doğal popülasyonların çoğu lojistik büyüme gösterir.","nl":"Populatiegroei die vertraagt naarmate de draagcapaciteit (K) wordt benaderd. Beschreven door een S-vormige (sigmoïdale) curve. De groeisnelheid is het hoogst bij N = K/2. De meeste natuurlijke populaties vertonen logistische groei.","ru":"Рост популяции, замедляющийся по мере приближения к ёмкости среды (K). Описывается S-образной (сигмоидной) кривой. Максимальная скорость роста достигается при N = K/2. Большинство природных популяций демонстрирует логистический рост.","zh":"种群增长随接近环境容纳量（K）而减慢。由S形（逻辑斯谛）曲线描述。当N = K/2时增长速率最高。大多数自然种群呈现逻辑斯谛增长。","pt_BR":"Crescimento populacional que desacelera à medida que se aproxima da capacidade de suporte (K). Descrito por uma curva em S (sigmoidal). A taxa de crescimento é mais alta em N = K/2. A maioria das populações naturais exibe crescimento logístico.","pt_PT":"Crescimento populacional que abranda à medida que se aproxima da capacidade de carga (K). Descrito por uma curva em S (sigmoidal). A taxa de crescimento é mais alta em N = K/2. A maioria das populações naturais exibe crescimento logístico."}},
  { id: 'dc-biology-0090', deck_id: 'deck-biology', sort_order: 90, front: "Exponential Growth", back: "Population growth at a constant rate (J-shaped curve). Occurs when resources are unlimited. dN/dt = rN. Unsustainable in nature; leads to boom-and-bust cycles or eventual resource depletion." , front_translations: {"es":"Crescimento Exponencial","de":"Exponentielles Wachstum","fr":"Croissance exponentielle","tr":"Üstel Büyüme","nl":"Exponentiële groei","ru":"Экспоненциальный рост","zh":"指数增长","pt_BR":"Crescimento Exponencial","pt_PT":"Crescimento Exponencial"}, back_translations: {"es":"Crescimento populacional a una taxa constante (curva en J). Ocorre cuando los recursos son ilimitados. dN/dt = rN. Insustentable en la natureza; leva a ciclos de explosão y colapso o eventual esgotamento de recursos.","de":"Populationswachstum mit konstanter Rate (J-förmige Kurve). Tritt auf, wenn Ressourcen unbegrenzt sind. dN/dt = rN. In der Natur nicht nachhaltig; führt zu Boom-und-Bust-Zyklen oder schließlich zur Ressourcenerschöpfung.","fr":"Croissance d'une population à taux constant (courbe en J). Se produit lorsque les ressources sont illimitées. dN/dt = rN. Insoutenable dans la nature ; conduit à des cycles d'explosion et d'effondrement ou à l'épuisement des ressources.","tr":"Sabit bir hızda gerçekleşen popülasyon büyümesi (J şeklinde eğri). Kaynaklar sınırsız olduğunda ortaya çıkar. dN/dt = rN. Doğada sürdürülemez; patlama-çöküş döngülerine veya kaynak tükenmesine yol açar.","nl":"Populatiegroei met een constante snelheid (J-vormige curve). Treedt op wanneer bronnen onbeperkt zijn. dN/dt = rN. Onhoudbaar in de natuur; leidt tot boom-and-bust-cycli of uiteindelijke uitputting van hulpbronnen.","ru":"Рост популяции с постоянной скоростью (J-образная кривая). Происходит при неограниченных ресурсах. dN/dt = rN. В природе неустойчив; приводит к циклам «бум—спад» или полному истощению ресурсов.","zh":"以恒定速率进行的种群增长（J形曲线）。发生在资源无限时。dN/dt = rN。在自然界中不可持续；导致繁荣-崩溃循环或最终资源耗尽。","pt_BR":"Crescimento populacional a uma taxa constante (curva em J). Ocorre quando os recursos são ilimitados. dN/dt = rN. Insustentável na natureza; leva a ciclos de explosão e colapso ou eventual esgotamento de recursos.","pt_PT":"Crescimento populacional a uma taxa constante (curva em J). Ocorre quando os recursos são ilimitados. dN/dt = rN. Insustentável na natureza; leva a ciclos de expansão e colapso ou eventual esgotamento de recursos."}},
  { id: 'dc-biology-0091', deck_id: 'deck-biology', sort_order: 91, front: "Symbiosis: Mutualism", back: "A relationship in which both species benefit. Examples: mycorrhizae (fungi + plant roots), nitrogen-fixing bacteria in legume root nodules, cleaner fish removing parasites from larger fish." , front_translations: {"es":"Simbiose: Mutualismo","de":"Symbiose: Mutualismus","fr":"Symbiose : mutualisme","tr":"Simbiyoz: Mutualizm","nl":"Symbiose: Mutualisme","ru":"Симбиоз: мутуализм","zh":"共生：互利共生","pt_BR":"Simbiose: Mutualismo","pt_PT":"Simbiose: Mutualismo"}, back_translations: {"es":"Una relación en que ambas las especies se beneficiam. Exemplos: micorrizas (fungos + raíces de plantas), bacterias fixadoras de nitrógeno en nódulos radiculares de leguminosas, peixes-limpadores removendo parasitas de peixes mayores.","de":"Eine Beziehung, von der beide Arten profitieren. Beispiele: Mykorrhiza (Pilze + Pflanzenwurzeln), stickstoffixierende Bakterien in Hülsenfrüchten-Wurzelknollen, Putzerfische, die Parasiten von größeren Fischen entfernen.","fr":"Une relation dans laquelle les deux espèces bénéficient mutuellement. Exemples : mycorhizes (champignons + racines de plantes), bactéries fixatrices d'azote dans les nodules racinaires des légumineuses, poissons nettoyeurs éliminant les parasites des grands poissons.","tr":"Her iki türün de yarar sağladığı bir ilişki. Örnekler: mikoriza (mantar + bitki kökleri), baklagil kök nodüllerindeki azot bağlayan bakteriler, büyük balıklardan parazitleri temizleyen temizleyici balıklar.","nl":"Een relatie waarbij beide soorten baat hebben. Voorbeelden: mycorrhiza (schimmels + plantenworrels), stikstofbindende bacteriën in leguminose wortelknolletjes, reinigingsvissen die parasieten van grotere vissen verwijderen.","ru":"Взаимоотношения, при которых оба вида получают пользу. Примеры: микориза (грибы + корни растений), азотфиксирующие бактерии в клубеньках бобовых, рыбы-чистильщики, удаляющие паразитов с крупных рыб.","zh":"双方物种均受益的关系。例子：菌根（真菌+植物根），豆科植物根瘤中的固氮细菌，清洁鱼为大鱼清除寄生虫。","pt_BR":"Uma relação em que ambas as espécies se beneficiam. Exemplos: micorrizas (fungos + raízes de plantas), bactérias fixadoras de nitrogênio em nódulos radiculares de leguminosas, peixes-limpadores removendo parasitas de peixes maiores.","pt_PT":"Uma relação em que ambas as espécies beneficiam. Exemplos: micorrizas (fungos + raízes de plantas), bactérias fixadoras de azoto em nódulos radiculares de leguminosas, peixes-limpadores a remover parasitas de peixes maiores."}},
  { id: 'dc-biology-0092', deck_id: 'deck-biology', sort_order: 92, front: "Symbiosis: Commensalism", back: "A relationship in which one species benefits and the other is neither helped nor harmed. E.g., barnacles on whales, birds nesting in trees, remora fish attached to sharks." , front_translations: {"es":"Simbiose: Comensalismo","de":"Symbiose: Kommensalismus","fr":"Symbiose : commensalisme","tr":"Simbiyoz: Kommensalizm","nl":"Symbiose: Commensalisme","ru":"Симбиоз: комменсализм","zh":"共生：偏利共生","pt_BR":"Simbiose: Comensalismo","pt_PT":"Simbiose: Comensalismo"}, back_translations: {"es":"Una relación en que una especie se beneficia y a outra no es ajudada nem prejudicada. Ex.: cracas en baleias, pássaros ninhos en árvores, peixes-remora presos a tubarões.","de":"Eine Beziehung, bei der eine Art profitiert und die andere weder begünstigt noch geschädigt wird. Z. B. Seepocken auf Walen, Vögel, die in Bäumen nisten, Remora-Fische, die an Haien haften.","fr":"Une relation dans laquelle une espèce bénéficie et l'autre n'est ni aidée ni nuisée. Ex. : bernacles sur les baleines, oiseaux nichant dans les arbres, poissons rémoras fixés aux requins.","tr":"Bir türün yarar sağladığı, diğerinin ne fayda gördüğü ne de zarar gördüğü bir ilişki. Örn. balinaların üzerindeki midyeler, ağaçlarda yuva yapan kuşlar, köpekbalıklarına tutunan remora balıkları.","nl":"Een relatie waarbij één soort voordeel heeft en de andere noch geholpen noch geschaad wordt. Bijv. barnakels op walvissen, vogels die nestelen in bomen, remora's die vastgehecht zijn aan haaien.","ru":"Взаимоотношения, при которых один вид получает пользу, а другой не получает ни пользы, ни вреда. Например: усоногие ракообразные на китах, птицы, гнездящиеся на деревьях, рыбы-прилипалы, прикреплённые к акулам.","zh":"一方受益而另一方既不受益也不受害的关系。例如：附着在鲸鱼上的藤壶、在树上筑巢的鸟类、附着在鲨鱼身上的䲟鱼。","pt_BR":"Uma relação em que uma espécie se beneficia e a outra não é ajudada nem prejudicada. Ex.: cracas em baleias, pássaros ninhos em árvores, peixes-rêmora presos a tubarões.","pt_PT":"Uma relação em que uma espécie beneficia e a outra não é ajudada nem prejudicada. Ex.: cracas em baleias, pássaros a ninhar em árvores, peixes-rêmora presos a tubarões."}},
  { id: 'dc-biology-0093', deck_id: 'deck-biology', sort_order: 93, front: "Symbiosis: Parasitism", back: "A relationship in which one organism (parasite) benefits at the expense of the host. Examples: tapeworms, ticks, fleas, mistletoe. Parasites do not usually kill hosts immediately." , front_translations: {"es":"Simbiose: Parasitismo","de":"Symbiose: Parasitismus","fr":"Symbiose : parasitisme","tr":"Simbiyoz: Parazitizm","nl":"Symbiose: Parasitisme","ru":"Симбиоз: паразитизм","zh":"共生：寄生","pt_BR":"Simbiose: Parasitismo","pt_PT":"Simbiose: Parasitismo"}, back_translations: {"es":"Una relación en que un organismo (parasita) se beneficia a las custas del hospedero. Exemplos: tenias, carrapatos, pulgas, erva-de-passarinho. Los parasitas generalmente no matam los hospederos imediatamente.","de":"Eine Beziehung, bei der ein Organismus (Parasit) auf Kosten des Wirts profitiert. Beispiele: Bandwürmer, Zecken, Flöhe, Mistelkraut. Parasiten töten ihre Wirte in der Regel nicht sofort.","fr":"Une relation dans laquelle un organisme (parasite) bénéficie aux dépens de l'hôte. Exemples : ténias, tiques, puces, gui. Les parasites ne tuent généralement pas leurs hôtes immédiatement.","tr":"Bir organizmanın (parazit) konağın zararına yarar sağladığı ilişki. Örnekler: tenyalar, keneler, pireler, ökseotu. Parazitler genellikle konakları hemen öldürmez.","nl":"Een relatie waarbij een organisme (parasiet) profiteert ten koste van de gastheer. Voorbeelden: lintwurmen, teken, vlooien, maretak. Parasieten doden hun gastheren gewoonlijk niet onmiddellijk.","ru":"Взаимоотношения, при которых один организм (паразит) извлекает пользу за счёт хозяина. Примеры: ленточные черви, клещи, блохи, омела. Паразиты, как правило, не убивают хозяев немедленно.","zh":"一种生物（寄生物）以牺牲宿主为代价获益的关系。例子：绦虫、蜱虫、跳蚤、槲寄生。寄生物通常不会立即杀死宿主。","pt_BR":"Uma relação em que um organismo (parasita) se beneficia às custas do hospedeiro. Exemplos: tênias, carrapatos, pulgas, erva-de-passarinho. Os parasitas geralmente não matam os hospedeiros imediatamente.","pt_PT":"Uma relação em que um organismo (parasita) beneficia à custa do hospedeiro. Exemplos: ténia, carraças, pulgas, visco. Os parasitas geralmente não matam os hospedeiros imediatamente."}},
  { id: 'dc-biology-0094', deck_id: 'deck-biology', sort_order: 94, front: "Ecological Succession", back: "The gradual process of change in species composition of an ecosystem over time. Primary succession begins on bare rock; secondary succession occurs after disturbance (fire, flood) in an area with existing soil." , front_translations: {"es":"Sucesión Ecológica","de":"Ökologische Sukzession","fr":"Succession écologique","tr":"Ekolojik Sükseyon","nl":"Ecologische successie","ru":"Экологическая сукцессия","zh":"生态演替","pt_BR":"Sucessão Ecológica","pt_PT":"Sucessão Ecológica"}, back_translations: {"es":"El proceso gradual de cambio en la composición de especies de un ecossistema a lo ancho del tiempo. La sucesión primária começa en rocha nua; a sucesión secundária ocurre após perturbación (fuego, inundación) en una área con solo existente.","de":"Der allmähliche Prozess der Veränderung in der Artenzusammensetzung eines Ökosystems im Laufe der Zeit. Primärsukzession beginnt auf nacktem Fels; Sekundärsukzession findet nach Störungen (Feuer, Überschwemmung) in Gebieten mit vorhandenem Boden statt.","fr":"Le processus graduel de changement dans la composition en espèces d'un écosystème au fil du temps. La succession primaire débute sur la roche nue ; la succession secondaire se produit après une perturbation (feu, inondation) dans une zone avec un sol existant.","tr":"Bir ekosistemin tür kompozisyonunun zamanla kademeli olarak değişmesi süreci. Birincil sükseyon çıplak kayadan başlar; ikincil sükseyon mevcut toprağı olan bir alanda bozulma (yangın, sel) sonrasında gerçekleşir.","nl":"Het geleidelijke proces van verandering in soortsamenstelling van een ecosysteem in de loop van de tijd. Primaire successie begint op kale rots; secundaire successie treedt op na verstoring (brand, overstromingen) in een gebied met bestaande bodem.","ru":"Постепенный процесс изменения видового состава экосистемы с течением времени. Первичная сукцессия начинается на голой породе; вторичная сукцессия происходит после нарушения (пожар, наводнение) на участке с уже имеющейся почвой.","zh":"生态系统物种组成随时间逐渐变化的过程。初生演替从裸岩开始；次生演替发生在有土壤存在的地区受到干扰（火灾、洪水）之后。","pt_BR":"O processo gradual de mudança na composição de espécies de um ecossistema ao longo do tempo. A sucessão primária começa em rocha nua; a sucessão secundária ocorre após perturbação (fogo, inundação) em uma área com solo existente.","pt_PT":"O processo gradual de mudança na composição de espécies de um ecossistema ao longo do tempo. A sucessão primária começa em rocha nua; a sucessão secundária ocorre após perturbação (fogo, inundação) numa área com solo existente."}},
  { id: 'dc-biology-0095', deck_id: 'deck-biology', sort_order: 95, front: "Nitrogen Cycle", back: "N₂ from atmosphere is fixed by bacteria (Rhizobium) into NH₃/NH₄⁺, nitrified to NO₃⁻, taken up by plants, returned to soil through decomposition, and denitrified back to N₂." , front_translations: {"es":"Ciclo del Nitrógeno","de":"Stickstoffkreislauf","fr":"Cycle de l'azote","tr":"Azot Döngüsü","nl":"Stikstofkringloop","ru":"Азотный цикл","zh":"氮循环","pt_BR":"Ciclo do Nitrogênio","pt_PT":"Ciclo do Azoto"}, back_translations: {"es":"El N₂ de la atmosfera es fixado por bacterias (Rhizobium) en NH₃/NH₄⁺, nitrificado a NO₃⁻, absorbido por las plantas, devolvido al solo por la decomposición y desnitrificado de volta a N₂.","de":"N₂ aus der Atmosphäre wird durch Bakterien (Rhizobium) zu NH₃/NH₄⁺ fixiert, zu NO₃⁻ nitrifiiert, von Pflanzen aufgenommen, durch Zersetzung in den Boden zurückgeführt und durch Denitrifikation wieder zu N₂ umgewandelt.","fr":"Le N₂ atmosphérique est fixé par des bactéries (Rhizobium) en NH₃/NH₄⁺, nitrifié en NO₃⁻, absorbé par les plantes, retourné au sol par décomposition, et dénitrifié en N₂.","tr":"Atmosferdeki N₂, bakteriler (Rhizobium) tarafından NH₃/NH₄⁺'ya dönüştürülür, NO₃⁻'e nitrifikasyon yapılır, bitkiler tarafından alınır, ayrışma yoluyla toprağa geri verilir ve denitrifikasyon ile N₂'ye geri dönüştürülür.","nl":"N₂ uit de atmosfeer wordt gefixeerd door bacteriën (Rhizobium) tot NH₃/NH₄⁺, genitrificeerd tot NO₃⁻, opgenomen door planten, via decompostie teruggebracht in de bodem en gedenitrificeerd terug naar N₂.","ru":"N₂ из атмосферы фиксируется бактериями (Rhizobium) в NH₃/NH₄⁺, нитрифицируется до NO₃⁻, усваивается растениями, возвращается в почву через разложение и денитрифицируется обратно в N₂.","zh":"大气中的N₂经细菌（根瘤菌）固定为NH₃/NH₄⁺，经硝化作用转化为NO₃⁻，被植物吸收，通过分解返回土壤，并经反硝化作用转化回N₂。","pt_BR":"O N₂ da atmosfera é fixado por bactérias (Rhizobium) em NH₃/NH₄⁺, nitrificado a NO₃⁻, absorvido pelas plantas, devolvido ao solo pela decomposição e desnitrificado de volta a N₂.","pt_PT":"O N₂ da atmosfera é fixado por bactérias (Rhizobium) em NH₃/NH₄⁺, nitrificado a NO₃⁻, absorvido pelas plantas, devolvido ao solo pela decomposição e desnitrificado de volta a N₂."}},
  { id: 'dc-biology-0096', deck_id: 'deck-biology', sort_order: 96, front: "Carbon Cycle", back: "Carbon flows through photosynthesis (CO₂ fixed), respiration (CO₂ released), decomposition, combustion, and ocean absorption. Burning fossil fuels increases atmospheric CO₂, driving climate change." , front_translations: {"es":"Ciclo del Carbono","de":"Kohlenstoffkreislauf","fr":"Cycle du carbone","tr":"Karbon Döngüsü","nl":"Koolstofkringloop","ru":"Углеродный цикл","zh":"碳循环","pt_BR":"Ciclo do Carbono","pt_PT":"Ciclo do Carbono"}, back_translations: {"es":"El carbono flui por la fotossíntese (fixación de CO₂), respiración (liberación de CO₂), decomposición, combustión y absorción oceanica. La queima de combustibles fósseis aumenta el CO₂ atmosférico, impulsionando las cambios climáticas.","de":"Kohlenstoff fließt durch Photosynthese (CO₂-Fixierung), Respiration (CO₂-Freisetzung), Zersetzung, Verbrennung und Ozeanabsorption. Die Verbrennung fossiler Brennstoffe erhöht den atmosphärischen CO₂-Gehalt und befördert den Klimawandel.","fr":"Le carbone circule par la photosynthèse (fixation du CO₂), la respiration (libération du CO₂), la décomposition, la combustion et l'absorption par les océans. La combustion des combustibles fossiles augmente le CO₂ atmosphérique, entraînant le changement climatique.","tr":"Karbon fotosentez (CO₂ sabitlenir), solunum (CO₂ serbest bırakılır), ayrışma, yanma ve okyanus absorpsiyonu yoluyla akar. Fosil yakıtların yakılması atmosferik CO₂'yi artırarak iklim değişikliğini tetikler.","nl":"Koolstof stroomt door fotosynthese (CO₂-vastlegging), respiratie (CO₂-vrijgave), decompostie, verbranding en oceaanabsorptie. Verbranding van fossiele brandstoffen verhoogt atmosferisch CO₂, wat klimaatverandering aandrijft.","ru":"Углерод циркулирует через фотосинтез (фиксация CO₂), дыхание (выделение CO₂), разложение, сжигание и поглощение океаном. Сжигание ископаемого топлива увеличивает содержание CO₂ в атмосфере, способствуя изменению климата.","zh":"碳通过光合作用（固定CO₂）、呼吸作用（释放CO₂）、分解、燃烧和海洋吸收流动。燃烧化石燃料增加大气中的CO₂，推动气候变化。","pt_BR":"O carbono flui pela fotossíntese (fixação de CO₂), respiração (liberação de CO₂), decomposição, combustão e absorção oceânica. A queima de combustíveis fósseis aumenta o CO₂ atmosférico, impulsionando as mudanças climáticas.","pt_PT":"O carbono flui pela fotossíntese (fixação de CO₂), respiração (libertação de CO₂), decomposição, combustão e absorção oceânica. A queima de combustíveis fósseis aumenta o CO₂ atmosférico, impulsionando as alterações climáticas."}},
  { id: 'dc-biology-0097', deck_id: 'deck-biology', sort_order: 97, front: "Protein Structure: Primary", back: "The sequence of amino acids in a polypeptide chain, linked by peptide bonds. This sequence is encoded by DNA and ultimately determines all higher levels of protein structure and function." , front_translations: {"es":"Estrutura de Proteína: Primária","de":"Proteinstruktur: Primär","fr":"Structure des protéines : primaire","tr":"Protein Yapısı: Birincil","nl":"Eiwitstructuur: Primair","ru":"Структура белка: первичная","zh":"蛋白质结构：一级结构","pt_BR":"Estrutura de Proteína: Primária","pt_PT":"Estrutura de Proteína: Primária"}, back_translations: {"es":"La secuencia de aminoácidos en una cadeia polipeptídica, ligados por enlaces peptídicas. Esta secuencia es codificada por el DNA y determina, en última análise, todos los niveles superiores de estructura y función proteica.","de":"Die Abfolge von Aminosäuren in einer Polypeptidkette, verbunden durch Peptidbindungen. Diese Sequenz wird durch DNA kodiert und bestimmt letztlich alle höheren Ebenen der Proteinstruktur und -funktion.","fr":"La séquence des acides aminés dans une chaîne polypeptidique, reliés par des liaisons peptidiques. Cette séquence est codée par l'ADN et détermine en fin de compte tous les niveaux supérieurs de la structure et de la fonction protéique.","tr":"Bir polipeptit zincirindeki amino asitlerin dizisi, peptit bağlarıyla birbirine bağlanmıştır. Bu dizi DNA tarafından kodlanır ve nihayetinde protein yapısının ve işlevinin tüm üst düzeylerini belirler.","nl":"De volgorde van aminozuren in een polypeptideketen, verbonden door peptidebindingen. Deze volgorde wordt gecodeerd door DNA en bepaalt uiteindelijk alle hogere niveaus van eiwitstructuur en -functie.","ru":"Последовательность аминокислот в полипептидной цепи, связанных пептидными связями. Эта последовательность закодирована в ДНК и в конечном счёте определяет все более высокие уровни структуры и функции белка.","zh":"多肽链中氨基酸的序列，由肽键连接。该序列由DNA编码，最终决定蛋白质结构和功能的所有更高层次。","pt_BR":"A sequência de aminoácidos em uma cadeia polipeptídica, ligados por ligações peptídicas. Esta sequência é codificada pelo DNA e determina, em última análise, todos os níveis superiores de estrutura e função proteica.","pt_PT":"A sequência de aminoácidos numa cadeia polipeptídica, ligados por ligações peptídicas. Esta sequência é codificada pelo DNA e determina, em última análise, todos os níveis superiores de estrutura e função proteica."}},
  { id: 'dc-biology-0098', deck_id: 'deck-biology', sort_order: 98, front: "Protein Structure: Secondary", back: "Local folding patterns stabilized by hydrogen bonds between backbone atoms. Two main types: α-helix and β-pleated sheet. Does not involve the amino acid side chains (R groups)." , front_translations: {"es":"Estrutura de Proteína: Secundária","de":"Proteinstruktur: Sekundär","fr":"Structure des protéines : secondaire","tr":"Protein Yapısı: İkincil","nl":"Eiwitstructuur: Secundair","ru":"Структура белка: вторичная","zh":"蛋白质结构：二级结构","pt_BR":"Estrutura de Proteína: Secundária","pt_PT":"Estrutura de Proteína: Secundária"}, back_translations: {"es":"Padrões de dobramento local estabilizados por enlaces de hidrógeno entre átomos de la cadeia principal. Dois tipos principales: α-hélice y hoja β pregueada. No involucra las cadeias laterais de los aminoácidos (grupos R).","de":"Lokale Faltungsmuster, stabilisiert durch Wasserstoffbrückenbindungen zwischen Rückgratatomen. Zwei Haupttypen: α-Helix und β-Faltblatt. Betrifft nicht die Aminosäure-Seitenketten (R-Gruppen).","fr":"Configurations de repliement locales stabilisées par des liaisons hydrogène entre les atomes du squelette. Deux types principaux : hélice α et feuillet β plissé. N'implique pas les chaînes latérales des acides aminés (groupes R).","tr":"Omurga atomları arasındaki hidrojen bağlarıyla stabilize edilmiş yerel kıvrım desenleri. İki ana tür: α-heliks ve β-kıvrımlı tabaka. Amino asit yan zincirlerini (R grupları) içermez.","nl":"Lokale vouwpatronen gestabiliseerd door waterstofbruggen tussen ruggraatatomen. Twee hoofdtypen: α-helix en β-geplooide plaat. Omvat de aminozuur-zijketens (R-groepen) niet.","ru":"Локальные структуры укладки, стабилизированные водородными связями между атомами основной цепи. Два основных типа: α-спираль и β-складчатый лист. Не затрагивает боковые цепи аминокислот (R-группы).","zh":"通过主链原子间氢键稳定的局部折叠模式。两种主要类型：α-螺旋和β-折叠。不涉及氨基酸侧链（R基）。","pt_BR":"Padrões de dobramento local estabilizados por ligações de hidrogênio entre átomos da cadeia principal. Dois tipos principais: α-hélice e folha β pregueada. Não envolve as cadeias laterais dos aminoácidos (grupos R).","pt_PT":"Padrões de dobramento local estabilizados por ligações de hidrogénio entre átomos da cadeia principal. Dois tipos principais: α-hélice e folha β pregueada. Não envolve as cadeias laterais dos aminoácidos (grupos R)."}},
  { id: 'dc-biology-0099', deck_id: 'deck-biology', sort_order: 99, front: "Protein Structure: Tertiary", back: "The overall 3D shape of a single polypeptide chain, stabilized by interactions between R groups: hydrophobic interactions, disulfide bonds, hydrogen bonds, and ionic bonds." , front_translations: {"es":"Estrutura de Proteína: Terciária","de":"Proteinstruktur: Tertiär","fr":"Structure des protéines : tertiaire","tr":"Protein Yapısı: Üçüncül","nl":"Eiwitstructuur: Tertiair","ru":"Структура белка: третичная","zh":"蛋白质结构：三级结构","pt_BR":"Estrutura de Proteína: Terciária","pt_PT":"Estrutura de Proteína: Terciária"}, back_translations: {"es":"La forma 3D global de una única cadeia polipeptídica, estabilizada por interacciones entre grupos R: interacciones hidrofóbicas, pontes dissulfeto, enlaces de hidrógeno y enlaces ionicas.","de":"Die gesamte 3D-Form einer einzelnen Polypeptidkette, stabilisiert durch Wechselwirkungen zwischen R-Gruppen: hydrophobe Wechselwirkungen, Disulfidbindungen, Wasserstoffbrückenbindungen und ionische Bindungen.","fr":"La forme tridimensionnelle globale d'une seule chaîne polypeptidique, stabilisée par des interactions entre groupes R : interactions hydrophobes, ponts disulfure, liaisons hydrogène et liaisons ioniques.","tr":"Tek bir polipeptit zincirinin genel 3B şekli, R grupları arasındaki etkileşimlerle stabilize edilir: hidrofobik etkileşimler, disülfit bağları, hidrojen bağları ve iyonik bağlar.","nl":"De algehele 3D-vorm van een enkele polypeptideketen, gestabiliseerd door interacties tussen R-groepen: hydrofobe interacties, disulfidebruggen, waterstofbruggen en ionische bindingen.","ru":"Общая трёхмерная форма одиночной полипептидной цепи, стабилизированная взаимодействиями между R-группами: гидрофобными взаимодействиями, дисульфидными связями, водородными связями и ионными связями.","zh":"单条多肽链的整体三维形状，由R基之间的相互作用稳定：疏水相互作用、二硫键、氢键和离子键。","pt_BR":"A forma 3D global de uma única cadeia polipeptídica, estabilizada por interações entre grupos R: interações hidrofóbicas, pontes dissulfeto, ligações de hidrogênio e ligações iônicas.","pt_PT":"A forma 3D global de uma única cadeia polipeptídica, estabilizada por interações entre grupos R: interações hidrofóbicas, pontes dissulfeto, ligações de hidrogénio e ligações iónicas."}},
  { id: 'dc-biology-0100', deck_id: 'deck-biology', sort_order: 100, front: "Protein Structure: Quaternary", back: "The arrangement of two or more polypeptide subunits into a functional protein complex. Example: hemoglobin (4 subunits). Not all proteins have quaternary structure." , front_translations: {"es":"Estrutura de Proteína: Quaternária","de":"Proteinstruktur: Quartär","fr":"Structure des protéines : quaternaire","tr":"Protein Yapısı: Dördüncül","nl":"Eiwitstructuur: Quaternair","ru":"Структура белка: четвертичная","zh":"蛋白质结构：四级结构","pt_BR":"Estrutura de Proteína: Quaternária","pt_PT":"Estrutura de Proteína: Quaternária"}, back_translations: {"es":"El arranjo de de los o más subunidades polipeptídicas en un complexo proteico funcional. Exemplo: hemoglobina (4 subunidades). Nem todas las proteínas tienen estructura quaternária.","de":"Die Anordnung von zwei oder mehr Polypeptid-Untereinheiten zu einem funktionellen Proteinkomplex. Beispiel: Hämoglobin (4 Untereinheiten). Nicht alle Proteine haben eine quartäre Struktur.","fr":"L'arrangement de deux ou plusieurs sous-unités polypeptidiques formant un complexe protéique fonctionnel. Exemple : l'hémoglobine (4 sous-unités). Toutes les protéines ne possèdent pas de structure quaternaire.","tr":"İki veya daha fazla polipeptit alt biriminin işlevsel bir protein kompleksi oluşturacak şekilde düzenlenmesi. Örnek: hemoglobin (4 alt birim). Tüm proteinlerin dördüncül yapısı yoktur.","nl":"De rangschikking van twee of meer polypeptidesubeenheden in een functioneel eiwitcomplex. Voorbeeld: hemoglobine (4 subeenheden). Niet alle eiwitten hebben een quaternaire structuur.","ru":"Расположение двух или более полипептидных субъединиц, образующих функциональный белковый комплекс. Пример: гемоглобин (4 субъединицы). Не все белки обладают четвертичной структурой.","zh":"两条或多条多肽亚基排列成功能性蛋白质复合物。例子：血红蛋白（4个亚基）。并非所有蛋白质都有四级结构。","pt_BR":"O arranjo de duas ou mais subunidades polipeptídicas em um complexo proteico funcional. Exemplo: hemoglobina (4 subunidades). Nem todas as proteínas têm estrutura quaternária.","pt_PT":"O arranjo de duas ou mais subunidades polipeptídicas num complexo proteico funcional. Exemplo: hemoglobina (4 subunidades). Nem todas as proteínas têm estrutura quaternária."}},
  { id: 'dc-biology-0101', deck_id: 'deck-biology', sort_order: 101, front: "Chromosomes and Chromatin", back: "DNA is wound around histone proteins forming nucleosomes, then further compacted into chromatin. During cell division, chromatin condenses into distinct chromosomes. Human cells have 46 chromosomes (23 pairs)." , front_translations: {"es":"Cromossomos y cromatina","de":"Chromosomen und Chromatin","fr":"Chromosomes et chromatine","tr":"Kromozomlar ve Kromatin","nl":"Chromosomen en chromatine","ru":"Хромосомы и хроматин","zh":"染色体与染色质","pt_BR":"Cromossomos e cromatina","pt_PT":"Cromossomas e cromatina"}, back_translations: {"es":"El DNA es enrolado alrededor de proteínas histonas formando nucleossomos, que son aún más compactados en cromatina. Durante a divisão celular, a cromatina se condensa en cromossomos distintos. As células humanas possuem 46 cromossomos (23 pares).","de":"Die DNA ist um Histonproteine gewickelt und bildet Nukleosomen, die dann weiter zu Chromatin verdichtet werden. Bei der Zellteilung kondensiert das Chromatin zu deutlich sichtbaren Chromosomen. Menschliche Zellen haben 46 Chromosomen (23 Paare).","fr":"L'ADN est enroulé autour de protéines histones formant des nucléosomes, puis compacté en chromatine. Lors de la division cellulaire, la chromatine se condense en chromosomes distincts. Les cellules humaines possèdent 46 chromosomes (23 paires).","tr":"DNA, nükleozomlar oluşturarak histon proteinlerinin etrafına sarılır ve ardından daha da sıkıştırılarak kromatine dönüşür. Hücre bölünmesi sırasında kromatin belirgin kromozomlara kondanse olur. İnsan hücrelerinde 46 kromozom (23 çift) bulunur.","nl":"DNA is gewonden om histoneiwitten en vormt nucleosomen, die vervolgens verder worden gecomprimeerd tot chromatine. Tijdens celdeling condenseren chromatine tot afzonderlijke chromosomen. Menselijke cellen hebben 46 chromosomen (23 paren).","ru":"ДНК намотана на белки гистоны, образуя нуклеосомы, которые затем дополнительно уплотняются в хроматин. В ходе деления клетки хроматин конденсируется в отчётливые хромосомы. В клетках человека 46 хромосом (23 пары).","zh":"DNA缠绕在组蛋白上形成核小体，进而压缩成染色质。细胞分裂时，染色质凝聚成清晰可见的染色体。人类细胞含有46条染色体（23对）。","pt_BR":"O DNA é enrolado em torno de proteínas histonas formando nucleossomos, que são ainda mais compactados em cromatina. Durante a divisão celular, a cromatina se condensa em cromossomos distintos. As células humanas possuem 46 cromossomos (23 pares).","pt_PT":"O DNA é enrolado em torno de proteínas histonas formando nucleossomas, que são ainda mais compactados em cromatina. Durante a divisão celular, a cromatina condensa-se em cromossomas distintos. As células humanas têm 46 cromossomas (23 pares)."}},
  { id: 'dc-biology-0102', deck_id: 'deck-biology', sort_order: 102, front: "Telomere", back: "Repetitive DNA sequences (TTAGGG in humans) at the ends of linear chromosomes. Protect chromosome ends from degradation and fusion. Shortened with each cell division; associated with aging and cancer." , front_translations: {"es":"Telomero","de":"Telomer","fr":"Télomère","tr":"Telomer","nl":"Telomeer","ru":"Теломер","zh":"端粒","pt_BR":"Telômero","pt_PT":"Telómero"}, back_translations: {"es":"Sequencias repetitivas de DNA (TTAGGG en humanos) en las extremidades de los cromossomos lineares. Protegem las extremidades de los cromossomos contra degradación y fusión. Encurtam a cada divisão celular; associados al envelhecimento y al cancer.","de":"Repetitive DNA-Sequenzen (TTAGGG beim Menschen) an den Enden linearer Chromosomen. Schützen Chromosomenenden vor Abbau und Fusion. Verkürzen sich mit jeder Zellteilung; werden mit Alterung und Krebs in Verbindung gebracht.","fr":"Séquences d'ADN répétitives (TTAGGG chez l'humain) aux extrémités des chromosomes linéaires. Protègent les extrémités des chromosomes contre la dégradation et la fusion. Raccourcissent à chaque division cellulaire ; associés au vieillissement et au cancer.","tr":"Doğrusal kromozomların uçlarındaki tekrarlayan DNA dizileri (insanlarda TTAGGG). Kromozom uçlarını bozunma ve füzyondan korur. Her hücre bölünmesiyle kısalır; yaşlanma ve kanserle ilişkilidir.","nl":"Repetitieve DNA-sequenties (TTAGGG bij mensen) aan de uiteinden van lineaire chromosomen. Beschermen chromosoomeinden tegen afbraak en fusie. Worden korter bij elke celdeling; geassocieerd met veroudering en kanker.","ru":"Повторяющиеся последовательности ДНК (TTAGGG у человека) на концах линейных хромосом. Защищают концы хромосом от деградации и слияния. Укорачиваются с каждым делением клетки; связаны со старением и раком.","zh":"线性染色体末端的重复DNA序列（人类中为TTAGGG）。保护染色体末端免于降解和融合。随每次细胞分裂而缩短，与衰老和癌症相关。","pt_BR":"Sequências repetitivas de DNA (TTAGGG em humanos) nas extremidades dos cromossomos lineares. Protegem as extremidades dos cromossomos contra degradação e fusão. Encurtam a cada divisão celular; associados ao envelhecimento e ao câncer.","pt_PT":"Sequências de DNA repetitivas (TTAGGG nos humanos) nas extremidades dos cromossomas lineares. Protegem as extremidades dos cromossomas contra a degradação e fusão. Encurtam a cada divisão celular; associados ao envelhecimento e ao cancro."}},
  { id: 'dc-biology-0103', deck_id: 'deck-biology', sort_order: 103, front: "Plasmid", back: "A small, circular, double-stranded DNA molecule in bacteria separate from the main chromosome. Often carries genes for antibiotic resistance or metabolic advantages. Key tool in recombinant DNA technology." , front_translations: {"es":"Plasmídeo","de":"Plasmid","fr":"Plasmide","tr":"Plazmit","nl":"Plasmide","ru":"Плазмида","zh":"质粒","pt_BR":"Plasmídeo","pt_PT":"Plasmídeo"}, back_translations: {"es":"Una pequeña molécula de DNA circular de fita dupla en bacterias, separada del cromossomo principal. Frequentemente carrega genes para resistencia a antibióticos o vantajes metabólicas. Ferramenta esencial en la tecnologia del DNA recombinante.","de":"Ein kleines, kreisförmiges, doppelsträngiges DNA-Molekül in Bakterien, das vom Hauptchromosom getrennt ist. Trägt häufig Gene für Antibiotikaresistenz oder Stoffwechselvorteile. Wichtiges Werkzeug in der rekombinanten DNA-Technologie.","fr":"Une petite molécule d'ADN circulaire double brin chez les bactéries, distincte du chromosome principal. Porte souvent des gènes de résistance aux antibiotiques ou des avantages métaboliques. Outil clé en technologie de l'ADN recombinant.","tr":"Bakterilerde ana kromozomdan ayrı olan küçük, dairesel, çift sarmallı bir DNA molekülü. Genellikle antibiyotik direnci veya metabolik avantajlar için genler taşır. Rekombinant DNA teknolojisinde temel bir araçtır.","nl":"Een klein, circulair, dubbelstrengs DNA-molecuul in bacteriën, los van het hoofdchromosoom. Draagt vaak genen voor antibioticaresistentie of metabole voordelen. Belangrijk hulpmiddel in recombinante DNA-technologie.","ru":"Небольшая кольцевая двуцепочечная молекула ДНК у бактерий, отдельная от главной хромосомы. Часто несёт гены устойчивости к антибиотикам или метаболические преимущества. Ключевой инструмент рекомбинантных ДНК-технологий.","zh":"细菌中独立于主染色体的小型环状双链DNA分子。通常携带抗生素抗性基因或代谢优势基因。是重组DNA技术中的重要工具。","pt_BR":"Uma pequena molécula de DNA circular de fita dupla em bactérias, separada do cromossomo principal. Frequentemente carrega genes para resistência a antibióticos ou vantagens metabólicas. Ferramenta essencial na tecnologia do DNA recombinante.","pt_PT":"Uma pequena molécula de DNA circular de cadeia dupla em bactérias, separada do cromossoma principal. Frequentemente transporta genes de resistência a antibióticos ou vantagens metabólicas. Ferramenta fundamental na tecnologia do DNA recombinante."}},
  { id: 'dc-biology-0104', deck_id: 'deck-biology', sort_order: 104, front: "Recombinant DNA Technology", back: "Techniques to join DNA from different sources. Key tools: restriction enzymes (cut DNA at specific sequences), DNA ligase (joins fragments), vectors (plasmids or viruses to carry DNA into host cells)." , front_translations: {"es":"Tecnologia del DNA recombinante","de":"Rekombinante DNA-Technologie","fr":"Technologie de l'ADN recombinant","tr":"Rekombinant DNA Teknolojisi","nl":"Recombinante DNA-technologie","ru":"Технология рекомбинантной ДНК","zh":"重组DNA技术","pt_BR":"Tecnologia do DNA recombinante","pt_PT":"Tecnologia do DNA recombinante"}, back_translations: {"es":"Técnicas para unir DNA de diferentes fontes. Ferramentas principales: enzimas de restrición (cortam el DNA en secuencias específicas), DNA ligase (une fragmentos), vetores (plasmídeos o virus para carregar DNA para células hospederas).","de":"Techniken zur Verbindung von DNA aus verschiedenen Quellen. Wichtige Werkzeuge: Restriktionsenzyme (schneiden DNA an spezifischen Sequenzen), DNA-Ligase (verbindet Fragmente), Vektoren (Plasmide oder Viren, um DNA in Wirtszellen zu übertragen).","fr":"Techniques pour assembler de l'ADN provenant de sources différentes. Outils clés : enzymes de restriction (coupent l'ADN à des séquences spécifiques), ADN ligase (relie des fragments), vecteurs (plasmides ou virus transportant l'ADN dans des cellules hôtes).","tr":"Farklı kaynaklardan DNA birleştirme teknikleri. Temel araçlar: restriksiyon enzimleri (DNA'yı belirli dizilerde keser), DNA ligaz (parçaları birleştirir), vektörler (DNA'yı konakçı hücrelere taşıyan plazmitler veya virüsler).","nl":"Technieken om DNA uit verschillende bronnen samen te voegen. Belangrijke hulpmiddelen: restrictie-enzymen (knippen DNA op specifieke sequenties), DNA-ligase (verbindt fragmenten), vectoren (plasmiden of virussen om DNA in gastheercellen te brengen).","ru":"Методы соединения ДНК из разных источников. Ключевые инструменты: рестрикционные ферменты (разрезают ДНК в определённых последовательностях), ДНК-лигаза (соединяет фрагменты), векторы (плазмиды или вирусы для доставки ДНК в клетки-хозяева).","zh":"将来自不同来源的DNA连接起来的技术。关键工具：限制酶（在特定序列处切割DNA）、DNA连接酶（连接片段）、载体（将DNA携带到宿主细胞的质粒或病毒）。","pt_BR":"Técnicas para unir DNA de diferentes fontes. Ferramentas principais: enzimas de restrição (cortam o DNA em sequências específicas), DNA ligase (une fragmentos), vetores (plasmídeos ou vírus para carregar DNA para células hospedeiras).","pt_PT":"Técnicas para unir DNA de diferentes fontes. Ferramentas principais: enzimas de restrição (cortam o DNA em sequências específicas), DNA ligase (une fragmentos), vetores (plasmídeos ou vírus para transportar DNA para células hospedeiras)."}},
  { id: 'dc-biology-0105', deck_id: 'deck-biology', sort_order: 105, front: "PCR (Polymerase Chain Reaction)", back: "Amplifies specific DNA sequences exponentially using repeated cycles of: denaturation (94°C), primer annealing, and extension (by Taq polymerase at 72°C). Doubles the target DNA with each cycle." , front_translations: {"es":"PCR (Reación en Cadeia de la Polimerase)","de":"PCR (Polymerase-Kettenreaktion)","fr":"PCR (Réaction en chaîne par polymérase)","tr":"PCR (Polimeraz Zincir Reaksiyonu)","nl":"PCR (Polymerasekettingreactie)","ru":"ПЦР (полимеразная цепная реакция)","zh":"PCR（聚合酶链式反应）","pt_BR":"PCR (Reação em Cadeia da Polimerase)","pt_PT":"PCR (Reação em Cadeia da Polimerase)"}, back_translations: {"es":"Amplifica secuencias específicas de DNA exponencialmente por medio de ciclos repetidos de: desnaturación (94 °C), enlace de primers y extensão (por la Taq polimerase a 72 °C). Duplica el DNA alvo a cada ciclo.","de":"Amplifiziert spezifische DNA-Sequenzen exponentiell durch wiederholte Zyklen: Denaturierung (94 °C), Primer-Anlagerung und Extension (durch Taq-Polymerase bei 72 °C). Verdoppelt die Ziel-DNA mit jedem Zyklus.","fr":"Amplifie exponentiellement des séquences d'ADN spécifiques par des cycles répétés de : dénaturation (94 °C), hybridation des amorces et extension (par la Taq polymérase à 72 °C). Double l'ADN cible à chaque cycle.","tr":"Belirli DNA dizilerini tekrarlayan döngülerle üstel olarak çoğaltır: denatürasyon (94 °C), primer bağlanması ve uzama (72 °C'de Taq polimeraz tarafından). Her döngüde hedef DNA'yı ikiye katlar.","nl":"Versterkt specifieke DNA-sequenties exponentieel via herhaalde cycli van: denaturatie (94 °C), primer-annealing en verlenging (door Taq-polymerase bij 72 °C). Verdubbelt het doel-DNA bij elke cyclus.","ru":"Амплифицирует специфические последовательности ДНК экспоненциально с помощью повторяющихся циклов: денатурации (94 °C), отжига праймеров и элонгации (Taq-полимеразой при 72 °C). Удваивает целевую ДНК с каждым циклом.","zh":"通过反复循环指数级扩增特定DNA序列：变性（94°C）、引物退火和延伸（Taq聚合酶在72°C进行）。每个循环使目标DNA数量翻倍。","pt_BR":"Amplifica sequências específicas de DNA exponencialmente por meio de ciclos repetidos de: desnaturação (94 °C), ligação de primers e extensão (pela Taq polimerase a 72 °C). Duplica o DNA alvo a cada ciclo.","pt_PT":"Amplifica sequências específicas de DNA exponencialmente através de ciclos repetidos de: desnaturação (94 °C), hibridação de primers e extensão (pela Taq polimerase a 72 °C). Duplica o DNA alvo em cada ciclo."}},
  { id: 'dc-biology-0106', deck_id: 'deck-biology', sort_order: 106, front: "CRISPR-Cas9", back: "A bacterial immune-derived gene-editing tool using a guide RNA to direct the Cas9 nuclease to a specific DNA sequence, where it makes a precise cut. Enables targeted gene knockouts and corrections." , front_translations: {"es":"CRISPR-Cas9","de":"CRISPR-Cas9","fr":"CRISPR-Cas9","tr":"CRISPR-Cas9","nl":"CRISPR-Cas9","ru":"CRISPR-Cas9","zh":"CRISPR-Cas9","pt_BR":"CRISPR-Cas9","pt_PT":"CRISPR-Cas9"}, back_translations: {"es":"Una herramienta de edición genómica derivada del sistema imune bacteriano que usa un RNA-guia para direcionar a nuclease Cas9 a una secuencia específica de DNA, donde hace un corte preciso. Permite knockouts y correciones genicas direcionadas.","de":"Ein vom bakteriellen Immunsystem abgeleitetes Genomeditierungswerkzeug, das eine Guide-RNA nutzt, um die Cas9-Nuklease zu einer spezifischen DNA-Sequenz zu dirigieren, wo sie einen präzisen Schnitt macht. Ermöglicht gezielte Gen-Knockouts und -Korrekturen.","fr":"Un outil d'édition génomique dérivé du système immunitaire bactérien, utilisant un ARN guide pour diriger la nucléase Cas9 vers une séquence d'ADN spécifique, où elle effectue une coupure précise. Permet des extinctions et corrections géniques ciblées.","tr":"Bakteriyel bağışıklık sisteminden türetilen bir gen düzenleme aracı; bir rehber RNA kullanarak Cas9 nükleazını belirli bir DNA dizisine yönlendirir ve hassas bir kesim yapar. Hedefli gen susturma ve düzeltmeleri mümkün kılar.","nl":"Een bacterieel immuunsysteem-afgeleid genoombewerkingtool dat een gids-RNA gebruikt om de Cas9-nuclease naar een specifieke DNA-sequentie te leiden, waar het een nauwkeurige snede maakt. Maakt gerichte gen-knockouts en -correcties mogelijk.","ru":"Инструмент редактирования генома, производный от бактериальной иммунной системы; использует направляющую РНК для наведения нуклеазы Cas9 на конкретную последовательность ДНК, где она делает точный разрез. Позволяет выполнять целенаправленные нокауты и коррекции генов.","zh":"一种源自细菌免疫系统的基因组编辑工具，利用向导RNA将Cas9核酸酶引导至特定DNA序列并进行精确切割。可实现靶向基因敲除和基因修正。","pt_BR":"Uma ferramenta de edição genômica derivada do sistema imune bacteriano que usa um RNA-guia para direcionar a nuclease Cas9 a uma sequência específica de DNA, onde faz um corte preciso. Permite knockouts e correções gênicas direcionadas.","pt_PT":"Uma ferramenta de edição genómica derivada do sistema imune bacteriano que usa um RNA-guia para dirigir a nuclease Cas9 a uma sequência específica de DNA, onde realiza um corte preciso. Permite silenciamentos e correções genéticas dirigidas."}},
  { id: 'dc-biology-0107', deck_id: 'deck-biology', sort_order: 107, front: "Epigenetics", back: "Heritable changes in gene expression that do not involve changes to the DNA sequence. Mechanisms include DNA methylation (gene silencing) and histone acetylation (gene activation). Environmental factors can trigger epigenetic changes." , front_translations: {"es":"Epigenética","de":"Epigenetik","fr":"Épigénétique","tr":"Epigenetik","nl":"Epigenetica","ru":"Эпигенетика","zh":"表观遗传学","pt_BR":"Epigenética","pt_PT":"Epigenética"}, back_translations: {"es":"Alteraciones hereditárias en la expresión genica que no involucran cambios en la secuencia de DNA. Los mecanismos incluyen metilación del DNA (silenciamento genico) y acetilación de histonas (ativación genica). Fatores ambientais pueden desencadear alteraciones epigenéticas.","de":"Vererbbare Veränderungen der Genexpression, die keine Veränderungen der DNA-Sequenz beinhalten. Mechanismen umfassen DNA-Methylierung (Genabschaltung) und Histon-Acetylierung (Genaktivierung). Umweltfaktoren können epigenetische Veränderungen auslösen.","fr":"Modifications héritables de l'expression génique n'impliquant pas de changements dans la séquence d'ADN. Les mécanismes comprennent la méthylation de l'ADN (silençage génique) et l'acétylation des histones (activation génique). Les facteurs environnementaux peuvent déclencher des modifications épigénétiques.","tr":"DNA dizisinde değişiklik içermeyen, kalıtsal gen ekspresyonu değişiklikleri. Mekanizmalar arasında DNA metilasyonu (gen susturma) ve histon asetilasyonu (gen aktivasyonu) yer alır. Çevresel faktörler epigenetik değişiklikleri tetikleyebilir.","nl":"Erfelijke veranderingen in genexpressie die geen wijzigingen in de DNA-sequentie inhouden. Mechanismen omvatten DNA-methylering (gen-silencing) en histonacetylering (genactivering). Omgevingsfactoren kunnen epigenetische veranderingen triggeren.","ru":"Наследуемые изменения экспрессии генов, не затрагивающие последовательность ДНК. Механизмы включают метилирование ДНК (подавление генов) и ацетилирование гистонов (активация генов). Факторы окружающей среды могут вызывать эпигенетические изменения.","zh":"不涉及DNA序列改变的可遗传基因表达变化。机制包括DNA甲基化（基因沉默）和组蛋白乙酰化（基因激活）。环境因素可触发表观遗传变化。","pt_BR":"Alterações hereditárias na expressão gênica que não envolvem mudanças na sequência de DNA. Os mecanismos incluem metilação do DNA (silenciamento gênico) e acetilação de histonas (ativação gênica). Fatores ambientais podem desencadear alterações epigenéticas.","pt_PT":"Alterações hereditárias na expressão génica que não envolvem mudanças na sequência de DNA. Os mecanismos incluem metilação do DNA (silenciamento génico) e acetilação de histonas (ativação génica). Fatores ambientais podem desencadear alterações epigenéticas."}},
  { id: 'dc-biology-0108', deck_id: 'deck-biology', sort_order: 108, front: "Stem Cells", back: "Undifferentiated cells capable of self-renewal and differentiation into specialized cell types. Pluripotent stem cells (embryonic) can become any cell type; multipotent stem cells are more restricted in lineage." , front_translations: {"es":"Células-tronco","de":"Stammzellen","fr":"Cellules souches","tr":"Kök Hücreler","nl":"Stamcellen","ru":"Стволовые клетки","zh":"干细胞","pt_BR":"Células-tronco","pt_PT":"Células estaminais"}, back_translations: {"es":"Células indiferenciadas capazes de autorrenovación y diferenciación en tipos celulares especializados. Células-tronco pluripotentes (embrionárias) pueden se tornar cualquier tipo celular; células-tronco multipotentes son más restritas en linhaje.","de":"Undifferenzierte Zellen, die zur Selbsterneuerung und Differenzierung in spezialisierte Zelltypen fähig sind. Pluripotente Stammzellen (embryonale) können jeden Zelltyp bilden; multipotente Stammzellen sind in ihrer Linie stärker eingeschränkt.","fr":"Cellules indifférenciées capables d'auto-renouvellement et de différenciation en types cellulaires spécialisés. Les cellules souches pluripotentes (embryonnaires) peuvent devenir n'importe quel type cellulaire ; les cellules souches multipotentes sont plus limitées en lignée.","tr":"Kendi kendini yenileme ve özelleşmiş hücre tiplerine farklılaşma kapasitesine sahip farklılaşmamış hücreler. Pluripotent kök hücreler (embriyonik) her hücre tipine dönüşebilir; multipotent kök hücreler soy açısından daha kısıtlıdır.","nl":"Ongedifferentieerde cellen die in staat zijn tot zelfvernieuwing en differentiatie in gespecialiseerde celtypen. Pluripotente stamcellen (embryonale) kunnen elk celtype worden; multipotente stamcellen zijn meer beperkt in afstamming.","ru":"Недифференцированные клетки, способные к самообновлению и дифференцировке в специализированные типы клеток. Плюрипотентные стволовые клетки (эмбриональные) могут превратиться в любой тип клеток; мультипотентные стволовые клетки более ограничены по линиям дифференцировки.","zh":"能够自我更新并分化为特化细胞类型的未分化细胞。多能干细胞（胚胎来源）可以分化为任何细胞类型；多潜能干细胞在分化谱系上受到更多限制。","pt_BR":"Células indiferenciadas capazes de autorrenovação e diferenciação em tipos celulares especializados. Células-tronco pluripotentes (embrionárias) podem se tornar qualquer tipo celular; células-tronco multipotentes são mais restritas em linhagem.","pt_PT":"Células indiferenciadas capazes de auto-renovação e diferenciação em tipos celulares especializados. Células estaminais pluripotentes (embrionárias) podem originar qualquer tipo celular; as células estaminais multipotentes são mais restritas em termos de linhagem."}},
  { id: 'dc-biology-0109', deck_id: 'deck-biology', sort_order: 109, front: "Cancer Biology", back: "Cancer results from uncontrolled cell division due to mutations in proto-oncogenes (gain of function → oncogenes) or tumor suppressor genes (loss of function, e.g., p53). Cells can become metastatic." , front_translations: {"es":"Biologia del cancer","de":"Krebsbiologie","fr":"Biologie du cancer","tr":"Kanser Biyolojisi","nl":"Kankerbiology","ru":"Биология рака","zh":"癌症生物学","pt_BR":"Biologia do câncer","pt_PT":"Biologia do cancro"}, back_translations: {"es":"El cancer resulta de la divisão celular descontrolada debido a mutaciones en proto-oncogenes (ganho de función → oncogenes) o genes supressores de tumor (perda de función, ex. p53). As células pueden se tornar metastáticas.","de":"Krebs entsteht durch unkontrollierte Zellteilung infolge von Mutationen in Proto-Onkogenen (Funktionsgewinn → Onkogene) oder Tumorsuppressorgenen (Funktionsverlust, z. B. p53). Zellen können metastatisch werden.","fr":"Le cancer résulte d'une division cellulaire incontrôlée due à des mutations dans des proto-oncogènes (gain de fonction → oncogènes) ou des gènes suppresseurs de tumeurs (perte de fonction, ex. p53). Les cellules peuvent devenir métastatiques.","tr":"Kanser, proto-onkogenlerdeki (kazanım mutasyonu → onkogenler) veya tümör baskılayıcı genlerdeki (fonksiyon kaybı, örn. p53) mutasyonlar nedeniyle kontrolsüz hücre bölünmesinden kaynaklanır. Hücreler metastatik hale gelebilir.","nl":"Kanker ontstaat door ongecontroleerde celdeling door mutaties in proto-oncogenen (functieverwerving → oncogenen) of tumorsuppressorgenen (functieverlies, bijv. p53). Cellen kunnen metastatisch worden.","ru":"Рак возникает в результате неконтролируемого деления клеток из-за мутаций в протоонкогенах (приобретение функции → онкогены) или генах-супрессорах опухолей (потеря функции, например p53). Клетки могут приобретать метастатические свойства.","zh":"癌症是由于原癌基因（功能获得性突变→癌基因）或肿瘤抑制基因（功能丧失，如p53）发生突变，导致细胞失控性分裂。细胞可发生转移。","pt_BR":"O câncer resulta da divisão celular descontrolada devido a mutações em proto-oncogenes (ganho de função → oncogenes) ou genes supressores de tumor (perda de função, ex. p53). As células podem se tornar metastáticas.","pt_PT":"O cancro resulta da divisão celular descontrolada devido a mutações em proto-oncogenes (ganho de função → oncogenes) ou genes supressores de tumor (perda de função, ex. p53). As células podem tornar-se metastáticas."}},
  { id: 'dc-biology-0110', deck_id: 'deck-biology', sort_order: 110, front: "Plant Cell vs. Animal Cell", back: "Plant cells have a cell wall (cellulose), large central vacuole, chloroplasts, and plasmodesmata. Animal cells have centrioles, lysosomes, and are more variable in shape. Both have nucleus, mitochondria, and ER." , front_translations: {"es":"Célula vegetal vs. célula animal","de":"Pflanzenzelle vs. Tierzelle","fr":"Cellule végétale vs. cellule animale","tr":"Bitki Hücresi ve Hayvan Hücresi","nl":"Plantencel vs. diercel","ru":"Растительная клетка vs. животная клетка","zh":"植物细胞与动物细胞","pt_BR":"Célula vegetal vs. célula animal","pt_PT":"Célula vegetal vs. célula animal"}, back_translations: {"es":"Células vegetais possuem pared celular (celulose), grande vacúolo central, cloroplastos y plasmodesmos. Células animales possuem centríolos, lisossomos y son más variables en forma. Ambas tienen núcleo, mitocondrias y RE.","de":"Pflanzenzellen haben eine Zellwand (Zellulose), eine große zentrale Vakuole, Chloroplasten und Plasmodesmata. Tierzellen haben Zentrosomen, Lysosomen und sind in ihrer Form variabler. Beide haben Zellkern, Mitochondrien und ER.","fr":"Les cellules végétales ont une paroi cellulaire (cellulose), une grande vacuole centrale, des chloroplastes et des plasmodesmes. Les cellules animales ont des centrioles, des lysosomes et sont plus variables en forme. Les deux ont un noyau, des mitochondries et un RE.","tr":"Bitki hücrelerinde hücre duvarı (selüloz), büyük merkezi vakuol, kloroplastlar ve plazmodezmatalar bulunur. Hayvan hücrelerinde sentrioller, lizozomlar bulunur ve şekil açısından daha değişkendirler. Her ikisinde de çekirdek, mitokondri ve ER vardır.","nl":"Plantencellen hebben een celwand (cellulose), een grote centrale vacuole, chloroplasten en plasmodesmata. Diercellen hebben centriolen, lysosomen en zijn variabeler in vorm. Beide hebben een kern, mitochondriën en ER.","ru":"Растительные клетки имеют клеточную стенку (целлюлоза), большую центральную вакуоль, хлоропласты и плазмодесмы. Животные клетки имеют центриоли, лизосомы и более вариабельную форму. В обоих типах есть ядро, митохондрии и ЭР.","zh":"植物细胞具有细胞壁（纤维素）、大型中央液泡、叶绿体和胞间连丝。动物细胞具有中心粒、溶酶体，形态更多变。两者均有细胞核、线粒体和内质网。","pt_BR":"Células vegetais possuem parede celular (celulose), grande vacúolo central, cloroplastos e plasmodesmos. Células animais possuem centríolos, lisossomos e são mais variáveis em forma. Ambas têm núcleo, mitocôndrias e RE.","pt_PT":"As células vegetais têm parede celular (celulose), grande vacúolo central, cloroplastos e plasmodesmos. As células animais têm centríolos, lisossomas e são mais variáveis em forma. Ambas têm núcleo, mitocôndrias e RE."}},
  { id: 'dc-biology-0111', deck_id: 'deck-biology', sort_order: 111, front: "Xylem and Phloem", back: "Xylem transports water and minerals upward from roots to leaves (driven by transpiration pull). Phloem transports sugars (photosynthate) from sources (leaves) to sinks (roots, fruits) by pressure flow." , front_translations: {"es":"Xilema y floema","de":"Xylem und Phloem","fr":"Xylème et phloème","tr":"Ksilem ve Floem","nl":"Xyleem en floëem","ru":"Ксилема и флоэма","zh":"木质部与韧皮部","pt_BR":"Xilema e floema","pt_PT":"Xilema e floema"}, back_translations: {"es":"El xilema transporta agua y minerais de las raíces para las hojas (impulsionado por la tración de la transpiración). El floema transporta açúcares (fotoassimilados) de las fontes (hojas) para los drenos (raíces, frutos) por el flujo de presión.","de":"Xylem transportiert Wasser und Mineralien von den Wurzeln aufwärts zu den Blättern (angetrieben durch Transpirationssog). Phloem transportiert Zucker (Photosyntheseprodukte) von Quellen (Blätter) zu Senken (Wurzeln, Früchte) durch Druckfluss.","fr":"Le xylème transporte l'eau et les minéraux vers le haut, des racines aux feuilles (propulsé par la traction de transpiration). Le phloème transporte les sucres (photosynthèse) des sources (feuilles) vers les puits (racines, fruits) par flux de pression.","tr":"Ksilem, su ve mineralleri köklerden yapraklara yukarı taşır (terleme çekimi ile). Floem, şekerleri (fotosentat) kaynaklardan (yapraklar) havuzlara (kökler, meyveler) basınç akışıyla taşır.","nl":"Xyleem transporteert water en mineralen omhoog van wortels naar bladeren (aangedreven door transpiratiestroom). Floëem transporteert suikers (fotosynthetisch product) van bronnen (bladeren) naar putten (wortels, vruchten) via drukstroom.","ru":"Ксилема переносит воду и минералы вверх от корней к листьям (за счёт транспирационной тяги). Флоэма переносит сахара (фотоассимиляты) от источников (листья) к стокам (корни, плоды) по механизму давления.","zh":"木质部通过蒸腾拉力将水分和矿物质从根部向上输送到叶片。韧皮部通过压力流将糖分（光合产物）从源（叶片）运输至库（根、果实）。","pt_BR":"O xilema transporta água e minerais das raízes para as folhas (impulsionado pela tração da transpiração). O floema transporta açúcares (fotoassimilados) das fontes (folhas) para os drenos (raízes, frutos) pelo fluxo de pressão.","pt_PT":"O xilema transporta água e minerais das raízes para as folhas (impulsionado pela tração da transpiração). O floema transporta açúcares (fotoassimilados) das fontes (folhas) para os destinos (raízes, frutos) pelo fluxo de pressão."}},
  { id: 'dc-biology-0112', deck_id: 'deck-biology', sort_order: 112, front: "Stomata", back: "Pores in plant leaves and stems (especially the underside) flanked by guard cells that control opening and closing. Allow gas exchange (CO₂ in, O₂ out) and regulate water loss (transpiration)." , front_translations: {"es":"Estomatos","de":"Stomata","fr":"Stomates","tr":"Stoma","nl":"Huidmondjes (stomata)","ru":"Устьица","zh":"气孔","pt_BR":"Estômatos","pt_PT":"Estomas"}, back_translations: {"es":"Poros en las hojas y caules de las plantas (especialmente en la face inferior) flanqueados por células-guarda que controlan a abertura y el fechamento. Permitem trocas gasosas (CO₂ entra, El₂ sai) y regulan a perda de agua (transpiración).","de":"Poren in Pflanzenblättern und -stielen (vor allem auf der Unterseite), die von Schließzellen flankiert werden und deren Öffnung und Schließung regulieren. Ermöglichen Gasaustausch (CO₂ rein, O₂ raus) und regulieren den Wasserverlust (Transpiration).","fr":"Pores dans les feuilles et tiges des plantes (surtout le dessous) flanqués de cellules de garde qui contrôlent l'ouverture et la fermeture. Permettent les échanges gazeux (CO₂ entrant, O₂ sortant) et régulent la perte d'eau (transpiration).","tr":"Bitki yaprak ve gövdelerinde (özellikle alt yüzeyde) bekçi hücreleri tarafından çevrilmiş, açılıp kapanmayı kontrol eden porlar. Gaz alışverişine (CO₂ giriş, O₂ çıkış) izin verir ve su kaybını (terleme) düzenler.","nl":"Poriën in bladeren en stengels van planten (vooral de onderkant), geflankeerd door sluitcellen die opening en sluiting controleren. Staan gasuitwisseling toe (CO₂ naar binnen, O₂ naar buiten) en reguleren waterverlies (transpiratie).","ru":"Поры в листьях и стеблях растений (особенно на нижней стороне), окружённые замыкающими клетками, которые управляют открытием и закрытием. Обеспечивают газообмен (CO₂ внутрь, O₂ наружу) и регулируют потерю воды (транспирацию).","zh":"植物叶片和茎（尤其是下表面）上的孔隙，由保卫细胞控制其开闭。允许气体交换（CO₂进入，O₂排出）并调节水分散失（蒸腾）。","pt_BR":"Poros nas folhas e caules das plantas (especialmente na face inferior) flanqueados por células-guarda que controlam a abertura e o fechamento. Permitem trocas gasosas (CO₂ entra, O₂ sai) e regulam a perda de água (transpiração).","pt_PT":"Poros nas folhas e caules das plantas (especialmente na face inferior) ladeados por células-guarda que controlam a abertura e o fecho. Permitem trocas gasosas (CO₂ entra, O₂ sai) e regulam a perda de água (transpiração)."}},
  { id: 'dc-biology-0113', deck_id: 'deck-biology', sort_order: 113, front: "Pollination", back: "The transfer of pollen (containing male gametophytes) from an anther to a stigma. Self-pollination occurs within one plant; cross-pollination between different plants. Agents: wind, insects, birds, bats." , front_translations: {"es":"Polinización","de":"Bestäubung","fr":"Pollinisation","tr":"Tozlaşma","nl":"Bestuiving","ru":"Опыление","zh":"传粉","pt_BR":"Polinização","pt_PT":"Polinização"}, back_translations: {"es":"La transferencia de pólen (conteniendo gametófitos masculinos) de una antera para un estigma. La autopolinización ocurre dentro de una misma planta; a polinización cruzada entre plantas diferentes. Agentes: vento, insetos, pássaros, morcegos.","de":"Die Übertragung von Pollen (mit männlichen Gametophyten) von einem Staubbeutel auf eine Narbe. Selbstbestäubung erfolgt innerhalb einer Pflanze; Fremdbestäubung zwischen verschiedenen Pflanzen. Überträger: Wind, Insekten, Vögel, Fledermäuse.","fr":"Le transfert du pollen (contenant les gamétophytes mâles) d'une anthère à un stigmate. L'autopollinisation se produit au sein d'une même plante ; la pollinisation croisée entre différentes plantes. Agents : vent, insectes, oiseaux, chauves-souris.","tr":"Polen (erkek gametofitleri içeren) transferinin bir antenden bir stigmaya aktarılması. Öz-tozlaşma tek bir bitki içinde gerçekleşir; çapraz tozlaşma farklı bitkiler arasında olur. Etmenler: rüzgar, böcekler, kuşlar, yarasalar.","nl":"De overdracht van pollen (met mannelijke gametofyten) van een meeldraad naar een stamper. Zelfbestuiving vindt binnen één plant plaats; kruisbestuiving tussen verschillende planten. Agenten: wind, insecten, vogels, vleermuizen.","ru":"Перенос пыльцы (содержащей мужские гаметофиты) с пыльника на рыльце пестика. Самоопыление происходит в пределах одного растения; перекрёстное опыление — между разными растениями. Переносчики: ветер, насекомые, птицы, летучие мыши.","zh":"将花粉（含雄配子体）从花药转移到柱头的过程。自花传粉在同一植株内进行；异花传粉在不同植株间进行。传播媒介：风、昆虫、鸟类、蝙蝠。","pt_BR":"A transferência de pólen (contendo gametófitos masculinos) de uma antera para um estigma. A autopolinização ocorre dentro de uma mesma planta; a polinização cruzada entre plantas diferentes. Agentes: vento, insetos, pássaros, morcegos.","pt_PT":"A transferência de pólen (contendo gametófitos masculinos) de uma antera para um estigma. A autopolinização ocorre dentro de uma mesma planta; a polinização cruzada entre plantas diferentes. Agentes: vento, insetos, aves, morcegos."}},
  { id: 'dc-biology-0114', deck_id: 'deck-biology', sort_order: 114, front: "Double Fertilization (Plants)", back: "Unique to angiosperms: one sperm fuses with the egg (forming 2n zygote) and another fuses with two polar nuclei (forming 3n endosperm). The endosperm provides nutrition for the developing embryo." , front_translations: {"es":"Dupla fertilización (plantas)","de":"Doppelte Befruchtung (Pflanzen)","fr":"Double fécondation (plantes)","tr":"Çifte Döllenme (Bitkiler)","nl":"Dubbele bevruchting (planten)","ru":"Двойное оплодотворение (растения)","zh":"双受精（植物）","pt_BR":"Dupla fertilização (plantas)","pt_PT":"Dupla fertilização (plantas)"}, back_translations: {"es":"Exclusivo de las angiospermas: un espermatozoide funde-se con el óvulo (formando el zigoto 2n) y outro funde-se con de los núcleos polares (formando el endosperma 3n). El endosperma proporciona nutrición para el embrião en desarrollo.","de":"Einzigartig bei Bedecktsamern: Ein Spermium verschmilzt mit der Eizelle (bildet 2n-Zygote) und ein weiteres verschmilzt mit zwei Polkernen (bildet 3n-Endosperm). Das Endosperm liefert Nährstoffe für den sich entwickelnden Embryo.","fr":"Propre aux angiospermes : un spermatozoïde fusionne avec l'ovule (formant le zygote 2n) et un autre fusionne avec deux noyaux polaires (formant l'endosperme 3n). L'endosperme fournit la nutrition pour l'embryon en développement.","tr":"Kapalı tohumlu bitkilere özgü: bir sperm hücresi yumurtayla (2n zigot oluşturarak) ve diğeri iki polar çekirdekle (3n endosperm oluşturarak) kaynaşır. Endosperm, gelişen embriyoya besin sağlar.","nl":"Uniek voor bedektzadigen: één zaadcel fuseert met de eicel (vormt 2n-zygote) en een andere fuseert met twee polaire kernen (vormt 3n-endosperm). Het endosperm voorziet de ontwikkelende kiem van voedingsstoffen.","ru":"Уникально для покрытосеменных: один спермий сливается с яйцеклеткой (образуя 2n-зиготу), а другой — с двумя полярными ядрами (образуя 3n-эндосперм). Эндосперм обеспечивает питание развивающегося зародыша.","zh":"被子植物特有：一个精子与卵细胞融合（形成2n合子），另一个与两个极核融合（形成3n胚乳）。胚乳为发育中的胚提供营养。","pt_BR":"Exclusivo das angiospermas: um espermatozoide funde-se com o óvulo (formando o zigoto 2n) e outro funde-se com dois núcleos polares (formando o endosperma 3n). O endosperma fornece nutrição para o embrião em desenvolvimento.","pt_PT":"Exclusivo das angiospérmicas: um espermatozoide funde-se com o óvulo (formando o zigoto 2n) e outro funde-se com dois núcleos polares (formando o endosperma 3n). O endosperma fornece nutrição para o embrião em desenvolvimento."}},
  { id: 'dc-biology-0115', deck_id: 'deck-biology', sort_order: 115, front: "Animal Reproduction: Sexual vs. Asexual", back: "Asexual reproduction (binary fission, budding, parthenogenesis) produces genetically identical offspring but lacks genetic diversity. Sexual reproduction (meiosis + fertilization) produces variation, aiding evolution." , front_translations: {"es":"Reprodución animal: sexual vs. assexual","de":"Tierische Fortpflanzung: Geschlechtlich vs. ungeschlechtlich","fr":"Reproduction animale : sexuée vs. asexuée","tr":"Hayvan Üremesi: Eşeyli ve Eşeysiz","nl":"Dierlijke voortplanting: seksueel vs. aseksueel","ru":"Размножение животных: половое и бесполое","zh":"动物繁殖：有性生殖与无性生殖","pt_BR":"Reprodução animal: sexual vs. assexual","pt_PT":"Reprodução animal: sexual vs. assexuada"}, back_translations: {"es":"La reprodución assexual (divisão binária, brotamento, partenogenese) produce descendentes geneticamente identicos, pero carece de diversidad genética. La reprodución sexual (meiose + fertilización) produce variación, favorecendo a evolución.","de":"Ungeschlechtliche Fortpflanzung (binäre Spaltung, Knospung, Parthenogenese) erzeugt genetisch identische Nachkommen, hat aber keine genetische Vielfalt. Geschlechtliche Fortpflanzung (Meiose + Befruchtung) erzeugt Variation und fördert die Evolution.","fr":"La reproduction asexuée (fission binaire, bourgeonnement, parthénogenèse) produit des descendants génétiquement identiques mais manque de diversité génétique. La reproduction sexuée (méiose + fécondation) produit de la variation, favorisant l'évolution.","tr":"Eşeysiz üreme (ikiye bölünme, tomurcuklanma, partenogenez) genetik olarak özdeş yavrular üretir ancak genetik çeşitlilikten yoksundur. Eşeyli üreme (mayoz + dölleme) evrime yardımcı olan varyasyon üretir.","nl":"Aseksuele voortplanting (binaire splitsing, knopvorming, parthenogenese) produceert genetisch identieke nakomelingen maar mist genetische diversiteit. Seksuele voortplanting (meiose + bevruchting) produceert variatie, wat evolutie bevordert.","ru":"Бесполое размножение (бинарное деление, почкование, партеногенез) даёт генетически идентичное потомство, но лишено генетического разнообразия. Половое размножение (мейоз + оплодотворение) создаёт изменчивость, способствуя эволюции.","zh":"无性生殖（二分裂、出芽、孤雌生殖）产生基因相同的后代，但缺乏遗传多样性。有性生殖（减数分裂+受精）产生变异，有助于进化。","pt_BR":"A reprodução assexual (divisão binária, brotamento, partenogênese) produz descendentes geneticamente idênticos, mas carece de diversidade genética. A reprodução sexual (meiose + fertilização) produz variação, favorecendo a evolução.","pt_PT":"A reprodução assexuada (divisão binária, gemulação, partenogénese) produz descendentes geneticamente idênticos, mas carece de diversidade genética. A reprodução sexual (meiose + fecundação) produz variação, favorecendo a evolução."}},
  { id: 'dc-biology-0116', deck_id: 'deck-biology', sort_order: 116, front: "Embryonic Development: Gastrulation", back: "The process forming three primary germ layers: ectoderm (skin, nervous system), mesoderm (muscle, bone, circulatory), endoderm (digestive and respiratory lining). Follows blastulation after fertilization." , front_translations: {"es":"Desenvolvimento embrionário: gastrulación","de":"Embryonale Entwicklung: Gastrulation","fr":"Développement embryonnaire : gastrulation","tr":"Embriyonik Gelişim: Gastrülasyon","nl":"Embryonale ontwikkeling: gastrulatie","ru":"Эмбриональное развитие: гаструляция","zh":"胚胎发育：原肠胚形成","pt_BR":"Desenvolvimento embrionário: gastrulação","pt_PT":"Desenvolvimento embrionário: gastrulação"}, back_translations: {"es":"El proceso que forma tres capas germinativas primárias: ectoderme (piel, sistema nervioso), mesoderme (músculo, hueso, circulatório) y endoderme (revestimento digestivo y respiratório). Segue a blastulación após a fertilización.","de":"Der Prozess, der drei primäre Keimblätter bildet: Ektoderm (Haut, Nervensystem), Mesoderm (Muskel, Knochen, Kreislauf), Entoderm (Verdauungs- und Atemwegsauskleidung). Folgt der Blasulation nach der Befruchtung.","fr":"Le processus formant trois feuillets germinatifs primaires : ectoderme (peau, système nerveux), mésoderme (muscles, os, système circulatoire), endoderme (revêtement digestif et respiratoire). Suit la blastulation après la fécondation.","tr":"Üç birincil germ tabakasını oluşturan süreç: ektoderm (deri, sinir sistemi), mezoderm (kas, kemik, dolaşım), endoderm (sindirim ve solunum sistemi astarı). Döllenmenin ardından blastülasyonu takip eder.","nl":"Het proces dat drie primaire kiembladen vormt: ectoderm (huid, zenuwstelsel), mesoderm (spier, bot, circulatiestelsel), endoderm (spijsverterings- en ademhalingsbekledeling). Volgt op blastulatie na bevruchting.","ru":"Процесс формирования трёх первичных зародышевых листков: эктодерма (кожа, нервная система), мезодерма (мышцы, кости, система кровообращения), энтодерма (выстилка пищеварительного и дыхательного трактов). Следует за бластуляцией после оплодотворения.","zh":"形成三个初级胚层的过程：外胚层（皮肤、神经系统）、中胚层（肌肉、骨骼、循环系统）、内胚层（消化道和呼吸道内衬）。在受精后的囊胚期之后发生。","pt_BR":"O processo que forma três camadas germinativas primárias: ectoderme (pele, sistema nervoso), mesoderme (músculo, osso, circulatório) e endoderme (revestimento digestivo e respiratório). Segue a blastulação após a fertilização.","pt_PT":"O processo que forma três camadas germinativas primárias: ectoderme (pele, sistema nervoso), mesoderme (músculo, osso, sistema circulatório) e endoderme (revestimento digestivo e respiratório). Segue a blastulação após a fecundação."}},
  { id: 'dc-biology-0117', deck_id: 'deck-biology', sort_order: 117, front: "Genome vs. Proteome", back: "The genome is the complete set of an organism's DNA. The proteome is the complete set of proteins expressed by a cell or organism at a given time. More proteins than genes exist due to alternative splicing." , front_translations: {"es":"Genoma vs. proteoma","de":"Genom vs. Proteom","fr":"Génome vs. protéome","tr":"Genom ve Proteom","nl":"Genoom vs. proteoom","ru":"Геном vs. протеом","zh":"基因组与蛋白质组","pt_BR":"Genoma vs. proteoma","pt_PT":"Genoma vs. proteoma"}, back_translations: {"es":"El genoma es el conjunto completo de DNA de un organismo. El proteoma es el conjunto completo de proteínas expressas por una célula o organismo en un dato momento. Existem más proteínas del que genes debido al splicing alternativo.","de":"Das Genom ist die vollständige DNA eines Organismus. Das Proteom ist die vollständige Menge der von einer Zelle oder einem Organismus zu einem bestimmten Zeitpunkt exprimierten Proteine. Es gibt mehr Proteine als Gene aufgrund von alternativem Spleißen.","fr":"Le génome est l'ensemble complet de l'ADN d'un organisme. Le protéome est l'ensemble complet des protéines exprimées par une cellule ou un organisme à un moment donné. Il existe plus de protéines que de gènes grâce à l'épissage alternatif.","tr":"Genom, bir organizmanın tam DNA setini oluşturur. Proteom, belirli bir zamanda bir hücre veya organizma tarafından ifade edilen proteinlerin tam setidir. Alternatif eklenme nedeniyle genlerden daha fazla protein mevcuttur.","nl":"Het genoom is de volledige DNA-set van een organisme. Het proteoom is de volledige set eiwitten die door een cel of organisme op een bepaald moment worden uitgedrukt. Er zijn meer eiwitten dan genen vanwege alternatieve splicing.","ru":"Геном — это полный набор ДНК организма. Протеом — полный набор белков, экспрессируемых клеткой или организмом в данный момент времени. Белков больше, чем генов, благодаря альтернативному сплайсингу.","zh":"基因组是生物体完整的DNA集合。蛋白质组是细胞或生物体在特定时间表达的全部蛋白质集合。由于可变剪接，蛋白质数量多于基因数量。","pt_BR":"O genoma é o conjunto completo de DNA de um organismo. O proteoma é o conjunto completo de proteínas expressas por uma célula ou organismo em um dado momento. Existem mais proteínas do que genes devido ao splicing alternativo.","pt_PT":"O genoma é o conjunto completo de DNA de um organismo. O proteoma é o conjunto completo de proteínas expressas por uma célula ou organismo num determinado momento. Existem mais proteínas do que genes devido ao splicing alternativo."}},
  { id: 'dc-biology-0118', deck_id: 'deck-biology', sort_order: 118, front: "Alternative Splicing", back: "Different combinations of exons from a single pre-mRNA are joined to produce different mature mRNA molecules and thus different proteins. A major mechanism for proteome diversity (one gene → many proteins)." , front_translations: {"es":"Splicing alternativo","de":"Alternatives Spleißen","fr":"Épissage alternatif","tr":"Alternatif Eklenme (Splicing)","nl":"Alternatieve splicing","ru":"Альтернативный сплайсинг","zh":"可变剪接","pt_BR":"Splicing alternativo","pt_PT":"Splicing alternativo"}, back_translations: {"es":"Diferentes combinaciones de éxons de un único pré-mRNA son unidas para produzir diferentes moléculas de mRNA maduro y, por lo tanto, diferentes proteínas. Un mecanismo importante para a diversidad del proteoma (un gen → muchas proteínas).","de":"Verschiedene Kombinationen von Exons aus einer einzigen prä-mRNA werden verbunden, um verschiedene reife mRNA-Moleküle und damit verschiedene Proteine zu erzeugen. Ein wichtiger Mechanismus für die Proteom-Diversität (ein Gen → viele Proteine).","fr":"Différentes combinaisons d'exons d'une seule pré-ARNm sont assemblées pour produire différentes molécules d'ARNm matures et donc différentes protéines. Un mécanisme majeur pour la diversité du protéome (un gène → plusieurs protéines).","tr":"Tek bir pre-mRNA'dan farklı ekzon kombinasyonları birleştirilerek farklı olgun mRNA molekülleri ve dolayısıyla farklı proteinler üretilir. Proteom çeşitliliği için temel bir mekanizma (bir gen → çok sayıda protein).","nl":"Verschillende combinaties van exonen uit één pre-mRNA worden samengevoegd om verschillende rijpe mRNA-moleculen en dus verschillende eiwitten te produceren. Een belangrijk mechanisme voor proteoomdiversiteit (één gen → veel eiwitten).","ru":"Из одной пре-мРНК путём соединения разных комбинаций экзонов образуются разные зрелые молекулы мРНК и соответственно разные белки. Основной механизм обеспечения разнообразия протеома (один ген → множество белков).","zh":"同一前体mRNA中不同外显子的组合被拼接在一起，产生不同的成熟mRNA分子，从而产生不同的蛋白质。这是蛋白质组多样性的重要机制（一个基因→多种蛋白质）。","pt_BR":"Diferentes combinações de éxons de um único pré-mRNA são unidas para produzir diferentes moléculas de mRNA maduro e, portanto, diferentes proteínas. Um mecanismo importante para a diversidade do proteoma (um gene → muitas proteínas).","pt_PT":"Diferentes combinações de exões de um único pré-mRNA são unidas para produzir diferentes moléculas de mRNA maduro e, portanto, diferentes proteínas. Um mecanismo importante para a diversidade do proteoma (um gene → muitas proteínas)."}},
  { id: 'dc-biology-0119', deck_id: 'deck-biology', sort_order: 119, front: "Signal Transduction", back: "The process by which a cell converts an extracellular signal (hormone, growth factor) into an intracellular response. Steps: signal binds receptor → second messengers activated → cellular response." , front_translations: {"es":"Transdución de señal","de":"Signaltransduktion","fr":"Transduction du signal","tr":"Sinyal İletimi","nl":"Signaaltransductie","ru":"Сигнальная трансдукция","zh":"信号转导","pt_BR":"Transdução de sinal","pt_PT":"Transdução de sinal"}, back_translations: {"es":"El proceso por el qual una célula convierte un señal extracelular (hormona, fator de crecimiento) en respuesta intracelular. Etapas: señal liga-se al receptor → segundos mensageros ativados → respuesta celular.","de":"Der Prozess, durch den eine Zelle ein extrazelluläres Signal (Hormon, Wachstumsfaktor) in eine intrazelluläre Antwort umwandelt. Schritte: Signal bindet Rezeptor → zweite Botenstoffe aktiviert → zelluläre Antwort.","fr":"Le processus par lequel une cellule convertit un signal extracellulaire (hormone, facteur de croissance) en réponse intracellulaire. Étapes : le signal se lie au récepteur → seconds messagers activés → réponse cellulaire.","tr":"Bir hücrenin hücre dışı sinyali (hormon, büyüme faktörü) hücre içi yanıta dönüştürdüğü süreç. Adımlar: sinyal reseptöre bağlanır → ikincil mesajcılar aktive edilir → hücresel yanıt.","nl":"Het proces waarbij een cel een extracellulair signaal (hormoon, groeifactor) omzet in een intracellulaire respons. Stappen: signaal bindt aan receptor → tweede boodschappers geactiveerd → cellulaire respons.","ru":"Процесс, посредством которого клетка преобразует внеклеточный сигнал (гормон, фактор роста) во внутриклеточный ответ. Этапы: сигнал связывается с рецептором → активируются вторичные мессенджеры → клеточный ответ.","zh":"细胞将胞外信号（激素、生长因子）转化为胞内应答的过程。步骤：信号与受体结合→激活第二信使→产生细胞应答。","pt_BR":"O processo pelo qual uma célula converte um sinal extracelular (hormônio, fator de crescimento) em resposta intracelular. Etapas: sinal liga-se ao receptor → segundos mensageiros ativados → resposta celular.","pt_PT":"O processo pelo qual uma célula converte um sinal extracelular (hormona, fator de crescimento) em resposta intracelular. Etapas: sinal liga-se ao receptor → segundos mensageiros ativados → resposta celular."}},
  { id: 'dc-biology-0120', deck_id: 'deck-biology', sort_order: 120, front: "cAMP Signaling Pathway", back: "A common second messenger system: ligand binds GPCR → activates adenylyl cyclase via G protein → cAMP produced → activates protein kinase A (PKA) → phosphorylates target proteins → cellular response." , front_translations: {"es":"Via de sinalización del AMP cíclico","de":"cAMP-Signalweg","fr":"Voie de signalisation de l'AMPc","tr":"cAMP Sinyal Yolu","nl":"cAMP-signaleringspad","ru":"Сигнальный путь цАМФ","zh":"cAMP信号通路","pt_BR":"Via de sinalização do AMP cíclico","pt_PT":"Via de sinalização do AMP cíclico"}, back_translations: {"es":"Un sistema comum de según mensagero: ligante liga-se al GPCR → ativa a adenilil ciclase via proteína G → AMP cíclico es producido → ativa a proteína quinase A (PKA) → fosforila proteínas-alvo → respuesta celular.","de":"Ein häufiges Second-Messenger-System: Ligand bindet GPCR → aktiviert Adenylylcyclase über G-Protein → cAMP wird produziert → aktiviert Proteinkinase A (PKA) → phosphoryliert Zielproteine → zelluläre Antwort.","fr":"Un système de second messager courant : le ligand se lie au RCPG → active l'adénylyl cyclase via la protéine G → production d'AMPc → activation de la protéine kinase A (PKA) → phosphorylation des protéines cibles → réponse cellulaire.","tr":"Yaygın bir ikincil mesajcı sistemi: ligand GPCR'ye bağlanır → G proteini aracılığıyla adenilil siklazı aktive eder → cAMP üretilir → protein kinaz A'yı (PKA) aktive eder → hedef proteinleri fosforile eder → hücresel yanıt.","nl":"Een veelvoorkomend tweede boodschapperssysteem: ligand bindt GPCR → activeert adenylylcyclase via G-proteïne → cAMP geproduceerd → activeert proteïnekinase A (PKA) → fosforyleert doeleiwitten → cellulaire respons.","ru":"Распространённая система вторичных мессенджеров: лиганд связывается с GPCR → активирует аденилилциклазу через G-белок → образуется цАМФ → активирует протеинкиназу A (PKA) → фосфорилирует белки-мишени → клеточный ответ.","zh":"一种常见的第二信使系统：配体与GPCR结合→通过G蛋白激活腺苷酸环化酶→产生cAMP→激活蛋白激酶A（PKA）→磷酸化靶蛋白→产生细胞应答。","pt_BR":"Um sistema comum de segundo mensageiro: ligante liga-se ao GPCR → ativa a adenilil ciclase via proteína G → AMP cíclico é produzido → ativa a proteína quinase A (PKA) → fosforila proteínas-alvo → resposta celular.","pt_PT":"Um sistema comum de segundo mensageiro: o ligando liga-se ao GPCR → ativa a adenilil ciclase via proteína G → é produzido AMP cíclico → ativa a proteína cinase A (PKA) → fosforila proteínas-alvo → resposta celular."}},
  { id: 'dc-biology-0121', deck_id: 'deck-biology', sort_order: 121, front: "Membrane Potential", back: "The electrical voltage difference across a cell membrane, typically around -70 mV (resting potential) in neurons. Maintained by the Na⁺/K⁺ pump and selective permeability to K⁺." , front_translations: {"es":"Potencial de membrana","de":"Membranpotenzial","fr":"Potentiel membranaire","tr":"Membran Potansiyeli","nl":"Membraanpotentiaal","ru":"Мембранный потенциал","zh":"膜电位","pt_BR":"Potencial de membrana","pt_PT":"Potencial de membrana"}, back_translations: {"es":"La diferencia de voltaje eléctrica a través de una membrana celular, típicamente alrededor de -70 mV (potencial de reposo) en neuronas. Mantido por la bomba Na⁺/K⁺ y por la permeabilidad seletiva al K⁺.","de":"Die elektrische Spannungsdifferenz über eine Zellmembran, typischerweise etwa -70 mV (Ruhepotenzial) in Neuronen. Aufrechterhalten durch die Na⁺/K⁺-Pumpe und selektive Permeabilität für K⁺.","fr":"La différence de tension électrique à travers une membrane cellulaire, généralement d'environ -70 mV (potentiel de repos) dans les neurones. Maintenu par la pompe Na⁺/K⁺ et la perméabilité sélective au K⁺.","tr":"Bir hücre zarındaki elektriksel voltaj farkı, nöronlarda tipik olarak yaklaşık -70 mV (dinlenme potansiyeli). Na⁺/K⁺ pompası ve K⁺'a seçici geçirgenlik tarafından sürdürülür.","nl":"Het elektrische spanningsverschil over een celmembraan, typisch ongeveer -70 mV (rustpotentiaal) in neuronen. Onderhouden door de Na⁺/K⁺-pomp en selectieve permeabiliteit voor K⁺.","ru":"Электрическая разность потенциалов на клеточной мембране, обычно около -70 мВ (потенциал покоя) в нейронах. Поддерживается Na⁺/K⁺-насосом и избирательной проницаемостью для K⁺.","zh":"细胞膜两侧的电位差，神经元中通常约为-70 mV（静息电位）。由Na⁺/K⁺泵和对K⁺的选择性通透性维持。","pt_BR":"A diferença de voltagem elétrica através de uma membrana celular, tipicamente em torno de -70 mV (potencial de repouso) em neurônios. Mantido pela bomba Na⁺/K⁺ e pela permeabilidade seletiva ao K⁺.","pt_PT":"A diferença de voltagem elétrica através de uma membrana celular, tipicamente cerca de -70 mV (potencial de repouso) em neurónios. Mantido pela bomba Na⁺/K⁺ e pela permeabilidade seletiva ao K⁺."}},
  { id: 'dc-biology-0122', deck_id: 'deck-biology', sort_order: 122, front: "Reflex Arc", back: "The neural pathway for an involuntary response: stimulus → sensory receptor → afferent nerve → spinal cord (integration) → efferent nerve → effector (muscle or gland). Bypasses the brain for speed." , front_translations: {"es":"Arco reflexo","de":"Reflexbogen","fr":"Arc réflexe","tr":"Refleks Yayı","nl":"Reflexboog","ru":"Рефлекторная дуга","zh":"反射弧","pt_BR":"Arco reflexo","pt_PT":"Arco reflexo"}, back_translations: {"es":"La via neural para una respuesta involuntária: estímulo → receptor sensorial → nervio aferente → medula espinal (integración) → nervio eferente → efetor (músculo o glándula). Contorna el cerebro para mayor velocidad.","de":"Der neuronale Weg für eine unwillkürliche Reaktion: Reiz → sensorischer Rezeptor → afferenter Nerv → Rückenmark (Integration) → efferenter Nerv → Effektor (Muskel oder Drüse). Umgeht das Gehirn der Schnelligkeit wegen.","fr":"La voie neuronale d'une réponse involontaire : stimulus → récepteur sensoriel → nerf afférent → moelle épinière (intégration) → nerf efférent → effecteur (muscle ou glande). Court-circuite le cerveau pour plus de rapidité.","tr":"İstemsiz bir yanıt için sinirsel yol: uyaran → duyusal reseptör → afferent sinir → omurilik (entegrasyon) → efferent sinir → efektör (kas veya bez). Hız için beynin önüne geçer.","nl":"De neurale route voor een onwillekeurige respons: stimulus → sensorische receptor → afferente zenuw → ruggenmerg (integratie) → efferente zenuw → effector (spier of klier). Omzeilt de hersenen voor snelheid.","ru":"Нейронный путь непроизвольной реакции: раздражитель → сенсорный рецептор → афферентный нерв → спинной мозг (интеграция) → эфферентный нерв → эффектор (мышца или железа). Обходит головной мозг для ускорения реакции.","zh":"非随意性反应的神经通路：刺激→感觉感受器→传入神经→脊髓（整合）→传出神经→效应器（肌肉或腺体）。为提高速度绕过大脑。","pt_BR":"A via neural para uma resposta involuntária: estímulo → receptor sensorial → nervo aferente → medula espinal (integração) → nervo eferente → efetor (músculo ou glândula). Contorna o cérebro para maior velocidade.","pt_PT":"A via neural para uma resposta involuntária: estímulo → receptor sensorial → nervo aferente → medula espinal (integração) → nervo eferente → efetor (músculo ou glândula). Contorna o cérebro para maior velocidade."}},
  { id: 'dc-biology-0123', deck_id: 'deck-biology', sort_order: 123, front: "Muscle Contraction (Sliding Filament Theory)", back: "Myosin heads bind actin filaments, form cross-bridges, and pull actin toward the center (power stroke) using ATP hydrolysis. Ca²⁺ (released from SR) triggers contraction by exposing myosin binding sites on actin." , front_translations: {"es":"Contración muscular (teoría de los filamentos deslizantes)","de":"Muskelkontraktion (Gleitfilamenttheorie)","fr":"Contraction musculaire (théorie des filaments glissants)","tr":"Kas Kasılması (Kayan Filament Teorisi)","nl":"Spiercontractie (glijfilamenttheorie)","ru":"Сокращение мышц (теория скользящих нитей)","zh":"肌肉收缩（肌丝滑动学说）","pt_BR":"Contração muscular (teoria dos filamentos deslizantes)","pt_PT":"Contração muscular (teoria dos filamentos deslizantes)"}, back_translations: {"es":"As cabeças de miosina ligam-se a los filamentos de actina, forman pontes cruzadas y puxam a actina para el centro (golpe de fuerza) usando hidrólise de ATP. El Ca²⁺ (liberado del RS) desencadeia a contración expondo los sítios de enlace de la miosina en la actina.","de":"Myosinköpfe binden an Aktinfilamente, bilden Querbrücken und ziehen Aktin zur Mitte (Kraftschlag) unter Verwendung der ATP-Hydrolyse. Ca²⁺ (aus dem SR freigesetzt) löst die Kontraktion aus, indem es Myosin-Bindungsstellen am Aktin freilegt.","fr":"Les têtes de myosine se lient aux filaments d'actine, forment des ponts transversaux et tirent l'actine vers le centre (coup de force) grâce à l'hydrolyse de l'ATP. Le Ca²⁺ (libéré du RS) déclenche la contraction en exposant les sites de liaison à la myosine sur l'actine.","tr":"Miyozin başları aktin filamentlerine bağlanır, çapraz köprüler oluşturur ve ATP hidrolizini kullanarak aktini merkeze doğru çeker (güç darbesi). Ca²⁺ (SR'dan salınır), aktin üzerindeki miyozin bağlanma bölgelerini açığa çıkararak kasılmayı tetikler.","nl":"Myosinekoppen binden aan actinefilamenten, vormen dwarsbanden en trekken actine naar het centrum (krachtslag) met behulp van ATP-hydrolyse. Ca²⁺ (vrijgegeven uit SR) triggert contractie door myosinebindingssites op actine bloot te stellen.","ru":"Головки миозина связываются с актиновыми филаментами, образуют поперечные мостики и тянут актин к центру (рабочий ход), используя гидролиз АТФ. Ca²⁺ (высвобождаемый из СПР) запускает сокращение, обнажая сайты связывания миозина на актине.","zh":"肌球蛋白头部与肌动蛋白纤维结合，形成横桥，利用ATP水解将肌动蛋白向中心拉动（动力冲程）。Ca²⁺（从肌质网释放）通过暴露肌动蛋白上的肌球蛋白结合位点来触发收缩。","pt_BR":"As cabeças de miosina ligam-se aos filamentos de actina, formam pontes cruzadas e puxam a actina para o centro (golpe de força) usando hidrólise de ATP. O Ca²⁺ (liberado do RS) desencadeia a contração expondo os sítios de ligação da miosina na actina.","pt_PT":"As cabeças de miosina ligam-se aos filamentos de actina, formam pontes cruzadas e puxam a actina para o centro (golpe de força) usando hidrólise de ATP. O Ca²⁺ (libertado do RS) desencadeia a contração expondo os locais de ligação da miosina na actina."}},
  { id: 'dc-biology-0124', deck_id: 'deck-biology', sort_order: 124, front: "Thermoregulation", back: "Endotherms (mammals, birds) generate body heat internally and maintain a constant temperature. Ectotherms (reptiles, fish) rely on environmental heat. Mechanisms: sweating, shivering, vasodilation, vasoconstriction." , front_translations: {"es":"Termorregulación","de":"Thermoregulation","fr":"Thermorégulation","tr":"Termoregülasyon","nl":"Thermoregulatie","ru":"Терморегуляция","zh":"体温调节","pt_BR":"Termorregulação","pt_PT":"Termorregulação"}, back_translations: {"es":"Endotermos (mamíferos, aves) generan calor corporal internamente y mantem temperatura constante. Ectotermos (répteis, peixes) dependen del calor ambiental. Mecanismos: suor, calafrios, vasodilatación, vasoconstrición.","de":"Endotherme (Säugetiere, Vögel) erzeugen Körperwärme intern und halten eine konstante Temperatur. Ektotherme (Reptilien, Fische) sind auf Umgebungswärme angewiesen. Mechanismen: Schwitzen, Zittern, Vasodilatation, Vasokonstriktion.","fr":"Les endothermes (mammifères, oiseaux) génèrent leur chaleur corporelle en interne et maintiennent une température constante. Les ectothermes (reptiles, poissons) dépendent de la chaleur environnementale. Mécanismes : transpiration, frissons, vasodilatation, vasoconstriction.","tr":"Endotermler (memeliler, kuşlar) vücut ısısını içsel olarak üretir ve sabit bir sıcaklık korur. Ektotermler (sürüngenler, balıklar) çevresel ısıya güvenir. Mekanizmalar: terleme, titreme, vazodilasyon, vazokonstriksiyon.","nl":"Endothermen (zoogdieren, vogels) genereren lichaamswarmte intern en behouden een constante temperatuur. Ectothermen (reptielen, vissen) vertrouwen op omgevingswarmte. Mechanismen: zweten, rillen, vasodilatatie, vasoconstrictie.","ru":"Эндотермные животные (млекопитающие, птицы) вырабатывают тепло тела внутренне и поддерживают постоянную температуру. Эктотермные животные (рептилии, рыбы) зависят от тепла окружающей среды. Механизмы: потоотделение, дрожание, вазодилатация, вазоконстрикция.","zh":"内温动物（哺乳动物、鸟类）在体内产生热量并维持恒定体温。外温动物（爬行动物、鱼类）依赖环境热量。机制：出汗、颤抖、血管扩张、血管收缩。","pt_BR":"Endotermos (mamíferos, aves) geram calor corporal internamente e mantêm temperatura constante. Ectotermos (répteis, peixes) dependem do calor ambiental. Mecanismos: suor, calafrios, vasodilatação, vasoconstrição.","pt_PT":"Os endotermos (mamíferos, aves) geram calor corporal internamente e mantêm uma temperatura constante. Os ectotermos (répteis, peixes) dependem do calor ambiental. Mecanismos: transpiração, tremores, vasodilatação, vasoconstrição."}},
  { id: 'dc-biology-0125', deck_id: 'deck-biology', sort_order: 125, front: "Osmoregulation", back: "The regulation of water and ion balance to maintain homeostasis. Marine fish drink seawater; freshwater fish excrete dilute urine. The kidney is the primary osmoregulatory organ in vertebrates." , front_translations: {"es":"Osmorregulación","de":"Osmoregulation","fr":"Osmorégulation","tr":"Osmoregülasyon","nl":"Osmoregulatie","ru":"Осморегуляция","zh":"渗透调节","pt_BR":"Osmorregulação","pt_PT":"Osmorregulação"}, back_translations: {"es":"La regulación del equilíbrio hídrico y ionico para mantener a homeostase. Peixes marinhos bebem agua del mar; peixes de agua doce excretam urina diluída. El riñón es el principal órgano osmorregulador en los vertebrados.","de":"Die Regulierung des Wasser- und Ionenhaushalts zur Aufrechterhaltung der Homöostase. Meeresfische trinken Meerwasser; Süßwasserfische scheiden verdünnten Urin aus. Die Niere ist das primäre Osmoregulationsorgan bei Wirbeltieren.","fr":"La régulation de l'équilibre hydrique et ionique pour maintenir l'homéostasie. Les poissons marins boivent de l'eau de mer ; les poissons d'eau douce excrètent une urine diluée. Le rein est l'organe osmorégulateur principal chez les vertébrés.","tr":"Homeostazisi korumak için su ve iyon dengesinin düzenlenmesi. Deniz balıkları tuzlu su içer; tatlısu balıkları seyreltik idrar atar. Böbrek, omurgalılardaki başlıca osmoregülatör organdır.","nl":"De regulatie van water- en ionenbalans om homeostase te handhaven. Zeevis drinkt zeewater; zoetwatervis scheidt verdunde urine uit. De nier is het primaire osmoregulerende orgaan bij gewervelden.","ru":"Регуляция баланса воды и ионов для поддержания гомеостаза. Морские рыбы пьют морскую воду; пресноводные рыбы выделяют разбавленную мочу. Почка является основным осморегуляторным органом позвоночных.","zh":"调节水分和离子平衡以维持稳态。海水鱼饮用海水；淡水鱼排出稀释的尿液。肾脏是脊椎动物的主要渗透调节器官。","pt_BR":"A regulação do equilíbrio hídrico e iônico para manter a homeostase. Peixes marinhos bebem água do mar; peixes de água doce excretam urina diluída. O rim é o principal órgão osmorregulador nos vertebrados.","pt_PT":"A regulação do equilíbrio hídrico e iónico para manter a homeostase. Os peixes marinhos bebem água do mar; os peixes de água doce excretam urina diluída. O rim é o principal órgão osmorregulador nos vertebrados."}},
  { id: 'dc-biology-0126', deck_id: 'deck-biology', sort_order: 126, front: "Decomposers", back: "Organisms (mainly bacteria and fungi) that break down dead organic matter into inorganic molecules, returning nutrients to the ecosystem. Essential for nutrient cycling; without them, nutrients would be locked in dead matter." , front_translations: {"es":"Decompositores","de":"Destruenten","fr":"Décomposeurs","tr":"Ayrıştırıcılar","nl":"Afbrekers","ru":"Редуценты","zh":"分解者","pt_BR":"Decompositores","pt_PT":"Decompositores"}, back_translations: {"es":"Organismos (principalmente bacterias y fungos) que decompõem materia orgánica morta en moléculas inorganicas, devolvendo nutrientes al ecossistema. Essenciais para el ciclo de nutrientes; sin eles, los nutrientes ficariam presos en la materia morta.","de":"Organismen (hauptsächlich Bakterien und Pilze), die totes organisches Material in anorganische Moleküle zersetzen und Nährstoffe in das Ökosystem zurückführen. Unverzichtbar für den Nährstoffkreislauf; ohne sie würden Nährstoffe in toter Materie gebunden bleiben.","fr":"Organismes (principalement des bactéries et des champignons) qui décomposent la matière organique morte en molécules inorganiques, restituant les nutriments à l'écosystème. Essentiels au cycle des nutriments ; sans eux, les nutriments seraient bloqués dans la matière morte.","tr":"Ölü organik maddeyi inorganik moleküllere parçalayan ve besin maddelerini ekosisteme geri döndüren organizmalar (esas olarak bakteri ve mantarlar). Besin döngüsü için hayati öneme sahiptir; onlar olmadan besin maddeleri ölü maddede hapsolurdu.","nl":"Organismen (voornamelijk bacteriën en schimmels) die dood organisch materiaal afbreken tot anorganische moleculen en nutriënten teruggeven aan het ecosysteem. Essentieel voor de nutriëntenkringloop; zonder hen zouden nutriënten opgesloten zitten in dood materiaal.","ru":"Организмы (главным образом бактерии и грибы), которые разлагают мёртвое органическое вещество на неорганические молекулы, возвращая питательные вещества в экосистему. Незаменимы для круговорота веществ; без них питательные вещества были бы заперты в мёртвом органическом материале.","zh":"将死亡有机物分解为无机分子、将养分归还给生态系统的生物（主要是细菌和真菌）。对养分循环至关重要；若没有它们，养分将被锁在死亡的有机物中。","pt_BR":"Organismos (principalmente bactérias e fungos) que decompõem matéria orgânica morta em moléculas inorgânicas, devolvendo nutrientes ao ecossistema. Essenciais para o ciclo de nutrientes; sem eles, os nutrientes ficariam presos na matéria morta.","pt_PT":"Organismos (principalmente bactérias e fungos) que decompõem matéria orgânica morta em moléculas inorgânicas, devolvendo nutrientes ao ecossistema. Essenciais para o ciclo de nutrientes; sem eles, os nutrientes ficariam presos na matéria morta."}},
  { id: 'dc-biology-0127', deck_id: 'deck-biology', sort_order: 127, front: "Keystone Species", back: "A species that has a disproportionately large effect on its ecosystem relative to its abundance. Removal causes dramatic shifts in species composition. E.g., sea otters (control sea urchins, protect kelp forests)." , front_translations: {"es":"Espécie-Chave","de":"Schlüsselart","fr":"Espèce clé de voûte","tr":"Kilit Tür","nl":"Sleutelsoort","ru":"Ключевой вид","zh":"关键物种","pt_BR":"Espécie-Chave","pt_PT":"Espécie-Chave"}, back_translations: {"es":"Una especie que tiene un efecto desproporcionalmente grande en su ecossistema en relación con la su abundancia. Sua remoción causa cambios dramáticas en la composición de las especies. Ex.: lontras-marinhas (controlan ouriços-del-mar, protegen florestas de algas).","de":"Eine Art, die im Verhältnis zu ihrer Häufigkeit einen unverhältnismäßig großen Einfluss auf ihr Ökosystem hat. Ihr Verschwinden führt zu dramatischen Verschiebungen in der Artenzusammensetzung. Z. B. Seeotter (kontrollieren Seeigel, schützen Kelpwälder).","fr":"Une espèce qui a un effet disproportionnellement important sur son écosystème par rapport à son abondance. Sa disparition entraîne des changements dramatiques dans la composition des espèces. Ex. : la loutre de mer (contrôle les oursins, protège les forêts de varech).","tr":"Bolluğuna oranla ekosistemi üzerinde orantısız derecede büyük bir etkiye sahip olan tür. Ortadan kalkması, tür bileşiminde dramatik değişimlere neden olur. Örn. deniz sorları (deniz kirpilerini kontrol eder, yosun ormanlarını korur).","nl":"Een soort die een onevenredig groot effect heeft op zijn ecosysteem in verhouding tot zijn abundantie. Verwijdering veroorzaakt dramatische verschuivingen in de soortensamenstelling. Bijv. zeeotters (beheersen zee-egels, beschermen kelpbossen).","ru":"Вид, оказывающий несоразмерно большое влияние на свою экосистему относительно своей численности. Его исчезновение вызывает резкие изменения в видовом составе. Например, морские выдры (контролируют морских ежей, защищают леса из ламинарий).","zh":"相对于其数量，对生态系统具有不成比例的巨大影响的物种。移除该物种会导致物种组成发生剧烈变化。例如：海獭（控制海胆，保护海带林）。","pt_BR":"Uma espécie que tem um efeito desproporcionalmente grande em seu ecossistema em relação à sua abundância. Sua remoção causa mudanças dramáticas na composição das espécies. Ex.: lontras-marinhas (controlam ouriços-do-mar, protegem florestas de algas).","pt_PT":"Uma espécie que tem um efeito desproporcionalmente grande no seu ecossistema em relação à sua abundância. A sua remoção causa mudanças dramáticas na composição das espécies. Ex.: lontras-marinhas (controlam ouriços-do-mar, protegem florestas de algas)."}},
  { id: 'dc-biology-0128', deck_id: 'deck-biology', sort_order: 128, front: "Biodiversity", back: "The variety of life at genetic, species, and ecosystem levels. Higher biodiversity generally means greater ecosystem stability and resilience. Threatened by habitat destruction, invasive species, overexploitation, and climate change." , front_translations: {"es":"Biodiversidad","de":"Biodiversität","fr":"Biodiversité","tr":"Biyoçeşitlilik","nl":"Biodiversiteit","ru":"Биоразнообразие","zh":"生物多样性","pt_BR":"Biodiversidade","pt_PT":"Biodiversidade"}, back_translations: {"es":"La variedad de vida en los niveles genético, de especies y de ecossistemas. Una biodiversidad mayor generalmente significa mayor estabilidad y resiliencia del ecossistema. Ameaçada por la destrucción de habitats, especies invasoras, superexploración y cambios climáticas.","de":"Die Vielfalt des Lebens auf genetischer, Art- und Ökosystemebene. Höhere Biodiversität bedeutet im Allgemeinen eine größere Stabilität und Widerstandsfähigkeit des Ökosystems. Bedroht durch Habitatzerstörung, invasive Arten, Übernutzung und Klimawandel.","fr":"La variété du vivant aux niveaux génétique, des espèces et des écosystèmes. Une biodiversité plus élevée signifie généralement une plus grande stabilité et résilience de l'écosystème. Menacée par la destruction des habitats, les espèces invasives, la surexploitation et le changement climatique.","tr":"Genetik, tür ve ekosistem düzeylerinde yaşam çeşitliliği. Daha yüksek biyoçeşitlilik genellikle daha büyük ekosistem istikrarı ve dayanıklılığı anlamına gelir. Habitat tahribatı, istilacı türler, aşırı sömürü ve iklim değişikliği tarafından tehdit edilmektedir.","nl":"De verscheidenheid aan leven op genetisch, soort- en ecosysteemniveau. Hogere biodiversiteit betekent over het algemeen grotere ecosysteemstabiliteit en veerkracht. Bedreigd door habitatvernietiging, invasieve soorten, overexploitatie en klimaatverandering.","ru":"Разнообразие жизни на генетическом, видовом и экосистемном уровнях. Более высокое биоразнообразие, как правило, означает большую стабильность и устойчивость экосистемы. Находится под угрозой из-за разрушения среды обитания, инвазивных видов, сверхэксплуатации и изменения климата.","zh":"基因、物种和生态系统层面的生命多样性。较高的生物多样性通常意味着更大的生态系统稳定性和恢复力。受到栖息地破坏、入侵物种、过度开发和气候变化的威胁。","pt_BR":"A variedade de vida nos níveis genético, de espécies e de ecossistemas. Uma biodiversidade maior geralmente significa maior estabilidade e resiliência do ecossistema. Ameaçada pela destruição de habitats, espécies invasoras, superexploração e mudanças climáticas.","pt_PT":"A variedade de vida nos níveis genético, de espécies e de ecossistemas. Uma biodiversidade maior geralmente significa maior estabilidade e resiliência do ecossistema. Ameaçada pela destruição de habitats, espécies invasoras, sobreexploração e alterações climáticas."}},
  { id: 'dc-biology-0129', deck_id: 'deck-biology', sort_order: 129, front: "Five Kingdoms (Classic Classification)", back: "Monera (prokaryotes), Protista, Fungi, Plantae, Animalia. Superseded by the three-domain system but still sometimes used in introductory biology. Domains split Monera into Bacteria and Archaea." , front_translations: {"es":"Cinco Reinos (Classificación Clássica)","de":"Fünf Reiche (Klassische Klassifikation)","fr":"Cinq règnes (classification classique)","tr":"Beş Alem (Klasik Sınıflandırma)","nl":"Vijf rijken (klassieke classificatie)","ru":"Пять царств (классическая классификация)","zh":"五界（经典分类）","pt_BR":"Cinco Reinos (Classificação Clássica)","pt_PT":"Cinco Reinos (Classificação Clássica)"}, back_translations: {"es":"Monera (procariotos), Protista, Fungi, Plantae, Animalia. Substituído por el sistema de tres domínios, pero aún a las veces usado en biologia introdutória. Los domínios dividem Monera en Bacteria y Archaea.","de":"Monera (Prokaryoten), Protista, Fungi, Plantae, Animalia. Vom Drei-Domänen-System abgelöst, aber in der einführenden Biologie noch manchmal verwendet. Domänen unterteilen Monera in Bacteria und Archaea.","fr":"Monera (procaryotes), Protista, Fungi, Plantae, Animalia. Remplacé par le système à trois domaines, mais encore parfois utilisé en biologie introductive. Les domaines divisent Monera en Bacteria et Archaea.","tr":"Monera (prokaryotlar), Protista, Fungi, Plantae, Animalia. Üç-alan sistemiyle aşıldı ancak tanıtıcı biyolojide hâlâ zaman zaman kullanılmaktadır. Alanlar, Monera'yı Bacteria ve Archaea olarak ikiye böler.","nl":"Monera (prokaryoten), Protista, Fungi, Plantae, Animalia. Vervangen door het drie-domeinensysteem, maar nog steeds soms gebruikt in de inleidende biologie. Domeinen splitsen Monera op in Bacteria en Archaea.","ru":"Monera (прокариоты), Protista, Fungi, Plantae, Animalia. Вытеснены системой трёх доменов, но иногда всё ещё используются в вводной биологии. Домены разделяют Monera на Bacteria и Archaea.","zh":"原核生物界（Monera）、原生生物界（Protista）、真菌界（Fungi）、植物界（Plantae）、动物界（Animalia）。已被三域系统取代，但在入门生物学中有时仍在使用。三域系统将原核生物界分为细菌域和古菌域。","pt_BR":"Monera (procariotos), Protista, Fungi, Plantae, Animalia. Substituído pelo sistema de três domínios, mas ainda às vezes usado em biologia introdutória. Os domínios dividem Monera em Bacteria e Archaea.","pt_PT":"Monera (procariotas), Protista, Fungi, Plantae, Animalia. Substituído pelo sistema de três domínios, mas ainda por vezes utilizado em biologia introdutória. Os domínios dividem Monera em Bacteria e Archaea."}},
  { id: 'dc-biology-0130', deck_id: 'deck-biology', sort_order: 130, front: "Convergent Evolution", back: "The independent evolution of similar traits in unrelated lineages due to similar selective pressures. E.g., wings in bats, birds, and insects; streamlined bodies in dolphins and sharks. Analogous structures (similar function, different origin)." , front_translations: {"es":"Evolución Convergente","de":"Konvergente Evolution","fr":"Évolution convergente","tr":"Yakınsak Evrim","nl":"Convergente evolutie","ru":"Конвергентная эволюция","zh":"趋同进化","pt_BR":"Evolução Convergente","pt_PT":"Evolução Convergente"}, back_translations: {"es":"La evolución independente de traços similares en linhajes no relacionadas debido a presiones seletivas semelhantes. Ex.: asas en morcegos, aves y insetos; cuerpos aerodinamicos en golfinhos y tubarões. Estruturas análogas (función similar, origem diferente).","de":"Die unabhängige Entwicklung ähnlicher Merkmale in nicht verwandten Linien aufgrund ähnlicher Selektionsdrücke. Z. B. Flügel bei Fledermäusen, Vögeln und Insekten; stromlinienförmige Körper bei Delfinen und Haien. Analoge Strukturen (ähnliche Funktion, unterschiedlicher Ursprung).","fr":"L'évolution indépendante de traits similaires dans des lignées non apparentées en raison de pressions sélectives similaires. Ex. : ailes chez les chauves-souris, les oiseaux et les insectes ; corps fuselés chez les dauphins et les requins. Structures analogues (fonction similaire, origine différente).","tr":"Benzer seçilim baskıları nedeniyle birbirleriyle ilişkisiz soylar arasında benzer özelliklerin bağımsız olarak evrimleşmesi. Örn. yarasa, kuş ve böceklerde kanatlar; yunus ve köpekbalıklarında aerodinamik gövdeler. Analog yapılar (benzer işlev, farklı köken).","nl":"De onafhankelijke evolutie van vergelijkbare kenmerken in niet-verwante lijnen door vergelijkbare selectiedrukken. Bijv. vleugels bij vleermuizen, vogels en insecten; gestroomlijnde lichamen bij dolfijnen en haaien. Analoge structuren (vergelijkbare functie, andere oorsprong).","ru":"Независимое развитие сходных признаков у неродственных линий под влиянием схожих факторов отбора. Например, крылья у летучих мышей, птиц и насекомых; обтекаемая форма тела у дельфинов и акул. Аналогичные структуры (схожая функция, разное происхождение).","zh":"在不相关的谱系中，由于相似的选择压力而独立进化出相似性状。例如：蝙蝠、鸟类和昆虫的翅膀；海豚和鲨鱼的流线型身体。同功结构（功能相似，起源不同）。","pt_BR":"A evolução independente de traços similares em linhagens não relacionadas devido a pressões seletivas semelhantes. Ex.: asas em morcegos, aves e insetos; corpos aerodinâmicos em golfinhos e tubarões. Estruturas análogas (função similar, origem diferente).","pt_PT":"A evolução independente de traços semelhantes em linhagens não relacionadas devido a pressões seletivas similares. Ex.: asas em morcegos, aves e insetos; corpos aerodinâmicos em golfinhos e tubarões. Estruturas análogas (função semelhante, origem diferente)."}},
  { id: 'dc-biology-0131', deck_id: 'deck-biology', sort_order: 131, front: "Homologous Structures", back: "Structures in different species that share common ancestry and underlying anatomy, even if their functions differ. E.g., human arm, whale flipper, bat wing. Evidence for common descent." , front_translations: {"es":"Estruturas Homólogas","de":"Homologe Strukturen","fr":"Structures homologues","tr":"Homolog Yapılar","nl":"Homologe structuren","ru":"Гомологичные структуры","zh":"同源结构","pt_BR":"Estruturas Homólogas","pt_PT":"Estruturas Homólogas"}, back_translations: {"es":"Estruturas en diferentes especies que compartilham ancestralidad comum y anatomia subjacente, mismo que sus funciones difiram. Ex.: brazo humano, nadadera de baleia, asa de morcego. Evidencia de descendencia comum.","de":"Strukturen bei verschiedenen Arten, die eine gemeinsame Abstammung und zugrunde liegende Anatomie teilen, auch wenn ihre Funktionen unterschiedlich sind. Z. B. menschlicher Arm, Walflossen, Fledermausflügel. Beweis für gemeinsame Abstammung.","fr":"Structures chez différentes espèces qui partagent une ascendance commune et une anatomie sous-jacente, même si leurs fonctions diffèrent. Ex. : bras humain, nageoire de baleine, aile de chauve-souris. Preuve de la descendance commune.","tr":"İşlevleri farklı olsa bile ortak atalardan miras kalan anatomik yapıya sahip olan, farklı türlerdeki yapılar. Örn. insan kolu, balina yüzgeci, yarasa kanadı. Ortak soyun kanıtıdır.","nl":"Structuren bij verschillende soorten die een gemeenschappelijke voorouder en onderliggende anatomie delen, ook al verschillen hun functies. Bijv. menselijke arm, walvisvin, vleermuisvleugel. Bewijs voor gemeenschappelijke afstamming.","ru":"Структуры у разных видов, имеющие общее происхождение и сходную анатомию, даже если их функции различаются. Например, рука человека, плавник кита, крыло летучей мыши. Свидетельство общего происхождения.","zh":"不同物种中具有共同祖先和相似解剖结构的器官，即使功能不同。例如：人类手臂、鲸鱼鳍肢、蝙蝠翅膀。是共同起源的证据。","pt_BR":"Estruturas em diferentes espécies que compartilham ancestralidade comum e anatomia subjacente, mesmo que suas funções difiram. Ex.: braço humano, nadadeira de baleia, asa de morcego. Evidência de descendência comum.","pt_PT":"Estruturas em diferentes espécies que partilham uma ancestralidade comum e anatomia subjacente, mesmo que as suas funções difiram. Ex.: braço humano, barbatana de baleia, asa de morcego. Evidência de descendência comum."}},
  { id: 'dc-biology-0132', deck_id: 'deck-biology', sort_order: 132, front: "Vestigial Structures", back: "Rudimentary organs or structures with little or no apparent function in present-day organisms, but were functional in ancestors. E.g., human coccyx (tailbone), whale pelvis, appendix (debated)." , front_translations: {"es":"Estruturas Vestigiais","de":"Vestigiale Strukturen","fr":"Structures vestigiales","tr":"Körelmiş Yapılar","nl":"Vestigiale structuren","ru":"Рудиментарные структуры","zh":"痕迹结构","pt_BR":"Estruturas Vestigiais","pt_PT":"Estruturas Vestigiais"}, back_translations: {"es":"Órgãos o estructuras rudimentares con pouca o ninguna función aparente en los organismos atuais, pero que eran funcionais en ancestrais. Ex.: cóccix humano, pelve de baleia, apéndice (debatido).","de":"Rudimentäre Organe oder Strukturen mit wenig oder keiner offensichtlichen Funktion in heutigen Organismen, die aber bei Vorfahren funktional waren. Z. B. menschliches Steißbein, Walsbecken, Blinddarm (umstritten).","fr":"Organes ou structures rudimentaires avec peu ou pas de fonction apparente chez les organismes actuels, mais qui étaient fonctionnels chez les ancêtres. Ex. : coccyx humain, bassin de la baleine, appendice (débattu).","tr":"Günümüz organizmalarında çok az veya hiç belirgin işlevi olmayan, ancak atalarda işlevsel olan ilkel organ veya yapılar. Örn. insanda kuyruk sokumu, balinada leğen kemiği, apandis (tartışmalı).","nl":"Rudimentaire organen of structuren met weinig of geen duidelijke functie in hedendaagse organismen, maar die functioneel waren bij voorouders. Bijv. het menselijk staartbeen (coccyx), walvisbekken, appendix (betwist).","ru":"Недоразвитые органы или структуры с малой или нулевой очевидной функцией у современных организмов, но бывшие функциональными у предков. Например, копчик человека, тазовые кости кита, аппендикс (спорно).","zh":"在现代生物中几乎没有或完全没有明显功能的退化器官或结构，但在祖先中曾发挥功能。例如：人类尾骨、鲸鱼骨盆、阑尾（存在争议）。","pt_BR":"Órgãos ou estruturas rudimentares com pouca ou nenhuma função aparente nos organismos atuais, mas que eram funcionais em ancestrais. Ex.: cóccix humano, pelve de baleia, apêndice (debatido).","pt_PT":"Órgãos ou estruturas rudimentares com pouca ou nenhuma função aparente nos organismos atuais, mas que eram funcionais em ancestrais. Ex.: cóccix humano, pélvis de baleia, apêndice (debatido)."}},
  { id: 'dc-biology-0133', deck_id: 'deck-biology', sort_order: 133, front: "Horizontal Gene Transfer", back: "Transfer of genetic material between organisms other than from parent to offspring (non-vertical). Common in bacteria via conjugation (plasmid transfer), transformation (absorb DNA), and transduction (via virus)." , front_translations: {"es":"Transferencia Horizontal de Genes","de":"Horizontaler Gentransfer","fr":"Transfert horizontal de gènes","tr":"Yatay Gen Transferi","nl":"Horizontale genoverdracht","ru":"Горизонтальный перенос генов","zh":"水平基因转移","pt_BR":"Transferência Horizontal de Genes","pt_PT":"Transferência Horizontal de Genes"}, back_translations: {"es":"Transferencia de material genético entre organismos de forma diferente de pai para hijo (no vertical). Comum en bacterias por conjugación (transferencia de plasmídeo), transformación (absorción de DNA) y transdución (por virus).","de":"Übertragung von genetischem Material zwischen Organismen auf anderem Weg als von Elternteil zu Nachkomme (nicht vertikal). Häufig bei Bakterien durch Konjugation (Plasmidübertragung), Transformation (Aufnahme von DNA) und Transduktion (durch Viren).","fr":"Transfert de matériel génétique entre organismes autrement que de parent à descendant (non vertical). Courant chez les bactéries par conjugaison (transfert de plasmide), transformation (absorption d'ADN) et transduction (par virus).","tr":"Ebeveynden yavruya doğru olmayan (dikey olmayan) genetik materyalin organizmalar arasında aktarılması. Bakterilerde konjugasyon (plazmit transferi), transformasyon (DNA emilimi) ve transdüksiyon (virüs aracılığıyla) ile yaygın görülür.","nl":"Overdracht van genetisch materiaal tussen organismen anders dan van ouder op nakomelingen (niet verticaal). Gebruikelijk bij bacteriën via conjugatie (plasmidetransfer), transformatie (opnemen van DNA) en transductie (via virus).","ru":"Передача генетического материала между организмами иначе, чем от родителя к потомку (не вертикальная). Широко распространён у бактерий посредством конъюгации (передача плазмиды), трансформации (поглощение ДНК) и трансдукции (через вирус).","zh":"在非亲代到子代（非垂直）方式下，生物体之间遗传物质的转移。在细菌中常见，途径包括接合（质粒转移）、转化（吸收DNA）和转导（通过病毒）。","pt_BR":"Transferência de material genético entre organismos de forma diferente de pai para filho (não vertical). Comum em bactérias por conjugação (transferência de plasmídeo), transformação (absorção de DNA) e transdução (por vírus).","pt_PT":"Transferência de material genético entre organismos de forma diferente de progenitor para descendente (não vertical). Comum em bactérias por conjugação (transferência de plasmídeo), transformação (absorção de DNA) e transdução (por vírus)."}},
  { id: 'dc-biology-0134', deck_id: 'deck-biology', sort_order: 134, front: "Endosymbiotic Theory", back: "Proposes that mitochondria and chloroplasts evolved from prokaryotes engulfed by ancestral eukaryotic cells. Evidence: both organelles have circular DNA, double membranes, and replicate by binary fission." , front_translations: {"es":"Teoria Endossimbiótica","de":"Endosymbiontentheorie","fr":"Théorie endosymbiotique","tr":"Endosimbiyotik Teori","nl":"Endosymbionttheorie","ru":"Теория эндосимбиоза","zh":"内共生理论","pt_BR":"Teoria Endossimbiótica","pt_PT":"Teoria Endossimbiótica"}, back_translations: {"es":"Propõe que mitocondrias y cloroplastos evoluíram a partir de procariotos engolfados por células eucarióticas ancestrais. Evidencias: ambas las organelas possuem DNA circular, duplas membranas y se replicam por fisión binária.","de":"Schlägt vor, dass Mitochondrien und Chloroplasten sich aus Prokaryoten entwickelt haben, die von ancestralen eukaryotischen Zellen aufgenommen wurden. Beweise: Beide Organellen besitzen ringförmige DNA, Doppelmembranen und replizieren durch binäre Spaltung.","fr":"Propose que les mitochondries et les chloroplastes ont évolué à partir de procaryotes englobés par des cellules eucaryotes ancestrales. Preuves : les deux organites possèdent de l'ADN circulaire, des doubles membranes et se répliquent par fission binaire.","tr":"Mitokondrinin ve kloroplastların, atalardan gelen ökaryotik hücreler tarafından yutulmuş prokaryotlardan evrildiğini öne sürer. Kanıt: her iki organelin de halkasal DNA'sı, çift zarı vardır ve ikili bölünmeyle çoğalır.","nl":"Stelt voor dat mitochondriën en chloroplasten zijn geëvolueerd uit prokaryoten die werden opgenomen door voorouderlijke eukaryotische cellen. Bewijs: beide organellen hebben circulair DNA, dubbele membranen en repliceren door binaire splitsing.","ru":"Предполагает, что митохондрии и хлоропласты произошли от прокариот, поглощённых предковыми эукариотическими клетками. Доказательства: оба органоида имеют кольцевую ДНК, двойные мембраны и размножаются путём бинарного деления.","zh":"认为线粒体和叶绿体由被祖先真核细胞吞噬的原核生物进化而来。证据：两种细胞器均具有环状DNA、双层膜，并通过二分裂方式复制。","pt_BR":"Propõe que mitocôndrias e cloroplastos evoluíram a partir de procariotos engolfados por células eucarióticas ancestrais. Evidências: ambas as organelas possuem DNA circular, duplas membranas e se replicam por fissão binária.","pt_PT":"Propõe que as mitocôndrias e os cloroplastos evoluíram a partir de procariontes englobados por células eucarióticas ancestrais. Evidências: ambas as organelas têm DNA circular, membranas duplas e replicam-se por fissão binária."}},
  { id: 'dc-biology-0135', deck_id: 'deck-biology', sort_order: 135, front: "Crossing Over (Recombination)", back: "The exchange of DNA segments between homologous chromosomes during prophase I of meiosis. Creates new combinations of alleles (recombinant chromosomes), increasing genetic diversity in offspring." , front_translations: {"es":"Crossing-over (Recombinación)","de":"Crossing-over (Rekombination)","fr":"Enjambement (recombinaison)","tr":"Krosing Over (Rekombinasyon)","nl":"Crossing-over (recombinatie)","ru":"Кроссинговер (рекомбинация)","zh":"交叉互换（重组）","pt_BR":"Crossing-over (Recombinação)","pt_PT":"Crossing-over (Recombinação)"}, back_translations: {"es":"La troca de segmentos de DNA entre cromossomos homólogos durante a prófase I de la meiose. Cria nuevas combinaciones de alelos (cromossomos recombinantes), aumentando a diversidad genética de los descendentes.","de":"Der Austausch von DNA-Segmenten zwischen homologen Chromosomen während der Prophase I der Meiose. Erzeugt neue Kombinationen von Allelen (rekombinante Chromosomen) und erhöht die genetische Vielfalt der Nachkommen.","fr":"L'échange de segments d'ADN entre chromosomes homologues lors de la prophase I de la méiose. Crée de nouvelles combinaisons d'allèles (chromosomes recombinants), augmentant la diversité génétique de la descendance.","tr":"Mayoz bölünmenin profaz I evresinde homolog kromozomlar arasında DNA segmentlerinin değiş tokuşu. Yeni alel kombinasyonları (rekombinant kromozomlar) oluşturarak yavru bireylerin genetik çeşitliliğini artırır.","nl":"De uitwisseling van DNA-segmenten tussen homologe chromosomen tijdens profase I van de meiose. Creëert nieuwe combinaties van allelen (recombinante chromosomen), waardoor de genetische diversiteit van nakomelingen toeneemt.","ru":"Обмен сегментами ДНК между гомологичными хромосомами в профазе I мейоза. Создаёт новые комбинации аллелей (рекомбинантные хромосомы), увеличивая генетическое разнообразие потомства.","zh":"在减数第一次分裂前期，同源染色体之间DNA片段的交换。产生新的等位基因组合（重组染色体），增加后代的遗传多样性。","pt_BR":"A troca de segmentos de DNA entre cromossomos homólogos durante a prófase I da meiose. Cria novas combinações de alelos (cromossomos recombinantes), aumentando a diversidade genética dos descendentes.","pt_PT":"A troca de segmentos de DNA entre cromossomas homólogos durante a profase I da meiose. Cria novas combinações de alelos (cromossomas recombinantes), aumentando a diversidade genética dos descendentes."}},
  { id: 'dc-biology-0136', deck_id: 'deck-biology', sort_order: 136, front: "Linked Genes", back: "Genes located on the same chromosome tend to be inherited together (not assort independently). The closer two genes are, the less likely they are to be separated by crossing over. Morgan used Drosophila to map genes." , front_translations: {"es":"Genes Ligados","de":"Gekoppelte Gene","fr":"Gènes liés","tr":"Bağlantılı Genler","nl":"Gekoppelde genen","ru":"Сцепленные гены","zh":"连锁基因","pt_BR":"Genes Ligados","pt_PT":"Genes Ligados"}, back_translations: {"es":"Genes localizados en el mismo cromossomo tendem a ser herdados juntos (no se segregam independentemente). Quanto más próximos de los genes están, menor a probabilidad de serem separados por crossing-over. Morgan usou Drosophila para mapear genes.","de":"Gene, die sich auf demselben Chromosom befinden, werden tendenziell gemeinsam vererbt (nicht unabhängig assortiert). Je näher zwei Gene beieinander liegen, desto unwahrscheinlicher ist es, dass sie durch Crossing-over getrennt werden. Morgan nutzte Drosophila zur Genkartierung.","fr":"Les gènes situés sur le même chromosome ont tendance à être hérités ensemble (ne s'assortissent pas indépendamment). Plus deux gènes sont proches, moins ils risquent d'être séparés par enjambement. Morgan a utilisé la Drosophile pour cartographier les gènes.","tr":"Aynı kromozom üzerinde bulunan genler birlikte kalıtılma eğilimindedir (bağımsız olarak ayrışmaz). İki gen birbirine ne kadar yakınsa, krosing over ile ayrılma olasılıkları o kadar düşüktür. Morgan, genleri haritalamak için Drosophila kullandı.","nl":"Genen op hetzelfde chromosoom worden doorgaans samen overgeërfd (assorteerden niet onafhankelijk). Hoe dichter twee genen bij elkaar liggen, hoe minder kans dat ze worden gescheiden door crossing-over. Morgan gebruikte Drosophila om genen in kaart te brengen.","ru":"Гены, расположенные на одной хромосоме, как правило, наследуются вместе (не расходятся независимо). Чем ближе расположены два гена, тем меньше вероятность их разделения при кроссинговере. Морган использовал дрозофилу для картирования генов.","zh":"位于同一条染色体上的基因倾向于一起遗传（不独立分配）。两个基因越近，被交叉互换分离的可能性越小。摩尔根利用果蝇进行基因作图。","pt_BR":"Genes localizados no mesmo cromossomo tendem a ser herdados juntos (não se segregam independentemente). Quanto mais próximos dois genes estão, menor a probabilidade de serem separados por crossing-over. Morgan usou Drosophila para mapear genes.","pt_PT":"Os genes localizados no mesmo cromossoma tendem a ser herdados juntos (não se segregam independentemente). Quanto mais próximos dois genes estão, menor a probabilidade de serem separados por crossing-over. Morgan usou a Drosophila para mapear genes."}},
  { id: 'dc-biology-0137', deck_id: 'deck-biology', sort_order: 137, front: "Non-disjunction", back: "The failure of chromosomes to separate properly during meiosis, resulting in gametes with abnormal chromosome numbers. Produces conditions like Down syndrome (trisomy 21), Turner (45,X), and Klinefelter (47,XXY)." , front_translations: {"es":"No-disjunción","de":"Nondisjunktion","fr":"Non-disjonction","tr":"Ayrılmama (Non-Disjunction)","nl":"Non-disjunctie","ru":"Нерасхождение хромосом","zh":"不分离","pt_BR":"Não-disjunção","pt_PT":"Não-disjunção"}, back_translations: {"es":"La falha de los cromossomos en se separar corretamente durante a meiose, resultando en gametas con números anormais de cromossomos. Produz condiciones como síndrome de Down (trissomia 21), Turner (45,X) y Klinefelter (47,XXY).","de":"Das Versagen der Chromosomen, sich während der Meiose ordnungsgemäß zu trennen, was zu Gameten mit abnormaler Chromosomenzahl führt. Verursacht Zustände wie Down-Syndrom (Trisomie 21), Turner-Syndrom (45,X) und Klinefelter-Syndrom (47,XXY).","fr":"Le manquement des chromosomes à se séparer correctement lors de la méiose, aboutissant à des gamètes avec un nombre anormal de chromosomes. Produit des conditions comme le syndrome de Down (trisomie 21), Turner (45,X) et Klinefelter (47,XXY).","tr":"Kromozomların mayoz sırasında düzgün şekilde ayrılamaması, bu da anormal sayıda kromozoma sahip gametlerle sonuçlanır. Down sendromu (trizomi 21), Turner (45,X) ve Klinefelter (47,XXY) gibi durumlara yol açar.","nl":"Het falen van chromosomen om zich correct te scheiden tijdens de meiose, resulterend in gameten met abnormale chromosoomaantallen. Veroorzaakt aandoeningen zoals het syndroom van Down (trisomie 21), Turner (45,X) en Klinefelter (47,XXY).","ru":"Неспособность хромосом правильно разойтись во время мейоза, что приводит к образованию гамет с аномальным числом хромосом. Вызывает такие состояния, как синдром Дауна (трисомия 21), синдром Тёрнера (45,X) и синдром Клайнфельтера (47,XXY).","zh":"减数分裂过程中染色体未能正常分离，导致配子染色体数目异常。引发唐氏综合征（21-三体）、特纳综合征（45,X）和克兰费尔特综合征（47,XXY）等情况。","pt_BR":"A falha dos cromossomos em se separar corretamente durante a meiose, resultando em gametas com números anormais de cromossomos. Produz condições como síndrome de Down (trissomia 21), Turner (45,X) e Klinefelter (47,XXY).","pt_PT":"A falha dos cromossomas em se separar corretamente durante a meiose, resultando em gâmetas com números anormais de cromossomas. Produz condições como síndrome de Down (trissomia 21), Turner (45,X) e Klinefelter (47,XXY)."}},
  { id: 'dc-biology-0138', deck_id: 'deck-biology', sort_order: 138, front: "Polyploidy", back: "Having more than two complete sets of chromosomes (e.g., tetraploid = 4n). Common in plants; responsible for evolution of many crop species (wheat is hexaploid 6n). Usually lethal in animals." , front_translations: {"es":"Poliploidia","de":"Polyploidie","fr":"Polyploïdie","tr":"Poliploidi","nl":"Polyploïdie","ru":"Полиплоидия","zh":"多倍性","pt_BR":"Poliploidia","pt_PT":"Poliploidia"}, back_translations: {"es":"Ter más de de los conjuntos completos de cromossomos (ex.: tetraploide = 4n). Comum en plantas; responsable por la evolución de muchas especies de culturas (el trigo es hexaploide 6n). Geralmente letal en animales.","de":"Mehr als zwei vollständige Chromosomensätze besitzen (z. B. tetraploid = 4n). Häufig bei Pflanzen; verantwortlich für die Evolution vieler Kulturpflanzenarten (Weizen ist hexaploid 6n). Bei Tieren meist letal.","fr":"Posséder plus de deux jeux complets de chromosomes (ex. tétraploïde = 4n). Courant chez les plantes ; responsable de l'évolution de nombreuses espèces cultivées (le blé est hexaploïde 6n). Généralement létale chez les animaux.","tr":"İkiden fazla tam kromozom setine sahip olmak (örn. tetraploid = 4n). Bitkilerde yaygındır; pek çok kültür bitkisi türünün evriminden sorumludur (buğday heksaploid 6n'dir). Hayvanlarda genellikle ölümcüldür.","nl":"Meer dan twee volledige sets chromosomen bezitten (bijv. tetraploïd = 4n). Gewoon bij planten; verantwoordelijk voor de evolutie van veel gewassoorten (tarwe is hexaploïd 6n). Meestal dodelijk bij dieren.","ru":"Наличие более двух полных наборов хромосом (например, тетраплоид = 4n). Широко распространена у растений; лежит в основе эволюции многих культурных растений (пшеница — гексаплоид, 6n). У животных обычно летальна.","zh":"拥有超过两套完整染色体组（如四倍体 = 4n）。在植物中常见；是许多作物物种进化的原因（小麦为六倍体 6n）。在动物中通常是致死的。","pt_BR":"Ter mais de dois conjuntos completos de cromossomos (ex.: tetraploide = 4n). Comum em plantas; responsável pela evolução de muitas espécies de culturas (o trigo é hexaploide 6n). Geralmente letal em animais.","pt_PT":"Ter mais de dois conjuntos completos de cromossomas (ex.: tetraploide = 4n). Comum em plantas; responsável pela evolução de muitas espécies cultivadas (o trigo é hexaploide 6n). Geralmente letal nos animais."}},
  { id: 'dc-biology-0139', deck_id: 'deck-biology', sort_order: 139, front: "Restriction Enzyme", back: "A bacterial enzyme that cleaves double-stranded DNA at specific recognition sequences (palindromic). Produces 'sticky ends' (staggered cuts) or 'blunt ends.' Essential tool in molecular biology and genetic engineering." , front_translations: {"es":"Enzima de Restrición","de":"Restriktionsenzym","fr":"Enzyme de restriction","tr":"Restriksiyon Enzimi","nl":"Restrictie-enzym","ru":"Рестриктаза","zh":"限制酶","pt_BR":"Enzima de Restrição","pt_PT":"Enzima de Restrição"}, back_translations: {"es":"Una enzima bacteriana que cliva DNA de fita dupla en secuencias de reconhecimento específicas (palindromicas). Produz \"extremidades coesivas\" (cortes escalonados) o \"extremidades rombas\". Ferramenta esencial en biologia molecular y engenharia genética.","de":"Ein bakterielles Enzym, das doppelsträngige DNA an spezifischen Erkennungssequenzen (palindromisch) spaltet. Erzeugt \"klebrige Enden\" (versetzte Schnitte) oder \"stumpfe Enden\". Unverzichtbares Werkzeug in der Molekularbiologie und Gentechnik.","fr":"Une enzyme bactérienne qui clive l'ADN double brin à des séquences de reconnaissance spécifiques (palindromiques). Produit des \"extrémités cohésives\" (coupures décalées) ou des \"extrémités franches\". Outil essentiel en biologie moléculaire et en génie génétique.","tr":"Çift sarmallı DNA'yı belirli tanıma dizilerinde (palindromik) kesen bir bakteri enzimidir. \"Yapışkan uçlar\" (kademeli kesimler) veya \"küt uçlar\" üretir. Moleküler biyoloji ve genetik mühendisliğinde temel araçtır.","nl":"Een bacterieel enzym dat dubbelstrengs DNA klieft op specifieke herkenningssequenties (palindromisch). Produceert \"plakkerige uiteinden\" (versprongen sneden) of \"stompe uiteinden\". Essentieel gereedschap in moleculaire biologie en genetische manipulatie.","ru":"Бактериальный фермент, расщепляющий двухцепочечную ДНК в определённых сайтах узнавания (палиндромных). Образует «липкие концы» (ступенчатые разрезы) или «тупые концы». Незаменимый инструмент молекулярной биологии и генной инженерии.","zh":"一种细菌酶，在特定识别序列（回文序列）处切割双链DNA。产生\"粘性末端\"（交错切割）或\"平末端\"。是分子生物学和基因工程中的重要工具。","pt_BR":"Uma enzima bacteriana que cliva DNA de fita dupla em sequências de reconhecimento específicas (palindrômicas). Produz \"extremidades coesivas\" (cortes escalonados) ou \"extremidades rombas\". Ferramenta essencial em biologia molecular e engenharia genética.","pt_PT":"Uma enzima bacteriana que cliva o DNA de cadeia dupla em sequências de reconhecimento específicas (palindrómicas). Produz \"extremidades coesivas\" (cortes escalonados) ou \"extremidades cegas\". Ferramenta essencial em biologia molecular e engenharia genética."}},
  { id: 'dc-biology-0140', deck_id: 'deck-biology', sort_order: 140, front: "Gel Electrophoresis", back: "Separates DNA, RNA, or protein fragments by size using an electric field. Smaller fragments migrate faster through the gel. DNA is stained and visualized under UV light; used in forensics and diagnostics." , front_translations: {"es":"Eletroforese en Gel","de":"Gelelektrophorese","fr":"Électrophorèse sur gel","tr":"Jel Elektroforezi","nl":"Gelelektroforese","ru":"Гель-электрофорез","zh":"凝胶电泳","pt_BR":"Eletroforese em Gel","pt_PT":"Eletroforese em Gel"}, back_translations: {"es":"Separa fragmentos de DNA, RNA o proteínas por tamaño usando un campo eléctrico. Fragmentos menores migram más rápido por el gel. El DNA es corado y visualizado sob luz UV; usado en perícia forense y diagnóstico.","de":"Trennt DNA-, RNA- oder Proteinfragmente nach Größe mithilfe eines elektrischen Feldes. Kleinere Fragmente wandern schneller durch das Gel. DNA wird angefärbt und unter UV-Licht sichtbar gemacht; wird in der Forensik und Diagnostik eingesetzt.","fr":"Sépare les fragments d'ADN, d'ARN ou de protéines par taille à l'aide d'un champ électrique. Les fragments plus petits migrent plus vite à travers le gel. L'ADN est coloré et visualisé sous lumière UV ; utilisé en médecine légale et en diagnostic.","tr":"DNA, RNA veya protein parçalarını elektrik alan kullanarak boyutlarına göre ayırır. Daha küçük parçalar jel içinde daha hızlı göç eder. DNA boyanır ve UV ışık altında görselleştirilir; adli bilimler ve tanıda kullanılır.","nl":"Scheidt DNA-, RNA- of proteïnefragmenten op grootte met behulp van een elektrisch veld. Kleinere fragmenten migreren sneller door het gel. DNA wordt gekleurd en gevisualiseerd onder UV-licht; gebruikt in forensisch onderzoek en diagnostiek.","ru":"Разделяет фрагменты ДНК, РНК или белков по размеру с помощью электрического поля. Более мелкие фрагменты мигрируют быстрее через гель. ДНК окрашивают и визуализируют в УФ-свете; применяется в криминалистике и диагностике.","zh":"利用电场按大小分离DNA、RNA或蛋白质片段。较小的片段在凝胶中迁移更快。DNA经染色后在紫外线下可视化；用于法医学和诊断。","pt_BR":"Separa fragmentos de DNA, RNA ou proteínas por tamanho usando um campo elétrico. Fragmentos menores migram mais rápido pelo gel. O DNA é corado e visualizado sob luz UV; usado em perícia forense e diagnóstico.","pt_PT":"Separa fragmentos de DNA, RNA ou proteínas por tamanho usando um campo elétrico. Os fragmentos mais pequenos migram mais rapidamente pelo gel. O DNA é corado e visualizado sob luz UV; usado em ciências forenses e diagnóstico."}},
  { id: 'dc-biology-0141', deck_id: 'deck-biology', sort_order: 141, front: "Central Dogma of Molecular Biology", back: "DNA → RNA → Protein. Information flows from DNA to RNA via transcription and from RNA to protein via translation. Reverse transcriptase (retroviruses) can copy RNA back to DNA, an exception to the central dogma." , front_translations: {"es":"Dogma Central de la Biologia Molecular","de":"Zentrales Dogma der Molekularbiologie","fr":"Dogme central de la biologie moléculaire","tr":"Moleküler Biyolojinin Merkezi Dogması","nl":"Centraal dogma van de moleculaire biologie","ru":"Центральная догма молекулярной биологии","zh":"分子生物学中心法则","pt_BR":"Dogma Central da Biologia Molecular","pt_PT":"Dogma Central da Biologia Molecular"}, back_translations: {"es":"DNA → RNA → Proteína. La información flui del DNA para el RNA por transcrición y del RNA para a proteína por tradución. La transcriptase reversa (retrovírus) puede copiar RNA de volta para DNA, una exceción al dogma central.","de":"DNA → RNA → Protein. Informationen fließen von DNA zu RNA durch Transkription und von RNA zu Protein durch Translation. Reverse Transkriptase (Retroviren) kann RNA zurück in DNA kopieren, eine Ausnahme vom zentralen Dogma.","fr":"ADN → ARN → Protéine. L'information circule de l'ADN à l'ARN par transcription et de l'ARN à la protéine par traduction. La transcriptase inverse (rétrovirus) peut copier l'ARN en ADN, une exception au dogme central.","tr":"DNA → RNA → Protein. Bilgi, transkripsiyon yoluyla DNA'dan RNA'ya ve translasyon yoluyla RNA'dan proteine akar. Ters transkriptaz (retrovirüsler), RNA'yı tekrar DNA'ya kopyalayabilir; bu, merkezi dogmanın bir istisnasıdır.","nl":"DNA → RNA → Eiwit. Informatie stroomt van DNA naar RNA via transcriptie en van RNA naar eiwit via translatie. Reverse transcriptase (retrovirussen) kan RNA terugkopiëren naar DNA, een uitzondering op het centrale dogma.","ru":"ДНК → РНК → Белок. Информация передаётся от ДНК к РНК посредством транскрипции и от РНК к белку посредством трансляции. Обратная транскриптаза (ретровирусы) может копировать РНК обратно в ДНК — исключение из центральной догмы.","zh":"DNA → RNA → 蛋白质。信息通过转录从DNA流向RNA，再通过翻译从RNA流向蛋白质。逆转录酶（逆转录病毒）可将RNA逆转录为DNA，是中心法则的例外。","pt_BR":"DNA → RNA → Proteína. A informação flui do DNA para o RNA por transcrição e do RNA para a proteína por tradução. A transcriptase reversa (retrovírus) pode copiar RNA de volta para DNA, uma exceção ao dogma central.","pt_PT":"DNA → RNA → Proteína. A informação flui do DNA para o RNA por transcrição e do RNA para a proteína por tradução. A transcriptase reversa (retrovírus) pode copiar RNA de volta para DNA, uma exceção ao dogma central."}},
  { id: 'dc-biology-0142', deck_id: 'deck-biology', sort_order: 142, front: "Intron vs. Exon", back: "In eukaryotes, pre-mRNA contains introns (non-coding sequences, spliced out) and exons (coding sequences, retained). The mature mRNA consists only of exons joined together. Splicing is performed by the spliceosome." , front_translations: {"es":"Íntron vs. Éxon","de":"Intron vs. Exon","fr":"Intron vs. Exon","tr":"İntron ve Ekzon","nl":"Intron vs. Exon","ru":"Интрон и экзон","zh":"内含子与外显子","pt_BR":"Íntron vs. Éxon","pt_PT":"Intrão vs. Exão"}, back_translations: {"es":"En eucariotos, el pré-mRNA contiene íntrons (secuencias no codificantes, removidas por splicing) y éxons (secuencias codificantes, retidas). El mRNA maduro consiste solo en éxons unidos. El splicing es realizado por el spliceossomo.","de":"Bei Eukaryoten enthält die Prä-mRNA Introns (nicht-kodierende Sequenzen, herausgespleißt) und Exons (kodierende Sequenzen, behalten). Die reife mRNA besteht nur aus zusammengefügten Exons. Das Spleißen wird durch das Spleißosom durchgeführt.","fr":"Chez les eucaryotes, le pré-ARNm contient des introns (séquences non codantes, épissées) et des exons (séquences codantes, conservées). L'ARNm mature ne consiste qu'en exons joints. L'épissage est réalisé par le splicéosome.","tr":"Ökaryotlarda ön-mRNA, intronlar (kodlamayan diziler, kesilerek uzaklaştırılır) ve ekzonlar (kodlayan diziler, korunur) içerir. Olgun mRNA yalnızca bir araya getirilmiş ekzonlardan oluşur. Kesip birleştirme işlemi splayzozom tarafından gerçekleştirilir.","nl":"Bij eukaryoten bevat pre-mRNA intronen (niet-coderende sequenties, eruit gespliced) en exonen (coderende sequenties, behouden). De volwassen mRNA bestaat alleen uit samen gevoegde exonen. Splicing wordt uitgevoerd door het spliceosome.","ru":"У эукариот пре-мРНК содержит интроны (некодирующие последовательности, вырезаемые при сплайсинге) и экзоны (кодирующие последовательности, остающиеся). Зрелая мРНК состоит только из соединённых экзонов. Сплайсинг осуществляется сплайсосомой.","zh":"在真核生物中，前体mRNA包含内含子（非编码序列，被剪接去除）和外显子（编码序列，保留）。成熟mRNA仅由连接在一起的外显子组成。剪接由剪接体完成。","pt_BR":"Em eucariotos, o pré-mRNA contém íntrons (sequências não codificantes, removidas por splicing) e éxons (sequências codificantes, retidas). O mRNA maduro consiste apenas em éxons unidos. O splicing é realizado pelo spliceossomo.","pt_PT":"Em eucariotas, o pré-mRNA contém intrões (sequências não codificantes, removidas por splicing) e exões (sequências codificantes, retidas). O mRNA maduro consiste apenas em exões unidos. O splicing é realizado pelo spliceossoma."}},
  { id: 'dc-biology-0143', deck_id: 'deck-biology', sort_order: 143, front: "microRNA (miRNA)", back: "Short (~22 nucleotide) non-coding RNA molecules that regulate gene expression by binding to complementary sequences in mRNA, leading to its degradation or translational repression. Important in development and disease." , front_translations: {"es":"MicroRNA (miRNA)","de":"MikroRNA (miRNA)","fr":"MicroARN (miARN)","tr":"MikroRNA (miRNA)","nl":"MicroRNA (miRNA)","ru":"МикроРНК (miRNA)","zh":"微RNA（miRNA）","pt_BR":"MicroRNA (miRNA)","pt_PT":"MicroRNA (miRNA)"}, back_translations: {"es":"Moléculas curtas (~22 nucleotídeos) de RNA no codificante que regulan a expresión genica ligando-se a secuencias complementares en el mRNA, levando a la su degradación o represión traducional. Importantes en el desarrollo y en enfermedades.","de":"Kurze (~22 Nukleotid) nicht-kodierende RNA-Moleküle, die die Genexpression regulieren, indem sie an komplementäre Sequenzen in der mRNA binden, was zu deren Abbau oder translationaler Repression führt. Wichtig in der Entwicklung und bei Krankheiten.","fr":"De courtes molécules d'ARN non codant (~22 nucléotides) qui régulent l'expression génique en se liant à des séquences complémentaires dans l'ARNm, entraînant sa dégradation ou sa répression traductionnelle. Importants dans le développement et les maladies.","tr":"mRNA'daki tamamlayıcı dizilere bağlanarak mRNA'nın bozunmasına veya translasyon baskılanmasına yol açan kısa (~22 nükleotid) kodlamayan RNA molekülleri. Gelişim ve hastalıkta önemli bir rol oynar.","nl":"Korte (~22 nucleotide) niet-coderende RNA-moleculen die genexpressie reguleren door te binden aan complementaire sequenties in mRNA, wat leidt tot afbraak of translationele repressie. Belangrijk in ontwikkeling en ziekte.","ru":"Короткие (~22 нуклеотида) некодирующие молекулы РНК, регулирующие экспрессию генов путём связывания с комплементарными последовательностями мРНК, что приводит к её деградации или трансляционной репрессии. Важны в развитии и при заболеваниях.","zh":"短小（约22个核苷酸）的非编码RNA分子，通过与mRNA中的互补序列结合来调控基因表达，导致mRNA降解或翻译抑制。在发育和疾病中具有重要作用。","pt_BR":"Moléculas curtas (~22 nucleotídeos) de RNA não codificante que regulam a expressão gênica ligando-se a sequências complementares no mRNA, levando à sua degradação ou repressão traducional. Importantes no desenvolvimento e em doenças.","pt_PT":"Moléculas curtas (~22 nucleótidos) de RNA não codificante que regulam a expressão génica ligando-se a sequências complementares no mRNA, levando à sua degradação ou repressão traducional. Importantes no desenvolvimento e em doenças."}},
  { id: 'dc-biology-0144', deck_id: 'deck-biology', sort_order: 144, front: "Lymphatic System", back: "A network of vessels that returns excess interstitial fluid to the blood, transports dietary lipids from the gut (as chylomicrons), and houses lymphocytes for immune surveillance. Lymph nodes filter pathogens." , front_translations: {"es":"Sistema Linfático","de":"Lymphatisches System","fr":"Système lymphatique","tr":"Lenfatik Sistem","nl":"Lymfestelsel","ru":"Лимфатическая система","zh":"淋巴系统","pt_BR":"Sistema Linfático","pt_PT":"Sistema Linfático"}, back_translations: {"es":"Una red de vasos que devolve el exceso de fluido intersticial al sangre, transporta lipídios alimentares del intestino (como quilomícrons) y abriga linfócitos para vigilancia imunológica. Los linfonodos filtram patógenos.","de":"Ein Netzwerk von Gefäßen, das überschüssige Gewebeflüssigkeit ins Blut zurückführt, Nahrungsfette aus dem Darm transportiert (als Chylomikronen) und Lymphozyten für die Immunüberwachung beherbergt. Lymphknoten filtern Krankheitserreger.","fr":"Un réseau de vaisseaux qui restitue l'excès de liquide interstitiel au sang, transporte les lipides alimentaires depuis l'intestin (sous forme de chylomicrons) et héberge des lymphocytes pour la surveillance immunitaire. Les ganglions lymphatiques filtrent les agents pathogènes.","tr":"Fazla interstisyel sıvıyı kana geri döndüren, bağırsaktan besinsel lipidleri (şilomikronlar olarak) taşıyan ve bağışıklık gözetimi için lenfositleri barındıran damar ağı. Lenf düğümleri patojenleri filtreler.","nl":"Een netwerk van vaten dat overtollig interstitieel vocht terugbrengt naar het bloed, voedingslipiden uit de darm vervoert (als chylomicronen) en lymfocyten herbergt voor immuunbewaking. Lymfeklieren filteren pathogenen.","ru":"Сеть сосудов, возвращающих избыток межклеточной жидкости в кровь, транспортирующих пищевые липиды из кишечника (в виде хиломикронов) и содержащих лимфоциты для иммунного надзора. Лимфатические узлы фильтруют патогены.","zh":"将多余组织液返回血液、从肠道输送食物脂质（以乳糜微粒形式）、并为免疫监视容纳淋巴细胞的管道网络。淋巴结负责过滤病原体。","pt_BR":"Uma rede de vasos que devolve o excesso de fluido intersticial ao sangue, transporta lipídios alimentares do intestino (como quilomícrons) e abriga linfócitos para vigilância imunológica. Os linfonodos filtram patógenos.","pt_PT":"Uma rede de vasos que devolve o excesso de fluido intersticial ao sangue, transporta lípidos alimentares do intestino (como quilomícrons) e alberga linfócitos para vigilância imunológica. Os gânglios linfáticos filtram os agentes patogénicos."}},
  { id: 'dc-biology-0145', deck_id: 'deck-biology', sort_order: 145, front: "Blood Components", back: "Red blood cells (erythrocytes; carry O₂ via hemoglobin), white blood cells (leukocytes; immune functions), platelets (thrombocytes; clotting), and plasma (liquid matrix with proteins, nutrients, hormones)." , front_translations: {"es":"Componentes del Sangue","de":"Blutbestandteile","fr":"Composants du sang","tr":"Kan Bileşenleri","nl":"Bloedcomponenten","ru":"Компоненты крови","zh":"血液成分","pt_BR":"Componentes do Sangue","pt_PT":"Componentes do Sangue"}, back_translations: {"es":"Glóbulos vermelhos (eritrócitos; transportan El₂ via hemoglobina), glóbulos brancos (leucócitos; funciones imunológicas), plaquetas (trombócitos; coagulación) y plasma (matriz líquida con proteínas, nutrientes, hormonas).","de":"Rote Blutkörperchen (Erythrozyten; transportieren O₂ über Hämoglobin), weiße Blutkörperchen (Leukozyten; Immunfunktionen), Blutplättchen (Thrombozyten; Blutgerinnung) und Plasma (flüssige Matrix mit Proteinen, Nährstoffen, Hormonen).","fr":"Globules rouges (érythrocytes ; transportent l'O₂ via l'hémoglobine), globules blancs (leucocytes ; fonctions immunitaires), plaquettes (thrombocytes ; coagulation) et plasma (matrice liquide avec protéines, nutriments, hormones).","tr":"Kırmızı kan hücreleri (eritrositler; hemoglobin aracılığıyla O₂ taşır), beyaz kan hücreleri (lökositler; bağışıklık işlevleri), trombositler (pıhtılaşma) ve plazma (proteinler, besin maddeleri, hormonlar içeren sıvı matris).","nl":"Rode bloedcellen (erytrocyten; transporteren O₂ via hemoglobine), witte bloedcellen (leukocyten; immuunfuncties), bloedplaatjes (trombocyten; stolling) en plasma (vloeibare matrix met eiwitten, voedingsstoffen, hormonen).","ru":"Красные кровяные клетки (эритроциты; переносят O₂ с помощью гемоглобина), белые кровяные клетки (лейкоциты; иммунные функции), тромбоциты (свёртывание крови) и плазма (жидкая среда с белками, питательными веществами, гормонами).","zh":"红细胞（红血球；通过血红蛋白携带O₂）、白细胞（白血球；免疫功能）、血小板（血栓细胞；凝血）和血浆（含蛋白质、营养素、激素的液态基质）。","pt_BR":"Glóbulos vermelhos (eritrócitos; transportam O₂ via hemoglobina), glóbulos brancos (leucócitos; funções imunológicas), plaquetas (trombócitos; coagulação) e plasma (matriz líquida com proteínas, nutrientes, hormônios).","pt_PT":"Glóbulos vermelhos (eritrócitos; transportam O₂ via hemoglobina), glóbulos brancos (leucócitos; funções imunológicas), plaquetas (trombócitos; coagulação) e plasma (matriz líquida com proteínas, nutrientes, hormonas)."}},
  { id: 'dc-biology-0146', deck_id: 'deck-biology', sort_order: 146, front: "Hemoglobin", back: "An iron-containing protein in red blood cells that binds and transports O₂ (four subunits, each carrying one O₂). Cooperativity: binding one O₂ increases affinity for more. CO₂ and low pH reduce O₂ affinity (Bohr effect)." , front_translations: {"es":"Hemoglobina","de":"Hämoglobin","fr":"Hémoglobine","tr":"Hemoglobin","nl":"Hemoglobine","ru":"Гемоглобин","zh":"血红蛋白","pt_BR":"Hemoglobina","pt_PT":"Hemoglobina"}, back_translations: {"es":"Una proteína conteniendo ferro en los glóbulos vermelhos que liga y transporta El₂ (cuatro subunidades, cada una carregando un El₂). Cooperatividad: ligar un El₂ aumenta a afinidad por más. CO₂ y pH bajo reducen a afinidad por El₂ (efecto Bohr).","de":"Ein eisenhaltiges Protein in roten Blutkörperchen, das O₂ bindet und transportiert (vier Untereinheiten, jede trägt ein O₂). Kooperativität: Die Bindung eines O₂ erhöht die Affinität für mehr. CO₂ und niedriger pH verringern die O₂-Affinität (Bohr-Effekt).","fr":"Une protéine contenant du fer dans les globules rouges qui lie et transporte l'O₂ (quatre sous-unités, chacune portant un O₂). Coopérativité : la liaison d'un O₂ augmente l'affinité pour d'autres. Le CO₂ et un pH bas réduisent l'affinité pour l'O₂ (effet Bohr).","tr":"Kırmızı kan hücrelerinde bulunan, O₂ bağlayıp taşıyan demir içerikli protein (her biri bir O₂ taşıyan dört alt birim). Kooperatiflik: bir O₂ bağlanması daha fazlası için ilgiyi artırır. CO₂ ve düşük pH, O₂ ilgisini azaltır (Bohr etkisi).","nl":"Een ijzerhoudend eiwit in rode bloedcellen dat O₂ bindt en transporteert (vier subeenheden, elk met één O₂). Coöperativiteit: binding van één O₂ verhoogt de affiniteit voor meer. CO₂ en lage pH verminderen de O₂-affiniteit (Bohr-effect).","ru":"Железосодержащий белок в красных кровяных клетках, связывающий и переносящий O₂ (четыре субъединицы, каждая несёт одну молекулу O₂). Кооперативность: связывание одной молекулы O₂ увеличивает сродство к следующим. CO₂ и низкий pH снижают сродство к O₂ (эффект Бора).","zh":"红细胞中含铁的蛋白质，结合并运输O₂（四个亚基，每个携带一个O₂）。协同效应：结合一个O₂后对更多O₂的亲和力增加。CO₂和低pH降低对O₂的亲和力（波尔效应）。","pt_BR":"Uma proteína contendo ferro nos glóbulos vermelhos que liga e transporta O₂ (quatro subunidades, cada uma carregando um O₂). Cooperatividade: ligar um O₂ aumenta a afinidade por mais. CO₂ e pH baixo reduzem a afinidade por O₂ (efeito Bohr).","pt_PT":"Uma proteína contendo ferro nos glóbulos vermelhos que liga e transporta O₂ (quatro subunidades, cada uma transportando um O₂). Cooperatividade: ligar um O₂ aumenta a afinidade por mais. CO₂ e pH baixo reduzem a afinidade para O₂ (efeito de Bohr)."}},
  { id: 'dc-biology-0147', deck_id: 'deck-biology', sort_order: 147, front: "Bone Marrow", back: "Soft tissue inside bones where hematopoiesis (blood cell formation) occurs. Red marrow produces all blood cells; yellow marrow stores fat. B lymphocytes mature in bone marrow." , front_translations: {"es":"Medula Óssea","de":"Knochenmark","fr":"Moelle osseuse","tr":"Kemik İliği","nl":"Beenmerg","ru":"Костный мозг","zh":"骨髓","pt_BR":"Medula Óssea","pt_PT":"Medula Óssea"}, back_translations: {"es":"Tecido mole dentro de los huesos donde ocurre a hematopoiese (formación de células sanguíneas). La medula roja produce todas las células sanguíneas; a medula amarela almacena gordura. Los linfócitos B maturam en la médula ósea.","de":"Weiches Gewebe im Inneren der Knochen, wo die Hämatopoese (Blutzellenbildung) stattfindet. Rotes Mark produziert alle Blutzellen; gelbes Mark speichert Fett. B-Lymphozyten reifen im Knochenmark heran.","fr":"Tissu mou à l'intérieur des os où se produit l'hématopoïèse (formation des cellules sanguines). La moelle rouge produit toutes les cellules sanguines ; la moelle jaune stocke les graisses. Les lymphocytes B arrivent à maturité dans la moelle osseuse.","tr":"Hematopoezin (kan hücresi oluşumunun) gerçekleştiği kemiklerin içindeki yumuşak doku. Kırmızı ilik tüm kan hücrelerini üretir; sarı ilik yağ depolar. B lenfositler kemik iliğinde olgunlaşır.","nl":"Zacht weefsel binnenin botten waar hematopoëse (bloedcelvorming) plaatsvindt. Rood beenmerg produceert alle bloedcellen; geel beenmerg slaat vet op. B-lymfocyten rijpen in het beenmerg.","ru":"Мягкая ткань внутри костей, где происходит гемопоэз (образование клеток крови). Красный костный мозг производит все клетки крови; жёлтый костный мозг запасает жир. В-лимфоциты созревают в костном мозге.","zh":"骨骼内部的软组织，是造血（血细胞形成）发生的场所。红骨髓产生所有血细胞；黄骨髓储存脂肪。B淋巴细胞在骨髓中成熟。","pt_BR":"Tecido mole dentro dos ossos onde ocorre a hematopoiese (formação de células sanguíneas). A medula vermelha produz todas as células sanguíneas; a medula amarela armazena gordura. Os linfócitos B maturam na medula óssea.","pt_PT":"Tecido mole no interior dos ossos onde ocorre a hematopoiese (formação de células sanguíneas). A medula vermelha produz todas as células sanguíneas; a medula amarela armazena gordura. Os linfócitos B maturam na medula óssea."}},
  { id: 'dc-biology-0148', deck_id: 'deck-biology', sort_order: 148, front: "Liver Functions", back: "Metabolizes carbohydrates (glycogenesis, glycogenolysis, gluconeogenesis), lipids, and proteins; detoxifies drugs and metabolic waste; produces bile for fat digestion; synthesizes clotting factors and albumin." , front_translations: {"es":"Funciones del Fígado","de":"Leberfunktionen","fr":"Fonctions du foie","tr":"Karaciğer İşlevleri","nl":"Leverfuncties","ru":"Функции печени","zh":"肝脏功能","pt_BR":"Funções do Fígado","pt_PT":"Funções do Fígado"}, back_translations: {"es":"Metaboliza carboidratos (glicogenese, glicogenólise, gliconeogenese), lipídios y proteínas; desintoxica drogas y resíduos metabólicos; produce bile para digestión de gordura; sintetiza fatores de coagulación y albumina.","de":"Metabolisiert Kohlenhydrate (Glykogenese, Glykogenolyse, Glukoneogenese), Lipide und Proteine; entgiftet Medikamente und Stoffwechselabfälle; produziert Galle zur Fettverdauung; synthetisiert Gerinnungsfaktoren und Albumin.","fr":"Métabolise les glucides (glycogénèse, glycogénolyse, gluconéogenèse), les lipides et les protéines ; détoxifie les médicaments et les déchets métaboliques ; produit la bile pour la digestion des graisses ; synthétise les facteurs de coagulation et l'albumine.","tr":"Karbonhidratları (glikojenez, glikogenoliz, glukoneogenez), lipidleri ve proteinleri metabolize eder; ilaçları ve metabolik atıkları detoksifiye eder; yağ sindiriminde safra üretir; pıhtılaşma faktörlerini ve albumini sentezler.","nl":"Metaboliseert koolhydraten (glycogenese, glycogenolyse, gluconeogenese), lipiden en eiwitten; ontgift geneesmiddelen en metabolisch afval; produceert gal voor vetvertering; synthetiseert stollingsfactoren en albumine.","ru":"Метаболизирует углеводы (гликогенез, гликогенолиз, глюконеогенез), липиды и белки; обезвреживает лекарства и метаболические отходы; вырабатывает желчь для переваривания жиров; синтезирует факторы свёртывания крови и альбумин.","zh":"代谢碳水化合物（糖原合成、糖原分解、糖异生）、脂质和蛋白质；解毒药物和代谢废物；产生胆汁用于脂肪消化；合成凝血因子和白蛋白。","pt_BR":"Metaboliza carboidratos (glicogênese, glicogenólise, gliconeogênese), lipídios e proteínas; desintoxica drogas e resíduos metabólicos; produz bile para digestão de gordura; sintetiza fatores de coagulação e albumina.","pt_PT":"Metaboliza hidratos de carbono (glicogénese, glicogenólise, gliconeogénese), lípidos e proteínas; desintoxica fármacos e resíduos metabólicos; produz bílis para digestão de gorduras; sintetiza fatores de coagulação e albumina."}},
  { id: 'dc-biology-0149', deck_id: 'deck-biology', sort_order: 149, front: "Epinephrine (Adrenaline)", back: "A hormone and neurotransmitter released by the adrenal medulla in response to stress ('fight or flight'). Increases heart rate, dilates airways, mobilizes glucose, and redirects blood flow to muscles." , front_translations: {"es":"Epinefrina (Adrenalina)","de":"Epinephrin (Adrenalin)","fr":"Épinéphrine (adrénaline)","tr":"Epinefrin (Adrenalin)","nl":"Epinefrine (adrenaline)","ru":"Эпинефрин (адреналин)","zh":"肾上腺素","pt_BR":"Epinefrina (Adrenalina)","pt_PT":"Epinefrina (Adrenalina)"}, back_translations: {"es":"Un hormona y neurotransmissor liberado por la medula adrenal en respuesta al estresse ('luta o fuga'). Aumenta a frecuencia cardíaca, dilata las vias aéreas, mobiliza a glicose y redireciona el flujo sanguíneo para los músculos.","de":"Ein Hormon und Neurotransmitter, der vom Nebennierenmark als Reaktion auf Stress ausgeschüttet wird ('Kampf oder Flucht'). Erhöht die Herzfrequenz, erweitert die Atemwege, mobilisiert Glukose und leitet den Blutfluss zu den Muskeln um.","fr":"Une hormone et neurotransmetteur libérée par la médullosurrénale en réponse au stress ('combat ou fuite'). Augmente la fréquence cardiaque, dilate les voies respiratoires, mobilise le glucose et redirige le flux sanguin vers les muscles.","tr":"Strese yanıt olarak böbreküstü bezi medullası tarafından salgılanan bir hormon ve nörotransmitter ('savaş ya da kaç'). Kalp atış hızını artırır, hava yollarını genişletir, glikozu harekete geçirir ve kan akışını kaslara yönlendirir.","nl":"Een hormoon en neurotransmitter vrijgegeven door het bijniermerg als reactie op stress ('vecht of vlucht'). Verhoogt de hartslag, verwijdt de luchtwegen, mobiliseert glucose en leidt bloedstroom om naar spieren.","ru":"Гормон и нейромедиатор, выделяемый мозговым веществом надпочечников в ответ на стресс («бей или беги»). Увеличивает частоту сердечных сокращений, расширяет дыхательные пути, мобилизует глюкозу и перераспределяет кровоток к мышцам.","zh":"由肾上腺髓质在应激反应（\"战斗或逃跑\"）时释放的激素和神经递质。增加心率、扩张气道、动员葡萄糖，并将血流重新导向肌肉。","pt_BR":"Um hormônio e neurotransmissor liberado pela medula adrenal em resposta ao estresse ('luta ou fuga'). Aumenta a frequência cardíaca, dilata as vias aéreas, mobiliza a glicose e redireciona o fluxo sanguíneo para os músculos.","pt_PT":"Uma hormona e neurotransmissor libertada pela medula suprarrenal em resposta ao stress ('luta ou fuga'). Aumenta a frequência cardíaca, dilata as vias aéreas, mobiliza a glicose e redireciona o fluxo sanguíneo para os músculos."}},
  { id: 'dc-biology-0150', deck_id: 'deck-biology', sort_order: 150, front: "Reproductive Strategies: r vs. K Selection", back: "r-selected species: small size, many offspring, little parental care, short lifespan (e.g., insects, mice). K-selected species: large size, few offspring, high parental investment, long lifespan (e.g., elephants, humans)." , front_translations: {"es":"Estratégias Reprodutivas: Seleción r vs. K","de":"Reproduktionsstrategien: r- vs. K-Selektion","fr":"Stratégies de reproduction : sélection r vs. K","tr":"Üreme Stratejileri: r ve K Seçilimi","nl":"Reproductiestrategieën: r- vs. K-selectie","ru":"Стратегии размножения: r- и K-отбор","zh":"繁殖策略：r对策与K对策","pt_BR":"Estratégias Reprodutivas: Seleção r vs. K","pt_PT":"Estratégias Reprodutivas: Seleção r vs. K"}, back_translations: {"es":"Espécies r-selecionadas: tamaño pequeño, muchos descendentes, pouco cuidado parental, vida corta (ex.: insetos, camundongos). Espécies K-selecionadas: tamaño grande, poucos descendentes, alto inversión parental, vida ancha (ex.: elefantes, humanos).","de":"R-selektierte Arten: kleine Größe, viele Nachkommen, wenig elterliche Fürsorge, kurze Lebensdauer (z. B. Insekten, Mäuse). K-selektierte Arten: große Größe, wenige Nachkommen, hohe elterliche Investition, lange Lebensdauer (z. B. Elefanten, Menschen).","fr":"Espèces à stratégie r : petite taille, nombreux descendants, peu de soins parentaux, courte durée de vie (ex. insectes, souris). Espèces à stratégie K : grande taille, peu de descendants, investissement parental élevé, longue durée de vie (ex. éléphants, humains).","tr":"r-seçilimli türler: küçük beden, çok sayıda yavru, az ebeveyn bakımı, kısa ömür (örn. böcekler, fareler). K-seçilimli türler: büyük beden, az yavru, yüksek ebeveyn yatırımı, uzun ömür (örn. filler, insanlar).","nl":"r-geselecteerde soorten: kleine omvang, veel nakomelingen, weinig ouderlijke zorg, korte levensduur (bijv. insecten, muizen). K-geselecteerde soorten: grote omvang, weinig nakomelingen, hoge ouderzorg, lange levensduur (bijv. olifanten, mensen).","ru":"r-стратеги: небольшой размер, многочисленное потомство, минимальная родительская забота, короткая продолжительность жизни (например, насекомые, мыши). K-стратеги: крупный размер, мало потомков, высокие родительские инвестиции, долгая жизнь (например, слоны, люди).","zh":"r对策物种：体型小、后代多、亲代投入少、寿命短（如昆虫、小鼠）。K对策物种：体型大、后代少、亲代投入高、寿命长（如大象、人类）。","pt_BR":"Espécies r-selecionadas: tamanho pequeno, muitos descendentes, pouco cuidado parental, vida curta (ex.: insetos, camundongos). Espécies K-selecionadas: tamanho grande, poucos descendentes, alto investimento parental, vida longa (ex.: elefantes, humanos).","pt_PT":"Espécies com seleção r: tamanho pequeno, muitos descendentes, pouco cuidado parental, vida curta (ex.: insetos, ratinhos). Espécies com seleção K: tamanho grande, poucos descendentes, elevado investimento parental, vida longa (ex.: elefantes, humanos)."}},
];
